            setLoggingTaskId(taskId);
            if (existingLog) {
                setEditingLogId(existingLog._id);
                // SPLIT
                const total = parseFloat(existingLog.hours) || 0;
                const h = Math.floor(total);
                const m = Math.round((total - h) * 60);

                setLogForm({
