                        </div>

                        {/* Export Button - Permission Check */
                            (user?.roles?.includes('Admin') || user?.roles?.includes('Manager') || user?.role === 'Admin' || usersList.length > 0 || user?.permissions?.includes('attendance.export')) && (
                                <div className="flex items-center space-x-2">
                                    {(user?.company?.settings?.attendance?.exportFormat === 'Monthly Timesheet') ? (
                                        <Button
                                            onClick={handleExportMonthlyTimesheet}
                                            variants="outline"
                                            className="p-2 border-slate-200 text-slate-600 hover:text-emerald-600 hover:border-emerald-300"
                                            title="Download Monthly Timesheet"
                                        >
                                            <Calendar size={20} />
                                        </Button>
                                    ) : (
                                        <Button
                                            onClick={handleExportAttendance}
                                            variants="outline"
                                            className="p-2 border-slate-200 text-slate-600 hover:text-blue-600 hover:border-blue-300"
                                            title="Download Personal Report"
                                        >
                                            <Download size={20} />
                                        </Button>
                                    )}
                                </div>
                            )}
                    </div>
                </div>
            </div>


            {/* Main Content - Flex/Grid taking remaining height */}
            <div className="flex-1 overflow-hidden px-4 pb-4 md:px-6 md:pb-6">
                <div className="grid grid-cols-1 xl:grid-cols-4 gap-6 h-full">

                    {/* Widget Column - Scrollable */}
                    <div className="xl:col-span-1 space-y-6 overflow-y-auto pr-2 h-full custom-scrollbar pb-2">
                        {/* Clock Widget */}
                        <div className="zoho-card p-6 flex flex-col items-center justify-center text-center border-t-4 border-t-blue-500">
                            <div className="mb-6 relative group">
                                <div className={`h-36 w-36 rounded-full flex items-center justify-center border-[6px] transition-all duration-500 ${isClockedIn ? 'border-[#08B87B] bg-[#EAF7F2] shadow-sm' : 'border-slate-200 bg-white shadow-sm'}`}>
                                    <Clock size={48} className={isClockedIn ? 'text-[#08B87B]' : 'text-slate-400'} />
                                </div>
                                {isClockedIn && (
                                    <div className="absolute -bottom-2 left-1/2 transform -translate-x-1/2 bg-[#08B87B] text-white text-[10px] font-extrabold px-3 py-1 rounded-full uppercase tracking-wider shadow-md">
                                        ACTIVE
                                    </div>
                                )}
                            </div>

                            <div className="space-y-1 mb-6">
                                <div className="text-xs font-semibold text-slate-400 uppercase tracking-widest">Status</div>
                                <div className={`text-xl font-bold ${isClockedIn ? 'text-[#08B87B]' : isClockedOut ? 'text-slate-500' : 'text-slate-700'}`}>
                                    {isClockedIn ? 'Clocked In' : isClockedOut ? 'Shift Ended' : 'Not Started'}
                                </div>
                            </div>

                            <div className="w-full space-y-3">
                                {!isClockedIn && !isClockedOut && (
                                    <button
                                        onClick={handleClockIn}
                                        disabled={loadingLocation}
                                        className={`w-full flex items-center justify-center gap-2 py-3 bg-[#1B5FF3] text-white font-bold rounded-[10px] shadow-[0_4px_16px_rgba(27,95,243,0.35)] hover:bg-blue-700 active:scale-95 transition-all text-[15px] tracking-wide ${loadingLocation ? 'opacity-70 cursor-not-allowed' : ''}`}
                                    >
                                        {loadingLocation ? (
                                            <>
                                                <Loader2 className="animate-spin" size={18} />
                                                <span>Loading...</span>
                                            </>
                                        ) : (
                                            <span>Check In</span>
                                        )}
                                    </button>
                                )}

                                {isClockedIn && (
                                    <button
                                        onClick={handleClockOut}
                                        disabled={loadingLocation}
                                        className={`w-full flex items-center justify-center gap-2 py-3 bg-[#e60000] text-white font-bold rounded-[10px] shadow-[0_4px_16px_rgba(230,0,0,0.35)] hover:bg-[#cc0000] active:scale-95 transition-all text-[15px] tracking-wide ${loadingLocation ? 'opacity-70 cursor-not-allowed' : ''}`}
                                    >
                                        {loadingLocation ? (
                                            <>
                                                <Loader2 className="animate-spin" size={18} />
                                                <span>Fetching Location...</span>
                                            </>
                                        ) : (
                                            <span>Check Out</span>
                                        )}
                                    </button>
                                )}

                                {isClockedOut && (
                                    <div className="w-full py-2.5 bg-slate-100 text-slate-500 rounded font-medium border border-slate-200 text-sm text-center">
                                        Output Logged
                                    </div>
                                )}
                            </div>

                            <div className="mt-6 w-full bg-slate-50 rounded border border-slate-100 divide-y divide-slate-100">
                                <div className="flex justify-between p-3 text-sm flex-col sm:flex-row gap-1 sm:gap-0">
                                    <span className="text-slate-500">In Time</span>
                                    <span className="font-mono font-medium text-slate-700 sm:text-right">
                                        {formatTime(status?.clockIn, status?.clockInIST)}
                                    </span>
                                </div>
                                <div className="flex justify-between p-3 text-sm flex-col sm:flex-row gap-1 sm:gap-0">
                                    <span className="text-slate-500">Out Time</span>
                                    <span className="font-mono font-medium text-slate-700 sm:text-right">
                                        {formatTime(status?.clockOut, status?.clockOutIST)}
                                    </span>
                                </div>
                                <div className="flex justify-between p-3 text-sm bg-slate-100/30 flex-col sm:flex-row gap-1 sm:gap-0 rounded-b">
                                    <span className="font-bold text-slate-700">Total Hours</span>
                                    <span className="font-mono font-bold text-[#1B5FF3] sm:text-right">
                                        {status?.clockIn ? calculateDuration(status.clockIn, status.clockOut) : '--'}
                                    </span>
                                </div>
                            </div>
                        </div>

                        {hasModule('projectManagement') && (
                            <div className="zoho-card p-5 mt-6">
                                <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-4">Recent Activity</h4>
                                {recentLogs.length > 0 ? (
                                    <div className="space-y-4">
                                        {recentLogs.map(log => (
                                            <div key={log._id} className="flex gap-3 text-sm border-b border-slate-50 pb-3 last:border-0 last:pb-0">
                                                <div className="mt-1">
                                                    <CheckSquare size={14} className="text-blue-500" />
                                                </div>
                                                <div>
                                                    <div className="font-medium text-slate-700">
                                                        {log.task?.name || 'Unknown Task'}
                                                    </div>
                                                    <div className="text-xs text-slate-500 mt-0.5">
                                                        {log.hours} hrs • {new Date(log.date).toLocaleDateString()}
                                                    </div>
                                                    {log.description && (
                                                        <div className="text-xs text-slate-400 mt-1 italic">
                                                            "{log.description}"
                                                        </div>
                                                    )}
                                                </div>
                                            </div>
                                        ))}
                                        <div className="pt-2 text-center">
                                            <a href="/timesheet" className="text-xs text-blue-600 hover:underline">View All in Timesheet</a>
                                        </div>
                                    </div>
                                ) : (
                                    <div className="text-center text-xs text-slate-400 py-2">
                                        No work logged recently.
                                    </div>
                                )}
                            </div>
                        )}

                        {!isClockedIn && hasModule('projectManagement') && (
                            <div className="zoho-card p-5 opacity-75 mt-6">
                                <div className="text-center space-y-2">
                                    <Briefcase size={32} className="mx-auto text-slate-300" />
                                    <h4 className="font-medium text-slate-600">Your Tasks</h4>
                                    <p className="text-xs text-slate-400">Clock in to view and manage your assigned tasks.</p>
                                </div>
                            </div>
                        )}

                        {/* Team Members Selection (Admins/Managers) */}
                        {(isAdmin || isManager) && (
                            <div className="zoho-card p-5">
                                <div className="flex justify-between items-center mb-4">
                                    <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wide">Team Members</h4>
                                    {!usersLoaded && !loadingUsers && (
                                        <button
                                            onClick={fetchUsers}
                                            className="text-[10px] text-blue-600 font-bold hover:underline"
                                        >
                                            Show All
                                        </button>
                                    )}
                                </div>
                                <div className="space-y-2 max-h-[300px] overflow-y-auto custom-scrollbar pr-1">
                                    {/* Self */}
                                    <button
                                        onClick={() => setSelectedUserId(user._id)}
                                        className={`w-full flex items-center gap-3 p-2.5 rounded-lg transition-all text-left ${selectedUserId === user._id ? 'bg-blue-50 border border-blue-100 text-blue-700' : 'hover:bg-slate-50 border border-transparent text-slate-600'}`}
                                    >
                                        <div className="h-8 w-8 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 text-[10px] font-bold">ME</div>
                                        <div className="flex-1 overflow-hidden">
                                            <p className="text-xs font-bold truncate">My Attendance</p>
                                            <p className="text-[10px] opacity-70 truncate">{user.email}</p>
                                        </div>
                                    </button>

                                    {loadingUsers && (
                                        <div className="flex items-center justify-center py-4">
                                            <Loader2 size={16} className="animate-spin text-blue-500" />
                                        </div>
                                    )}

                                    {usersLoaded && usersList.length > 0 && <div className="h-px bg-slate-100 my-2"></div>}

                                    {/* List */}
                                    {usersList.filter(u => u._id !== user._id).map((u) => (
                                        <button
                                            key={u._id}
                                            onClick={() => setSelectedUserId(u._id)}
                                            className={`w-full flex items-center gap-3 p-2.5 rounded-lg transition-all text-left ${selectedUserId === u._id ? 'bg-blue-50 border border-blue-100 text-blue-700' : 'hover:bg-slate-50 border border-transparent text-slate-600'}`}
                                        >
                                            <div className="h-8 w-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-600 text-[10px] font-bold">
                                                {u.firstName?.[0]}{u.lastName?.[0]}
                                            </div>
                                            <div className="flex-1 overflow-hidden">
                                                <p className="text-xs font-bold truncate">{u.firstName} {u.lastName}</p>
                                                <p className="text-[10px] opacity-70 truncate">{u.email}</p>
                                            </div>
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}

                        {/* Legend */}
                        <div className="zoho-card p-5">
                            <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-4">Legend</h4>
                            <div className="space-y-3">
                                <div className="flex items-center text-sm">
                                    <div className="w-3 h-3 rounded-full bg-emerald-500 mr-3"></div>
                                    <span className="text-slate-600">Present</span>
                                </div>
                                <div className="flex items-center text-sm">
                                    <div className="w-3 h-3 rounded-full bg-red-500 mr-3"></div>
                                    <span className="text-slate-600">Absent</span>
                                </div>
                                <div className="flex items-center text-sm">
                                    <div className="w-3 h-3 rounded-full bg-orange-500 mr-3"></div>
                                    <span className="text-slate-600">Half Day</span>
                                </div>
                                <div className="flex items-center text-sm">
                                    <div className="w-3 h-3 rounded-full bg-purple-500 mr-3"></div>
                                    <span className="text-slate-600">Leave</span>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Main Content Column with Tabs - Flex Column */}
                    <div className="xl:col-span-3 flex flex-col h-full overflow-hidden">
                        {/* Tab Navigation - Fixed */}
                        <div className="flex-none flex border-b border-slate-200 bg-white rounded-t-lg px-4 pt-2 mb-0">
                            <button
                                onClick={() => setActiveTab('history')}
                                className={`px-4 py-3 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeTab === 'history' ? 'border-blue-500 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                            >
                                <Calendar size={16} /> Attendance History
                            </button>
                            <button
                                onClick={() => setActiveTab('regularize')}
                                className={`px-4 py-3 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeTab === 'regularize' ? 'border-blue-500 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                            >
                                <Clock size={16} /> Regularization Requests
                            </button>
                            {hasModule('projectManagement') && (
                                <button
                                    onClick={() => setActiveTab('tasks')}
                                    className={`px-4 py-3 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${activeTab === 'tasks' ? 'border-blue-500 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                                >
                                    <Briefcase size={16} /> Assigned to Me {assignedTasks.length > 0 && <span className="bg-slate-100 text-slate-600 text-xs py-0.5 px-2 rounded-full ml-1">{assignedTasks.length}</span>}
                                </button>
                            )}
                        </div>

                        {/* Scrollable Content Area */}
                        <div className="flex-1 bg-white rounded-b-lg shadow-sm border border-t-0 border-slate-200 p-6 overflow-y-auto custom-scrollbar relative">
                            {activeTab === 'history' ? (
                                <AttendanceCalendar
                                    history={history}
                                    onMonthChange={(year, month) => {
                                        setCalendarDate(new Date(year, month - 1, 1));
                                        fetchMonthHistory(year, month);
                                    }}
                                    user={user}
                                    date={calendarDate}
                                    holidays={holidays}
                                    approvedLeaves={approvedLeaves}
                                    onRegularize={handleRegularize}
                                    weeklyOffs={weeklyOffs}
                                />
                            ) : activeTab === 'regularize' ? (
                                <RegularizationRequestsView
                                    requests={regularizationRequests}
                                    onProcess={processRegularization}
                                    processingId={processingRegId}
                                    currentUser={user}
                                />
                            ) : (
                                <AssignedTasksView
                                    assignedTasks={assignedTasks}
                                    isClockedIn={isClockedIn}
                                    onLogWork={handleLogWork}
                                    logForm={logForm}
                                    setLogForm={setLogForm}
                                    expandedLogTaskId={expandedLogTaskId}
                                    setExpandedLogTaskId={setExpandedLogTaskId} // Using this to track "selected task" for logging
                                    recentLogs={recentLogs}
                                    onDeleteLog={handleDeleteLog}
                                    toggleLogForm={toggleLogForm}
                                    editingLogId={editingLogId}
                                />
                            )}
                        </div>
                    </div>
                </div>
            </div>

            {/* Regularization Modal */}
            {showRegModal && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
                    <div className="bg-white rounded-2xl shadow-xl w-full max-w-md overflow-hidden transform transition-all scale-100">
                        <div className="px-6 py-4 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
                            <div>
                                <h3 className="text-lg font-bold text-slate-800">Request Regularization</h3>
                                <p className="text-xs text-slate-500 font-medium">{regDate ? format(new Date(regDate), 'MMMM dd, yyyy') : ''}</p>
                            </div>
                            <button onClick={() => setShowRegModal(false)} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
                                <X size={20} className="text-slate-500" />
                            </button>
                        </div>

                        <form onSubmit={submitRegularization} className="p-6 space-y-5">
                            <div>
                                <label className="block text-[11px] font-bold text-slate-500 uppercase tracking-wider mb-2">Regularize For</label>
                                <div className="grid grid-cols-3 gap-2">
                                    {['IN', 'OUT', 'BOTH'].map(type => (
                                        <button
                                            key={type}
                                            type="button"
                                            onClick={() => setRegForm({ ...regForm, type })}
                                            className={`py-2 text-xs font-semibold rounded-lg border transition-all ${regForm.type === type ? 'bg-blue-600 border-blue-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-600 hover:border-blue-300'}`}
                                        >
                                            {type}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                {(regForm.type === 'IN' || regForm.type === 'BOTH') && (
                                    <div>
                                        <label className="block text-[11px] font-bold text-slate-500 uppercase tracking-wider mb-2">Check In Time</label>
                                        <input
                                            type="time"
                                            required
                                            className="w-full p-2.5 bg-white border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none"
                                            value={regForm.checkIn}
                                            onChange={(e) => setRegForm({ ...regForm, checkIn: e.target.value })}
                                        />
                                    </div>
                                )}
                                {(regForm.type === 'OUT' || regForm.type === 'BOTH') && (
                                    <div>
                                        <label className="block text-[11px] font-bold text-slate-500 uppercase tracking-wider mb-2">Check Out Time</label>
                                        <input
                                            type="time"
                                            required
                                            className="w-full p-2.5 bg-white border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none"
                                            value={regForm.checkOut}
                                            onChange={(e) => setRegForm({ ...regForm, checkOut: e.target.value })}
                                        />
                                    </div>
                                )}
                            </div>

                            <div>
                                <label className="block text-[11px] font-bold text-slate-500 uppercase tracking-wider mb-2">Reason for Regularization</label>
                                <textarea
                                    required
                                    rows="3"
                                    placeholder="Please provide a valid reason..."
                                    className="w-full p-3 bg-white border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none resize-none"
                                    value={regForm.reason}
                                    onChange={(e) => setRegForm({ ...regForm, reason: e.target.value })}
                                ></textarea>
                            </div>

                            <div className="pt-2">
                                <button
                                    type="submit"
                                    className="w-full py-3 bg-blue-600 text-white font-bold rounded-xl shadow-lg shadow-blue-200 hover:bg-blue-700 active:scale-[0.98] transition-all"
                                >
                                    Submit Request
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

const AssignedTasksView = ({
    assignedTasks,
    isClockedIn,
    onLogWork,
    logForm,
    setLogForm,
    expandedLogTaskId,
    setExpandedLogTaskId,
    recentLogs,
    onDeleteLog,
    toggleLogForm,
    editingLogId
}) => {
    // 1. Group Tasks by Project -> Module
    const groupedData = useMemo(() => {
        const projects = {};
        assignedTasks.forEach(task => {
            const projectId = task.module?.project?._id || 'unknown';
            const projectName = task.module?.project?.name || 'Unknown Project';
            const moduleId = task.module?._id || 'unknown';
            const moduleName = task.module?.name || 'Unknown Module';

            if (!projects[projectId]) {
                projects[projectId] = { id: projectId, name: projectName, modules: {} };
            }
            if (!projects[projectId].modules[moduleId]) {
                projects[projectId].modules[moduleId] = { id: moduleId, name: moduleName, tasks: [] };
            }
            projects[projectId].modules[moduleId].tasks.push(task);
        });

        return Object.values(projects).map(p => ({
            ...p,
            modules: Object.values(p.modules)
        }));
    }, [assignedTasks]);

    // 2. Selection State
    const [selectedProjectId, setSelectedProjectId] = useState(null);
    const [selectedModuleId, setSelectedModuleId] = useState(null);

    // Derived Data for Views
    const selectedProject = selectedProjectId ? groupedData.find(p => p.id === selectedProjectId) : null;
    const selectedModule = (selectedProject && selectedModuleId) ? selectedProject.modules.find(m => m.id === selectedModuleId) : null;

    // Helper
    const getTodayLogForTask = (taskId) => {
        const today = new Date().toISOString().split('T')[0];
        return recentLogs.find(log =>
            log.task &&
            log.task._id === taskId &&
            new Date(log.date).toISOString().split('T')[0] === today
        );
    };

    // --- VIEW 1: PROJECTS GRID ---
    if (!selectedProjectId) {
        return (
            <div className="h-[500px] overflow-y-auto pr-2 custom-scrollbar">
                <div className="flex justify-between items-center mb-4 sticky top-0 bg-white z-10 py-2 border-b border-slate-100">
                    <h3 className="text-lg font-bold text-slate-800">My Projects</h3>
                    <span className="text-xs text-slate-500">{groupedData.length} Projects</span>
                </div>

                {groupedData.length > 0 ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {groupedData.map(project => (
                            <button
                                key={project.id}
                                onClick={() => setSelectedProjectId(project.id)}
                                className="flex items-center p-4 bg-white border border-slate-200 rounded-lg shadow-sm hover:shadow-md hover:border-blue-300 transition-all text-left group"
                            >
                                <div className="h-10 w-10 rounded-full bg-blue-50 flex items-center justify-center text-blue-600 mr-4 group-hover:scale-110 transition-transform">
                                    <Briefcase size={20} />
                                </div>
                                <div>
                                    <h4 className="font-semibold text-slate-800 group-hover:text-blue-600 transition-colors">{project.name}</h4>
                                    <p className="text-xs text-slate-500">{project.modules.length} Modules • {project.modules.reduce((acc, m) => acc + m.tasks.length, 0)} Tasks</p>
                                </div>
                                <ChevronRight className="ml-auto text-slate-300 group-hover:text-blue-400" size={20} />
                            </button>
                        ))}
                    </div>
                ) : (
                    <div className="text-center py-12 text-slate-400">
                        <CheckSquare size={48} className="mx-auto text-slate-200 mb-3" />
                        <p>No tasks assigned.</p>
                    </div>
                )}
            </div>
        );
    }

    // --- VIEW 2: MODULES GRID ---
    if (!selectedModuleId) {
        return (
            <div className="h-[500px] overflow-y-auto pr-2 custom-scrollbar">
                <div className="sticky top-0 bg-white z-10 pb-4 border-b border-slate-100 mb-4">
                    <button
                        onClick={() => setSelectedProjectId(null)}
                        className="flex items-center text-sm text-slate-500 hover:text-blue-600 transition-colors mb-2"
                    >
                        <ChevronLeft size={16} className="mr-1" /> Back to Projects
                    </button>
                    <h3 className="text-lg font-bold text-slate-800 flex items-center">
                        <span className="text-slate-400 font-normal mr-2">Project:</span>
                        {selectedProject?.name}
                    </h3>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {selectedProject?.modules.map(module => (
                        <button
                            key={module.id}
                            onClick={() => setSelectedModuleId(module.id)}
                            className="flex items-center p-4 bg-white border border-slate-200 rounded-lg shadow-sm hover:shadow-md hover:border-emerald-300 transition-all text-left group"
                        >
                            <div className="h-10 w-10 rounded-full bg-emerald-50 flex items-center justify-center text-emerald-600 mr-4 group-hover:scale-110 transition-transform">
                                <Layers size={20} />
                            </div>
                            <div>
                                <h4 className="font-semibold text-slate-800 group-hover:text-emerald-600 transition-colors">{module.name}</h4>
                                <p className="text-xs text-slate-500">{module.tasks.length} Assigned Tasks</p>
                            </div>
                            <ChevronRight className="ml-auto text-slate-300 group-hover:text-emerald-400" size={20} />
                        </button>
                    ))}
                </div>
            </div>
        );
    }

    // --- VIEW 3: TASKS LIST ---
    return (
        <div className="h-[500px] overflow-y-auto pr-2 custom-scrollbar">
            <div className="sticky top-0 bg-white z-10 pb-4 border-b border-slate-100 mb-4">
                <button
                    onClick={() => setSelectedModuleId(null)}
                    className="flex items-center text-sm text-slate-500 hover:text-blue-600 transition-colors mb-2"
                >
                    <ChevronLeft size={16} className="mr-1" /> Back to Modules
                </button>
                <div className="flex flex-col">
                    <div className="flex items-center space-x-2 text-xs text-slate-500 mb-1">
                        <span>{selectedProject?.name}</span>
                        <span>/</span>
                        <span>{selectedModule?.name}</span>
                    </div>
                    <div className="flex justify-between items-center">
                        <h3 className="text-lg font-bold text-slate-800">Tasks</h3>
                        {!isClockedIn && <span className="text-xs text-amber-600 font-medium bg-amber-50 px-3 py-1 rounded-full border border-amber-200">⚠️ Clock in to log work</span>}
                    </div>
                </div>
            </div>

            <div className="space-y-3">
                {selectedModule?.tasks.map(task => {
                    const existingLog = getTodayLogForTask(task._id);
                    const isExpanded = expandedLogTaskId === task._id;

                    return (
                        <div key={task._id} className={`border rounded-lg transition-all ${isExpanded ? 'border-blue-300 ring-1 ring-blue-100 bg-white' : 'border-slate-200 hover:border-blue-200 bg-white hover:bg-slate-50'}`}>
                            {/* Task Items */}
                            <div className="p-4">
                                <div className="flex justify-between items-start gap-4">
                                    <div className="flex-1">
                                        <h4 className={`font-semibold text-sm ${isExpanded ? 'text-blue-700' : 'text-slate-800'}`}>{task.name}</h4>
                                        <p className="text-xs text-slate-500 mt-1 line-clamp-2">{task.description || 'No description'}</p>
                                    </div>
                                    <div className="flex-shrink-0">
                                        {existingLog ? (
                                            <div className="flex items-center gap-2">
                                                <div className="px-3 py-1 bg-emerald-100 text-emerald-700 text-xs font-medium rounded-full flex items-center">
                                                    <CheckSquare size={12} className="mr-1.5" />
                                                    {existingLog.hours}h Logged
                                                </div>
                                                <button
                                                    onClick={() => toggleLogForm(task._id, existingLog)}
                                                    className="p-1.5 rounded hover:bg-slate-100 text-slate-400 hover:text-blue-600"
                                                    title="Edit"
                                                >
                                                    <Edit2 size={14} />
                                                </button>
                                                <button
                                                    onClick={() => onDeleteLog(existingLog._id)}
                                                    className="p-1.5 rounded hover:bg-red-50 text-slate-300 hover:text-red-500"
                                                    title="Delete"
                                                >
                                                    <Trash2 size={14} />
                                                </button>
                                            </div>
                                        ) : (
                                            <button
                                                onClick={() => toggleLogForm(task._id)}
                                                disabled={!isClockedIn}
                                                className={`flex items-center px-3 py-1.5 rounded text-xs font-medium transition-all ${isClockedIn ? (isExpanded ? 'bg-slate-100 text-slate-600' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-sm') : 'bg-slate-100 text-slate-400 cursor-not-allowed'}`}
                                            >
                                                {isExpanded ? 'Cancel' : 'Log Work'}
                                            </button>
                                        )}
                                    </div>
                                </div>
                            </div>

                            {/* Log Form Area */}
                            {isExpanded && (
                                <div className="bg-slate-50 p-4 border-t border-slate-100 rounded-b-lg animate-fadeIn">
                                    <form onSubmit={onLogWork} className="flex flex-col sm:flex-row gap-4 items-end">
                                        <div className="w-full sm:w-32 flex space-x-2">
                                            <div className="flex-1">
                                                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Hrs</label>
                                                <input
                                                    type="number"
                                                    min="0"
                                                    required
                                                    autoFocus
                                                    className="w-full p-2 border border-slate-300 rounded text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none"
                                                    placeholder="0"
                                                    value={logForm.hours}
                                                    onChange={(e) => setLogForm({ ...logForm, hours: e.target.value })}
                                                />
                                            </div>
                                            <div className="flex-1">
                                                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Min</label>
                                                <input
                                                    type="number"
                                                    min="0" max="59"
                                                    className="w-full p-2 border border-slate-300 rounded text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none"
                                                    placeholder="0"
                                                    value={logForm.minutes}
                                                    onChange={(e) => setLogForm({ ...logForm, minutes: e.target.value })}
                                                />
                                            </div>
                                        </div>
                                        <div className="flex-1 w-full">
                                            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Description</label>
                                            <input
                                                type="text"
                                                className="w-full p-2 border border-slate-300 rounded text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none"
                                                placeholder="What did you work on?"
                                                value={logForm.description}
                                                onChange={(e) => setLogForm({ ...logForm, description: e.target.value })}
                                            />
                                        </div>
                                        <button
                                            type="submit"
                                            className="w-full sm:w-auto px-6 py-2 bg-emerald-600 text-white rounded text-sm font-medium hover:bg-emerald-700 transition-colors shadow-sm h-[38px] flex items-center justify-center"
                                        >
                                            <CheckSquare size={16} className="mr-2" />
                                            {editingLogId ? 'Update' : 'Save'}
                                        </button>
                                    </form>
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

const RegularizationRequestsView = ({ requests, onProcess, processingId, currentUser }) => {
    const isAdmin = currentUser?.roles?.some(r => r.name === 'Admin' || r === 'Admin');

    if (requests.length === 0) {
        return (
            <div className="text-center py-20 bg-slate-50/50 rounded-xl border border-dashed border-slate-200">
                <div className="h-16 w-16 bg-white rounded-full shadow-sm flex items-center justify-center mx-auto mb-4">
                    <Info size={32} className="text-slate-300" />
                </div>
                <h3 className="text-slate-800 font-bold">No Requests Found</h3>
                <p className="text-slate-500 text-xs mt-1">Regularization requests will appear here once submitted.</p>
            </div>
        );
    }

    return (
        <div className="space-y-4">
            <div className="flex justify-between items-center mb-2">
                <h3 className="text-lg font-bold text-slate-800">Regularization Requests</h3>
                <span className="text-[10px] font-bold bg-blue-50 text-blue-600 px-2 py-1 rounded-full uppercase tracking-wider">
                    {requests.length} Total
                </span>
            </div>

            <div className="grid gap-4">
                {requests.map(req => {
                    const isMyRequest = req.user?._id === currentUser?._id;
                    // Manager check: identify if the current user is a reporting manager for the requester
                    const isManagerOfUser = currentUser?.directReports?.some(r =>
                        (typeof r === 'string' ? r === req.user?._id : (r._id === req.user?._id || r === req.user?._id))
                    );
                    const canProcess = !isMyRequest && (isAdmin || req.manager === currentUser?._id || req.manager?._id === currentUser?._id || isManagerOfUser) && req.status === 'PENDING';

                    return (
                        <div key={req._id} className={`bg-white border rounded-xl p-4 transition-all shadow-sm hover:shadow-md ${req.status === 'PENDING' ? 'border-amber-200 bg-amber-50/5' : 'border-slate-100'}`}>
                            <div className="flex flex-col sm:flex-row justify-between gap-4">
                                <div className="flex gap-4">
                                    <div className={`h-10 w-10 rounded-full flex items-center justify-center flex-shrink-0 ${req.status === 'APPROVED' ? 'bg-emerald-100 text-emerald-600' : req.status === 'REJECTED' ? 'bg-red-100 text-red-600' : 'bg-amber-100 text-amber-600'}`}>
                                        {req.status === 'APPROVED' ? <CheckCircle size={20} /> : req.status === 'REJECTED' ? <XCircle size={20} /> : <Clock size={20} />}
                                    </div>
                                    <div>
                                        <div className="flex items-center gap-2">
                                            <span className="font-bold text-slate-800">{req.user?.firstName} {req.user?.lastName}</span>
                                            <span className="text-[10px] text-slate-400 font-mono">#{req.user?.employeeCode}</span>
                                        </div>
                                        <div className="text-xs text-slate-500 font-medium flex items-center gap-2 mt-0.5">
                                            <span>{format(new Date(req.date), 'EEE, MMM dd')}</span>
                                            <span className="h-1 w-1 bg-slate-300 rounded-full"></span>
                                            <span className="text-blue-600 font-bold uppercase tracking-tighter">{req.type}</span>
                                        </div>
                                        <div className="text-[11px] text-slate-400 mt-1">
                                            Sent: {format(new Date(req.createdAt), 'EEE, MMM dd yyyy')} at {format(new Date(req.createdAt), 'hh:mm a')}
                                        </div>
                                        <div className="mt-3 bg-white/50 border border-slate-100 rounded-lg p-2 flex gap-4 text-[10px] font-mono">
                                            {(req.type === 'IN' || req.type === 'BOTH') && (
                                                <div>
                                                    <span className="text-slate-400 block mb-0.5">REQ IN</span>
                                                    <span className="text-slate-700 font-bold">{new Date(req.requestedClockIn).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                                                </div>
                                            )}
                                            {(req.type === 'OUT' || req.type === 'BOTH') && (
                                                <div>
                                                    <span className="text-slate-400 block mb-0.5">REQ OUT</span>
                                                    <span className="text-slate-700 font-bold">{new Date(req.requestedClockOut).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </div>

                                <div className="flex flex-col items-start sm:items-end justify-between gap-3">
                                    <div className={`px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${req.status === 'APPROVED' ? 'bg-emerald-100 text-emerald-700' : req.status === 'REJECTED' ? 'bg-red-100 text-red-700' : 'bg-amber-100 text-amber-700'}`}>
                                        {req.status}
                                    </div>

                                    {canProcess ? (
                                        <div className="flex gap-2">
                                            <button
                                                disabled={processingId === req._id}
                                                onClick={() => onProcess(req._id, 'REJECTED')}
                                                className="px-3 py-1.5 text-xs font-bold text-red-600 hover:bg-red-50 border border-red-200 rounded-lg transition-colors flex items-center gap-1.5"
                                            >
                                                <X size={14} /> Reject
                                            </button>
                                            <button
                                                disabled={processingId === req._id}
                                                onClick={() => onProcess(req._id, 'APPROVED')}
                                                className="px-3 py-1.5 text-xs font-bold text-white bg-blue-600 hover:bg-blue-700 shadow-sm rounded-lg transition-colors flex items-center gap-1.5"
                                            >
                                                {processingId === req._id ? <Loader2 size={14} className="animate-spin" /> : <CheckCircle size={14} />} Approve
                                            </button>
                                        </div>
                                    ) : (
                                        req.status !== 'PENDING' && (
                                            <div className="text-[10px] text-slate-400 italic flex items-center gap-1">
                                                {req.status === 'APPROVED' ? 'Approved by' : 'Rejected by'} {req.manager?.firstName}
                                            </div>
                                        )
                                    )}
                                </div>
                            </div>

                            <div className="mt-4 pt-4 border-t border-slate-50 flex items-start gap-2">
                                <Info size={14} className="text-slate-300 mt-0.5 flex-shrink-0" />
                                <div className="text-xs text-slate-600 italic leading-relaxed">
                                    "{req.reason}"
                                </div>
                            </div>
                            {req.rejectionReason && (
                                <div className="mt-2 p-2 bg-red-50 text-red-600 text-[10px] rounded border border-red-100 italic">
                                    Rejection: {req.rejectionReason}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

export default Attendance;

import React, { useState, useEffect, useRef } from 'react';
import api from '../api/axios';
import { Building, Plus } from 'lucide-react';
import Skeleton from '../components/Skeleton';
import toast from 'react-hot-toast';
import { createCachePayload, isCacheFresh, readSessionCache } from '../utils/cache';

import { useAuth } from '../context/AuthContext';
const BusinessUnits = () => {
    const { user } = useAuth();
    const canCreate = user?.roles?.includes('Admin') || user?.permissions?.includes('business_unit.create');
    const canUpdate = user?.roles?.includes('Admin') || user?.permissions?.includes('business_unit.update');
    const [units, setUnits] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);
    const [formData, setFormData] = useState({ name: '', description: '' });
    const [editingId, setEditingId] = useState(null);
    const initialFetchDoneRef = useRef(false);
    const BUSINESS_UNIT_CACHE_TTL_MS = 60 * 1000;
    const cacheKey = `business_unit_data_${user?._id}`;

    const fetchUnits = async ({ force = false } = {}) => {
        try {
            const cachedData = readSessionCache(cacheKey);

            if (cachedData) {
                const data = cachedData.data || cachedData;
                setUnits(data.units || []);
                setLoading(false);
                if (!force && isCacheFresh(cachedData, BUSINESS_UNIT_CACHE_TTL_MS)) return;
            }

            const res = await api.get('/projects/business-units');
            const unitData = res.data;

            const newFingerprint = JSON.stringify({ u: unitData.length, lu: unitData[0]?._id });
            const oldFingerprint = cachedData?.fingerprint || null;

            setUnits(unitData);

            if (newFingerprint !== oldFingerprint || force) {
                const minimalUnits = unitData.map(u => ({
                    _id: u._id,
                    name: u.name,
                    description: u.description,
                    headOfUnit: u.headOfUnit ? { firstName: u.headOfUnit.firstName, lastName: u.headOfUnit.lastName } : null,
                    createdAt: u.createdAt
                }));

                const payload = createCachePayload({ units: minimalUnits }, newFingerprint);
                sessionStorage.setItem(cacheKey, JSON.stringify(payload));
            }
        } catch (error) {
            console.error(error);
            toast.error('Failed to load Business Units');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (initialFetchDoneRef.current) return;
        initialFetchDoneRef.current = true;
        fetchUnits();
    }, []);

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            if (editingId) {
                await api.put(`/projects/business-units/${editingId}`, formData);
                toast.success('Business Unit Updated');
            } else {
                await api.post('/projects/business-units', formData);
                toast.success('Business Unit Created');
            }
            sessionStorage.removeItem(`business_unit_data_${user?._id}`);
            setShowModal(false);
            setFormData({ name: '', description: '' });
            setEditingId(null);
            fetchUnits({ force: true });
        } catch (error) {
            toast.error(editingId ? 'Failed to update' : 'Failed to create');
        }
    };

    const handleEdit = (unit) => {
        setFormData({ name: unit.name, description: unit.description || '' });
        setEditingId(unit._id);
        setShowModal(true);
    };

    const openCreateModal = () => {
        setFormData({ name: '', description: '' });
        setEditingId(null);
        setShowModal(true);
    };

    if (loading) return (
        <div className="min-h-screen bg-slate-100 font-sans p-6 md:p-10">
            <div className="max-w-6xl mx-auto space-y-6">
                <div className="flex justify-between items-center">
                    <div>
                        <Skeleton className="h-8 w-48 mb-2" />
                        <Skeleton className="h-4 w-64" />
                    </div>
                    <Skeleton className="h-10 w-32 rounded-lg" />
                </div>
                <div className="bg-white rounded-lg shadow-sm border border-slate-200 overflow-hidden">
                    <div className="px-6 py-4 border-b border-slate-100 bg-slate-50/50">
                        <div className="grid grid-cols-4 gap-4">
                            <Skeleton className="h-4 w-24" />
                            <Skeleton className="h-4 w-32" />
                            <Skeleton className="h-4 w-32" />
                            <Skeleton className="h-4 w-24 ml-auto" />
                        </div>
                    </div>
                    <div className="p-0">
                        {[1, 2, 3].map(i => (
                            <div key={i} className="px-6 py-4 border-b border-slate-50 last:border-0">
                                <div className="grid grid-cols-4 gap-4 items-center">
                                    <div className="flex items-center space-x-2">
                                        <Skeleton className="h-8 w-8 rounded" />
                                        <Skeleton className="h-5 w-32" />
                                    </div>
                                    <Skeleton className="h-4 w-48" />
                                    <Skeleton className="h-6 w-32 rounded-full" />
                                    <div className="flex justify-end space-x-2">
                                        <Skeleton className="h-4 w-12" />
                                        <Skeleton className="h-4 w-20" />
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
    );





    return (
        <div className="min-h-screen bg-slate-100 font-sans p-6 md:p-10">
            <div className="max-w-6xl mx-auto space-y-6">

                <div className="flex justify-between items-center">
                    <div>
                        <h1 className="text-2xl font-bold text-slate-800">Business Units</h1>
                        <p className="text-sm text-slate-500">Manage internal business divisions</p>
                    </div>
                    {canCreate && (
                        <button
                            onClick={openCreateModal}
                            className="flex items-center space-x-2 zoho-btn-primary"
                        >
                            <Plus size={18} />
                            <span>Add Unit</span>
                        </button>
                    )}
                </div>

                <div className="zoho-card overflow-hidden">
                    <div className="overflow-x-auto">
                        <table className="w-full text-sm text-left">
                            <thead className="bg-slate-50 text-slate-500 font-medium">
                                <tr>
                                    <th className="px-6 py-3">Name</th>
                                    <th className="px-6 py-3">Description</th>
                                    <th className="px-6 py-3">Head of Unit</th>
                                    <th className="px-6 py-3 text-right">Created</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100">
                                {units.map((unit) => (
                                    <tr key={unit._id} className="hover:bg-slate-50/50">
                                        <td className="px-6 py-3 font-medium text-slate-800">
                                            <div className="flex items-center space-x-2">
                                                <div className="p-1.5 bg-blue-100 text-blue-600 rounded">
                                                    <Building size={16} />
                                                </div>
                                                <span>{unit.name}</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-3 text-slate-600">{unit.description || '-'}</td>
                                        <td className="px-6 py-3 text-slate-600">
                                            {unit.headOfUnit ? (
                                                <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-slate-100 text-slate-700">
                                                    {unit.headOfUnit.firstName} {unit.headOfUnit.lastName}
                                                </span>
                                            ) : '-'}
                                        </td>
                                        <td className="px-6 py-3 text-right text-slate-500 space-x-2">
                                            {canUpdate && (
                                                <button onClick={() => handleEdit(unit)} className="text-blue-600 hover:text-blue-800 text-xs font-medium">Edit</button>
                                            )}
                                            <span className="text-slate-300">|</span>
                                            <span className="text-xs">{new Date(unit.createdAt).toLocaleDateString()}</span>
                                        </td>
                                    </tr>
                                ))}
                                {units.length === 0 && (
                                    <tr>
                                        <td colSpan="4" className="p-8 text-center text-slate-500">
                                            No Business Units found. Create one to get started.
                                        </td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>

            </div>

            {/* Modal */}
            {showModal && (
                <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50 p-4">
                    <div className="bg-white rounded-lg shadow-xl w-full max-w-md">
                        <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center">
                            <h3 className="font-bold text-slate-800">{editingId ? 'Edit Business Unit' : 'New Business Unit'}</h3>
                            <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600">&times;</button>
                        </div>
                        <form onSubmit={handleSubmit} className="p-6 space-y-4">
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Unit Name</label>
                                <input
                                    required
                                    className="zoho-input"
                                    value={formData.name}
                                    onChange={e => setFormData({ ...formData, name: e.target.value })}
                                    placeholder="e.g. Engineering, Sales"
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Description</label>
                                <textarea
                                    className="zoho-input"
                                    value={formData.description}
                                    onChange={e => setFormData({ ...formData, description: e.target.value })}
                                    rows="3"
                                />
                            </div>
                            <div className="flex justify-end space-x-3 pt-4">
                                <button type="button" onClick={() => setShowModal(false)} className="zoho-btn-secondary">Cancel</button>
                                <button type="submit" className="zoho-btn-primary">{editingId ? 'Update' : 'Create'}</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default BusinessUnits;

import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { ArrowLeft, Building2, Users, User, Plus, Trash2 } from 'lucide-react';
import api from '../api/axios';
import toast from 'react-hot-toast';

const EMPTY_CONTACT = { name: '', email: '', phone: '' };

const INITIAL_FORM = {
    // Company Details
    companyName: '',
    companyUrl: '',
    companyLocation: '',
    // Client Details
    name: '',
    email: '',
    businessUnit: '',
    location: '',

    
};








const ClientForm = () => {
    const navigate = useNavigate();
    const { id } = useParams();
    const isEditing = Boolean(id);

    const [formData, setFormData] = useState(INITIAL_FORM);
    const [contacts, setContacts] = useState([{ ...EMPTY_CONTACT }]);
    const [businessUnits, setBusinessUnits] = useState([]);
    const [loading, setLoading] = useState(isEditing);
    const [submitting, setSubmitting] = useState(false);
    const [errors, setErrors] = useState({});

    /* ── Fetch reference data ───────────────────── */
    useEffect(() => {
        const init = async () => {
            try {
                const buRes = await api.get('/projects/business-units');
                setBusinessUnits(buRes.data);
            } catch {
                toast.error('Failed to load business units');
            }

            if (isEditing) {
                try {
                    const res = await api.get('/projects/clients');
                    const client = res.data.find(c => c._id === id);
                    if (client) {
                        setFormData({
                            companyName: client.companyName || '',
                            companyUrl: client.companyUrl || '',
                            companyLocation: client.companyLocation || '',
                            name: client.name || '',
                            email: client.email || '',
                            businessUnit: client.businessUnit?._id || '',
                            location: client.location || '',
                        });
                        setContacts(
                            client.contactPersons?.length
                                ? client.contactPersons.map(cp => ({
                                    name: cp.name || '',
                                    email: cp.email || '',
                                    phone: cp.phone || '',
                                }))
                                : [{ ...EMPTY_CONTACT }]
                        );
                    } else {
                        toast.error('Client not found');
                        navigate('/clients');
                    }
                } catch {
                    toast.error('Failed to load client');
                    navigate('/clients');
                } finally {
                    setLoading(false);
                }
            }
        };
        init();
    }, [id]);

    /* ── Contact person helpers ─────────────────── */
    const addContact = () => setContacts(prev => [...prev, { ...EMPTY_CONTACT }]);

    const removeContact = (idx) =>
        setContacts(prev => prev.filter((_, i) => i !== idx));

    const handleContactChange = (idx, field, value) => {
        setContacts(prev => {
            const updated = [...prev];
            if (field === 'phone') {
                updated[idx] = { ...updated[idx], phone: value.replace(/\D/g, '').slice(0, 10) };
            } else {
                updated[idx] = { ...updated[idx], [field]: value };
            }
            return updated;
        });
        // clear contact-level error
        setErrors(prev => {
            const next = { ...prev };
            delete next[`contact_${idx}_${field}`];
            return next;
        });
    };

    /* ── Validation ─────────────────────────────── */
    const validate = () => {
        const errs = {};
        if (!formData.name.trim()) errs.name = 'Client name is required';

        if (formData.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email))
            errs.email = 'Invalid email address';

        if (formData.companyUrl && !/^https?:\/\/.+/.test(formData.companyUrl))
            errs.companyUrl = 'URL must start with http:// or https://';

        contacts.forEach((cp, idx) => {
            if (cp.phone && !/^\d{10}$/.test(cp.phone))
                errs[`contact_${idx}_phone`] = 'Must be exactly 10 digits';
            if (cp.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(cp.email))
                errs[`contact_${idx}_email`] = 'Invalid email address';
        });

        setErrors(errs);
        return Object.keys(errs).length === 0;
    };

    /* ── Form field handler ─────────────────────── */
    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
        if (errors[name]) setErrors(prev => ({ ...prev, [name]: undefined }));
    };

    /* ── Submit ─────────────────────────────────── */
    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!validate()) return;
        setSubmitting(true);

        // filter out fully empty contact rows
        const contactPersons = contacts.filter(
            cp => cp.name.trim() || cp.email.trim() || cp.phone.trim()
        );

        const payload = { ...formData, contactPersons };

        try {
            if (isEditing) {
                await api.put(`/projects/clients/${id}`, payload);
                toast.success('Client updated successfully');
            } else {
                await api.post('/projects/clients', payload);
                toast.success('Client created successfully');
            }
            sessionStorage.removeItem(`client_data_${user?._id}`);
            navigate('/clients');
        } catch {
            toast.error(isEditing ? 'Failed to update client' : 'Failed to create client');
        } finally {
            setSubmitting(false);
        }
    };

    /* ── Loading ────────────────────────────────── */
    if (loading) {
        return (
            <div className="min-h-screen bg-slate-100 flex items-center justify-center">
                <div className="text-slate-400 animate-pulse">Loading...</div>
            </div>
        );
    }

    /* ── Render ─────────────────────────────────── */
    return (
        <div className="min-h-screen bg-slate-100 font-sans p-6 md:p-10">
            <div className="max-w-3xl mx-auto space-y-6">

                {/* Header */}
                <div className="flex items-center space-x-3">
                    <button
                        onClick={() => navigate('/clients')}
                        className="text-slate-400 hover:text-slate-700 transition-colors"
                    >
                        <ArrowLeft size={20} />
                    </button>
                    <div>
                        <h1 className="text-2xl font-bold text-slate-800">
                            {isEditing ? 'Edit Client' : 'Add New Client'}
                        </h1>
                        <p className="text-sm text-slate-500">
                            {isEditing ? 'Update client information' : 'Fill in the details below to add a new client'}
                        </p>
                    </div>
                </div>

                <form onSubmit={handleSubmit} className="space-y-6">

                    {/* ── Section 1: Company Details ── */}
                    <div className="bg-white rounded-xl shadow-sm overflow-hidden">
                        <div className="flex items-center space-x-3 px-6 py-4 border-b border-slate-100 bg-slate-50">
                            <div className="h-8 w-8 rounded-lg bg-blue-50 text-blue-600 flex items-center justify-center">
                                <Building2 size={16} />
                            </div>
                            <h2 className="font-semibold text-slate-700">Company Details</h2>
                        </div>
                        <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-5">
                            <div>
                                <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Company Name</label>
                                <input name="companyName" value={formData.companyName} onChange={handleChange}
                                    placeholder="e.g. Acme Corporation" className="zoho-input" />
                            </div>
                            <div>
                                <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Company URL</label>
                                <input name="companyUrl" value={formData.companyUrl} onChange={handleChange}
                                    placeholder="https://example.com"
                                    className={`zoho-input ${errors.companyUrl ? 'border-red-400' : ''}`} />
                                {errors.companyUrl && <p className="text-red-500 text-xs mt-1">{errors.companyUrl}</p>}
                            </div>
                            <div className="md:col-span-2">
                                <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Company Location</label>
                                <input name="companyLocation" value={formData.companyLocation} onChange={handleChange}
                                    placeholder="City, Country" className="zoho-input" />
                            </div>
                        </div>
                    </div>

                    {/* ── Section 2: Client Details ── */}
                    <div className="bg-white rounded-xl shadow-sm overflow-hidden">
                        <div className="flex items-center space-x-3 px-6 py-4 border-b border-slate-100 bg-slate-50">
                            <div className="h-8 w-8 rounded-lg bg-indigo-50 text-indigo-600 flex items-center justify-center">
                                <Users size={16} />
                            </div>
                            <h2 className="font-semibold text-slate-700">Client Details</h2>
                        </div>
                        <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-5">
                            <div>
                                <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">
                                    Client Name <span className="text-red-500">*</span>
                                </label>
                                <input name="name" value={formData.name} onChange={handleChange}
                                    placeholder="Client name"
                                    className={`zoho-input ${errors.name ? 'border-red-400' : ''}`} />
                                {errors.name && <p className="text-red-500 text-xs mt-1">{errors.name}</p>}
                            </div>
                            <div>
                                <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Client Email</label>
                                <input type="email" name="email" value={formData.email} onChange={handleChange}
                                    placeholder="client@example.com"
                                    className={`zoho-input ${errors.email ? 'border-red-400' : ''}`} />
                                {errors.email && <p className="text-red-500 text-xs mt-1">{errors.email}</p>}
                            </div>
                            <div>
                                <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Business Unit</label>
                                <select name="businessUnit" value={formData.businessUnit} onChange={handleChange} className="zoho-input">
                                    <option value="">Select Business Unit</option>
                                    {businessUnits.map(bu => (
                                        <option key={bu._id} value={bu._id}>{bu.name}</option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Location</label>
                                <input name="location" value={formData.location} onChange={handleChange}
                                    placeholder="City, Country" className="zoho-input" />
                            </div>
                        </div>
                    </div>

                    {/* ── Section 3: Contact Persons (dynamic) ── */}
                    <div className="bg-white rounded-xl shadow-sm overflow-hidden">
                        <div className="flex items-center justify-between px-6 py-4 border-b border-slate-100 bg-slate-50">
                            <div className="flex items-center space-x-3">
                                <div className="h-8 w-8 rounded-lg bg-emerald-50 text-emerald-600 flex items-center justify-center">
                                    <User size={16} />
                                </div>
                                <h2 className="font-semibold text-slate-700">Contact Persons</h2>
                                <span className="text-xs font-medium text-slate-400 bg-slate-100 px-2 py-0.5 rounded-full">
                                    {contacts.length}
                                </span>
                            </div>
                            <button
                                type="button"
                                onClick={addContact}
                                className="flex items-center space-x-1.5 text-xs font-semibold text-emerald-600 hover:text-emerald-800 bg-emerald-50 hover:bg-emerald-100 px-3 py-1.5 rounded-md transition-colors"
                            >
                                <Plus size={14} />
                                <span>Add Contact</span>
                            </button>
                        </div>

                        <div className="divide-y divide-slate-100">
                            {contacts.map((cp, idx) => (
                                <div key={idx} className="p-6">
                                    {/* Contact row header */}
                                    <div className="flex items-center justify-between mb-4">
                                        <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider">
                                            Contact {idx + 1}
                                        </span>
                                        {contacts.length > 1 && (
                                            <button
                                                type="button"
                                                onClick={() => removeContact(idx)}
                                                className="flex items-center space-x-1 text-xs text-red-400 hover:text-red-600 hover:bg-red-50 px-2 py-1 rounded transition-colors"
                                            >
                                                <Trash2 size={13} />
                                                <span>Remove</span>
                                            </button>
                                        )}
                                    </div>

                                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                        {/* Name */}
                                        <div>
                                            <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Full Name</label>
                                            <input
                                                value={cp.name}
                                                onChange={e => handleContactChange(idx, 'name', e.target.value)}
                                                placeholder="Full name"
                                                className="zoho-input"
                                            />
                                        </div>
                                        {/* Email */}
                                        <div>
                                            <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Email</label>
                                            <input
                                                type="email"
                                                value={cp.email}
                                                onChange={e => handleContactChange(idx, 'email', e.target.value)}
                                                placeholder="contact@example.com"
                                                className={`zoho-input ${errors[`contact_${idx}_email`] ? 'border-red-400' : ''}`}
                                            />
                                            {errors[`contact_${idx}_email`] && (
                                                <p className="text-red-500 text-xs mt-1">{errors[`contact_${idx}_email`]}</p>
                                            )}
                                        </div>
                                        {/* Phone */}
                                        <div>
                                            <label className="block text-xs font-semibold text-slate-500 uppercase mb-1">Phone</label>
                                            <input
                                                value={cp.phone}
                                                onChange={e => handleContactChange(idx, 'phone', e.target.value)}
                                                placeholder="10-digit number"
                                                inputMode="numeric"
                                                maxLength={10}
                                                className={`zoho-input ${errors[`contact_${idx}_phone`] ? 'border-red-400' : ''}`}
                                            />
                                            <p className={`text-xs mt-1 ${errors[`contact_${idx}_phone`] ? 'text-red-500' : 'text-slate-400'}`}>
                                                {errors[`contact_${idx}_phone`] || `${cp.phone.length}/10 digits`}
                                            </p>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* ── Actions ── */}
                    <div className="flex justify-end space-x-3 pb-6">
                        <button
                            type="button"
                            onClick={() => navigate('/clients')}
                            className="zoho-btn-secondary"
                        >
                            Cancel
                        </button>
                        <button
                            type="submit"
                            disabled={submitting}
                            className="zoho-btn-primary disabled:opacity-60 disabled:cursor-not-allowed flex items-center gap-2"
                        >
                            {submitting && <svg className="animate-spin h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>}
                            {submitting ? 'Saving...' : isEditing ? 'Update Client' : 'Create Client'}
                        </button>
                    </div>

                </form>
            </div>
        </div>
    );
};

export default ClientForm;

import React, { useState, useEffect } from 'react';
import { useNavigate, useParams, useSearchParams } from 'react-router-dom';
import { ArrowLeft, Building2, Users, User, Globe, Mail, MapPin, Phone, Briefcase, ChevronRight } from 'lucide-react';
import api from '../api/axios';
import toast from 'react-hot-toast';
import { useAuth } from '../context/AuthContext';
import ClientTADashboard from './TalentAcquisition/ClientTADashboard';

const Field = ({ label, value, icon: Icon }) => (
    <div>
        <p className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-1">{label}</p>
        <div className="flex items-center space-x-2">
            {Icon && <Icon size={14} className="text-slate-400 flex-shrink-0" />}
            <p className="text-sm font-medium text-slate-700">{value || <span className="text-slate-300 font-normal">—</span>}</p>
        </div>
    </div>
);

const ClientView = () => {
    const navigate = useNavigate();
    const { id } = useParams();
    const { user } = useAuth();
    const canUpdate = user?.roles?.includes('Admin') || user?.permissions?.includes('client.update');

    const [client, setClient] = useState(null);
    const [projects, setProjects] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchParams] = useSearchParams();
    const [activeTab, setActiveTab] = useState('details');

    useEffect(() => {
        const tab = searchParams.get('tab');
        if (tab && (tab === 'details' || tab === 'ta')) {
            setActiveTab(tab);
        }
    }, [searchParams]);

    useEffect(() => {
        const fetchData = async () => {
            try {
                // Fetch Client
                const clientRes = await api.get('/projects/clients');
                const foundClient = clientRes.data.find(c => c._id === id);

                if (foundClient) {
                    setClient(foundClient);

                    // Fetch Projects
                    try {
                        const projectsRes = await api.get('/projects');
                        // Filter projects for this client
                        const clientProjects = projectsRes.data.filter(p =>
                            p.client && (typeof p.client === 'string' ? p.client === id : p.client._id === id)
                        );
                        setProjects(clientProjects);
                    } catch (err) {
                        console.error("Failed to load projects", err);
                        // Don't fail the whole page if projects fail
                    }
                } else {
                    toast.error('Client not found');
                    navigate('/clients');
                }
            } catch {
                toast.error('Failed to load client');
                navigate('/clients');
            } finally {
                setLoading(false);
            }
        };
        fetchData();
    }, [id]);

    if (loading) {
        return (
            <div className="min-h-screen bg-slate-100 flex items-center justify-center">
                <div className="text-slate-400 animate-pulse">Loading...</div>
            </div>
        );
    }

    if (!client) return null;

    return (
        <div className="min-h-screen bg-slate-100 font-sans p-6 md:p-10">
            <div className="max-w-7xl mx-auto space-y-6">

                {/* Header */}
                <div className="flex items-center justify-between">
                    <div className="flex items-center space-x-3">
                        <button
                            onClick={() => navigate(activeTab === 'ta' ? '/ta' : '/clients')}
                            className="text-slate-400 hover:text-slate-700 transition-colors"
                        >
                            <ArrowLeft size={20} />
                        </button>
                        <div>
                            <h1 className="text-2xl font-bold text-slate-800">{client.name}</h1>
                            <p className="text-sm text-slate-500">Client Details</p>
                        </div>
                    </div>
                    {canUpdate && (
                        <button
                            onClick={() => navigate(`/clients/${id}/edit`)}
                            className="text-xs font-semibold text-blue-600 hover:text-blue-800 bg-blue-50 hover:bg-blue-100 px-4 py-2 rounded-md transition-colors"
                        >
                            Edit Client
                        </button>
                    )}
                </div>

                {/* Tabs */}
                <div className="flex items-center space-x-6 border-b border-slate-200">
                    <button
                        onClick={() => setActiveTab('details')}
                        className={`pb-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'details' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'}`}
                    >
                        Project Details
                    </button>
                    {(user?.roles?.includes('Admin') || user?.permissions?.includes('ta.view')) && (
                        <button
                            onClick={() => setActiveTab('ta')}
                            className={`pb-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'ta' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'}`}
                        >
                            Talent Acquisition
                        </button>
                    )}
                </div>

                {activeTab === 'details' && (
                    <>
                        {/* Company Details */}
                        <div className="bg-white rounded-xl shadow-sm overflow-hidden">
                            <div className="flex items-center space-x-3 px-6 py-4 border-b border-slate-100 bg-slate-50">
                                <div className="h-8 w-8 rounded-lg bg-blue-50 text-blue-600 flex items-center justify-center">
                                    <Building2 size={16} />
                                </div>
                                <h2 className="font-semibold text-slate-700">Company Details</h2>
                            </div>
                            <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
                                <Field label="Company Name" value={client.companyName} icon={Building2} />
                                <Field label="Company URL" value={client.companyUrl} icon={Globe} />
                                <div className="md:col-span-2">
                                    <Field label="Company Location" value={client.companyLocation} icon={MapPin} />
                                </div>
                            </div>
                        </div>

                        {/* Client Details */}
                        <div className="bg-white rounded-xl shadow-sm overflow-hidden">
                            <div className="flex items-center space-x-3 px-6 py-4 border-b border-slate-100 bg-slate-50">
                                <div className="h-8 w-8 rounded-lg bg-indigo-50 text-indigo-600 flex items-center justify-center">
                                    <Users size={16} />
                                </div>
                                <h2 className="font-semibold text-slate-700">Client Details</h2>
                            </div>
                            <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
                                <Field label="Client Name" value={client.name} icon={User} />
                                <Field label="Client Email" value={client.email} icon={Mail} />
                                <div>
                                    <p className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-1">Business Unit</p>
                                    {client.businessUnit?.name
                                        ? <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-50 text-blue-700">{client.businessUnit.name}</span>
                                        : <span className="text-slate-300 text-sm">—</span>
                                    }
                                </div>
                                <Field label="Location" value={client.location} icon={MapPin} />
                            </div>
                        </div>

                        {/* Contact Persons */}
                        <div className="bg-white rounded-xl shadow-sm overflow-hidden">
                            <div className="flex items-center space-x-3 px-6 py-4 border-b border-slate-100 bg-slate-50">
                                <div className="h-8 w-8 rounded-lg bg-emerald-50 text-emerald-600 flex items-center justify-center">
                                    <User size={16} />
                                </div>
                                <h2 className="font-semibold text-slate-700">Contact Persons</h2>
                                <span className="text-xs font-medium text-slate-400 bg-slate-100 px-2 py-0.5 rounded-full">
                                    {client.contactPersons?.length || 0}
                                </span>
                            </div>
                            <div className="divide-y divide-slate-100">
                                {client.contactPersons?.length > 0 ? (
                                    client.contactPersons.map((cp, idx) => (
                                        <div key={idx} className="p-6">
                                            <p className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-4">
                                                Contact {idx + 1}
                                            </p>
                                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                                <Field label="Full Name" value={cp.name} icon={User} />
                                                <Field label="Email" value={cp.email} icon={Mail} />
                                                <Field label="Phone" value={cp.phone} icon={Phone} />
                                            </div>
                                        </div>
                                    ))
                                ) : (
                                    <div className="p-6 text-center text-slate-400 text-sm">
                                        No contact persons added.
                                    </div>
                                )}
                            </div>
                        </div>

                        {/* Projects */}
                        <div className="bg-white rounded-xl shadow-sm overflow-hidden">
                            <div className="flex items-center space-x-3 px-6 py-4 border-b border-slate-100 bg-slate-50">
                                <div className="h-8 w-8 rounded-lg bg-purple-50 text-purple-600 flex items-center justify-center">
                                    <Briefcase size={16} />
                                </div>
                                <h2 className="font-semibold text-slate-700">Projects</h2>
                                <span className="text-xs font-medium text-slate-400 bg-slate-100 px-2 py-0.5 rounded-full">
                                    {projects.length}
                                </span>
                            </div>

                            <div className="divide-y divide-slate-100">
                                {projects.length > 0 ? (
                                    projects.map(project => (
                                        <div key={project._id} className="p-6 flex flex-col md:flex-row md:items-center justify-between gap-4 hover:bg-slate-50 transition-colors cursor-pointer" onClick={() => navigate(`/projects/${project._id}`)}>
                                            <div className="space-y-1">
                                                <h3 className="font-semibold text-slate-800 flex items-center space-x-2">
                                                    <span>{project.name}</span>
                                                    <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wider border ${project.isActive
                                                        ? 'bg-green-50 text-green-700 border-green-100'
                                                        : 'bg-slate-100 text-slate-500 border-slate-200'
                                                        }`}>
                                                        {project.isActive ? 'Active' : 'Inactive'}
                                                    </span>
                                                </h3>
                                                <div className="flex items-center space-x-4 text-xs text-slate-500">
                                                    {project.manager && (
                                                        <span className="flex items-center space-x-1">
                                                            <User size={12} />
                                                            <span>{project.manager.firstName} {project.manager.lastName}</span>
                                                        </span>
                                                    )}
                                                </div>
                                            </div>
                                            <div className="flex items-center space-x-6">
                                                <div className="text-right">
                                                    <p className="text-xs font-semibold text-slate-400 uppercase tracking-wider">Due Date</p>
                                                    <p className="text-sm font-medium text-slate-700">
                                                        {project.dueDate ? new Date(project.dueDate).toLocaleDateString() : '—'}
                                                    </p>
                                                </div>
                                                <ChevronRight size={16} className="text-slate-300" />
                                            </div>
                                        </div>
                                    ))
                                ) : (
                                    <div className="p-6 text-center text-slate-400 text-sm">
                                        No projects found for this client.
                                    </div>
                                )}
                            </div>
                        </div>
                    </>
                )}

                {activeTab === 'ta' && (
                    <ClientTADashboard clientName={client.name} />
                )}

            </div>
        </div>
    );
};

export default ClientView;

import React, { useState, useEffect, useRef } from 'react';
import api from '../api/axios';
import { Users, Plus } from 'lucide-react';
import toast from 'react-hot-toast';
import { createCachePayload, isCacheFresh, readSessionCache } from '../utils/cache';
import Skeleton from '../components/Skeleton';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Clients = () => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const canCreate = user?.roles?.includes('Admin') || user?.permissions?.includes('client.create');
    const canUpdate = user?.roles?.includes('Admin') || user?.permissions?.includes('client.update');
    const [clients, setClients] = useState([]);
    const [businessUnits, setBusinessUnits] = useState([]);
    const [loading, setLoading] = useState(true);
    const initialFetchDoneRef = useRef(false);
    const CLIENT_CACHE_TTL_MS = 45 * 1000;
    const cacheKey = `client_data_${user?._id}`;

    const fetchData = async ({ force = false } = {}) => {
        try {
            const cachedData = readSessionCache(cacheKey);

            if (cachedData) {
                const data = cachedData.data || cachedData;
                setClients(data.clients || []);
                setBusinessUnits(data.businessUnits || []);
                setLoading(false);
                if (!force && isCacheFresh(cachedData, CLIENT_CACHE_TTL_MS)) return;
            }

            const bootstrapRes = await api.get('/projects/bootstrap');
            const clientData = bootstrapRes.data?.clients || [];
            const buData = bootstrapRes.data?.businessUnits || [];

            const newFingerprint = JSON.stringify({ c: clientData.length, b: buData.length });
            const oldFingerprint = cachedData?.fingerprint || null;

            setClients(clientData);
            setBusinessUnits(buData);

            if (newFingerprint !== oldFingerprint || force) {
                const minimalClients = clientData.map(c => ({
                    _id: c._id,
                    name: c.name,
                    location: c.location,
                    email: c.email,
                    businessUnit: c.businessUnit ? { _id: c.businessUnit._id, name: c.businessUnit.name } : null
                }));

                const minimalBUs = buData.map(bu => ({
                    _id: bu._id,
                    name: bu.name
                }));

                const payload = createCachePayload({ 
                    clients: minimalClients, 
                    businessUnits: minimalBUs 
                }, newFingerprint);
                sessionStorage.setItem(cacheKey, JSON.stringify(payload));
            }

        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (initialFetchDoneRef.current) return;
        initialFetchDoneRef.current = true;
        fetchData();
    }, []);



    if (loading) return (
        <div className="min-h-screen bg-slate-100 font-sans p-6 md:p-10">
            <div className="max-w-6xl mx-auto space-y-6">
                <div className="flex justify-between items-center">
                    <div>
                        <Skeleton className="h-8 w-48 mb-2" />
                        <Skeleton className="h-4 w-64" />
                    </div>
                    <Skeleton className="h-10 w-32 rounded-lg" />
                </div>
                <div className="bg-white rounded-xl shadow-sm overflow-hidden">
                    <table className="w-full text-sm">
                        <thead className="bg-slate-50 border-b border-slate-100">
                            <tr>
                                {['#', 'Client Name', 'Location', 'Business Unit', 'Email', 'Actions'].map(h => (
                                    <th key={h} className="px-4 py-3 text-left">
                                        <Skeleton className="h-3 w-20" />
                                    </th>
                                ))}
                            </tr>
                        </thead>
                        <tbody>
                            {[1, 2, 3, 4, 5].map(i => (
                                <tr key={i} className="border-b border-slate-50">
                                    {[1, 2, 3, 4, 5, 6].map(j => (
                                        <td key={j} className="px-4 py-3">
                                            <Skeleton className="h-4 w-full" />
                                        </td>
                                    ))}
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );

    return (
        <div className="min-h-screen bg-slate-100 font-sans p-6 md:p-10">
            <div className="max-w-6xl mx-auto space-y-6">

                <div className="flex justify-between items-center">
                    <div>
                        <h1 className="text-2xl font-bold text-slate-800">Clients</h1>
                        <p className="text-sm text-slate-500">External customers and partners</p>
                    </div>
                    {canCreate && (
                        <button
                            onClick={() => navigate('/clients/new')}
                            className="flex items-center space-x-2 zoho-btn-primary"
                        >
                            <Plus size={18} />
                            <span>Add Client</span>
                        </button>
                    )}
                </div>

                <div className="bg-white rounded-xl shadow-sm overflow-hidden">
                    <table className="w-full text-sm">
                        <thead className="bg-slate-50 border-b border-slate-200">
                            <tr>
                                <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider w-10">#</th>
                                <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Client Name</th>
                                <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Location</th>
                                <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Business Unit</th>
                                <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Email</th>
                                <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {clients.length === 0 ? (
                                <tr>
                                    <td colSpan={6} className="px-4 py-10 text-center text-slate-400">
                                        No clients found.
                                    </td>
                                </tr>
                            ) : (
                                clients.map((client, index) => (
                                    <tr key={client._id} className="hover:bg-slate-50 transition-colors">
                                        <td className="px-4 py-3 text-slate-400 font-medium">{index + 1}</td>
                                        <td className="px-4 py-3">
                                            <div className="flex items-center space-x-3">
                                                <div className="h-8 w-8 bg-indigo-50 text-indigo-600 rounded-lg flex items-center justify-center flex-shrink-0">
                                                    <Users size={16} />
                                                </div>
                                                <span className="font-semibold text-slate-800">{client.name}</span>
                                            </div>
                                        </td>
                                        <td className="px-4 py-3 text-slate-600">{client.location || <span className="text-slate-300">—</span>}</td>
                                        <td className="px-4 py-3">
                                            {client.businessUnit?.name
                                                ? <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-50 text-blue-700">{client.businessUnit.name}</span>
                                                : <span className="text-slate-300">—</span>
                                            }
                                        </td>
                                        <td className="px-4 py-3 text-slate-600">{client.email || <span className="text-slate-300">—</span>}</td>
                                        <td className="px-4 py-3">
                                            <div className="flex items-center space-x-2">
                                                <button
                                                    onClick={() => navigate(`/clients/${client._id}/view`)}
                                                    className="text-xs font-semibold text-indigo-600 hover:text-indigo-800 bg-indigo-50 hover:bg-indigo-100 px-3 py-1.5 rounded-md transition-colors"
                                                >
                                                    View
                                                </button>
                                                {canUpdate && (
                                                    <button
                                                        onClick={() => navigate(`/clients/${client._id}/edit`)}
                                                        className="text-xs font-semibold text-blue-600 hover:text-blue-800 bg-blue-50 hover:bg-blue-100 px-3 py-1.5 rounded-md transition-colors"
                                                    >
                                                        Edit
                                                    </button>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default Clients;

