import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import api from '../api/axios';
import Skeleton from '../components/Skeleton';
import Button from '../components/Button';
import { Link, useNavigate } from 'react-router-dom';
import { LogOut, Users, Clock, Calendar, Search, Bell, Menu, ChevronDown, Shield, Building, Briefcase, UserCheck, UserX, AlertCircle, ArrowUpRight, TrendingUp, MapPin } from 'lucide-react';
import { format } from 'date-fns';
import { createCachePayload, isCacheFresh, readSessionCache } from '../utils/cache';
import { motion, AnimatePresence } from 'framer-motion';

// Simple global cache for location lookups to avoid redundant API hits across polls
const locationCache = {};

const LocationLink = ({ location }) => {
    const [cityName, setCityName] = useState('...');
    const coordsKey = location ? `${location.lat},${location.lng}` : null;

    useEffect(() => {
        if (!coordsKey) return;
        if (locationCache[coordsKey]) {
            setCityName(locationCache[coordsKey]);
            return;
        }

        const fetchCity = async () => {
            try {
                const res = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${location.lat}&lon=${location.lng}&zoom=10&addressdetails=1`, {
                    headers: { 'Accept-Language': 'en-US,en;q=0.9' }
                });
                const data = await res.json();
                if (data && data.address) {
                    const city = data.address.city || data.address.town || data.address.village || data.address.county || data.address.state_district || 'Map';
                    locationCache[coordsKey] = city;
                    setCityName(city);
                } else {
                    setCityName('Map view');
                }
            } catch (error) {
                setCityName('Map view');
            }
        };
        fetchCity();
    }, [coordsKey]);

    if (!location || !location.lat) return <span className="text-[10px] font-bold text-slate-300 uppercase tracking-tight">Unknown</span>;

    return (
        <a
            href={`https://maps.google.com/?q=${location.lat},${location.lng}`}
            target="_blank"
            rel="noopener noreferrer"
            className="inline-flex items-center gap-1.5 px-2.5 py-1 bg-blue-50/50 text-blue-600 rounded-lg text-[10px] font-bold uppercase tracking-tight hover:bg-blue-100 transition-all group"
            title={cityName}
        >
            <MapPin size={10} className="shrink-0" />
            <span className="truncate max-w-[80px]">{cityName}</span>
        </a>
    );
};

const Dashboard = () => {
    const { user, logout } = useAuth();
    const navigate = useNavigate();
    const [stats, setStats] = useState(null);
    const [projects, setProjects] = useState([]);
    const [recentActivity, setRecentActivity] = useState([]);
    const [loading, setLoading] = useState(true);
    const attSettings = user?.company?.settings?.attendance || {};
    const showLocation = attSettings.requireLocationCheckIn || attSettings.requireLocationCheckOut || attSettings.locationCheck;
    const initialFetchDoneRef = useRef(false);
    const DASHBOARD_CACHE_TTL_MS = 15 * 1000;

    useEffect(() => {
        if (initialFetchDoneRef.current) return;
        initialFetchDoneRef.current = true;

        // Cache key: date-scoped so it auto-invalidates at midnight
        const CACHE_KEY = `dashboard_${new Date().toISOString().slice(0, 10)}`;

        const readCache = () => {
            const parsed = readSessionCache(CACHE_KEY);
            const data = parsed?.data || parsed;
            if (!data || !data.stats) {
                sessionStorage.removeItem(CACHE_KEY);
                return null;
            }
            return parsed;
        };

        const writeCache = (data, fingerprint) => {
            try {
                // Minimal data for caching
                const minimalActivity = (data.recentActivity || []).map(r => ({
                    id: r.id,
                    user: r.user ? { name: r.user.name, role: r.user.role, employmentType: r.user.employmentType } : null,
                    time: r.time,
                    status: r.status,
                    location: r.location
                }));

                const minimalProjects = (data.projects || []).map(p => ({
                    _id: p._id,
                    name: p.name,
                    status: p.status,
                    deadline: p.deadline
                }));

                const payload = createCachePayload({
                    stats: data.stats,
                    recentActivity: minimalActivity,
                    projects: minimalProjects
                }, fingerprint);

                sessionStorage.setItem(CACHE_KEY, JSON.stringify(payload));
            } catch {
                // sessionStorage unavailable or full — silently skip
            }
        };

        // Lightweight fingerprint: tracks every attendance record's
        // id + status + clockIn so any change (new clock-in, status update) is detected
        const buildFingerprint = (data) => {
            const payload = data?.data || data;
            if (!payload) return '';
            const activityPart = payload.recentActivity?.map(r => `${r.id}:${r.status}:${r.time ?? ''}`).join('|') || '';
            const statsPart = `${payload.stats?.totalEmployees || 0}:${payload.stats?.presentToday || 0}`;
            const projPart = payload.projects?.length || 0;
            return `${activityPart}#${statsPart}#${projPart}`;
        };

        const applyData = (payload) => {
            if (!payload?.stats) return;
            setStats(payload.stats);
            setRecentActivity(payload.recentActivity || []);
            setProjects(payload.projects || []);
        };

        const fetchDashboardData = async (skipCache = false) => {
            const cached = skipCache ? null : readCache();

            // 1. Show cached data instantly on first mount (no loading delay)
            if (!skipCache && cached) {
                applyData(cached.data || cached);
                setLoading(false);
                if (isCacheFresh(cached, DASHBOARD_CACHE_TTL_MS)) return;
            }

            // 2. Always fetch fresh data in background
            try {
                const res = await api.get('/dashboard');
                const payload = res.data;
                if (!payload?.stats) return;

                const freshFingerprint = buildFingerprint(payload);
                const cachedFingerprint = cached?.fingerprint ?? (readCache()?.fingerprint || '');

                if (freshFingerprint !== cachedFingerprint) {
                    // Data changed — update UI and overwrite cache
                    applyData(payload);
                    writeCache(payload, freshFingerprint);
                } else {
                    // Data unchanged — only refresh the cache entry (keep UI stable)
                    writeCache(payload, freshFingerprint);
                }
            } catch (error) {
                console.error('Failed to fetch dashboard data', error);
            } finally {
                setLoading(false);
            }
        };

        // Initial fetch
        fetchDashboardData();

        // 3. Continuously hit API for real-time updates (Polling every 10s)
        // Pass true to skip setting cache to UI again during interval
        const pollInterval = setInterval(() => fetchDashboardData(true), 10000);

        return () => clearInterval(pollInterval);
    }, []);

    return (
        <div className="flex-1 flex flex-col bg-[#f8f9fa] font-sans selection:bg-blue-100 selection:text-blue-900">
            {/* Main Content */}
            <main className="flex-1 flex flex-col overflow-hidden">
                <motion.div
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.5, ease: [0.23, 1, 0.32, 1] }}
                    className="flex-1 overflow-auto p-4 sm:p-5"
                >
                    <div className="max-w-6xl mx-auto space-y-5">
                        {/* Header Section */}
                        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3">
                            <div className="space-y-0.5">
                                <h1 className="text-xl font-black text-slate-900 tracking-tight">Executive Overview</h1>
                                <p className="text-[11px] text-slate-500 font-medium italic">
                                    Welcome back, {user?.firstName} 👋
                                </p>
                            </div>
                            <div className="flex items-center gap-2 px-3 py-1.5 bg-white border border-slate-200/60 rounded-lg shadow-sm text-[11px] font-bold text-slate-600">
                                <Calendar size={14} className="text-blue-600" />
                                {format(new Date(), 'MMM d, yyyy')}
                            </div>
                        </div>

                        {/* KPI Grid */}
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            {[
                                {
                                    label: 'Total Workforce',
                                    value: stats?.totalEmployees || 0,
                                    icon: Users,
                                    color: 'blue',
                                    trend: 'Active',
                                    bgColor: 'bg-blue-50',
                                    textColor: 'text-blue-600'
                                },
                                {
                                    label: 'Present Today',
                                    value: stats?.presentToday || 0,
                                    total: stats?.totalEmployees || 0,
                                    icon: UserCheck,
                                    color: 'emerald',
                                    trend: 'Verified',
                                    progress: (stats?.presentToday / (stats?.totalEmployees || 1)) * 100,
                                    bgColor: 'bg-emerald-50',
                                    textColor: 'text-emerald-600'
                                },
                                {
                                    label: 'Absent Personnel',
                                    value: stats?.absentToday || 0,
                                    icon: UserX,
                                    color: 'orange',
                                    trend: 'Tracked',
                                    bgColor: 'bg-orange-50',
                                    textColor: 'text-orange-600'
                                }
                            ].map((kpi, idx) => (
                                <motion.div
                                    key={kpi.label}
                                    initial={{ opacity: 0, y: 20 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    transition={{ delay: idx * 0.1 }}
                                    className="premium-card p-4 bg-white"
                                >
                                    <div className="flex justify-between items-start mb-3">
                                        <div className={`p-2 rounded-lg ${kpi.bgColor} ${kpi.textColor}`}>
                                            <kpi.icon size={16} />
                                        </div>
                                        <span className={`text-[9px] font-black uppercase tracking-widest px-1.5 py-0.5 rounded-md ${kpi.bgColor} ${kpi.textColor}`}>
                                            {kpi.trend}
                                        </span>
                                    </div>
                                    <div className="space-y-0.5">
                                        <h3 className="text-slate-500 text-[10px] font-bold uppercase tracking-wider">{kpi.label}</h3>
                                        <div className="flex items-baseline gap-1.5">
                                            {loading && !stats ? (
                                                <Skeleton className="h-8 w-16" />
                                            ) : (
                                                <span className="text-3xl font-black text-slate-900 tracking-tighter">
                                                    {kpi.value}
                                                </span>
                                            )}
                                            {kpi.total && (
                                                <span className="text-[11px] font-bold text-slate-400">/ {kpi.total}</span>
                                            )}
                                        </div>
                                    </div>
                                    {kpi.progress !== undefined && (
                                        <div className="mt-4 space-y-1.5">
                                            <div className="flex justify-between text-[9px] font-bold text-slate-400 uppercase">
                                                <span>Attendance Rate</span>
                                                <span>{Math.round(kpi.progress)}%</span>
                                            </div>
                                            <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                                                <motion.div
                                                    initial={{ width: 0 }}
                                                    animate={{ width: `${kpi.progress}%` }}
                                                    transition={{ duration: 1, delay: 0.5 }}
                                                    className={`h-full ${kpi.label === 'Present Today' ? 'bg-emerald-500' : 'bg-blue-500'} rounded-full`}
                                                />
                                            </div>
                                        </div>
                                    )}
                                </motion.div>
                            ))}
                        </div>

                        {/* Tables Section */}
                        <div className="grid grid-cols-1 lg:grid-cols-12 gap-5 items-start">
                            {/* Attendance Table */}
                            <div className="lg:col-span-8 premium-card bg-white overflow-hidden flex flex-col">
                                <div className="px-5 py-3.5 flex justify-between items-center border-b border-slate-50 bg-[#fcfcfc]">
                                    <div className="flex items-center gap-2.5">
                                        <div className="w-1 h-5 bg-blue-600 rounded-full"></div>
                                        <h2 className="text-base font-bold text-slate-900 tracking-tight">Recent Attendance</h2>
                                    </div>
                                    <div className="flex items-center gap-2 px-2 py-0.5 bg-emerald-50 text-emerald-600 rounded-md">
                                        <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></div>
                                        <span className="text-[9px] font-black uppercase tracking-widest">Live Updates</span>
                                    </div>
                                </div>
                                <div className="overflow-x-auto">
                                    <table className="w-full">
                                        <thead>
                                            <tr className="bg-slate-50/50">
                                                <th className="px-5 py-2.5 text-left text-[9px] font-black text-slate-500 uppercase tracking-widest">Employee</th>
                                                <th className="px-5 py-2.5 text-left text-[9px] font-black text-slate-500 uppercase tracking-widest">Clock In</th>
                                                <th className="px-5 py-2.5 text-left text-[9px] font-black text-slate-500 uppercase tracking-widest">Type</th>
                                                <th className="px-5 py-2.5 text-right text-[9px] font-black text-slate-500 uppercase tracking-widest">Location</th>
                                            </tr>
                                        </thead>
                                        <tbody className="divide-y divide-slate-50">
                                            {loading ? (
                                                [1, 2, 3, 4, 5].map(i => (
                                                    <tr key={i}><td colSpan="4" className="px-5 py-2.5"><Skeleton className="h-10 w-full" /></td></tr>
                                                ))
                                            ) : recentActivity.filter(r => r.status === 'PRESENT').length > 0 ? (
                                                recentActivity.filter(r => r.status === 'PRESENT').map((record) => (
                                                    <tr key={record.id} className="group hover:bg-slate-50/30 transition-colors border-b border-slate-50 last:border-0">
                                                        <td className="px-5 py-3">
                                                            <div className="flex items-center gap-2.5">
                                                                <div className="h-8 w-8 rounded-lg bg-slate-100 flex items-center justify-center text-[10px] font-bold text-slate-600 border border-slate-200/50 group-hover:scale-105 transition-transform">
                                                                    {record.user.name.charAt(0).toUpperCase()}
                                                                </div>
                                                                <div>
                                                                    <div className="text-[13px] font-bold text-slate-900 leading-none mb-0.5">{record.user.name}</div>
                                                                    <div className="text-[9px] font-bold text-slate-400 text-left">{record.user.role || 'Personnel'}</div>
                                                                </div>
                                                            </div>
                                                        </td>
                                                        <td className="px-5 py-3">
                                                            <div className="flex items-center gap-1 text-slate-700 font-bold">
                                                                <Clock size={10} className="text-slate-400" />
                                                                <span className="text-[11px] uppercase">
                                                                    {record.time ? format(new Date(record.time), 'hh:mm a') : '--:--'}
                                                                </span>
                                                            </div>
                                                        </td>
                                                        <td className="px-5 py-3">
                                                            <span className="px-2 py-0.5 rounded-md bg-blue-50/50 text-blue-600 text-[9px] font-black uppercase tracking-tight border border-blue-100/30">
                                                                {record.user.employmentType || 'FT'}
                                                            </span>
                                                        </td>
                                                        <td className="px-5 py-3 text-right">
                                                            <LocationLink location={record.location} />
                                                        </td>
                                                    </tr>
                                                ))
                                            ) : (
                                                <tr>
                                                    <td colSpan="4" className="px-6 py-10 text-center">
                                                        <div className="flex flex-col items-center gap-2 text-slate-400">
                                                            <AlertCircle size={24} strokeWidth={1.5} />
                                                            <p className="text-xs font-medium italic">No attendance records found for today.</p>
                                                        </div>
                                                    </td>
                                                </tr>
                                            )}
                                        </tbody>
                                    </table>
                                </div>
                            </div>

                            {/* Projects Table */}
                            {user?.company?.enabledModules?.includes('projectManagement') && (
                                <div className="lg:col-span-4 premium-card bg-white overflow-hidden flex flex-col">
                                    <div className="px-5 py-3.5 flex justify-between items-center border-b border-slate-50 bg-[#fcfcfc]">
                                        <div className="flex items-center gap-2.5">
                                            <div className="w-1 h-5 bg-purple-600 rounded-full"></div>
                                            <h2 className="text-base font-bold text-slate-900 tracking-tight">Active Projects</h2>
                                        </div>
                                        <Link to="/projects" className="text-[9px] font-black text-blue-600 bg-blue-50/80 px-2 py-1 rounded-md hover:bg-blue-100 transition-colors uppercase tracking-widest">
                                            View Data
                                        </Link>
                                    </div>
                                    <div className="p-0">
                                        <div className="divide-y divide-slate-50">
                                            {loading ? (
                                                [1, 2, 3].map(i => <div key={i} className="p-4"><Skeleton className="h-10 w-full" /></div>)
                                            ) : projects.filter(p => p.status === 'Active').length > 0 ? (
                                                projects.filter(p => p.status === 'Active').slice(0, 5).map((project) => (
                                                    <div
                                                        key={project._id}
                                                        onClick={() => navigate('/projects')}
                                                        className="px-5 py-3.5 hover:bg-slate-50/30 cursor-pointer transition-all group"
                                                    >
                                                        <div className="flex justify-between items-start mb-2">
                                                            <h3 className="font-bold text-slate-900 text-[13px] group-hover:text-blue-600 transition-colors leading-tight">
                                                                {project.name}
                                                            </h3>
                                                            <span className="text-[8px] font-black bg-blue-50 text-blue-700 px-1.5 py-0.5 rounded-md uppercase tracking-widest border border-blue-100/50">
                                                                {project.status}
                                                            </span>
                                                        </div>
                                                        <div className="flex items-center justify-between">
                                                            <div className="flex items-center gap-1 text-slate-400">
                                                                <Calendar size={10} />
                                                                <span className="text-[10px] font-bold">
                                                                    {project.deadline ? format(new Date(project.deadline), 'MMM d, yy') : 'No Deadline'}
                                                                </span>
                                                            </div>
                                                            <ArrowUpRight size={12} className="text-slate-300 group-hover:text-blue-600 group-hover:translate-x-0.5 transition-all" />
                                                        </div>
                                                    </div>
                                                ))
                                            ) : (
                                                <div className="p-10 text-center text-slate-400 italic text-xs">
                                                    No active projects listed.
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                </motion.div>
            </main>
        </div>
    );
};

export default Dashboard;

import React, { useState, useEffect, useRef } from 'react';
import api from '../api/axios';
import { Plus, MessageSquare, Calendar, Search, ChevronLeft, ChevronRight, X, Eye, EyeOff, Edit, Trash2 } from 'lucide-react';
import toast from 'react-hot-toast';
import Skeleton from '../components/Skeleton';
import { useNavigate } from 'react-router-dom';
import { format, startOfMonth, endOfMonth } from 'date-fns';
import * as ExcelJS from 'exceljs';
import { saveAs } from 'file-saver';
import { Download, Loader } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import { createCachePayload, isCacheFresh, readSessionCache } from '../utils/cache';

const Discussions = () => {
    const navigate = useNavigate();
    const [discussions, setDiscussions] = useState([]);
    const [loading, setLoading] = useState(true);

    // Export Dates State
    const [exportStartDate, setExportStartDate] = useState('');
    const [exportEndDate, setExportEndDate] = useState('');
    const [isExporting, setIsExporting] = useState(false);
    const [showExportMenu, setShowExportMenu] = useState(false);
    const exportMenuRef = useRef(null);

    // New states for inline creation
    const [isCreating, setIsCreating] = useState(false);
    const [isSaving, setIsSaving] = useState(false);

    // New states for inline editing
    const [editingId, setEditingId] = useState(null);
    const [editData, setEditData] = useState(null);

    // State for toggling full descriptions inline
    const [expandedIds, setExpandedIds] = useState([]);

    const { user } = useAuth();
    const [supervisors, setSupervisors] = useState([]);

    const [newDiscussion, setNewDiscussion] = useState({
        discussion: '',
        status: 'inprogress',
        dueDate: '',
        supervisor: ''
    });

    // Pagination state
    const [currentPage, setCurrentPage] = useState(1);
    const [totalPages, setTotalPages] = useState(1);
    const limit = 10;
    const initialFetchDoneRef = useRef(false);
    const DISCUSSION_CACHE_TTL_MS = 30 * 1000;
    const SUPERVISOR_CACHE_TTL_MS = 60 * 1000;

    const fetchDiscussions = async (page, force = false, isBackground = false) => {
        const CACHE_KEY = `discussion_data_${user?._id}_p${page}`;

        // 1. Initial Load from Cache
        if (!isBackground && !force) {
            const cached = readSessionCache(CACHE_KEY);
            if (cached) {
                const data = cached.data || cached;
                setDiscussions(data.discussions || []);
                setTotalPages(data.totalPages || 1);
                setCurrentPage(data.currentPage || page);
                setLoading(false);
                if (isCacheFresh(cached, DISCUSSION_CACHE_TTL_MS)) return;
            }
        }

        try {
            if (!isBackground && !readSessionCache(CACHE_KEY)) setLoading(true);
            const res = await api.get('/discussions/bootstrap', { params: { page, limit } });
            const freshData = {
                discussions: res.data.discussions || [],
                supervisors: res.data.supervisors || [],
                totalPages: res.data.totalPages || 1,
                currentPage: res.data.currentPage || page
            };
            const newFingerprint = (freshData.discussions || []).map(d => `${d._id}-${d.status}-${d.discussion?.substring(0, 20)}-${d.dueDate}`).join('|');
            const cachedValue = readSessionCache(CACHE_KEY);
            const oldFingerprint = cachedValue?.fingerprint || '';

            if (newFingerprint !== oldFingerprint || force) {
                setDiscussions(freshData.discussions);
                setCurrentPage(freshData.currentPage);
                setTotalPages(freshData.totalPages);
                setSupervisors(freshData.supervisors);

                // Minimal data for caching
                const minimalDiscussions = freshData.discussions.map(d => ({
                    _id: d._id,
                    discussion: d.discussion,
                    status: d.status,
                    dueDate: d.dueDate,
                    createdAt: d.createdAt,
                    supervisor: d.supervisor ? { _id: d.supervisor._id, firstName: d.supervisor.firstName, lastName: d.supervisor.lastName, profilePicture: d.supervisor.profilePicture } : null
                }));

                const payload = createCachePayload({
                    discussions: minimalDiscussions,
                    totalPages: freshData.totalPages,
                    currentPage: freshData.currentPage
                }, newFingerprint);

                sessionStorage.setItem(CACHE_KEY, JSON.stringify(payload));

                const minimalSupervisors = freshData.supervisors.map(s => ({
                    _id: s._id,
                    firstName: s.firstName,
                    lastName: s.lastName
                }));
                const supervisorFingerprint = minimalSupervisors.map(s => s._id).join('|');
                sessionStorage.setItem(
                    `supervisors_data_${user?._id}`,
                    JSON.stringify(createCachePayload(minimalSupervisors, supervisorFingerprint))
                );
            }
        } catch (error) {
            console.error(error);
            if (!isBackground) toast.error('Failed to load discussions');
        } finally {
            setLoading(false);
        }
    };

    const fetchSupervisors = async () => {
        const SUPERVISOR_CACHE_KEY = `supervisors_data_${user?._id}`;

        // Load from cache first
        const cached = readSessionCache(SUPERVISOR_CACHE_KEY);
        if (cached) {
            setSupervisors(cached.data || cached);
            if (isCacheFresh(cached, SUPERVISOR_CACHE_TTL_MS)) return;
        }

        try {
            const res = await api.get('/discussions/supervisors');
            const freshData = res.data;

            const oldFingerprint = cached?.fingerprint || '';
            const newFingerprint = freshData.map(s => `${s._id}`).join('|');

            if (newFingerprint !== oldFingerprint) {
                setSupervisors(freshData);

                // Minimal data
                const minimalSupervisors = freshData.map(s => ({
                    _id: s._id,
                    firstName: s.firstName,
                    lastName: s.lastName
                }));

                sessionStorage.setItem(SUPERVISOR_CACHE_KEY, JSON.stringify(createCachePayload(minimalSupervisors, newFingerprint)));
            }
        } catch (error) {
            console.error('Error fetching supervisors:', error);
        }
    };

    useEffect(() => {
        if (currentPage === 1 && initialFetchDoneRef.current) return;
        if (currentPage === 1) initialFetchDoneRef.current = true;
        fetchDiscussions(currentPage);
        if (currentPage === 1) fetchSupervisors();
    }, [currentPage]);

    // Close export menu when clicking outside
    useEffect(() => {
        const handleClickOutside = (event) => {
            if (exportMenuRef.current && !exportMenuRef.current.contains(event.target)) {
                setShowExportMenu(false);
            }
        };
        if (showExportMenu) {
            document.addEventListener('mousedown', handleClickOutside);
        }
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, [showExportMenu]);

    const handleExportExcel = async () => {
        try {
            setIsExporting(true);

            // If no dates selected, use current month
            let start = exportStartDate;
            let end = exportEndDate;

            if (!start || !end) {
                const now = new Date();
                start = format(startOfMonth(now), 'yyyy-MM-dd');
                end = format(endOfMonth(now), 'yyyy-MM-dd');
                // Optionally update state to show user what was used
                setExportStartDate(start);
                setExportEndDate(end);
            }

            // Fetch all discussions for the date range (using a large limit to get all)
            // Realistically, backend might need a specific export endpoint, but we'll use existing with large limit
            const res = await api.get(`/discussions?page=1&limit=1000`);
            let exportData = res.data.discussions || [];

            // Filter data by date range locally if backend doesn't support date filters on this endpoint yet
            exportData = exportData.filter(d => {
                if (!d.createdAt) return false;
                const createdDate = new Date(d.createdAt);
                const startDate = new Date(start);
                startDate.setHours(0, 0, 0, 0);
                const endDate = new Date(end);
                endDate.setHours(23, 59, 59, 999);
                return createdDate >= startDate && createdDate <= endDate;
            });

            if (exportData.length === 0) {
                toast.error('No discussions found in this date range');
                setIsExporting(false);
                return;
            }

            const workbook = new ExcelJS.Workbook();
            const sheet = workbook.addWorksheet('Discussions');

            sheet.columns = [
                { header: 'S.No', key: 'slNo', width: 10 },
                { header: 'Description', key: 'description', width: 50 },
                { header: 'Created Date', key: 'createdDate', width: 20 },
                { header: 'Due Date', key: 'dueDate', width: 20 },
                { header: 'Status', key: 'status', width: 20 },
            ];

            sheet.getRow(1).font = { bold: true };
            sheet.getRow(1).fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFE0E0E0' } };

            exportData.forEach((item, index) => {
                const row = sheet.addRow({
                    slNo: index + 1,
                    description: item.discussion || '-',
                    createdDate: item.createdAt ? format(new Date(item.createdAt), 'dd MMM yyyy') : '-',
                    dueDate: item.dueDate ? format(new Date(item.dueDate), 'dd MMM yyyy') : 'No due date',
                    status: item.status || '-',
                });

                const statusCell = row.getCell('status');
                const statusStr = (item.status || '').toLowerCase();

                // Set styles matching the UI badge colors
                if (statusStr === 'inprogress') {
                    statusCell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFFEF3C7' } }; // Amber-100
                    statusCell.font = { color: { argb: 'FFB45309' } }; // Amber-700
                } else if (statusStr === 'mark as complete') {
                    statusCell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFDCFCE7' } }; // Green-100
                    statusCell.font = { color: { argb: 'FF15803D' } }; // Green-700
                } else if (statusStr === 'on-hold') {
                    statusCell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFF1F5F9' } }; // Slate-100
                    statusCell.font = { color: { argb: 'FF334155' } }; // Slate-700
                } else {
                    statusCell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFDBEAFE' } }; // Blue-100
                    statusCell.font = { color: { argb: 'FF1D4ED8' } }; // Blue-700
                }
            });

            sheet.getColumn('description').alignment = { wrapText: true, vertical: 'top' };

            const buffer = await workbook.xlsx.writeBuffer();
            const blob = new Blob([buffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
            saveAs(blob, `Discussions_Export_${start}_to_${end}.xlsx`);
            toast.success('Excel downloaded successfully');
            setShowExportMenu(false);

        } catch (error) {
            console.error('Error exporting excel:', error);
            toast.error('Failed to export excel');
        } finally {
            setIsExporting(false);
        }
    };

    const handleStatusChange = async (id, newStatus) => {
        try {
            await api.put(`/discussions/${id}`, { status: newStatus });
            toast.success('Status updated');
            setDiscussions(prev => {
                const updated = prev.map(d => d._id === id ? { ...d, status: newStatus } : d);
                return updated.sort((a, b) => {
                    const aCompleted = a.status === 'mark as complete';
                    const bCompleted = b.status === 'mark as complete';
                    if (aCompleted && !bCompleted) return 1;
                    if (!aCompleted && bCompleted) return -1;
                    return 0;
                });
            });
        } catch (error) {
            console.error('Error updating status:', error);
            toast.error('Failed to update status');
        }
    };

    const handleCreateInline = async () => {
        if (!newDiscussion.discussion) {
            toast.error('Description is required');
            return;
        }
        try {
            setIsSaving(true);
            const payload = { ...newDiscussion, title: 'Discussion' }; // Setting default title since field is removed
            if (!payload.dueDate) delete payload.dueDate;

            await api.post('/discussions', payload);
            toast.success('Discussion created');

            // Force refresh the first page and clear cache for it
            sessionStorage.removeItem(`discussion_data_${user?._id}_p1`);
            fetchDiscussions(1, true); 

            setIsCreating(false);
            setNewDiscussion({
                discussion: '',
                status: 'inprogress',
                dueDate: '',
                supervisor: ''
            });
        } catch (error) {
            console.error('Error creating discussion:', error);
            toast.error('Failed to create discussion');
        } finally {
            setIsSaving(false);
        }
    };

    const handleEditInline = (discussion) => {
        setEditingId(discussion._id);
        setEditData({
            discussion: discussion.discussion,
            status: discussion.status,
            dueDate: discussion.dueDate ? discussion.dueDate.split('T')[0] : '',
            supervisor: discussion.supervisor?._id || discussion.supervisor
        });
    };

    const handleUpdateInline = async (id) => {
        if (!editData.discussion) {
            toast.error('Description is required');
            return;
        }
        try {
            setIsSaving(true);
            const payload = { ...editData };
            if (!payload.dueDate) delete payload.dueDate;

            await api.put(`/discussions/${id}`, payload);
            toast.success('Discussion updated');

            // Update local state and push completed to bottom
            const updatedDiscussions = discussions.map(d => d._id === id ? { ...d, ...payload } : d)
                .sort((a, b) => {
                    const aCompleted = a.status === 'mark as complete';
                    const bCompleted = b.status === 'mark as complete';
                    if (aCompleted && !bCompleted) return 1;
                    if (!aCompleted && bCompleted) return -1;
                    return 0;
                });
            
            setDiscussions(updatedDiscussions);

            // Update cache for current page
            const CACHE_KEY = `discussion_data_${user?._id}_p${currentPage}`;
            const buildFingerprint = (items) => items.map(d => `${d._id}-${d.status}-${d.discussion?.substring(0, 20)}-${d.dueDate}`).join('|');
            const newFingerprint = buildFingerprint(updatedDiscussions);
            
            const minimalDiscussions = updatedDiscussions.map(d => ({
                _id: d._id,
                discussion: d.discussion,
                status: d.status,
                dueDate: d.dueDate,
                createdAt: d.createdAt,
                supervisor: d.supervisor ? { _id: d.supervisor._id, firstName: d.supervisor.firstName, lastName: d.supervisor.lastName, profilePicture: d.supervisor.profilePicture } : null
            }));

            sessionStorage.setItem(CACHE_KEY, JSON.stringify(createCachePayload({
                discussions: minimalDiscussions,
                totalPages: totalPages,
                currentPage: currentPage
            }, newFingerprint)));

            setEditingId(null);
            setEditData(null);
        } catch (error) {
            console.error('Error updating discussion:', error);
            toast.error('Failed to update discussion');
        } finally {
            setIsSaving(false);
        }
    };

    const handleDelete = async (id) => {
        if (window.confirm('Are you sure you want to delete this discussion?')) {
            try {
                await api.delete(`/discussions/${id}`);
                toast.success('Discussion deleted');
                sessionStorage.removeItem(`discussion_data_${user?._id}_p${currentPage}`);
                fetchDiscussions(currentPage, true);
            } catch (error) {
                console.error('Error deleting discussion:', error);
                toast.error('Failed to delete discussion');
            }
        }
    };

    const toggleDescription = (id) => {
        setExpandedIds(prev =>
            prev.includes(id) ? prev.filter(item => item !== id) : [...prev, id]
        );
    };

    const getStatusBadgeColor = (status) => {
        const styles = {
            'inprogress': 'bg-amber-100 text-amber-700 border-amber-200',
            'mark as complete': 'bg-green-100 text-green-700 border-green-200',
            'on-hold': 'bg-slate-100 text-slate-700 border-slate-200'
        };
        return styles[status] || 'bg-blue-100 text-blue-700 border-blue-200';
    };

    if (loading && discussions.length === 0) return (
        <div className="min-h-screen bg-slate-50 p-6 md:p-10">
            <div className="max-w-7xl mx-auto space-y-6">
                <Skeleton className="h-8 w-48 mb-2" />
                <div className="bg-white rounded-xl shadow-sm overflow-hidden p-6 border border-slate-200">
                    <Skeleton className="h-64 w-full" />
                </div>
            </div>
        </div>
    );

    return (
        <div className="min-h-screen bg-slate-50 font-sans p-4 sm:p-6 md:p-10">
            <div className="max-w-7xl mx-auto space-y-4 sm:space-y-6">

                {/* View Toggle */}
                <div className="flex justify-center mb-8">
                    <div className="inline-flex bg-slate-200/70 p-1 rounded-lg">
                        <button
                            onClick={() => navigate('/meetings')}
                            className="px-6 py-2 text-sm font-medium rounded-md transition-all text-slate-600 hover:text-slate-800"
                        >
                            Meetings
                        </button>
                        <button
                            onClick={() => navigate('/discussions')}
                            className="px-6 py-2 text-sm font-medium rounded-md transition-all shadow-sm bg-white text-slate-800"
                        >
                            Discussions
                        </button>
                    </div>
                </div>

                {/* Header */}
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3">
                    <div>
                        <h1 className="text-xl sm:text-2xl font-bold text-slate-800 flex items-center gap-2">
                            <MessageSquare className="text-indigo-600" /> Discussions
                        </h1>
                        <p className="text-sm text-slate-500 mt-1">Create and manage team discussions, tasks, and topics.</p>
                    </div>
                    <div className="flex flex-col sm:flex-row gap-2 w-full sm:w-auto mt-3 sm:mt-0 items-center">
                        <div className="relative" ref={exportMenuRef}>
                            <button
                                onClick={() => setShowExportMenu(!showExportMenu)}
                                className="flex items-center justify-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg font-medium transition-colors shadow-sm w-full sm:w-auto"
                            >
                                <Download size={18} />
                                <span>Export Data</span>
                            </button>

                            {/* Export Dropdown Menu */}
                            {showExportMenu && (
                                <div className="absolute right-0 mt-2 w-72 bg-white rounded-xl shadow-lg border border-slate-200 z-50 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
                                    <div className="p-4 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
                                        <h3 className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                                            <Download size={16} className="text-emerald-600" />
                                            Export to Excel
                                        </h3>
                                        <button
                                            onClick={() => setShowExportMenu(false)}
                                            className="text-slate-400 hover:text-slate-600 transition-colors"
                                        >
                                            <X size={16} />
                                        </button>
                                    </div>
                                    <div className="p-4 space-y-3">
                                        <div className="grid grid-cols-2 gap-2">
                                            <div className="space-y-1">
                                                <label className="text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Start Date</label>
                                                <input
                                                    type="date"
                                                    value={exportStartDate}
                                                    onChange={(e) => setExportStartDate(e.target.value)}
                                                    className="w-full text-xs py-1.5 px-2 border border-slate-300 rounded focus:outline-none focus:ring-1 focus:ring-emerald-500 focus:border-emerald-500 text-slate-700"
                                                />
                                            </div>
                                            <div className="space-y-1">
                                                <label className="text-[11px] font-semibold text-slate-500 uppercase tracking-wider">End Date</label>
                                                <input
                                                    type="date"
                                                    value={exportEndDate}
                                                    onChange={(e) => setExportEndDate(e.target.value)}
                                                    className="w-full text-xs py-1.5 px-2 border border-slate-300 rounded focus:outline-none focus:ring-1 focus:ring-emerald-500 focus:border-emerald-500 text-slate-700"
                                                />
                                            </div>
                                        </div>
                                        <p className="text-[11px] text-slate-500 leading-tight">
                                            Leave dates empty to export all discussions from the current month.
                                        </p>
                                        <button
                                            onClick={handleExportExcel}
                                            disabled={isExporting}
                                            className="w-full flex items-center justify-center gap-2 px-3 py-2 text-sm font-medium text-white bg-emerald-600 rounded-lg hover:bg-emerald-700 disabled:opacity-50 transition-colors mt-2"
                                        >
                                            {isExporting ? <Loader size={14} className="animate-spin" /> : <Download size={14} />}
                                            Download Excel
                                        </button>
                                    </div>
                                </div>
                            )}
                        </div>

                        <button
                            onClick={() => setIsCreating(true)}
                            className="flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg font-medium transition-colors shadow-sm w-full sm:w-auto"
                        >
                            <Plus size={18} />
                            <span>Create Discussion</span>
                        </button>
                    </div>
                </div>

                {/* List View */}
                <div className="bg-white rounded-xl shadow-sm overflow-hidden border border-slate-200">

                    {/* ── Mobile card list (hidden on md+) ── */}
                    <div className="md:hidden divide-y divide-slate-100">
                        {loading ? (
                            <div className="flex justify-center py-10"><Skeleton className="h-8 w-8 rounded-full" /></div>
                        ) : discussions.length === 0 && !isCreating ? (
                            <div className="flex flex-col items-center justify-center py-12 text-slate-400">
                                <MessageSquare size={48} className="text-slate-200 mb-4" />
                                <p className="text-base font-medium text-slate-600">No discussions found</p>
                                <p className="text-sm">Start a new discussion.</p>
                            </div>
                        ) : (
                            discussions.map((discussion, index) => (
                                <div key={discussion._id} className="p-4 space-y-2 hover:bg-slate-50 transition-colors">
                                    <div className="flex items-start justify-between gap-2">
                                        <div className="flex-1 min-w-0">
                                            <span className="text-xs font-semibold text-slate-400 mr-1">#{(currentPage - 1) * limit + index + 1}</span>
                                            <span className="text-sm text-slate-700 break-words leading-relaxed">
                                                {discussion.discussion && discussion.discussion.length > 80 && !expandedIds.includes(discussion._id)
                                                    ? `${discussion.discussion.substring(0, 80)}...`
                                                    : discussion.discussion}
                                            </span>
                                        </div>
                                    </div>
                                    <div className="flex flex-wrap items-center gap-2">
                                        <select
                                            value={discussion.status}
                                            onChange={(e) => handleStatusChange(discussion._id, e.target.value)}
                                            className={`px-2.5 py-1 text-xs font-semibold rounded-full border cursor-pointer focus:outline-none focus:ring-2 focus:ring-indigo-500/20 ${getStatusBadgeColor(discussion.status)}`}
                                        >
