const EmployeeDossier = ({ userId: propUserId, embedded = false }) => {
    const { userId: paramUserId } = useParams();
    const userId = propUserId || paramUserId;
    const navigate = useNavigate();
    const { user: currentUser } = useAuth();

    // Permissions
    const canEdit = currentUser?.roles?.some(r => r === 'Admin' || r?.name === 'Admin') || currentUser?.permissions?.includes('dossier.edit');
    const canApprove = currentUser?.roles?.some(r => r === 'Admin' || r?.name === 'Admin') || currentUser?.permissions?.includes('dossier.approve');

    // State
    const [profile, setProfile] = useState(null);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('personal');
    const [editMode, setEditMode] = useState(false);
    const [formData, setFormData] = useState({});
    const [historyLogs, setHistoryLogs] = useState([]);
    const [uploadingDocTitle, setUploadingDocTitle] = useState(null);
    const [savingSection, setSavingSection] = useState(null);
    const [isUploading, setIsUploading] = useState(false);
    const [deletingDocId, setDeletingDocId] = useState(null);
    // Preview State
    const [previewFile, setPreviewFile] = useState(null);
    const [previewUrl, setPreviewUrl] = useState(null);
    const [isDocumentDeclared, setIsDocumentDeclared] = useState(false);
    const [showUploadPreview, setShowUploadPreview] = useState(false);
    const [uploadCategory, setUploadCategory] = useState(null);
    const fileInputRef = useRef(null);

    // New state for custom document titles
    const [showTitleModal, setShowTitleModal] = useState(false);
    const [customDocTitle, setCustomDocTitle] = useState('');
    const [selectedCategory, setSelectedCategory] = useState(null);

    // HRIS Requests State
    const [hrisRequests, setHrisRequests] = useState([]);
    const [loadingRequests, setLoadingRequests] = useState(false);
    const [hrisSearchTerm, setHrisSearchTerm] = useState('');

    // Cleanup preview URL on unmount
    useEffect(() => {
        return () => {
            if (previewUrl) URL.revokeObjectURL(previewUrl);
        };
    }, [previewUrl]);

    // Initialize formData when entering edit mode if it's empty
    useEffect(() => {
        if (editMode && profile && (Object.keys(formData).length === 0 || editMode !== 'hris')) {
            // If it's a section-specific edit, we might want to just target that? 
            // But usually formData is the whole profile for simplicity in this component.
            setFormData(JSON.parse(JSON.stringify(profile)));
        }
    }, [editMode, profile]);

    const handleFileSelect = (e) => {
        const file = e.target.files[0];
        if (!file) return;

        // If we have a fixed title (from old flow), use it
        if (uploadingDocTitle) {
            let category = 'Other';
            const titleLower = uploadingDocTitle.toLowerCase();

            // Allow dynamic resolution from config
            const foundCat = documentCategories.find(cat =>
                cat.fixedDocs?.some(doc => doc.toLowerCase() === titleLower)
            );
            if (foundCat) category = foundCat.category;

            // Fallback heuristics for legacy/undefined
            if (category === 'Other') {
                if (titleLower.includes('resume')) category = 'Resume';
                else if (titleLower.includes('offer letter')) category = 'Offer Letter';
                else if (titleLower.includes('appointment')) category = 'Appointment Letter';
                else if (titleLower.includes('experience')) category = 'Employment';
            }

            setPreviewFile(file);
            setPreviewUrl(URL.createObjectURL(file));
            setUploadCategory(category);
            setShowUploadPreview(true);
        }
        // If we have a selected category (new flow), show title modal
        else if (selectedCategory) {
            setPreviewFile(file);
            setPreviewUrl(URL.createObjectURL(file));
            setShowTitleModal(true);
        }
    };

    const handleCancelUpload = () => {
        setPreviewFile(null);
        setPreviewUrl(null);
        setUploadCategory(null);
        setShowUploadPreview(false);
        setUploadingDocTitle(null);
        setShowTitleModal(false);
        setCustomDocTitle('');
        setSelectedCategory(null);
        if (fileInputRef.current) fileInputRef.current.value = '';
    };

    const handleConfirmUpload = async () => {
        if (!previewFile) return;

        const title = uploadingDocTitle || customDocTitle;
        const category = uploadCategory || selectedCategory;

        if (!title || !category) {
            toast.error('Please provide document title');
            return;
        }

        const formData = new FormData();
        formData.append('file', previewFile);
        formData.append('title', title);
        formData.append('category', category);

        try {
            setIsUploading(true);
            const toastId = toast.loading('Uploading document...');
            await api.post(`/dossier/${userId}/documents`, formData, {
                headers: { 'Content-Type': 'multipart/form-data' }
            });
            toast.dismiss(toastId);
            toast.success('Document uploaded successfully');
            setIsDocumentDeclared(false);
            fetchDossier(); // Refresh
            if (activeTab === 'history') fetchHistory(); // Refresh history if needed
            handleCancelUpload(); // Close and reset
        } catch (error) {
            console.error('Upload failed', error);
            toast.error('Upload failed');
        } finally {
            setIsUploading(false);
        }
    };

    const triggerUpload = (docTitle) => {
        setUploadingDocTitle(docTitle);
        setTimeout(() => {
            if (fileInputRef.current) {
                fileInputRef.current.value = '';
                fileInputRef.current.click();
            }
        }, 0);
    };

    // New function to trigger upload for a category with custom title
    const triggerCategoryUpload = (categoryName, categoryType) => {
        setSelectedCategory(categoryType);
        setTimeout(() => {
            if (fileInputRef.current) {
                fileInputRef.current.value = '';
                fileInputRef.current.click();
            }
        }, 0);
    };

    const handleDeleteDocument = async (docId) => {
        if (!window.confirm('Are you sure you want to delete this document?')) return;

        try {
            setDeletingDocId(docId);
            const toastId = toast.loading('Deleting document...');
            await api.delete(`/dossier/${userId}/documents/${docId}`);
            toast.dismiss(toastId);
            toast.success('Document deleted successfully');
            setIsDocumentDeclared(false);
            fetchDossier(); // Refresh
            if (activeTab === 'history') fetchHistory();
        } catch (error) {
            console.error('Delete failed', error);
            toast.error('Failed to delete document');
        } finally {
            setDeletingDocId(null);
        }
    };

    const fetchHistory = useCallback(async () => {
        try {
            const res = await api.get(`/dossier/${userId}/history`);
            setHistoryLogs(res.data);
        } catch (error) {
            console.error('Failed to fetch history', error);
            toast.error('Could not load history');
        }
    }, [userId]);

    useEffect(() => {
        if (activeTab === 'history') {
            fetchHistory();
        }
    }, [activeTab, userId, fetchHistory]);

    // Fetch Dossier Data
    const fetchDossier = useCallback(async () => {
        try {
            setLoading(true);
            const res = await api.get(`/dossier/${userId}`);
            setProfile(res.data);
            setFormData(res.data); // Initialize form data
        } catch (error) {
            console.error(error);
            toast.error('Failed to load employee dossier');
            if (error.response && error.response.status === 404) {
                navigate('/users');
            }
            if (error.response && error.response.status === 403) {
                navigate('/unauthorized');
            }
        } finally {
            setLoading(false);
        }
    }, [userId, navigate]);

    useEffect(() => {
        if (userId) fetchDossier();
    }, [userId, fetchDossier]);

    const fetchHRISRequests = async () => {
        try {
            setLoadingRequests(true);
            const res = await api.get('/dossier/requests');
            setHrisRequests(res.data);
        } catch (error) {
            console.error('Failed to fetch HRIS requests', error);
        } finally {
            setLoadingRequests(false);
        }
    };

    const handleHRISApproveOther = async (id) => {
        try {
            const toastId = toast.loading('Approving HRIS request...');
            await api.patch(`/dossier/${id}/approve-hris`);
            toast.dismiss(toastId);
            toast.success('HRIS Approved');
            fetchHRISRequests();
        } catch (error) {
            console.error(error);
            toast.error('Failed to approve HRIS');
        }
    };

    const handleHRISRejectOther = async (id) => {
        const reason = window.prompt('Please enter a reason for rejection:');
        if (reason === null) return;
        try {
            const toastId = toast.loading('Rejecting HRIS request...');
            await api.patch(`/dossier/${id}/reject-hris`, { reason });
            toast.dismiss(toastId);
            toast.success('HRIS Rejected');
            fetchHRISRequests();
        } catch (error) {
            console.error(error);
            toast.error('Failed to reject HRIS');
        }
    };

    useEffect(() => {
        const isManager = currentUser?.roles?.some(r => r.name === 'Admin') || currentUser?.directReportsCount > 0 || canApprove;
        if (isManager && activeTab === 'requests') {
            fetchHRISRequests();
        }
    }, [activeTab, currentUser]);

    const tabs = [
        { id: 'personal', label: 'Personal', icon: User },
        { id: 'employment', label: 'Employment History', icon: Briefcase }
    ];

    const hasDossierModule = currentUser?.company?.enabledModules?.includes('employeeDossier');

    if (hasDossierModule) {
        tabs.push(
            { id: 'documents', label: 'Documents', icon: FileText },
            { id: 'hris', label: 'HRIS', icon: Shield },
            { id: 'history', label: 'Activities', icon: Calendar }
        );
    }

    const isManager = currentUser?.roles?.some(r => r === 'Admin' || r?.name === 'Admin') || currentUser?.directReportsCount > 0 || canApprove;
    if (isManager && hasDossierModule) {
        tabs.push({ id: 'requests', label: 'Requests', icon: AlertCircle });
    }

    // Ensure active tab defaults to 'personal' if user tries to reach a disabled tab
    useEffect(() => {
        if (!hasDossierModule && ['documents', 'hris', 'history', 'requests'].includes(activeTab)) {
            setActiveTab('personal');
        }
    }, [hasDossierModule, activeTab]);

    // Handle Input Change for nested objects
    const handleInputChange = (section, field, value) => {
        setFormData(prev => {
            const newState = {
                ...prev,
                [section]: {
                    ...prev[section],
                    [field]: value
                }
            };

            // Auto-uncheck declaration on any change (unless we are toggling the declaration itself)
            if (section !== 'hris' || field !== 'isDeclared') {
                if (newState.hris) {
                    newState.hris = { ...newState.hris, isDeclared: false };
                }
            }

            return newState;
        });
    };

    const handleEmergencyChange = (field, value) => {
        setFormData(prev => ({
            ...prev,
            contact: {
                ...prev.contact,
                emergencyContact: {
                    ...prev.contact?.emergencyContact,
                    [field]: value
                }
            },
            hris: { ...prev.hris, isDeclared: false }
        }));
    };

    const handleAddressChange = (type, field, value) => {
        setFormData(prev => {
            const currentAddresses = prev.contact?.addresses || [];
            const existingIndex = currentAddresses.findIndex(a => a.type === type);
            let newAddresses = [...currentAddresses];

            if (existingIndex >= 0) {
                newAddresses[existingIndex] = { ...newAddresses[existingIndex], [field]: value };
            } else {
                newAddresses.push({ type, [field]: value });
            }

            return {
                ...prev,
                contact: {
                    ...prev.contact,
                    addresses: newAddresses
                },
                hris: { ...prev.hris, isDeclared: false }
            };
        });
    };

    const handleHRISSave = async () => {
        // HRIS Validation
        const p = formData.personal || {};
        const b = formData.compensation?.bankDetails || {};

        if (!p.firstName || !p.lastName || !p.fullName) return toast.error('All fields are required');

        if (!b.accountNumber || !b.ifscCode || !b.bankName || !b.accountHolderName || !b.branchAddress) {
            return toast.error('All fields are required');
        }

        try {
            setSavingSection('hris');
            const dataToSubmit = { ...formData };

            // Allow Admins to submit without explicit checkbox (forces status update)
            const isAdmin = currentUser?.roles?.some(r => r === 'Admin' || r?.name === 'Admin');
            if (isAdmin) {
                if (!dataToSubmit.hris) dataToSubmit.hris = {};
                dataToSubmit.hris.isDeclared = true;
            }

            await api.patch(`/dossier/${userId}/submit-hris`, dataToSubmit);
            toast.success('HRIS Form saved successfully');
            setEditMode(false);
            fetchDossier();
        } catch (error) {
            console.error(error);
            toast.error('Failed to save HRIS form');
        } finally {
            setSavingSection(null);
        }
    };


    const handleExcelExport = async (targetUserId = null) => {
        try {
            const toastId = toast.loading('Generating Excel...');
            const params = targetUserId ? { userId: targetUserId } : {};
            const response = await api.get('/dossier/export-excel', {
                params,
                responseType: 'blob'
            });
            const url = window.URL.createObjectURL(new Blob([response.data]));
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', `HRIS_Export_${format(new Date(), 'dd_MMM_yyyy')}.xlsx`);
            document.body.appendChild(link);
            link.click();
            link.remove();
            toast.dismiss(toastId);
            toast.success('Excel exported successfully');
        } catch (error) {
            console.error(error);
            toast.error('Failed to export Excel');
        }
    };


    // Validation Helper
    const validateSectionData = (section) => {
        const data = formData[section] || {};

        const isEmpty = (val) => val === undefined || val === null || val === '';

        if (section === 'personal') {
            const required = ['dob', 'gender', 'maritalStatus', 'nationality', 'bloodGroup', 'disabilityStatus'];
            const missing = required.filter(f => isEmpty(data[f]));
            if (missing.length > 0) return 'All fields are required'; // Generic warning
        }
        if (section === 'contact') {
            if (isEmpty(data.personalEmail) || isEmpty(data.mobileNumber)) return 'Email and Mobile Number are required';

            // Check Emergency Contact
            const ec = data.emergencyContact || {};
            if (isEmpty(ec.name) || isEmpty(ec.relation) || isEmpty(ec.phone)) return 'Name, relation, and phone for emergency contact are required';

            // Validate Addresses
            const addresses = data.addresses || [];
            const hasCurrent = addresses.some(a => a.type === 'Current' && !isEmpty(a.street) && !isEmpty(a.city) && !isEmpty(a.state) && !isEmpty(a.zipCode) && !isEmpty(a.country));
            const hasPermanent = addresses.some(a => a.type === 'Permanent' && !isEmpty(a.street) && !isEmpty(a.city) && !isEmpty(a.state) && !isEmpty(a.zipCode) && !isEmpty(a.country));

            if (!hasCurrent || !hasPermanent) return 'All fields are required';
        }
        if (section === 'identity') {
            if (isEmpty(data.aadhaarNumber) || isEmpty(data.panNumber)) return 'All fields are required';
        }
        if (section === 'family') {
            if (isEmpty(data.fatherName) || isEmpty(data.motherName)) return 'All fields are required';
        }
        if (section === 'experience') {
            return null; // Optional fields, no strict validation required
        }
        return null;
    };

    // Save Changes
    const handleSave = async (section) => {
        const error = validateSectionData(section);
        if (error) {
            toast.error(error);
            return;
        }

        try {
            setSavingSection(section);
            const updates = formData[section];
            await api.patch(`/dossier/${userId}/${section}`, updates);
            toast.success('Changes saved successfully');
            setEditMode(false);
            fetchDossier(); // Refresh to ensure sync
        } catch (error) {
            console.error(error);
            toast.error('Failed to save changes');
        } finally {
            setSavingSection(null);
        }
    };

    // --- RENDER SECTIONS ---



    const renderPersonal = () => {

        const getAddress = (type) => formData.contact?.addresses?.find(a => a.type === type) || {};
        const getProfileAddress = (type) => profile.contact?.addresses?.find(a => a.type === type) || {};

        return (
            <div className="space-y-6">
                {/* 1. Basic Personal Info */}
                <SectionCard
                    title="Basic Information"
                    sectionName="personal"
                    icon={User}
                    editMode={editMode}
                    setEditMode={setEditMode}
                    onSave={handleSave}
                    isLoading={savingSection === 'personal'}
                    canEdit={canEdit}
                >
                    {(isEditing) => (
                        <div className="space-y-4">
                            <p className="text-xs text-red-500 italic">* fields are mandatory</p>
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                <Field section="personal" isEditing={isEditing} label="Date of Birth" field="dob" value={profile.personal?.dob} type="date" formData={formData} onChange={handleInputChange} required />
                                <Field section="personal" isEditing={isEditing} label="Gender" field="gender" value={profile.personal?.gender} options={['Male', 'Female', 'Other']} formData={formData} onChange={handleInputChange} required />
                                <Field section="personal" isEditing={isEditing} label="Marital Status" field="maritalStatus" value={profile.personal?.maritalStatus} options={['Single', 'Married', 'Divorced', 'Widowed']} formData={formData} onChange={handleInputChange} required />
                                <Field section="personal" isEditing={isEditing} label="Nationality" field="nationality" value={profile.personal?.nationality} formData={formData} onChange={handleInputChange} required />
                                <Field section="personal" isEditing={isEditing} label="Blood Group" field="bloodGroup" value={profile.personal?.bloodGroup} formData={formData} onChange={handleInputChange} required />
                                <Field
                                    section="personal"
                                    isEditing={isEditing}
                                    label="Disability Status"
                                    field="disabilityStatus"
                                    value={profile.personal?.disabilityStatus ? 'Yes' : 'No'}
                                    valueOverride={formData.personal?.disabilityStatus ? 'Yes' : 'No'}
                                    options={['No', 'Yes']}
                                    hideIfEmpty
                                    formData={formData}
                                    onChangeOverride={(e) => handleInputChange('personal', 'disabilityStatus', e.target.value === 'Yes')}
                                    required
                                />
                            </div>
                        </div>
                    )}
                </SectionCard>

                {/* 2. Contact Details */}
                <SectionCard
                    title="Contact Information"
                    sectionName="contact"
                    icon={Briefcase}
                    editMode={editMode}
                    setEditMode={setEditMode}
                    onSave={handleSave}
                    isLoading={savingSection === 'contact'}
                    canEdit={canEdit}
                >
                    {(isEditing) => (
                        <div className="space-y-6">
                            <p className="text-xs text-red-500 italic">* fields are mandatory</p>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <Field section="contact" isEditing={isEditing} label="Personal Email" field="personalEmail" value={profile.contact?.personalEmail} formData={formData} onChange={handleInputChange} required />
                                <Field
                                    section="contact" isEditing={isEditing} label="Mobile Number" field="mobileNumber"
                                    value={profile.contact?.mobileNumber} formData={formData}
                                    maxLength={10}
                                    error={formData.contact?.mobileNumber?.length > 0 && formData.contact?.mobileNumber?.length < 10 ? 'Must be 10 digits' : null}
                                    onChangeOverride={(e) => {
                                        const val = e.target.value.replace(/\D/g, '');
                                        handleInputChange('contact', 'mobileNumber', val);
                                    }}
                                    required
                                />
                                <Field
                                    section="contact" isEditing={isEditing} label="Alternate Number" field="alternateNumber"
                                    value={profile.contact?.alternateNumber} formData={formData}
                                    maxLength={10}
                                    error={formData.contact?.alternateNumber?.length > 0 && formData.contact?.alternateNumber?.length < 10 ? 'Must be 10 digits' : null}
                                    onChangeOverride={(e) => {
                                        const val = e.target.value.replace(/\D/g, '');
                                        handleInputChange('contact', 'alternateNumber', val);
                                    }}
                                />
                            </div>

                            {/* Emergency Contact Sub-section */}
                            <div className="pt-4 border-t border-slate-100">
                                <h4 className="text-sm font-bold text-slate-700 mb-4">Emergency Contact</h4>
                                <div className="grid grid-cols-1 md:grid-cols-4 gap-4 bg-slate-50 p-4 rounded-lg border border-slate-100">
                                    <Field
                                        section="contact" isEditing={isEditing}
                                        label="Name" field="EC_name"
                                        value={profile.contact?.emergencyContact?.name}
                                        valueOverride={formData.contact?.emergencyContact?.name}
                                        onChangeOverride={(e) => handleEmergencyChange('name', e.target.value)}
                                        formData={formData} onChange={handleInputChange}
                                        required
                                    />
                                    <Field
                                        section="contact" isEditing={isEditing}
                                        label="Relation" field="EC_relation"
                                        value={profile.contact?.emergencyContact?.relation}
                                        valueOverride={formData.contact?.emergencyContact?.relation}
                                        onChangeOverride={(e) => handleEmergencyChange('relation', e.target.value)}
                                        formData={formData} onChange={handleInputChange}
                                        required
                                    />
                                    <Field
                                        section="contact" isEditing={isEditing}
                                        label="Phone" field="EC_phone"
                                        value={profile.contact?.emergencyContact?.phone}
                                        valueOverride={formData.contact?.emergencyContact?.phone}
                                        maxLength={10}
                                        error={formData.contact?.emergencyContact?.phone?.length > 0 && formData.contact?.emergencyContact?.phone?.length < 10 ? 'Must be 10 digits' : null}
                                        onChangeOverride={(e) => {
                                            const val = e.target.value.replace(/\D/g, '');
                                            handleEmergencyChange('phone', val);
                                        }}
                                        formData={formData} onChange={handleInputChange}
                                        required
                                    />
                                    <Field
                                        section="contact" isEditing={isEditing}
                                        label="Email" field="EC_email"
                                        value={profile.contact?.emergencyContact?.email}
                                        valueOverride={formData.contact?.emergencyContact?.email}
                                        onChangeOverride={(e) => handleEmergencyChange('email', e.target.value)}
                                        formData={formData} onChange={handleInputChange}
                                    />
                                </div>
                            </div>

                            {/* Address Sub-section */}
                            <div className="pt-4 border-t border-slate-100">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    {/* Current Address */}
                                    <div className="bg-slate-50 p-4 rounded-lg border border-slate-100">
                                        <h4 className="text-sm font-bold text-slate-700 mb-4">Current Address <span className="text-red-500">*</span></h4>
                                        <div className="space-y-3">
                                            <Field section="contact" isEditing={isEditing} label="Street" field="C_street" value={getProfileAddress('Current').street}
                                                valueOverride={getAddress('Current').street} onChangeOverride={(e) => handleAddressChange('Current', 'street', e.target.value)}
                                                formData={formData} onChange={handleInputChange} />
                                            <Field section="contact" isEditing={isEditing} label="Line 2" field="C_line2" value={getProfileAddress('Current').addressLine2}
                                                valueOverride={getAddress('Current').addressLine2} onChangeOverride={(e) => handleAddressChange('Current', 'addressLine2', e.target.value)}
                                                formData={formData} onChange={handleInputChange} />
                                            <div className="grid grid-cols-2 gap-3">
                                                <Field section="contact" isEditing={isEditing} label="City" field="C_city" value={getProfileAddress('Current').city}
                                                    valueOverride={getAddress('Current').city} onChangeOverride={(e) => handleAddressChange('Current', 'city', e.target.value)}
                                                    formData={formData} onChange={handleInputChange} />
                                                <Field section="contact" isEditing={isEditing} label="State" field="C_state" value={getProfileAddress('Current').state}
                                                    valueOverride={getAddress('Current').state} onChangeOverride={(e) => handleAddressChange('Current', 'state', e.target.value)}
                                                    formData={formData} onChange={handleInputChange} />
                                            </div>
                                            <div className="grid grid-cols-2 gap-3">
                                                <Field section="contact" isEditing={isEditing} label="Pincode" field="C_zip" value={getProfileAddress('Current').zipCode}
                                                    valueOverride={getAddress('Current').zipCode} onChangeOverride={(e) => handleAddressChange('Current', 'zipCode', e.target.value)}
                                                    formData={formData} onChange={handleInputChange} />
                                                <Field section="contact" isEditing={isEditing} label="Country" field="C_country" value={getProfileAddress('Current').country}
                                                    valueOverride={getAddress('Current').country} onChangeOverride={(e) => handleAddressChange('Current', 'country', e.target.value)}
                                                    formData={formData} onChange={handleInputChange} />
                                            </div>
                                        </div>
                                    </div>

                                    {/* Permanent Address */}
                                    <div className="bg-slate-50 p-4 rounded-lg border border-slate-100">
                                        <div className="flex justify-between items-center mb-4">
                                            <h4 className="text-sm font-bold text-slate-700">Permanent Address <span className="text-red-500">*</span></h4>
                                            {isEditing && (
                                                <label className="flex items-center space-x-2 text-xs text-slate-600 cursor-pointer select-none">
                                                    <input
                                                        type="checkbox"
                                                        onChange={(e) => {
                                                            if (e.target.checked) {
                                                                const current = getAddress('Current');
                                                                // Batch update all fields in a single state update
                                                                setFormData(prev => {
                                                                    const currentAddresses = prev.contact?.addresses || [];
                                                                    const permIndex = currentAddresses.findIndex(a => a.type === 'Permanent');
                                                                    const permAddr = { type: 'Permanent', street: current.street, addressLine2: current.addressLine2, city: current.city, state: current.state, zipCode: current.zipCode, country: current.country };
                                                                    let newAddresses = [...currentAddresses];
                                                                    if (permIndex >= 0) { newAddresses[permIndex] = permAddr; } else { newAddresses.push(permAddr); }
                                                                    return { ...prev, contact: { ...prev.contact, addresses: newAddresses }, hris: { ...prev.hris, isDeclared: false } };
                                                                });
                                                            }
                                                        }}
                                                        className="rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                                                    />
                                                    <span>Same as Current</span>
                                                </label>
                                            )}
                                        </div>
                                        <div className="space-y-3">
                                            <Field section="contact" isEditing={isEditing} label="Street" field="P_street" value={getProfileAddress('Permanent').street}
                                                valueOverride={getAddress('Permanent').street} onChangeOverride={(e) => handleAddressChange('Permanent', 'street', e.target.value)}
                                                formData={formData} onChange={handleInputChange} />
                                            <Field section="contact" isEditing={isEditing} label="Line 2" field="P_line2" value={getProfileAddress('Permanent').addressLine2}
                                                valueOverride={getAddress('Permanent').addressLine2} onChangeOverride={(e) => handleAddressChange('Permanent', 'addressLine2', e.target.value)}
                                                formData={formData} onChange={handleInputChange} />
                                            <div className="grid grid-cols-2 gap-3">
                                                <Field section="contact" isEditing={isEditing} label="City" field="P_city" value={getProfileAddress('Permanent').city}
                                                    valueOverride={getAddress('Permanent').city} onChangeOverride={(e) => handleAddressChange('Permanent', 'city', e.target.value)}
                                                    formData={formData} onChange={handleInputChange} />
                                                <Field section="contact" isEditing={isEditing} label="State" field="P_state" value={getProfileAddress('Permanent').state}
                                                    valueOverride={getAddress('Permanent').state} onChangeOverride={(e) => handleAddressChange('Permanent', 'state', e.target.value)}
                                                    formData={formData} onChange={handleInputChange} />
                                            </div>
                                            <div className="grid grid-cols-2 gap-3">
                                                <Field section="contact" isEditing={isEditing} label="Pincode" field="P_zip" value={getProfileAddress('Permanent').zipCode}
                                                    valueOverride={getAddress('Permanent').zipCode} onChangeOverride={(e) => handleAddressChange('Permanent', 'zipCode', e.target.value)}
                                                    formData={formData} onChange={handleInputChange} />
                                                <Field section="contact" isEditing={isEditing} label="Country" field="P_country" value={getProfileAddress('Permanent').country}
                                                    valueOverride={getAddress('Permanent').country} onChangeOverride={(e) => handleAddressChange('Permanent', 'country', e.target.value)}
                                                    formData={formData} onChange={handleInputChange} />
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}
                </SectionCard>

                {/* 3. Identity (Sensitive) */}
                <SectionCard
                    title="Identity & Legal (Sensitive)"
                    sectionName="identity"
                    icon={Shield}
                    editMode={editMode}
                    setEditMode={setEditMode}
                    onSave={handleSave}
                    isLoading={savingSection === 'identity'}
                    canEdit={canEdit}
                >
                    {(isEditing) => (
                        <div className="space-y-4">
                            <p className="text-xs text-red-500 italic">* fields are mandatory</p>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <Field section="identity" isEditing={isEditing} label="Aadhaar Number" field="aadhaarNumber" value={profile.identity?.aadhaarNumber} formData={formData} onChange={handleInputChange} required />
                                <Field section="identity" isEditing={isEditing} label="PAN Number" field="panNumber" value={profile.identity?.panNumber} formData={formData} onChange={handleInputChange} required />
                                <Field section="identity" isEditing={isEditing} label="Passport Number" field="passportNumber" value={profile.identity?.passportNumber} formData={formData} onChange={handleInputChange} />
                            </div>
                        </div>
                    )}
                </SectionCard>
            </div>
        )
    }

    const renderEmployment = () => {
        return (
            <div className="space-y-6">
                <div className="bg-white rounded-lg shadow-sm border border-slate-200 p-6">
                    <div className="flex justify-between items-center mb-6">
                        <h3 className="text-lg font-bold text-slate-800">Employment Details</h3>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {/* Designation */}
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">Designation</label>
                            <div className="text-slate-800 font-medium text-sm">{profile.employment?.designation || profile.user?.roles?.[0]?.name || '-'}</div>
                        </div>

                        {/* Department */}
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">Department</label>
                            <div className="text-slate-800 font-medium text-sm">{profile.employment?.department || '-'}</div>
                        </div>

                        {/* Joining Date */}
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">Joining Date</label>
                            <div className="text-slate-800 font-medium text-sm">{(profile.employment?.joiningDate || profile.user?.joiningDate) ? format(new Date(profile.employment?.joiningDate || profile.user?.joiningDate), 'dd MMM yyyy') : '-'}</div>
                        </div>

                        {/* Status */}
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">Status</label>
                            <div className="inline-flex items-center px-2.5 py-0.5 rounded-full text-[11px] font-bold bg-emerald-100 text-emerald-800 uppercase tracking-tight">
                                {profile.employment?.status || 'Active'}
                            </div>
                        </div>

                        {/* Work Location */}
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">Work Location</label>
                            <div className="text-slate-800 font-medium text-sm">{profile.user?.workLocation || profile.employment?.workLocation || 'Office'}</div>
                        </div>

                        {/* Employment Type */}
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">Employment Type</label>
                            <div className="text-slate-800 font-medium text-sm">{profile.user?.employmentType || 'Full Time'}</div>
                        </div>
                    </div>
                </div>

                <SectionCard
                    title="Previous Work Experience"
                    sectionName="experience"
                    icon={Briefcase}
                    editMode={editMode}
                    setEditMode={setEditMode}
                    onSave={handleSave}
                    isLoading={savingSection === 'experience'}
                >
                    {(isEditing) => (
                        <div className="space-y-6">
                            {(formData.experience || []).map((exp, idx) => (
                                <div key={idx} className={`p-4 rounded-xl border ${isEditing ? 'border-blue-100 bg-blue-50/20' : 'border-slate-100 bg-slate-50/30'}`}>
                                    <div className="flex justify-between items-start mb-4">
                                        <h4 className="text-sm font-bold text-slate-700">Experience #{idx + 1}</h4>
                                        {isEditing && (
                                            <button
                                                onClick={() => removeArrayItem('experience', idx)}
                                                className="text-red-500 hover:text-red-700 p-1 rounded-full hover:bg-red-50 transition-colors"
                                                title="Remove Experience"
                                            >
                                                <X size={16} />
                                            </button>
                                        )}
                                    </div>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        <Field
                                            label="Company Name"
                                            section="experience"
                                            value={exp.companyName}
                                            valueOverride={formData.experience?.[idx]?.companyName || exp.companyName}
                                            isEditing={isEditing}
                                            onChangeOverride={(e) => handleArrayChange('experience', idx, 'companyName', e.target.value)}
                                        />
                                        <Field
                                            label="Designation"
                                            section="experience"
                                            value={exp.designation}
                                            valueOverride={formData.experience?.[idx]?.designation || exp.designation}
                                            isEditing={isEditing}
                                            onChangeOverride={(e) => handleArrayChange('experience', idx, 'designation', e.target.value)}
                                        />
                                        <Field
                                            label="From Date"
                                            section="experience"
                                            type="date"
                                            value={exp.startDate}
                                            valueOverride={formData.experience?.[idx]?.startDate || exp.startDate}
                                            isEditing={isEditing}
                                            onChangeOverride={(e) => handleArrayChange('experience', idx, 'startDate', e.target.value)}
                                        />
                                        <Field
                                            label="To Date"
                                            section="experience"
                                            type="date"
                                            value={exp.endDate}
                                            valueOverride={formData.experience?.[idx]?.endDate || exp.endDate}
                                            isEditing={isEditing}
                                            onChangeOverride={(e) => handleArrayChange('experience', idx, 'endDate', e.target.value)}
                                        />
                                        <div className="md:col-span-2">
                                            <Field
                                                label="Reason for Leaving"
                                                section="experience"
                                                value={exp.reasonForLeaving}
                                                valueOverride={formData.experience?.[idx]?.reasonForLeaving || exp.reasonForLeaving}
                                                isEditing={isEditing}
                                                onChangeOverride={(e) => handleArrayChange('experience', idx, 'reasonForLeaving', e.target.value)}
                                            />
                                        </div>
                                    </div>
                                </div>
                            ))}

                            {isEditing && (
                                <button
                                    onClick={() => addArrayItem('experience', {
                                        companyName: '',
                                        designation: '',
                                        startDate: '',
                                        endDate: '',
                                        reasonForLeaving: '',
                                        totalExperience: ''
                                    })}
                                    className="w-full py-3 border-2 border-dashed border-blue-200 rounded-xl text-blue-600 hover:bg-blue-50 hover:border-blue-300 transition-all font-semibold flex items-center justify-center gap-2"
                                >
                                    + Add Past Experience
                                </button>
                            )}

                            {(!formData.experience || formData.experience.length === 0) && !isEditing && (
                                <div className="text-center py-10 bg-slate-50 rounded-xl border border-dashed border-slate-200">
                                    <Briefcase size={40} className="mx-auto text-slate-300 mb-3" />
                                    <p className="text-slate-500 text-sm italic">No past work experience added yet.</p>
                                </div>
                            )}
                        </div>
                    )}
                </SectionCard>
            </div>
        );
    };

    const renderDocuments = () => {
        const canVerify = currentUser?.roles?.some(r => r === 'Admin' || r?.name === 'Admin')
            || currentUser?.permissions?.includes('dossier.verify_documents')
            || currentUser?.permissions?.includes('dossier.approve');
        const hasPendingDocs = profile.documents?.some(d => d.verificationStatus === 'Pending');
        // Robust ID comparison
        const isSelf = currentUser?._id && userId && (currentUser._id.toString() === userId.toString());

        const handleVerifyAllDocuments = async () => {
            try {
                const targetUserId = userId || currentUser?._id;
                const response = await api.patch(`/dossier/${targetUserId}/documents/verify-all`, { status: 'Verified' });
                if (response.status === 200) {
                    toast.success(`All pending documents verified`);
                    // Optimistic update
                    setProfile(prev => ({
                        ...prev,
                        documentSubmissionStatus: response.data.submissionStatus,
                        documents: prev.documents.map(d => d.verificationStatus === 'Pending' ? { ...d, verificationStatus: 'Verified' } : d)
                    }));
                }
            } catch (error) {
                console.error('Verify All Documents Error:', error);
                toast.error(error.response?.data?.message || 'Failed to verify documents');
            }
        };

        const handleSubmitDocuments = async () => {
            // Validation: Check for mandatory documents
            const uploadedTitles = profile.documents?.map(d => d.title.toLowerCase()) || [];

            // 1. Mandatory Identity Docs (Except Passport)
            const identityCategory = documentCategories.find(c => c.name === 'Identity Documents');
            const requiredIdentityDocs = identityCategory?.fixedDocs.filter(doc => doc !== 'Passport') || [];

            const missingIdentityDocs = requiredIdentityDocs.filter(reqDoc =>
                !uploadedTitles.includes(reqDoc.toLowerCase())
            );

            // 2. Mandatory Qualification Docs
            const qualificationCategory = documentCategories.find(c => c.name === 'Qualification Certificates');
            const requiredQualificationDocs = qualificationCategory?.fixedDocs || [];

            const missingQualificationDocs = requiredQualificationDocs.filter(reqDoc =>
                !uploadedTitles.includes(reqDoc.toLowerCase())
            );

            const allMissing = [...missingIdentityDocs, ...missingQualificationDocs];

            if (allMissing.length > 0) {
                toast.error(`All fields are required.`);
                return;
            }

            try {
                const targetUserId = userId || currentUser?._id;
                const response = await api.patch(`/dossier/${targetUserId}/documents/submit`);
                if (response.status === 200) {
                    toast.success('Documents submitted for approval');
                    setProfile(prev => ({
                        ...prev,
                        documentSubmissionStatus: response.data.submissionStatus
                        // documents status doesn't change on submit, just global status
                    }));
                }
            } catch (error) {
                console.error('Submit Documents Error:', error);
                toast.error(error.response?.data?.message || 'Failed to submit documents');
            }
        };

        const handleVerifyDocument = async (docId, status) => {
            try {
                const targetUserId = userId || currentUser?._id;
                const response = await api.patch(`/dossier/${targetUserId}/documents/${docId}/verify`, { status });
                if (response.status === 200) {
                    toast.success(`Document marked as ${status}`);
                    setProfile(prev => ({
                        ...prev,
                        documentSubmissionStatus: response.data.submissionStatus,
                        documents: response.data.documents
                    }));
                }
            } catch (error) {
                console.error('Verify Document Error:', error);
                toast.error(error.response?.data?.message || 'Failed to verify document');
            }
        };

        const handleDownload = async (doc) => {
            try {
                const toastId = toast.loading('Preparing download...');
                const response = await api.get('/dossier/proxy-pdf', {
                    params: { url: doc.url, download: true },
                    responseType: 'blob'
                });

                const url = window.URL.createObjectURL(new Blob([response.data]));
                const link = document.createElement('a');
                link.href = url;
                link.setAttribute('download', doc.fileName || `${doc.title}.pdf`); // Fallback name
                document.body.appendChild(link);
                link.click();
                link.remove();
                window.URL.revokeObjectURL(url);
                toast.dismiss(toastId);
                toast.success('Download started');
            } catch (error) {
                console.error('Download Error:', error);
                toast.error('Failed to download document');
            }
        };



        // Render a single document card
        const DocumentCard = ({ doc }) => (
            <div className="group relative bg-white border border-slate-200 rounded-xl p-4 hover:shadow-lg hover:border-blue-200 transition-all duration-300 flex flex-col justify-between min-w-[280px] max-w-[280px]">
                <div className="flex justify-between items-start mb-3">
                    <div className="p-2.5 bg-blue-50 rounded-lg text-blue-600 group-hover:bg-blue-100 transition-colors">
                        <FileText size={20} />
                    </div>
                    <div className={`px-2.5 py-1 rounded-full text-[10px] uppercase font-bold tracking-wider ${doc.verificationStatus === 'Verified' ? 'bg-emerald-100 text-emerald-700' :
                        doc.verificationStatus === 'Rejected' ? 'bg-red-100 text-red-700' :
                            'bg-amber-100 text-amber-700'
                        }`}>
                        {doc.verificationStatus || 'Pending'}
                    </div>
                </div>

                <div className="mb-3">
                    <h4 className="font-semibold text-slate-800 text-sm mb-1 line-clamp-2" title={doc.title}>{doc.title}</h4>
                    <p className="text-xs text-slate-500 flex items-center gap-2">
                        <span>{doc.category || 'Document'}</span>
                        <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                        <span>{format(new Date(doc.uploadDate), 'MMM dd, yyyy')}</span>
                    </p>
                </div>

                {/* Action Footer */}
                <div className="pt-3 border-t border-slate-100 flex items-center justify-between gap-2 mt-auto">
                    <div className="flex gap-1">
                        <button
                            onClick={() => window.open(doc.url, '_blank')}
                            className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                            title="View"
                        >
                            <Eye size={16} />
                        </button>
                        <button
                            onClick={() => handleDownload(doc)}
                            className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                            title="Download"
                        >
                            <Download size={16} />
                        </button>
                    </div>

                    <div className="flex gap-1 pl-2 border-l border-slate-100">
                        {canVerify && (
                            <>
                                <button
                                    onClick={() => handleVerifyDocument(doc._id, 'Verified')}
                                    className="p-2 text-slate-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-lg transition-colors"
                                    title="Approve"
                                >
                                    <CheckCircle size={16} />
                                </button>
                                <button
                                    onClick={() => handleVerifyDocument(doc._id, 'Rejected')}
                                    className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                                    title="Reject"
                                >
                                    <X size={16} />
                                </button>
                            </>
                        )}

                        <button
                            onClick={() => handleDeleteDocument(doc._id)}
                            disabled={deletingDocId === doc._id}
                            className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                            title="Delete"
                        >
                            {deletingDocId === doc._id ? (
                                <span className="block h-4 w-4 border-2 border-red-500 border-t-transparent rounded-full animate-spin"></span>
                            ) : (
                                <Trash2 size={16} />
                            )}
                        </button>
                    </div>
                </div>
            </div>
        );

        return (
            <div className="bg-white rounded-lg shadow-sm border border-slate-200 p-6">
                <div className="flex justify-between items-center mb-1">
                    <h3 className="text-lg font-bold text-slate-800">Documents</h3>

                    {/* Approve All Button for Admins - Always Visible */}
                    {canVerify && (
                        <Button
                            onClick={handleVerifyAllDocuments}
                            disabled={!profile.documents?.some(d => d.verificationStatus === 'Pending')}
                            className={`flex items-center gap-2 shadow-sm ${!profile.documents?.some(d => d.verificationStatus === 'Pending')
                                ? 'bg-emerald-900 text-emerald-400'
                                : 'bg-emerald-600 hover:bg-emerald-700 text-white'
                                }`}
                        >
                            <CheckCircle size={18} />
                            Approve All Pending
                        </Button>
                    )}
                </div>
                <p className="text-xs text-red-500 italic mb-6">* fields are mandatory</p>

                {/* Submission Status Banner */}
                {profile.documentSubmissionStatus && profile.documentSubmissionStatus !== 'Draft' && (
                    <div className={`mb-4 p-3 rounded-lg border flex items-center gap-3 shadow-sm transition-all duration-300 ${profile.documentSubmissionStatus === 'Approved' ? 'bg-emerald-50/80 border-emerald-200 text-emerald-900' :
                        profile.documentSubmissionStatus === 'Changes Requested' ? 'bg-amber-50/80 border-amber-200 text-amber-900' :
                            'bg-blue-50/80 border-blue-200 text-blue-900'
                        }`}>
                        <div className={`p-1.5 rounded-full shrink-0 ${profile.documentSubmissionStatus === 'Approved' ? 'bg-emerald-100 text-emerald-600' :
                            profile.documentSubmissionStatus === 'Changes Requested' ? 'bg-amber-100 text-amber-600' :
                                'bg-blue-100 text-blue-600'
                            }`}>
                            {profile.documentSubmissionStatus === 'Approved' ? <CheckCircle size={18} /> :
                                profile.documentSubmissionStatus === 'Changes Requested' ? <AlertCircle size={18} /> :
                                    <Shield size={18} />}
                        </div>
                        <div className="flex-1">
                            <h4 className="font-bold text-sm tracking-tight flex items-center gap-2">
                                Submission Status: {profile.documentSubmissionStatus}
                                {profile.documentSubmissionStatus === 'Approved' && <span className="text-xs font-normal opacity-80">(All documents verified)</span>}
                            </h4>
                            {profile.documentSubmissionStatus !== 'Approved' && (
                                <p className="text-xs mt-0.5 opacity-90 leading-relaxed">
                                    {profile.documentSubmissionStatus === 'Submitted' && "Documents submitted for review."}
                                    {profile.documentSubmissionStatus === 'Changes Requested' && "Action Required: Please review feedback."}
                                </p>
                            )}
                        </div>
                    </div>
                )}

                {/* Hidden file input */}
                <input
                    type="file"
                    ref={fileInputRef}
                    className="hidden"
                    accept=".pdf,.jpg,.jpeg,.png"
                    onChange={handleFileSelect}
                />

                {/* Document Categories */}
                <div className="space-y-8">
                    {documentCategories.map((catConfig) => {
                        const categoryDocs = profile.documents?.filter(d => d.category === catConfig.category) || [];

                        return (
                            <div key={catConfig.name} className="border border-slate-200 rounded-xl p-5 bg-slate-50/50">
                                <div className="flex justify-between items-center mb-4">
                                    <h4 className="font-bold text-slate-700 flex items-center gap-2">
                                        {catConfig.icon && <span className="text-xl">{catConfig.icon}</span>}
                                        {catConfig.name}
                                        <span className="text-xs font-normal text-slate-500">({categoryDocs.length})</span>
                                    </h4>
                                    {catConfig.allowMultiple && (
                                        <button
                                            onClick={() => triggerCategoryUpload(catConfig.name, catConfig.category)}
                                            className="flex items-center gap-2 px-3 py-1.5 bg-blue-600 hover:bg-blue-700 text-white text-sm rounded-lg transition-colors shadow-sm"
                                        >
                                            <Upload size={14} />
                                            Add Document
                                        </button>
                                    )}
                                </div>

                                {/* Document Row - Horizontal Scroll */}
                                <div className="flex gap-4 overflow-x-auto pb-2 custom-scrollbar">
                                    {/* Fixed documents for Identity */}
                                    {/* Fixed documents (Identity, Education, Bank etc.) */}
                                    {catConfig.fixedDocs?.map((docTitle) => {
                                        const doc = categoryDocs.find(d => d.title.toLowerCase() === docTitle.toLowerCase());
                                        const isMandatory = (catConfig.name === 'Identity Documents' && docTitle !== 'Passport') || (catConfig.name === 'Qualification Certificates');

                                        if (doc) {
                                            return <DocumentCard key={doc._id} doc={doc} />;
                                        }

                                        // Empty state for fixed docs
                                        return (
                                            <div
                                                key={docTitle}
                                                onClick={() => triggerUpload(docTitle)}
                                                className="group cursor-pointer border-2 border-dashed border-slate-200 rounded-xl p-4 flex flex-col items-center justify-center text-center bg-white hover:bg-blue-50/30 hover:border-blue-300 hover:shadow-md transition-all duration-300 min-w-[280px] max-w-[280px] min-h-[180px]"
                                            >
                                                <div className="p-3 bg-slate-100 rounded-full text-slate-400 mb-3 group-hover:text-blue-500 group-hover:bg-blue-100 group-hover:scale-110 transition-all">
                                                    <Upload size={20} />
                                                </div>
                                                <h4 className="font-semibold text-slate-700 text-sm mb-1 group-hover:text-blue-700 transition-colors">
                                                    {docTitle} {isMandatory && <span className="text-red-500">*</span>}
                                                </h4>
                                                <p className="text-xs text-slate-400">Click to upload</p>
                                            </div>
                                        );
                                    })}

                                    {/* Dynamic documents (exclude those that match fixedDocs titles) */}
                                    {catConfig.allowMultiple && categoryDocs
                                        .filter(doc => !catConfig.fixedDocs?.some(fixedTitle => fixedTitle.toLowerCase() === doc.title.toLowerCase()))
                                        .map(doc => (
                                            <DocumentCard key={doc._id} doc={doc} />
                                        ))}

                                    {/* Show empty state if no documents in dynamic category AND no fixed docs */}
                                    {catConfig.allowMultiple && categoryDocs.length === 0 && (!catConfig.fixedDocs || catConfig.fixedDocs.length === 0) && (
                                        <div className="flex items-center justify-center min-w-[280px] h-[180px] border-2 border-dashed border-slate-200 rounded-xl bg-white text-slate-400 text-sm">
                                            No documents uploaded yet
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>

                {/* Document Final Declaration */}
                {(!canVerify || isSelf) && profile.documentSubmissionStatus !== 'Approved' && (
                    <div className="mt-10 pt-10 border-t border-slate-200">
                        <div className="bg-slate-50 p-6 rounded-xl border border-slate-200 flex flex-col items-center text-center">
                            <h3 className="font-bold text-slate-800 text-lg mb-2">Final Declaration</h3>
                            <p className="text-sm text-slate-600 max-w-2xl mb-6">
                                I hereby declare that all the documents provided above are true and accurate to the best of my knowledge.
                                I understand that any false information or forged documents may lead to disciplinary action or termination of employment.
                            </p>

                            {profile.documentSubmissionStatus === 'Submitted' ? (
                                <div className="space-y-4 flex flex-col items-center">
                                    <div className="flex items-center text-emerald-600 space-x-2 font-bold bg-emerald-50 px-4 py-2 rounded-full border border-emerald-100">
                                        <CheckCircle size={20} />
                                        <span>Declared on {profile.updatedAt ? format(new Date(profile.updatedAt), 'dd MMM yyyy') : 'Recently'}</span>
                                    </div>
                                </div>
                            ) : (
                                <div className="space-y-4 flex flex-col items-center">
                                    <label className="flex items-center space-x-3 cursor-pointer group">
                                        <input
                                            type="checkbox"
                                            checked={isDocumentDeclared}
                                            onChange={(e) => setIsDocumentDeclared(e.target.checked)}
                                            className="h-5 w-5 rounded border-slate-300 text-blue-600 focus:ring-blue-500 group-hover:border-blue-400 transition"
                                        />
                                        <span className="text-sm font-semibold text-slate-700 select-none">I agree to the declaration</span>
                                    </label>
                                    {isDocumentDeclared && (
                                        <p className="text-xs text-blue-600 font-medium animate-pulse">
                                            Ready to submit! Click "Submit for Approval" below to finish.
                                        </p>
                                    )}
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {/* Submit for Approval Button - Bottom */}
                {(!canVerify || isSelf) && !(profile.documentSubmissionStatus === 'Approved' && !hasPendingDocs) && (
                    <div className="mt-8 flex justify-end border-t border-slate-100 pt-6">
                        <button
                            onClick={handleSubmitDocuments}
                            disabled={!profile.documents?.length || profile.documentSubmissionStatus === 'Submitted' || !isDocumentDeclared}
                            className={`flex items-center gap-2 shadow-sm px-6 py-2.5 rounded-xl font-semibold outline-none ${!profile.documents?.length || profile.documentSubmissionStatus === 'Submitted' || !isDocumentDeclared
                                ? 'bg-slate-100 text-slate-400 border border-slate-200 cursor-not-allowed'
                                : 'bg-blue-600 text-white hover:bg-blue-700'
                                }`}
                        >
                            <Shield size={18} />
                            {profile.documentSubmissionStatus === 'Submitted' ? 'Submitted for Approval' :
                                profile.documentSubmissionStatus === 'Approved' && hasPendingDocs ? 'Submit New Documents' :
                                    'Submit for Approval'}
                        </button>
                    </div>
                )}

                {/* Fixed Document Upload Preview */}
                {showUploadPreview && previewFile && (
                    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4" onClick={handleCancelUpload}>
                        <div className="bg-white rounded-xl shadow-2xl max-w-sm w-full overflow-hidden" onClick={e => e.stopPropagation()}>
                            <div className="p-6">
                                <div className="flex justify-between items-start mb-4">
                                    <h3 className="text-lg font-bold text-slate-800">Confirm Upload</h3>
                                    <button onClick={handleCancelUpload} className="text-slate-400 hover:text-slate-600 transition-colors">
                                        <X size={20} />
                                    </button>
                                </div>

                                <div className="bg-slate-50 border border-slate-100 rounded-lg p-4 flex items-center gap-4 mb-6">
                                    <div className="h-12 w-12 rounded-lg bg-blue-100 flex items-center justify-center shrink-0 text-blue-600">
                                        <FileText size={24} />
                                    </div>
                                    <div className="min-w-0">
                                        <p className="font-semibold text-slate-700 text-sm truncate" title={uploadingDocTitle}>{uploadingDocTitle}</p>
                                        <p className="text-xs text-slate-500 mt-1">
                                            {(previewFile.size / 1024 / 1024).toFixed(2)} MB • {previewFile.name.split('.').pop().toUpperCase()}
                                        </p>
                                    </div>
                                </div>

                                <div className="flex gap-3">
                                    <Button
                                        onClick={handleConfirmUpload}
                                        isLoading={isUploading}
                                        className="flex-1 shadow-lg shadow-blue-100"
                                    >
                                        Upload Now
                                    </Button>
                                    <Button
                                        variants="ghost"
                                        onClick={handleCancelUpload}
                                        disabled={isUploading}
                                        className="flex-1 border border-slate-200"
                                    >
                                        Cancel
                                    </Button>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {/* Custom Title Modal */}
                {
                    showTitleModal && (
                        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50" onClick={handleCancelUpload}>
                            <div className="bg-white rounded-xl p-6 max-w-md w-full mx-4 shadow-2xl" onClick={(e) => e.stopPropagation()}>
                                <h3 className="text-lg font-bold text-slate-800 mb-4">Enter Document Title</h3>
                                <input
                                    type="text"
                                    value={customDocTitle}
                                    onChange={(e) => setCustomDocTitle(e.target.value)}
                                    placeholder="e.g., B.Tech Degree Certificate"
                                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none mb-4"
                                    autoFocus
                                    onKeyDown={(e) => {
                                        if (e.key === 'Enter' && customDocTitle.trim()) {
                                            handleConfirmUpload();
                                        }
                                    }}
                                />
                                <div className="flex gap-3">
                                    <Button
                                        onClick={handleConfirmUpload}
                                        disabled={!customDocTitle.trim()}
                                        isLoading={isUploading}
                                        className="flex-1"
                                    >
                                        Upload
                                    </Button>
                                    <Button
                                        variant="ghost"
                                        onClick={handleCancelUpload}
                                        disabled={isUploading}
                                        className="flex-1 border border-slate-200"
                                    >
                                        Cancel
                                    </Button>
                                </div>
                            </div>
                        </div>
                    )
                }
            </div >
        );
    };
    const handleArrayChange = (section, index, field, value) => {
        setFormData(prev => {
            const newArray = [...(prev[section] || [])];
            newArray[index] = { ...newArray[index], [field]: value };
            return { ...prev, [section]: newArray, hris: { ...prev.hris, isDeclared: false } };
        });
    };

    const addArrayItem = (section, defaultObj = {}) => {
        setFormData(prev => ({
            ...prev,
            [section]: [...(prev[section] || []), defaultObj],
            hris: { ...prev.hris, isDeclared: false }
        }));
    };

    const removeArrayItem = (section, index) => {
        setFormData(prev => ({
            ...prev,
            [section]: prev[section].filter((_, i) => i !== index),
            hris: { ...prev.hris, isDeclared: false }
        }));
    };

    const getStatusBadge = (status) => {
        const badgeBase = "px-3 py-1.5 rounded-full text-[11px] font-bold border flex items-center shadow-sm transition-all";
        switch (status) {
            case 'Approved':
                return <span className={`${badgeBase} bg-emerald-50 text-emerald-700 border-emerald-200`}><CheckCircle size={14} className="mr-1.5 flex-shrink-0" /> Approved</span>;
            case 'Pending Approval':
                return <span className={`${badgeBase} bg-amber-50 text-amber-700 border-amber-200`}><AlertCircle size={14} className="mr-1.5 flex-shrink-0" /> Pending Approval</span>;
            case 'Rejected':
                return <span className={`${badgeBase} bg-red-50 text-red-700 border-red-200`}><X size={14} className="mr-1.5 flex-shrink-0" /> Rejected</span>;
            default:
                return <span className={`${badgeBase} bg-slate-50 text-slate-600 border-slate-200`}>Draft</span>;
        }
    };

    const renderHRIS = () => {
        if (!profile) return null;
        const isEditing = editMode === 'hris';
        const isAdmin = currentUser?.roles?.some(r => r === 'Admin' || r?.name === 'Admin');
        const isManager = profile.employment?.reportingManager?._id === currentUser?._id || profile.employment?.reportingManager === currentUser?._id;
        const hrisStatus = profile.hris?.status || 'Draft';

        return (
            <div className="space-y-8 bg-white p-4 md:p-8 rounded-xl border border-slate-200 shadow-sm transition-all animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-slate-50 -m-4 md:-m-8 p-4 md:p-6 mb-12 border-b border-slate-200 rounded-t-xl gap-4">
                    <div className="flex items-center space-x-4">
                        <div>
                            <h2 className="text-xl font-extrabold text-slate-800 tracking-tight">HRIS Information Form</h2>
                            <div className="mt-4 flex items-center gap-4">
                                {getStatusBadge(hrisStatus)}
                                {profile.hris?.submittedAt && (
                                    <span className="text-[11px] text-slate-400 font-semibold uppercase tracking-wider bg-slate-100 px-2 py-0.5 rounded">
                                        Submitted: {format(new Date(profile.hris.submittedAt), 'dd MMM yyyy')}
                                    </span>
                                )}
                            </div>
                            {hrisStatus === 'Rejected' && profile.hris?.rejectionReason && (
                                <div className="mt-4 bg-red-50/50 p-3 rounded-lg border border-red-100/50 flex items-start gap-2 max-w-xl">
                                    <AlertCircle size={14} className="text-red-500 mt-0.5" />
                                    <p className="text-xs text-red-700 leading-relaxed font-medium">
                                        <span className="font-bold">Rejection Reason:</span> {profile.hris.rejectionReason}
                                    </p>
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="flex flex-wrap items-center gap-3">
                        {/* Admin Action: Export */}



                        {/* Edit Action for Self (and Admin) */}
                        {!isEditing && (hrisStatus === 'Draft' || hrisStatus === 'Rejected' || hrisStatus === 'Approved' || isAdmin) && (
                            <div className="flex space-x-2">
                                <Button onClick={() => setEditMode('hris')} className="flex items-center text-xs px-3 py-1.5 h-8">
                                    <Save size={14} className="mr-1.5" /> Edit Form
                                </Button>
                            </div>
                        )}
                    </div>
                </div>

                <div className="grid grid-cols-1 gap-6 py-12">
                    <p className="text-xs text-red-500 italic px-1">* fields are mandatory</p>
                    {/* 1. Basic Details */}
                    <div className="space-y-6">
                        <div className="flex items-center space-x-2 border-b border-slate-100 pb-2">
                            <User size={18} className="text-blue-500" />
                            <h3 className="font-bold text-slate-700">1. Basic Employee Details</h3>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                            <Field section="user" isEditing={false} label="Employee Code" field="employeeCode" value={profile.user?.employeeCode} />
                            <Field section="contact" isEditing={isEditing} label="Personal Email" field="personalEmail" value={profile.contact?.personalEmail} formData={formData} onChange={handleInputChange} required />
                            <Field section="identity" isEditing={isEditing} label="PAN Card Number" field="panNumber" value={profile.identity?.panNumber} formData={formData} onChange={handleInputChange} required />
                            <Field section="identity" isEditing={isEditing} label="Passport Number" field="passportNumber" value={profile.identity?.passportNumber} formData={formData} onChange={handleInputChange} />
                        </div>
                    </div>

                    {/* 2. Name Details */}
                    <div className="space-y-6">
                        <div className="flex items-center space-x-2 border-b border-slate-100 pb-2">
                            <User size={18} className="text-blue-500" />
                            <h3 className="font-bold text-slate-700">2. Name Details</h3>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                            <Field section="personal" isEditing={isEditing} label="Full Name" field="fullName" value={profile.personal?.fullName} formData={formData} onChange={handleInputChange} required />
                            <Field section="personal" isEditing={isEditing} label="First Name" field="firstName" value={profile.personal?.firstName} formData={formData} onChange={handleInputChange} required />
                            <Field section="personal" isEditing={isEditing} label="Middle Name" field="middleName" value={profile.personal?.middleName} formData={formData} onChange={handleInputChange} />
                            <Field section="personal" isEditing={isEditing} label="Last Name" field="lastName" value={profile.personal?.lastName} formData={formData} onChange={handleInputChange} required />
                        </div>
                    </div>

                    {/* 3. Personal Info */}
                    <div className="space-y-6">
                        <div className="flex items-center space-x-2 border-b border-slate-100 pb-2">
                            <Calendar size={18} className="text-blue-500" />
                            <h3 className="font-bold text-slate-700">3. Personal Information</h3>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                            <Field section="personal" isEditing={isEditing} label="Gender" field="gender" value={profile.personal?.gender} options={['Male', 'Female', 'Other']} formData={formData} onChange={handleInputChange} />
                            <Field section="personal" isEditing={isEditing} label="Date of Birth" field="dob" type="date" value={profile.personal?.dob} formData={formData} onChange={handleInputChange} />
                            <Field section="employment" isEditing={false} label="Date of Joining" field="joiningDate" type="date" value={profile.employment?.joiningDate} />
                        </div>
                    </div>

                    {/* 4. Bank Details */}
                    <div className="space-y-6">
                        <div className="flex items-center space-x-2 border-b border-slate-100 pb-2">
                            <DollarSign size={18} className="text-blue-500" />
                            <h3 className="font-bold text-slate-700">4. Bank Account Details</h3>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                            <Field
                                section="compensation" isEditing={isEditing} label="Account Number" field="bankAccount"
                                value={profile.compensation?.bankDetails?.accountNumber}
                                valueOverride={formData.compensation?.bankDetails?.accountNumber}
                                onChangeOverride={(e) => setFormData(prev => ({ ...prev, compensation: { ...prev.compensation, bankDetails: { ...prev.compensation?.bankDetails, accountNumber: e.target.value } } }))}
                                required
                            />
                            <Field
                                section="compensation" isEditing={isEditing} label="IFSC Code" field="ifsc"
                                value={profile.compensation?.bankDetails?.ifscCode}
                                valueOverride={formData.compensation?.bankDetails?.ifscCode}
                                onChangeOverride={(e) => setFormData(prev => ({ ...prev, compensation: { ...prev.compensation, bankDetails: { ...prev.compensation?.bankDetails, ifscCode: e.target.value } } }))}
                                required
                            />
                            <Field
                                section="compensation" isEditing={isEditing} label="Bank Name" field="bankName"
                                value={profile.compensation?.bankDetails?.bankName}
                                valueOverride={formData.compensation?.bankDetails?.bankName}
                                onChangeOverride={(e) => setFormData(prev => ({ ...prev, compensation: { ...prev.compensation, bankDetails: { ...prev.compensation?.bankDetails, bankName: e.target.value } } }))}
                                required
                            />
                            <Field
                                section="compensation" isEditing={isEditing} label="Account Holder Name" field="holder"
                                value={profile.compensation?.bankDetails?.accountHolderName}
                                valueOverride={formData.compensation?.bankDetails?.accountHolderName}
                                onChangeOverride={(e) => setFormData(prev => ({ ...prev, compensation: { ...prev.compensation, bankDetails: { ...prev.compensation?.bankDetails, accountHolderName: e.target.value } } }))}
                                required
                            />
                            <Field
                                section="compensation" isEditing={isEditing} label="Branch Address" field="branchAddress"
                                value={profile.compensation?.bankDetails?.branchAddress}
                                valueOverride={formData.compensation?.bankDetails?.branchAddress}
                                onChangeOverride={(e) => setFormData(prev => ({ ...prev, compensation: { ...prev.compensation, bankDetails: { ...prev.compensation?.bankDetails, branchAddress: e.target.value } } }))}
                                required
                            />
                        </div>
                    </div>

                    {/* 5. Addresses */}
                    <div className="space-y-6">
                        <div className="flex items-center space-x-2 border-b border-slate-100 pb-2">
                            <FileText size={18} className="text-blue-500" />
                            <h3 className="font-bold text-slate-700">5. Address Details</h3>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                            {['Current', 'Permanent', 'Mailing'].map(type => (
                                <div key={type} className="bg-slate-50 p-4 rounded-lg border border-slate-100">
                                    <h4 className="text-xs font-bold text-slate-500 uppercase mb-4 tracking-widest">{type} Address</h4>
                                    <div className="space-y-6">
                                        <Field section="contact" isEditing={isEditing} label="Street" field={`${type}_street`}
                                            value={profile.contact?.addresses?.find(a => a.type === type)?.street}
                                            valueOverride={formData.contact?.addresses?.find(a => a.type === type)?.street}
                                            onChangeOverride={(e) => handleAddressChange(type, 'street', e.target.value)}
                                        />
                                        <Field section="contact" isEditing={isEditing} label="City" field={`${type}_city`}
                                            value={profile.contact?.addresses?.find(a => a.type === type)?.city}
                                            valueOverride={formData.contact?.addresses?.find(a => a.type === type)?.city}
                                            onChangeOverride={(e) => handleAddressChange(type, 'city', e.target.value)}
                                        />
                                        <Field section="contact" isEditing={isEditing} label="State" field={`${type}_state`}
                                            value={profile.contact?.addresses?.find(a => a.type === type)?.state}
                                            valueOverride={formData.contact?.addresses?.find(a => a.type === type)?.state}
                                            onChangeOverride={(e) => handleAddressChange(type, 'state', e.target.value)}
                                        />
                                        <Field section="contact" isEditing={isEditing} label="Zip Code" field={`${type}_zip`}
                                            value={profile.contact?.addresses?.find(a => a.type === type)?.zipCode}
                                            valueOverride={formData.contact?.addresses?.find(a => a.type === type)?.zipCode}
                                            onChangeOverride={(e) => handleAddressChange(type, 'zipCode', e.target.value)}
                                        />
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* 6. Contact Details */}
                    <div className="space-y-6">
                        <div className="flex items-center space-x-2 border-b border-slate-100 pb-2">
                            <Shield size={18} className="text-blue-500" />
                            <h3 className="font-bold text-slate-700">6. Contact Details</h3>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                            <Field section="contact" isEditing={isEditing} label="Personal Mobile" field="mobileNumber" value={profile.contact?.mobileNumber} formData={formData} onChange={handleInputChange} />
                            <Field section="contact" isEditing={isEditing} label="Alternate Mobile Number" field="alternateNumber" value={profile.contact?.alternateNumber} formData={formData} onChange={handleInputChange} />
                            <Field section="contact" isEditing={isEditing} label="Emergency Mobile (from Personal)" field="emergencyNumber" value={profile.contact?.emergencyContact?.phone} formData={formData} onChange={handleInputChange} />
                            <Field section="contact" isEditing={isEditing} label="Landline Number" field="landlineNumber" value={profile.contact?.landlineNumber} formData={formData} onChange={handleInputChange} />
                        </div>
                    </div>

                    {/* 7. Family Details */}
                    <div className="space-y-6">
                        <div className="flex items-center space-x-2 border-b border-slate-100 pb-2">
                            <User size={18} className="text-blue-500" />
                            <h3 className="font-bold text-slate-700">7. Medical Insurance / Family Information</h3>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                            <Field section="family" isEditing={isEditing} label="Father's Name" field="fatherName" value={profile.family?.fatherName} formData={formData} onChange={handleInputChange} required />
                            <Field section="family" isEditing={isEditing} label="Father's Occupation" field="fatherOccupation" value={profile.family?.fatherOccupation} formData={formData} onChange={handleInputChange} />
                            <Field section="family" isEditing={isEditing} label="Mother's Name" field="motherName" value={profile.family?.motherName} formData={formData} onChange={handleInputChange} required />
                            <Field section="family" isEditing={isEditing} label="Mother's Occupation" field="motherOccupation" value={profile.family?.motherOccupation} formData={formData} onChange={handleInputChange} />
                            <Field section="family" isEditing={isEditing} label="Marital Status" field="parentsMaritalStatus" value={profile.family?.parentsMaritalStatus} options={['Married', 'Divorced', 'Widowed', 'Separated']} formData={formData} onChange={handleInputChange} />
                            <Field section="family" isEditing={isEditing} label="Total Siblings" field="totalSiblings" type="number" value={profile.family?.totalSiblings} formData={formData} onChange={handleInputChange} />
                            <Field section="personal" isEditing={isEditing} label="Date of Marriage" field="dateOfMarriage" type="date" value={profile.personal?.dateOfMarriage} formData={formData} onChange={handleInputChange} />
                            <Field section="family" isEditing={isEditing} label="Spouse Name" field="spouseName" value={profile.family?.spouseName} formData={formData} onChange={handleInputChange} />
                            <Field section="family" isEditing={isEditing} label="Spouse DOB" field="spouseDob" type="date" value={profile.family?.spouseDob} formData={formData} onChange={handleInputChange} />

                        </div>

                        {/* Children List */}
                        <div className="mt-4 bg-slate-50 p-4 rounded-lg border border-slate-100">
                            <div className="flex justify-between items-center mb-4">
                                <h4 className="text-sm font-bold text-slate-700">Children Details</h4>
                                {isEditing && (
                                    <button
                                        onClick={() => setFormData(prev => ({ ...prev, family: { ...prev.family, children: [...(prev.family?.children || []), { name: '', dob: '' }] } }))}
                                        className="text-xs bg-emerald-50 text-emerald-600 px-2 py-1 rounded border border-emerald-200 hover:bg-emerald-100"
                                    >
                                        + Add Child
                                    </button>
                                )}
                            </div>
                            <div className="space-y-3">
                                {(formData.family?.children || profile.family?.children || []).map((child, idx) => (
                                    <div key={idx} className="flex gap-4 items-end bg-white p-3 rounded border border-slate-200">
                                        <div className="flex-1">
                                            <Field section="family" isEditing={isEditing} label="Child's Name" field={`child_${idx}_name`}
                                                value={child.name} valueOverride={formData.family?.children?.[idx]?.name}
                                                onChangeOverride={(e) => {
                                                    const newChildren = [...(formData.family?.children || [])];
                                                    newChildren[idx] = { ...newChildren[idx], name: e.target.value };
                                                    handleInputChange('family', 'children', newChildren);
                                                }}
                                            />
                                        </div>
                                        <div className="flex-1">
                                            <Field section="family" isEditing={isEditing} label="Date of Birth" field={`child_${idx}_dob`}
                                                value={child.dob} valueOverride={formData.family?.children?.[idx]?.dob} type="date"
                                                onChangeOverride={(e) => {
                                                    const newChildren = [...(formData.family?.children || [])];
                                                    newChildren[idx] = { ...newChildren[idx], dob: e.target.value };
                                                    handleInputChange('family', 'children', newChildren);
                                                }}
                                            />
                                        </div>
                                        {isEditing && (
                                            <button
                                                onClick={() => {
                                                    const newChildren = formData.family?.children.filter((_, i) => i !== idx);
                                                    handleInputChange('family', 'children', newChildren);
                                                }}
                                                className="p-2 text-red-500 hover:bg-red-50 rounded"
                                            >
                                                <Trash2 size={16} />
                                            </button>
                                        )}
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>

                    {/* 8. Education */}
                    <div className="space-y-6">
                        <div className="flex justify-between items-center border-b border-slate-100 pb-2">
                            <div className="flex items-center space-x-2">
                                <FileText size={18} className="text-blue-500" />
                                <h3 className="font-bold text-slate-700">8. Educational Qualification</h3>
                            </div>
                            {isEditing && (
                                <button
                                    onClick={() => addArrayItem('education', { institution: '', degree: '', grade: '' })}
                                    className="text-xs bg-emerald-50 text-emerald-600 px-2 py-1 rounded border border-emerald-200"
                                >
                                    + Add Education
                                </button>
                            )}
                        </div>
                        <div className="space-y-6">
                            {(formData.education || profile.education || []).map((edu, idx) => (
                                <div key={idx} className="bg-slate-50 p-4 rounded-lg border border-slate-100 flex gap-6">
                                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4 flex-1">
                                        <Field section="education" isEditing={isEditing} label="Institution" field={`inst_${idx}`}
                                            value={edu.institution} valueOverride={formData.education?.[idx]?.institution || edu.institution}
                                            onChangeOverride={(e) => handleArrayChange('education', idx, 'institution', e.target.value)}
                                        />
                                        <Field section="education" isEditing={isEditing} label="University" field={`univ_${idx}`}
                                            value={edu.university} valueOverride={formData.education?.[idx]?.university || edu.university}
                                            onChangeOverride={(e) => handleArrayChange('education', idx, 'university', e.target.value)}
                                        />
                                        <Field section="education" isEditing={isEditing} label="Degree" field={`deg_${idx}`}
                                            value={edu.degree} valueOverride={formData.education?.[idx]?.degree || edu.degree}
                                            onChangeOverride={(e) => handleArrayChange('education', idx, 'degree', e.target.value)}
                                        />
                                        <Field section="education" isEditing={isEditing} label="Course Name" field={`course_${idx}`}
                                            value={edu.courseName} valueOverride={formData.education?.[idx]?.courseName || edu.courseName}
                                            onChangeOverride={(e) => handleArrayChange('education', idx, 'courseName', e.target.value)}
                                        />
                                        <Field section="education" isEditing={isEditing} label="Grade/CGPA" field={`grade_${idx}`}
                                            value={edu.grade} valueOverride={formData.education?.[idx]?.grade || edu.grade}
                                            onChangeOverride={(e) => handleArrayChange('education', idx, 'grade', e.target.value)}
                                        />
                                        <Field section="education" isEditing={isEditing} label="College Rank" field={`rank_${idx}`}
                                            value={edu.collegeRank} valueOverride={formData.education?.[idx]?.collegeRank || edu.collegeRank}
                                            onChangeOverride={(e) => handleArrayChange('education', idx, 'collegeRank', e.target.value)}
                                        />
                                        <Field section="education" isEditing={isEditing} label="From Date" field={`from_${idx}`} type="date"
                                            value={edu.fromDate} valueOverride={formData.education?.[idx]?.fromDate || edu.fromDate}
                                            onChangeOverride={(e) => handleArrayChange('education', idx, 'fromDate', e.target.value)}
                                        />
                                        <Field section="education" isEditing={isEditing} label="To Date" field={`to_${idx}`} type="date"
                                            value={edu.toDate} valueOverride={formData.education?.[idx]?.toDate || edu.toDate}
                                            onChangeOverride={(e) => handleArrayChange('education', idx, 'toDate', e.target.value)}
                                        />
                                    </div>
                                    {isEditing && (
                                        <button onClick={() => removeArrayItem('education', idx)} className="self-center p-2 text-red-500"><Trash2 size={18} /></button>
                                    )}
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* 9. Experience */}
                    <div className="space-y-6">
                        <div className="flex justify-between items-center border-b border-slate-100 pb-2">
                            <div className="flex items-center space-x-2">
                                <Briefcase size={18} className="text-blue-500" />
                                <h3 className="font-bold text-slate-700">9. Work Experience</h3>
                            </div>
                            {isEditing && (
                                <button
                                    onClick={() => addArrayItem('experience', { companyName: '', designation: '', startDate: '', endDate: '' })}
                                    className="text-xs bg-emerald-50 text-emerald-600 px-2 py-1 rounded border border-emerald-200"
                                >
                                    + Add Work History
                                </button>
                            )}
                        </div>
                        <div className="space-y-6">
                            {(formData.experience || profile.experience || []).map((exp, idx) => (
                                <div key={idx} className="bg-slate-50 p-4 rounded-lg border border-slate-100 flex gap-6">
                                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4 flex-1">
                                        <Field section="experience" isEditing={isEditing} label="Company Name" field={`comp_${idx}`}
                                            value={exp.companyName} valueOverride={formData.experience?.[idx]?.companyName || exp.companyName}
                                            onChangeOverride={(e) => handleArrayChange('experience', idx, 'companyName', e.target.value)}
                                        />
                                        <Field section="experience" isEditing={isEditing} label="Designation" field={`desig_${idx}`}
                                            value={exp.designation} valueOverride={formData.experience?.[idx]?.designation || exp.designation}
                                            onChangeOverride={(e) => handleArrayChange('experience', idx, 'designation', e.target.value)}
                                        />
                                        <Field section="experience" isEditing={isEditing} label="Start Date" field={`start_${idx}`} type="date"
                                            value={exp.startDate} valueOverride={formData.experience?.[idx]?.startDate || exp.startDate}
                                            onChangeOverride={(e) => handleArrayChange('experience', idx, 'startDate', e.target.value)}
                                        />
                                        <Field section="experience" isEditing={isEditing} label="End Date" field={`end_${idx}`} type="date"
                                            value={exp.endDate} valueOverride={formData.experience?.[idx]?.endDate || exp.endDate}
                                            onChangeOverride={(e) => handleArrayChange('experience', idx, 'endDate', e.target.value)}
                                        />
                                        <Field section="experience" isEditing={isEditing} label="Total Work Experience" field={`total_${idx}`}
                                            value={exp.totalExperience} valueOverride={formData.experience?.[idx]?.totalExperience || exp.totalExperience}
                                            onChangeOverride={(e) => handleArrayChange('experience', idx, 'totalExperience', e.target.value)}
                                        />
                                    </div>
                                    {isEditing && (
                                        <button onClick={() => removeArrayItem('experience', idx)} className="self-center p-2 text-red-500"><Trash2 size={18} /></button>
                                    )}
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* 10. Skills */}
                    <div className="space-y-4">
                        <div className="flex items-center space-x-2 border-b border-slate-100 pb-2">
                            <Shield size={18} className="text-blue-500" />
                            <h3 className="font-bold text-slate-700">10. Skills Information</h3>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div>
                                {isEditing ? (
                                    <SkillsInput
                                        label="Technical Skills"
                                        skills={formData.skills?.technical || []}
                                        onUpdate={(newSkills) => handleInputChange('skills', 'technical', newSkills)}
                                        placeholder="e.g. React, Node.js"
                                    />
                                ) : (
                                    <div>
                                        <label className="block text-xs font-semibold text-slate-500 uppercase mb-2">Technical Skills</label>
                                        <div className="flex flex-wrap gap-2">
                                            {(profile.skills?.technical || []).map((s, i) => <span key={`${s}-${i}`} className="bg-blue-50 text-blue-700 px-2 py-1 rounded text-xs border border-blue-100">{s}</span>)}
                                            {profile.skills?.technical?.length === 0 && <span className="text-slate-400 italic text-sm">Not specified</span>}
                                        </div>
                                    </div>
                                )}
                            </div>
                            <div>
                                {isEditing ? (
                                    <SkillsInput
                                        label="Behavioral Skills"
                                        skills={formData.skills?.behavioral || []}
                                        onUpdate={(newSkills) => handleInputChange('skills', 'behavioral', newSkills)}
                                        placeholder="e.g. Leadership, Teamwork"
                                    />
                                ) : (
                                    <div>
                                        <label className="block text-xs font-semibold text-slate-500 uppercase mb-2">Behavioral Skills</label>
                                        <div className="flex flex-wrap gap-2">
                                            {(profile.skills?.behavioral || []).map((s, i) => <span key={`${s}-${i}`} className="bg-emerald-50 text-emerald-700 px-2 py-1 rounded text-xs border border-emerald-100">{s}</span>)}
                                            {profile.skills?.behavioral?.length === 0 && <span className="text-slate-400 italic text-sm">Not specified</span>}
                                        </div>
                                    </div>
                                )}
                            </div>
                            <div>
                                {isEditing ? (
                                    <SkillsInput
                                        label="Skill you would like to learn"
                                        skills={formData.skills?.learningInterests || []}
                                        onUpdate={(newSkills) => handleInputChange('skills', 'learningInterests', newSkills)}
                                        placeholder="e.g. AI, Machine Learning"
                                    />
                                ) : (
                                    <div>
                                        <label className="block text-xs font-semibold text-slate-500 uppercase mb-2">Skill you would like to learn</label>
                                        <div className="flex flex-wrap gap-2">
                                            {(profile.skills?.learningInterests || []).map((s, i) => <span key={`${s}-${i}`} className="bg-purple-50 text-purple-700 px-2 py-1 rounded text-xs border border-purple-100">{s}</span>)}
                                            {profile.skills?.learningInterests?.length === 0 && <span className="text-slate-400 italic text-sm">Not specified</span>}
                                        </div>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>

                    {/* 11. Declaration */}
                    <div className="mt-10 pt-10 border-t border-slate-200">
                        <div className="bg-slate-50 p-6 rounded-xl border border-slate-200 flex flex-col items-center text-center">
                            <h3 className="font-bold text-slate-800 text-lg mb-2">11. Final Declaration</h3>
                            <p className="text-sm text-slate-600 max-w-2xl mb-6">
                                I hereby declare that all the information provided above is true and accurate to the best of my knowledge.
                                I understand that any false information may lead to disciplinary action or termination of employment.
                            </p>
                            {isEditing ? (
                                <div className="space-y-4 flex flex-col items-center">
                                    <label className="flex items-center space-x-3 cursor-pointer group">
                                        <input
                                            type="checkbox"
                                            checked={formData.hris?.isDeclared}
                                            onChange={(e) => handleInputChange('hris', 'isDeclared', e.target.checked)}
                                            className="h-5 w-5 rounded border-slate-300 text-blue-600 focus:ring-blue-500 group-hover:border-blue-400 transition"
                                        />
                                        <span className="text-sm font-semibold text-slate-700 select-none">I agree to the declaration</span>
                                    </label>
                                    {formData.hris?.isDeclared && (
                                        <p className="text-xs text-blue-600 font-medium animate-pulse">
                                            Ready to submit! Click "Submit for Approval" to finish.
                                        </p>
                                    )}
                                </div>
                            ) : (
                                <div className="space-y-4 flex flex-col items-center">
                                    <div className="flex items-center text-emerald-600 space-x-2 font-bold bg-emerald-50 px-4 py-2 rounded-full border border-emerald-100">
                                        <CheckCircle size={20} />
                                        <span>{profile.hris?.isDeclared ? `Declared on ${format(new Date(profile.hris.declarationDate || profile.updatedAt), 'dd MMM yyyy')}` : 'Not Declared Yet'}</span>
                                    </div>
                                    {profile.hris?.isDeclared && (hrisStatus === 'Draft' || hrisStatus === 'Rejected') && (
                                        <Button onClick={handleHRISSave} className="bg-blue-600 hover:bg-blue-700 text-white shadow-lg flex items-center">
                                            <Shield size={18} className="mr-2" /> Submit HRIS for Approval
                                        </Button>
                                    )}
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {
                    isEditing && (
                        <div className="flex justify-end space-x-4 pt-8 mt-10 border-t border-slate-100">
                            <Button variants="ghost" onClick={() => { setEditMode(false); setFormData(profile); }}>Discard Changes</Button>
                            <Button onClick={handleHRISSave} isLoading={savingSection === 'hris'} className="px-8 flex items-center shadow-lg">
                                <Save size={18} className="mr-2" /> Complete & Save Form
                            </Button>
                        </div>
                    )
                }

                {/* Submit Logic Moved to Bottom */}
                {!isEditing && (hrisStatus === 'Draft' || hrisStatus === 'Rejected' || hrisStatus === 'Approved') && (profile.hris?.isDeclared || (currentUser?.roles?.some(r => r.name === 'Admin'))) && (
                    <div className="flex justify-end pt-8 mt-10 border-t border-slate-100">
                        <Button onClick={() => handleHRISSave()} className="bg-blue-600 hover:bg-blue-700 text-white border-none shadow-lg px-6 py-2.5 flex items-center">
                            <Shield size={18} className="mr-2" /> {profile.hris?.isDeclared ? 'Submit for Approval' : 'Submit as Admin'}
                        </Button>
                    </div>
                )}
            </div >
        );
    };

    const renderHistory = () => {
        return (
            <div className="bg-white rounded-lg shadow-sm border border-slate-200 p-6">
                <h3 className="text-lg font-bold text-slate-800 mb-6">Activity History</h3>

                {historyLogs.length === 0 ? (
                    <div className="text-center py-10 text-slate-500">No history available</div>
                ) : (
                    <div className="relative border-l border-slate-200 ml-3 space-y-8 max-h-[600px] overflow-y-auto pr-2 custom-scrollbar">
                        {historyLogs.map((log, idx) => (
                            <div key={log._id || idx} className="ml-6 relative">
                                <span className="absolute -left-[31px] bg-blue-100 h-4 w-4 rounded-full border-2 border-white ring-1 ring-blue-500"></span>
                                <div className="bg-slate-50 p-4 rounded-lg border border-slate-100">
                                    <div className="flex justify-between items-start mb-2">
                                        <p className="text-sm font-semibold text-slate-800">
                                            {log.action === 'UPDATE_DOSSIER' ? `Updated ${log.details?.section || 'Dossier'}` :
                                                log.action === 'UPLOAD_DOCUMENT' ? 'Uploaded Document' : log.action}
                                        </p>
                                        <span className="text-xs text-slate-400 whitespace-nowrap">
                                            {format(new Date(log.createdAt), 'dd MMM yyyy, hh:mm a')}
                                        </span>
                                    </div>
                                    <p className="text-xs text-slate-500 mb-2">
                                        by <span className="font-medium text-slate-700">
                                            {log.performedBy ? `${log.performedBy.firstName} ${log.performedBy.lastName}` : 'Unknown'}
                                        </span>
                                    </p>

                                    {log.details?.updates && (
                                        <div className="text-xs text-slate-600 bg-white p-2 rounded border border-slate-200 mt-2">
                                            <div className="font-semibold mb-1">Changes:</div>
                                            {Array.isArray(log.details.updates) ? (
                                                <span>{log.details.updates.join(', ')}</span>
                                            ) : (
                                                <ul className="list-disc ml-4 space-y-0.5">
                                                    {Object.entries(log.details.updates).map(([key, val]) => (
                                                        <li key={key}>
                                                            <span className="font-medium capitalize">{key.replace(/([A-Z])/g, ' $1').trim()}:</span> {val !== null && val !== undefined ? String(val) : <em className="text-slate-400">Empty</em>}
                                                        </li>
                                                    ))}
                                                </ul>
                                            )}
                                        </div>
                                    )}
                                    {log.details?.docTitle && (
                                        <div className="text-xs text-slate-600 bg-white p-2 rounded border border-slate-200 mt-2">
                                            Document: <span className="font-medium">{log.details.docTitle}</span>
                                        </div>
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        );
    };

    const renderHRISRequests = () => {
        const filtered = hrisRequests.filter(req =>
            `${req.firstName} ${req.lastName}`.toLowerCase().includes(hrisSearchTerm.toLowerCase()) ||
            req.employeeCode?.toLowerCase().includes(hrisSearchTerm.toLowerCase())
        );

        return (
            <div className="space-y-6">
                <div className="bg-white rounded-lg shadow-sm border border-slate-200 p-6">
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
                        <div>
                            <h3 className="text-lg font-bold text-slate-800">HRIS Requests Management</h3>
                            <p className="text-sm text-slate-500">View and manage HRIS submissions history</p>
                        </div>
                        <div className="relative">
                            <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input
                                type="text"
                                value={hrisSearchTerm}
                                onChange={(e) => setHrisSearchTerm(e.target.value)}
                                placeholder="Search by name or code..."
                                className="pl-9 pr-4 py-2 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-100 outline-none w-64"
                            />
                        </div>
                    </div>

                    <div className="overflow-x-auto border border-slate-100 rounded-lg">
                        <table className="w-full text-sm text-left">
                            <thead className="bg-slate-50 text-slate-500 font-medium">
                                <tr>
                                    <th className="px-4 py-3">Employee</th>
                                    <th className="px-4 py-3">Dept</th>
                                    <th className="px-4 py-3">Submitted</th>
                                    <th className="px-4 py-3">Status</th>
                                    <th className="px-4 py-3 text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100">
                                {loadingRequests ? (
                                    <tr>
                                        <td colSpan="5" className="px-4 py-10 text-center">
                                            <div className="animate-spin h-6 w-6 border-2 border-blue-600 border-t-transparent rounded-full mx-auto mb-2"></div>
                                            <p className="text-slate-500">Fetching requests...</p>
                                        </td>
                                    </tr>
                                ) : filtered.length === 0 ? (
                                    <tr>
                                        <td colSpan="5" className="px-4 py-10 text-center text-slate-500 italic">
                                            No HRIS requests found
                                        </td>
                                    </tr>
                                ) : (
                                    filtered.map(req => (
                                        <tr key={req._id} className="hover:bg-slate-50/50">
                                            <td className="px-4 py-3">
                                                <div className="font-semibold text-slate-800">{req.firstName} {req.lastName}</div>
                                                <div className="text-[11px] text-slate-500 font-medium">{req.employeeCode}</div>
                                            </td>
                                            <td className="px-4 py-3 text-slate-600">{req.department || '-'}</td>
                                            <td className="px-4 py-3 text-slate-600">
                                                {req.employeeProfile?.hris?.submittedAt ? format(new Date(req.employeeProfile.hris.submittedAt), 'dd MMM yyyy') : '-'}
                                            </td>
                                            <td className="px-4 py-3">
                                                <div className="scale-75 origin-left w-32">
                                                    {getStatusBadge(req.employeeProfile?.hris?.status)}
                                                </div>
                                            </td>
                                            <td className="px-4 py-3 text-right">
                                                <div className="flex items-center justify-end space-x-2">
                                                    {req.employeeProfile?.hris?.status === 'Pending Approval' && (
                                                        <>
                                                            <button
                                                                onClick={() => handleHRISApproveOther(req._id)}
                                                                className="p-1.5 text-emerald-600 hover:bg-emerald-50 rounded-md transition-colors"
                                                                title="Approve"
                                                            >
                                                                <CheckCircle size={18} />
                                                            </button>
                                                            <button
                                                                onClick={() => handleHRISRejectOther(req._id)}
                                                                className="p-1.5 text-red-600 hover:bg-red-50 rounded-md transition-colors"
                                                                title="Reject"
                                                            >
                                                                <X size={18} />
                                                            </button>
                                                        </>
                                                    )}
                                                    <button
                                                        onClick={() => {
                                                            navigate(`/dossier/${req._id}`);
                                                            setActiveTab('hris');
                                                        }}
                                                        className="p-1.5 text-blue-600 hover:bg-blue-50 rounded-md transition-colors"
                                                        title="View Form"
                                                    >
                                                        <FileText size={18} />
                                                    </button>
                                                    <button
                                                        onClick={() => handleExcelExport(req._id)}
                                                        className="p-1.5 text-slate-500 hover:bg-slate-100 rounded-md transition-colors"
                                                        title="Download Excel"
                                                    >
                                                        <Download size={18} />
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>
        );
    };

    // Loading State
    if (loading) return (
        <div className="min-h-screen bg-slate-50 p-6 flex justify-center">
            <div className="max-w-5xl w-full space-y-4">
                <Skeleton className="h-40 w-full rounded-xl" />
                <div className="flex space-x-4">
                    <Skeleton className="h-64 w-1/4 rounded-lg" />
                    <Skeleton className="h-64 w-3/4 rounded-lg" />
                </div>
            </div>
        </div>
    );

    return (
        <div className={embedded ? "w-full font-sans" : "min-h-screen bg-slate-50 font-sans"}>
            {/* Top Navigation Bar - Hidden if embedded */}
            {!embedded && (
                <div className="bg-white border-b border-slate-200 sticky top-0 z-10 px-6 py-3 flex justify-between items-center">
                    <div className="flex items-center space-x-3">
                        <button onClick={() => navigate(-1)} className="p-2 hover:bg-slate-100 rounded-full text-slate-500">
                            <ArrowLeft size={20} />
                        </button>
                        <h1 className="text-lg font-bold text-slate-800">Employee Dossier</h1>
                    </div>
                </div>
            )}

            <div className={embedded ? "w-full" : "max-w-6xl mx-auto p-6 md:p-8"}>

                {/* Tabs */}
                <div className="mb-8 overflow-x-auto">
                    <div className="flex space-x-1 border-b border-slate-200 min-w-max">
                        {tabs.map(tab => (
                            <button
                                key={tab.id}
                                onClick={() => setActiveTab(tab.id)}
                                className={`flex items-center space-x-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === tab.id
                                    ? 'border-blue-600 text-blue-600 bg-blue-50/50'
                                    : 'border-transparent text-slate-500 hover:text-slate-700 hover:bg-slate-50'
                                    }`}
                            >
                                <tab.icon size={16} />
                                <span>{tab.label}</span>
                            </button>
                        ))}
                    </div>
                </div>

                {/* Content Area */}
                <div className="min-h-[400px]">

                    {activeTab === 'personal' && renderPersonal()}
                    {activeTab === 'employment' && renderEmployment()}

                    {activeTab === 'documents' && renderDocuments()}
                    {activeTab === 'hris' && renderHRIS()}
                    {activeTab === 'history' && renderHistory()}
                    {activeTab === 'requests' && renderHRISRequests()}
                </div>



            </div>
        </div>
    );
};

export default EmployeeDossier;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../api/axios';
import { useAuth } from '../context/AuthContext';
import {
    User, Mail, Briefcase, Shield, Hash, Users, MapPin, Calendar,
    ArrowLeft, Edit2, Clock, FileText, Activity, AlertCircle, UserMinus, UserCheck
} from 'lucide-react';
import toast from 'react-hot-toast';
import Skeleton from '../components/Skeleton';
import { format } from 'date-fns';
import UserTADashboard from './TalentAcquisition/UserTADashboard';
import Timesheet from './Timesheet';
import EmployeeDossier from './EmployeeDossier';

const EmployeeProfile = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user: currentUser } = useAuth();

    const [profile, setProfile] = useState(null);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('overview'); // overview, edit, timesheet, dossier, ta-analytics
    const [roles, setRoles] = useState([]);
    const [allUsers, setAllUsers] = useState([]); // for reporting managers/direct reports

    // Form State for Editing
    const [formData, setFormData] = useState({
        firstName: '',
        lastName: '',
        email: '',
        password: '',
        roleId: '',
        department: '',
        employeeCode: '',
        joiningDate: '',
        employmentType: 'Full Time',
        workLocation: '',
        directReports: [],
        reportingManagers: []
    });

    const enabledModules = currentUser?.company?.enabledModules || [];
    const hasTA = enabledModules.includes('talentAcquisition');
    const hasAttendance = enabledModules.includes('attendance');
    const hasTimesheet = enabledModules.includes('timesheet');
    const hasDossier = enabledModules.includes('employeeDossier');

    const isAuthorizedForTA = (currentUser?.roles?.includes('Admin') || currentUser?.permissions?.includes('ta.read')) && hasTA;
    const isAuthorizedForEdit = currentUser?.roles?.includes('Admin') || currentUser?.permissions?.includes('user.update');

    // Reset active tab if it becomes unauthorized or module is disabled
    useEffect(() => {
        if (activeTab === 'ta-analytics' && !isAuthorizedForTA) setActiveTab('overview');
        if (activeTab === 'attendance' && !hasAttendance) setActiveTab('overview');
        if (activeTab === 'timesheet' && !hasTimesheet) setActiveTab('overview');
        if (activeTab === 'dossier' && !hasDossier) setActiveTab('overview');
    }, [activeTab, isAuthorizedForTA, hasAttendance, hasTimesheet, hasDossier]);

    const fetchData = useCallback(async () => {
        setLoading(true);
        try {
            // Fetch the specific user profile
            const res = await api.get(`/admin/users/${id}`);
            const userData = res.data;
            setProfile(userData);

            // Pre-fill form data
            setFormData({
                firstName: userData.firstName || '',
                lastName: userData.lastName || '',
                email: userData.email || '',
                password: '', // Blank by default, only sent if changed
                roleId: userData.roles?.[0]?._id || '',
                department: userData.department || '',
                employeeCode: userData.employeeCode || '',
                joiningDate: userData.joiningDate ? new Date(userData.joiningDate).toISOString().split('T')[0] : '',
                employmentType: userData.employmentType || 'Full Time',
                workLocation: userData.workLocation || '',
                directReports: userData.directReports?.map(u => u._id) || [],
                reportingManagers: userData.reportingManagers?.map(u => u._id) || []
            });

            // Fetch roles and all users for edit form context if authorized
            if (isAuthorizedForEdit) {
                try {
                    const [rolesRes, usersRes] = await Promise.all([
                        api.get('/admin/roles'),
                        api.get('/admin/users')
                    ]);
                    setRoles(rolesRes.data);
                    setAllUsers(usersRes.data);
                } catch (err) {
                    console.log("Could not fetch roles/users context for edit form:", err);
                }
            }

        } catch (error) {
            console.error(error);
            toast.error('Failed to load employee profile');
            if (error.response?.status === 403 || error.response?.status === 404) {
                navigate('/users');
            }
        } finally {
            setLoading(false);
        }
    }, [id, isAuthorizedForEdit, navigate]);

    useEffect(() => {
        if (id) {
            fetchData();
        }
    }, [id]);

    const handleToggleStatus = async () => {
        if (!window.confirm(`Are you sure you want to ${profile.isActive ? 'deactivate' : 'reactivate'} this user?`)) return;
        
        try {
            const loadingToast = toast.loading(`${profile.isActive ? 'Deactivating' : 'Activating'} user...`);
            const res = await api.patch(`/admin/users/${id}/status`);
            toast.success(res.data.message, { id: loadingToast });
            setProfile(prev => ({ ...prev, isActive: res.data.isActive }));
        } catch (error) {
            toast.error(error.response?.data?.message || 'Failed to update status');
        }
    };

    const handleFormChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleEditSubmit = async (e) => {
        e.preventDefault();
        try {
            const loadingToast = toast.loading('Updating user...');
            await api.put(`/admin/users/${id}`, formData);
            toast.success('User updated successfully', { id: loadingToast });
            // Refresh data and switch back to overview
            await fetchData();
            setActiveTab('overview');
        } catch (error) {
            toast.error(error.response?.data?.message || 'Failed to update user');
        }
    };

    if (loading) {
        return (
            <div className="p-6 max-w-7xl mx-auto space-y-6 animate-pulse">
                <div className="h-32 bg-slate-200 rounded-xl"></div>
                <div className="flex gap-4">
                    <div className="h-10 bg-slate-200 rounded w-24"></div>
                    <div className="h-10 bg-slate-200 rounded w-24"></div>
                    <div className="h-10 bg-slate-200 rounded w-24"></div>
                </div>
                <div className="h-64 bg-slate-200 rounded-xl"></div>
            </div>
        );
    }

    if (!profile) return null;

    return (
        <div className="min-h-screen bg-slate-100 font-sans p-4 sm:p-6 md:p-10">
            <div className="max-w-7xl mx-auto space-y-6">

                {/* Back Button & Header */}
                <div className="flex items-center gap-4 mb-2">
                    <button
                        onClick={() => navigate('/users')}
                        className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-200/50 rounded-full transition-colors"
                    >
                        <ArrowLeft size={20} />
                    </button>
                    <div>
                        <h1 className="text-2xl font-bold text-slate-800">Employee Details</h1>
                        <p className="text-sm text-slate-500">Manage profile and view analytics</p>
                    </div>
                </div>

                {/* Profile Header Card */}
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden relative">
                    <div className="h-24 bg-gradient-to-r from-slate-700 to-slate-900"></div>
                    <div className="px-6 sm:px-8 pb-6 bg-white relative">
                        <div className="flex flex-col sm:flex-row sm:items-end sm:justify-between -mt-10 sm:-mt-12 gap-4">
                            <div className="flex items-end gap-4">
                                <div className="h-20 w-20 sm:h-24 sm:w-24 rounded-full border-4 border-white bg-slate-100 flex items-center justify-center text-3xl font-bold text-slate-400 shadow-sm shrink-0">
                                    {profile.firstName?.charAt(0)}{profile.lastName?.charAt(0)}
                                </div>
                                <div className="pb-1 sm:pb-2">
                                    <h2 className="text-xl sm:text-2xl font-bold text-slate-800 whitespace-nowrap">
                                        {profile.firstName} {profile.lastName}
                                    </h2>
                                    <p className="text-sm text-slate-500 flex items-center gap-1.5 mt-0.5">
                                        <Mail size={14} /> {profile.email}
                                    </p>
                                </div>
                            </div>

                            <div className="flex flex-wrap items-center gap-2 sm:pb-2">
                                <span className={`px-2.5 py-1 rounded-full text-xs font-bold uppercase tracking-wide border ${profile.isActive ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-red-50 text-red-700 border-red-200'}`}>
                                    {profile.isActive ? 'Active' : 'Inactive'}
                                </span>
                                {profile.roles?.map(role => (
                                    <span key={role._id} className="px-2.5 py-1 rounded-full text-xs font-semibold bg-blue-50 text-blue-700 border border-blue-200 flex items-center gap-1">
                                        <Shield size={12} /> {role.name}
                                    </span>
                                ))}
                                {isAuthorizedForEdit && (
                                    <button
                                        onClick={handleToggleStatus}
                                        className={`ml-2 px-3 py-1 rounded-lg text-xs font-bold transition-all flex items-center gap-1.5 shadow-sm border ${
                                            profile.isActive 
                                            ? 'bg-white text-red-600 border-red-200 hover:bg-red-50' 
                                            : 'bg-white text-emerald-600 border-emerald-200 hover:bg-emerald-50'
                                        }`}
                                    >
                                        {profile.isActive ? <UserMinus size={14} /> : <UserCheck size={14} />}
                                        {profile.isActive ? 'Deactivate User' : 'Activate User'}
                                    </button>
                                )}
                            </div>
                        </div>
                    </div>
                </div>

                {/* Navigation Tabs */}
                <div className="bg-white p-2 rounded-xl shadow-sm border border-slate-200 flex flex-nowrap overflow-x-auto hide-scrollbar gap-1">
                    <button
                        onClick={() => setActiveTab('overview')}
                        className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-semibold whitespace-nowrap transition-colors ${activeTab === 'overview' ? 'bg-blue-50 text-blue-700' : 'text-slate-600 hover:bg-slate-50 hover:text-slate-800'}`}
                    >
                        <User size={16} /> Overview
                    </button>

                    {isAuthorizedForEdit && (
                        <button
                            onClick={() => setActiveTab('edit')}
                            className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-semibold whitespace-nowrap transition-colors ${activeTab === 'edit' ? 'bg-blue-50 text-blue-700' : 'text-slate-600 hover:bg-slate-50 hover:text-slate-800'}`}
                        >
                            <Edit2 size={16} /> Edit Details
                        </button>
                    )}

                    {hasTimesheet && (
                        <button
                            onClick={() => setActiveTab('timesheet')}
                            className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-semibold whitespace-nowrap transition-colors ${activeTab === 'timesheet' ? 'bg-blue-50 text-blue-700' : 'text-slate-600 hover:bg-slate-50 hover:text-slate-800'}`}
                        >
                            <Clock size={16} /> Timesheet
                        </button>
                    )}

                    {hasAttendance && (
                        <button
                            onClick={() => setActiveTab('attendance')}
                            className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-semibold whitespace-nowrap transition-colors ${activeTab === 'attendance' ? 'bg-blue-50 text-blue-700' : 'text-slate-600 hover:bg-slate-50 hover:text-slate-800'}`}
                        >
                            <Clock size={16} /> Attendance
                        </button>
                    )}

                    {hasDossier && (
                        <button
                            onClick={() => setActiveTab('dossier')}
                            className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-semibold whitespace-nowrap transition-colors ${activeTab === 'dossier' ? 'bg-blue-50 text-blue-700' : 'text-slate-600 hover:bg-slate-50 hover:text-slate-800'}`}
                        >
                            <FileText size={16} /> Dossier
                        </button>
                    )}

                    {isAuthorizedForTA && (
                        <button
                            onClick={() => setActiveTab('ta-analytics')}
                            className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-semibold whitespace-nowrap transition-colors ${activeTab === 'ta-analytics' ? 'bg-purple-50 text-purple-700' : 'text-slate-600 hover:bg-slate-50 hover:text-slate-800'}`}
                        >
                            <Activity size={16} /> TA Analytics
                        </button>
                    )}
                </div>

                {/* Main Content Area */}
                <div className="w-full">

                    {/* OVERVIEW TAB */}
                    {activeTab === 'overview' && (
                        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                            {/* Basic Info Card */}
                            <div className="lg:col-span-2 space-y-6">
                                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                                    <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2 border-b border-slate-100 pb-3">
                                        <Briefcase size={18} className="text-blue-600" /> Work Information
                                    </h3>

                                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-y-6 gap-x-8">
                                        <div>
                                            <p className="text-[11px] font-bold text-slate-400 uppercase tracking-wider mb-1">Employee ID</p>
                                            <p className="text-[14px] font-semibold text-slate-800 flex items-center gap-2">
                                                <Hash size={16} className="text-slate-400" /> {profile.employeeCode || 'Not Assigned'}
                                            </p>
                                        </div>
                                        <div>
                                            <p className="text-[11px] font-bold text-slate-400 uppercase tracking-wider mb-1">Department</p>
                                            <p className="text-[14px] font-semibold text-slate-800 flex items-center gap-2">
                                                <Briefcase size={16} className="text-slate-400" /> {profile.department || 'N/A'}
                                            </p>
                                        </div>
                                        <div>
                                            <p className="text-[11px] font-bold text-slate-400 uppercase tracking-wider mb-1">Employment Type</p>
                                            <p className="text-[14px] font-semibold text-slate-800 flex items-center gap-2">
                                                <User size={16} className="text-slate-400" /> {profile.employmentType || 'Full Time'}
                                            </p>
                                        </div>
                                        <div>
                                            <p className="text-[11px] font-bold text-slate-400 uppercase tracking-wider mb-1">Work Location</p>
                                            <p className="text-[14px] font-semibold text-slate-800 flex items-center gap-2">
                                                <MapPin size={16} className="text-slate-400" /> {profile.workLocation || 'Headquarters'}
                                            </p>
                                        </div>
                                        <div>
                                            <p className="text-[11px] font-bold text-slate-400 uppercase tracking-wider mb-1">Date of Joining</p>
                                            <p className="text-[14px] font-semibold text-slate-800 flex items-center gap-2">
                                                <Calendar size={16} className="text-slate-400" />
                                                {profile.joiningDate ? format(new Date(profile.joiningDate), 'MMM dd, yyyy') : 'N/A'}
                                            </p>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            {/* Organization Card */}
                            <div className="space-y-6">
                                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                                    <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2 border-b border-slate-100 pb-3">
                                        <Users size={18} className="text-blue-600" /> Organization
                                    </h3>

                                    <div className="space-y-5">
                                        <div>
                                            <p className="text-[11px] font-bold text-slate-400 uppercase tracking-wider mb-2">Reporting Manager(s)</p>
                                            {profile.reportingManagers && profile.reportingManagers.length > 0 ? (
                                                <div className="space-y-2">
                                                    {profile.reportingManagers.map(manager => (
                                                        <div key={manager._id} className="flex items-center gap-3 p-2 rounded-lg bg-slate-50 border border-slate-100 cursor-pointer hover:bg-blue-50 transition-colors" onClick={() => navigate(`/users/${manager._id}`)}>
                                                            <div className="h-8 w-8 rounded-full bg-slate-200 text-slate-600 flex items-center justify-center font-bold text-xs shrink-0">
                                                                {manager.firstName.charAt(0)}
                                                            </div>
                                                            <div className="min-w-0">
                                                                <p className="text-sm font-semibold text-slate-800 truncate">{manager.firstName} {manager.lastName}</p>
                                                                <p className="text-[11px] text-slate-500 truncate">{manager.email}</p>
                                                            </div>
                                                        </div>
                                                    ))}
                                                </div>
                                            ) : (
                                                <p className="text-sm text-slate-500 italic">No reporting manager assigned.</p>
                                            )}
                                        </div>

                                        {profile.directReports && profile.directReports.length > 0 && (
                                            <div>
                                                <p className="text-[11px] font-bold text-slate-400 uppercase tracking-wider mb-2">Direct Reports ({profile.directReports.length})</p>
                                                <div className="space-y-2 max-h-48 overflow-y-auto pr-1 custom-scrollbar">
                                                    {profile.directReports.map(report => (
                                                        <div key={report._id} className="flex items-center gap-3 p-2 rounded-lg bg-slate-50 border border-slate-100 cursor-pointer hover:bg-blue-50 transition-colors" onClick={() => navigate(`/users/${report._id}`)}>
                                                            <div className="h-8 w-8 rounded-full bg-slate-200 text-slate-600 flex items-center justify-center font-bold text-xs shrink-0">
                                                                {report.firstName.charAt(0)}
                                                            </div>
                                                            <div className="min-w-0">
                                                                <p className="text-sm font-semibold text-slate-800 truncate">{report.firstName} {report.lastName}</p>
                                                                <p className="text-[11px] text-slate-500 truncate">{report.department || report.employeeCode || '-'}</p>
                                                            </div>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>

                        </div>
                    )}

                    {/* EDIT TAB */}
                    {activeTab === 'edit' && isAuthorizedForEdit && (
                        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 max-w-4xl mx-auto">
                            <div className="mb-6 border-b border-slate-100 pb-4">
                                <h3 className="text-lg font-bold text-slate-800">Edit Employee Details</h3>
                                <p className="text-sm text-slate-500">Update system records and access for this user.</p>
                            </div>

                            <form onSubmit={handleEditSubmit} className="space-y-6">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">First Name</label>
                                        <input name="firstName" required value={formData.firstName} onChange={handleFormChange} className="zoho-input" />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Last Name</label>
                                        <input name="lastName" value={formData.lastName} onChange={handleFormChange} className="zoho-input" />
                                    </div>
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Email</label>
                                        <input name="email" type="email" required value={formData.email} onChange={handleFormChange} className="zoho-input" />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Password (Leave blank to keep current)</label>
                                        <input name="password" type="password" onChange={handleFormChange} className="zoho-input" placeholder="••••••••" />
                                    </div>
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Employee Code</label>
                                        <input name="employeeCode" value={formData.employeeCode} onChange={handleFormChange} className="zoho-input" />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Date of Joining</label>
                                        <input name="joiningDate" type="date" value={formData.joiningDate} onChange={handleFormChange} className="zoho-input" />
                                    </div>
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Department</label>
                                        <input name="department" value={formData.department} onChange={handleFormChange} className="zoho-input" />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Work Location</label>
                                        <input name="workLocation" value={formData.workLocation} onChange={handleFormChange} className="zoho-input" placeholder="e.g. Remote, NY Office" />
                                    </div>
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Employment Type</label>
                                        <select name="employmentType" value={formData.employmentType} onChange={handleFormChange} className="zoho-input">
                                            <option value="Full Time">Full Time</option>
                                            <option value="Part Time">Part Time</option>
                                            <option value="Contract">Contract</option>
                                            <option value="Intern">Intern</option>
                                            <option value="Consultant">Consultant</option>
                                            <option value="Freelance">Freelance</option>
                                            <option value="Probation">Probation</option>
                                        </select>
                                    </div>
                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">System Role</label>
                                        <select name="roleId" required value={formData.roleId} onChange={handleFormChange} className="zoho-input">
                                            <option value="">Select Role</option>
                                            {roles.map(r => (
                                                <option key={r._id} value={r._id}>{r.name}</option>
                                            ))}
                                        </select>
                                    </div>
                                </div>

                                <div>
                                    <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Assign Subordinates (Users who report to this employee)</label>
                                    <div className="h-48 overflow-y-auto border border-slate-200 rounded-lg p-3 bg-slate-50 grid grid-cols-1 sm:grid-cols-2 gap-2 custom-scrollbar">
                                        {allUsers.filter(u => u._id !== profile._id).map(userAcc => (
                                            <label key={userAcc._id} className="flex items-start space-x-3 text-sm bg-white p-2.5 rounded hover:bg-blue-50 cursor-pointer border border-transparent hover:border-blue-100 transition-colors">
                                                <input
                                                    type="checkbox"
                                                    value={userAcc._id}
                                                    checked={formData.directReports?.includes(userAcc._id)}
                                                    onChange={(e) => {
                                                        const checked = e.target.checked;
                                                        const uId = userAcc._id;
                                                        setFormData(prev => {
                                                            const current = prev.directReports || [];
                                                            if (checked) return { ...prev, directReports: [...current, uId] };
                                                            return { ...prev, directReports: current.filter(x => x !== uId) };
                                                        });
                                                    }}
                                                    className="mt-1 rounded border-slate-300 text-blue-600 focus:ring-blue-500 cursor-pointer"
                                                />
                                                <div className="flex flex-col min-w-0">
                                                    <span className="font-semibold text-slate-700 truncate">{userAcc.firstName} {userAcc.lastName}</span>
                                                    <span className="text-[11px] text-slate-500 truncate">{userAcc.email}</span>
                                                </div>
                                            </label>
                                        ))}
                                    </div>
                                </div>

                                <div className="flex justify-end gap-3 pt-6 border-t border-slate-100">
                                    <button type="button" onClick={() => setActiveTab('overview')} className="zoho-btn-secondary px-6">Cancel</button>
                                    <button type="submit" className="zoho-btn-primary px-6">Save Changes</button>
                                </div>
                            </form>
                        </div>
                    )}

                    {/* TIMESHEET TAB */}
                    {activeTab === 'timesheet' && (
                        <div className="w-full">
                            <Timesheet
                                propUserId={profile._id}
                                propUserName={`${profile.firstName} ${profile.lastName}`}
                                initialTab="timesheet"
                                isEmbedded={true}
                            />
                        </div>
                    )}

                    {/* ATTENDANCE TAB */}
                    {activeTab === 'attendance' && (
                        <div className="w-full">
                            <Timesheet
                                propUserId={profile._id}
                                propUserName={`${profile.firstName} ${profile.lastName}`}
                                initialTab="attendance"
                                isEmbedded={true}
                            />
                        </div>
                    )}

                    {/* DOSSIER TAB */}
                    {activeTab === 'dossier' && (
                        <div className="w-full">
                            <EmployeeDossier userId={profile._id} embedded={true} />
                        </div>
                    )}

                    {/* TA ANALYTICS TAB */}
                    {activeTab === 'ta-analytics' && isAuthorizedForTA && (
                        <div className="w-full">
                            <UserTADashboard providedUserName={`${profile.firstName} ${profile.lastName}`} />
                        </div>
                    )}

                </div>
            </div>
        </div>
    );
};

export default EmployeeProfile;

import React, { useState, useEffect } from 'react';
import api from '../api/axios';
import { LifeBuoy, Plus, Clock, CheckCircle, AlertCircle, MessageSquare, X, AlertTriangle } from 'lucide-react';
import toast from 'react-hot-toast';
import Skeleton from '../components/Skeleton';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { format } from 'date-fns';
import { createCachePayload, isCacheFresh, readSessionCache } from '../utils/cache';
import HelpdeskWorkflows from './HelpdeskWorkflows';

const QueryFormModal = ({ isOpen, onClose, onSuccess }) => {
    const [queryTypes, setQueryTypes] = useState([]);
    const [formData, setFormData] = useState({ subject: '', description: '', queryTypeId: '', priority: 'Medium' });
    const [submitting, setSubmitting] = useState(false);

    useEffect(() => {
        if (isOpen) {
            fetchTypes();
            setFormData({ subject: '', description: '', queryTypeId: '', priority: 'Medium' });
        }
    }, [isOpen]);

    const fetchTypes = async () => {
        try {
            const res = await api.get('/helpdesk/types');
            setQueryTypes(res.data.data.filter(qt => qt.isActive));
        } catch (error) {
            toast.error('Failed to load query types');
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setSubmitting(true);
        try {
            await api.post('/helpdesk', formData);
            toast.success('Query submitted successfully');
            onSuccess();
            onClose();
        } catch (error) {
            toast.error(error.response?.data?.message || 'Failed to submit query');
        } finally {
            setSubmitting(false);
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                <div className="flex justify-between items-center p-5 border-b border-slate-100">
                    <h2 className="text-xl font-bold flex items-center text-slate-800">
                        <LifeBuoy className="mr-2 text-indigo-600" size={20} />
                        Raise a Query
                    </h2>
                    <button onClick={onClose} className="text-slate-400 hover:text-slate-600 transition-colors">
                        <X size={20} />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="p-5 space-y-4">
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1.5">Query Type</label>
                        <select
                            required
                            value={formData.queryTypeId}
                            onChange={e => setFormData({ ...formData, queryTypeId: e.target.value })}
                            className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all bg-white"
                        >
                            <option value="">Select Type...</option>
                            {queryTypes.map(qt => (
                                <option key={qt._id} value={qt._id}>{qt.name}</option>
                            ))}
                        </select>
                        {formData.queryTypeId && (
                            <div className="mt-2 p-2 bg-indigo-50 border border-indigo-100 rounded-lg animate-in fade-in duration-300">
                                <p className="text-[11px] font-bold text-slate-500 uppercase tracking-wider mb-0.5">Assigned Responsible Person</p>
                                <p className="text-sm font-semibold text-indigo-700">
                                    {queryTypes.find(qt => qt._id === formData.queryTypeId)?.assignedPerson?.firstName} {queryTypes.find(qt => qt._id === formData.queryTypeId)?.assignedPerson?.lastName}
                                </p>
                            </div>
                        )}
                    </div>

                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1.5">Priority</label>
                        <select
                            value={formData.priority}
                            onChange={e => setFormData({ ...formData, priority: e.target.value })}
                            className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all bg-white"
                        >
                            <option value="Low">Low</option>
                            <option value="Medium">Medium</option>
                            <option value="High">High</option>
                            <option value="Urgent">Urgent</option>
                        </select>
                    </div>

                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1.5">Subject</label>
                        <input
                            required
                            type="text"
                            value={formData.subject}
                            onChange={e => setFormData({ ...formData, subject: e.target.value })}
                            className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                            placeholder="Brief summary of the issue"
                        />
                    </div>

                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1.5">Description</label>
                        <textarea
                            required
                            rows={4}
                            value={formData.description}
                            onChange={e => setFormData({ ...formData, description: e.target.value })}
                            className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all resize-none"
                            placeholder="Detailed explanation of your query..."
                        />
                    </div>

                    <div className="flex justify-end pt-4 gap-3">
                        <button type="button" onClick={onClose} className="px-5 py-2 text-sm font-medium text-slate-600 bg-slate-100 hover:bg-slate-200 rounded-lg transition-colors">
                            Cancel
                        </button>
                        <button type="submit" disabled={submitting} className="px-5 py-2 text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 rounded-lg transition-colors disabled:opacity-50 flex items-center">
                            {submitting ? 'Submitting...' : 'Submit Query'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

const HelpDesk = () => {
    const { user } = useAuth();
    const navigate = useNavigate();

    const [queries, setQueries] = useState([]);
    const [assignedQueries, setAssignedQueries] = useState([]);
    const [allQueries, setAllQueries] = useState([]);
    const [escalatedQueries, setEscalatedQueries] = useState([]);
    const [tabLoading, setTabLoading] = useState(false);
    const [activeTab, setActiveTab] = useState('my-queries');
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [showAllQueries, setShowAllQueries] = useState(false);

    const [filters, setFilters] = useState({ status: '', priority: '' });
    const initialBootstrapDoneRef = React.useRef(false);
    const HELPDESK_CACHE_TTL_MS = 20 * 1000;

    const isAdmin = user?.roles?.some(r => ['Admin', 'System'].includes(r.name || r) || r?.isSystem === true);
    const isResolverRole = user?.roles?.some(r => ['HR', 'Supervisor', 'Admin', 'System'].includes(r.name || r));

    // Debugging: Log admin status on load
    React.useEffect(() => {
        if (user) {
            console.log('HelpDesk Admin Status:', isAdmin);
            console.log('HelpDesk Roles:', user.roles);
        }
    }, [user, isAdmin]);

    // Track which tabs have already been fetched to avoid redundant API calls
    const loadedTabs = React.useRef(new Set());

    const getCacheFieldForTab = (tab) =>
        tab === 'my-queries' ? 'myQueries' : tab === 'assigned' ? 'assignedQueries' : 'escalatedQueries';

    const fetchTabData = async (tab, force = false, isBackground = false) => {
        if (!force && !isBackground && loadedTabs.current.has(tab)) return; 
        
        const CACHE_KEY = `helpdesk_data_${user?._id}_admin_${isAdmin}`;

        // Helper: Generate fingerprint for change detection
        const buildFingerprint = (data) => {
            const items = data?.data || data;
            if (!Array.isArray(items)) return '';
            return items.map(q => `${q._id}-${q.status}-${q.priority}-${q.commentsCount || q.comments?.length || 0}`).join('|');
        };

        // 1. Initial Load from Cache
        if (!isBackground && !force) {
            const parsed = readSessionCache(CACHE_KEY);
            if (parsed) {
                const data = parsed.data || parsed;
                if (tab === 'my-queries' && data.myQueries) setQueries(data.myQueries);
                if (tab === 'assigned') {
                    if (data.assignedQueries) setAssignedQueries(data.assignedQueries);
                    if (data.allQueries) setAllQueries(data.allQueries);
                }
                if (tab === 'escalated' && data.escalatedQueries) setEscalatedQueries(data.escalatedQueries);
                if (data[getCacheFieldForTab(tab)]) {
                    setTabLoading(false);
                    if (isCacheFresh(parsed, HELPDESK_CACHE_TTL_MS)) {
                        loadedTabs.current.add(tab);
                        return;
                    }
                }
            }
        }

        try {
            if (!isBackground && !readSessionCache(CACHE_KEY)) setTabLoading(true);

            let freshData = null;
            let freshAllData = null;

            if (tab === 'my-queries') {
                const res = await api.get('/helpdesk/my-queries');
                freshData = res.data.data || res.data;
            } else if (tab === 'assigned') {
                const [assignedRes, allRes] = await Promise.all([
                    api.get('/helpdesk/assigned'),
                    isAdmin ? api.get('/helpdesk/all') : Promise.resolve({ data: { data: [] } }),
                ]);
                freshData = assignedRes.data.data || assignedRes.data;
                freshAllData = allRes.data.data || allRes.data;
            } else if (tab === 'escalated' && isAdmin) {
                const res = await api.get('/helpdesk/escalated');
                freshData = res.data.data || res.data;
            }

            // 2. Update status and cache if changed
            if (freshData) {
                const cachedData = readSessionCache(CACHE_KEY) || {};
                const currentData = cachedData.data || cachedData;
                const cacheField = getCacheFieldForTab(tab);
                
                const oldFingerprint = buildFingerprint(currentData[cacheField] || []);
                const newFingerprint = buildFingerprint(freshData);

                let changed = newFingerprint !== oldFingerprint || force;
                
                if (tab === 'assigned' && freshAllData) {
                    const oldAllFingerprint = buildFingerprint(currentData['allQueries'] || []);
                    const newAllFingerprint = buildFingerprint(freshAllData);
                    if (oldAllFingerprint !== newAllFingerprint) changed = true;
                }

                if (changed) {
                    if (tab === 'my-queries') setQueries(freshData);
                    else if (tab === 'assigned') {
                        setAssignedQueries(freshData);
                        if (freshAllData) setAllQueries(freshAllData);
                    } else if (tab === 'escalated') setEscalatedQueries(freshData);

                    // Minimalize and Sync
                    const minimal = (items) => (items || []).map(q => ({
                        _id: q._id,
                        queryId: q.queryId,
                        subject: q.subject,
                        status: q.status,
                        priority: q.priority,
                        queryType: q.queryType ? { _id: q.queryType._id, name: q.queryType.name } : null,
                        raisedBy: q.raisedBy ? { _id: q.raisedBy._id, firstName: q.raisedBy.firstName, lastName: q.raisedBy.lastName } : null,
                        createdAt: q.createdAt,
                        closedAt: q.closedAt,
                        commentsCount: q.comments?.length || q.commentsCount || 0
                    }));

                    const nextData = { ...currentData };
                    nextData[cacheField] = minimal(freshData);
                    if (tab === 'assigned' && freshAllData) nextData['allQueries'] = minimal(freshAllData);

                    const fp = [
                        buildFingerprint(nextData.myQueries),
                        buildFingerprint(nextData.assignedQueries),
                        buildFingerprint(nextData.allQueries),
                        buildFingerprint(nextData.escalatedQueries)
                    ].join('##');

                    sessionStorage.setItem(CACHE_KEY, JSON.stringify(createCachePayload(nextData, fp)));
                }
            }

            loadedTabs.current.add(tab);
        } catch (error) {
            console.error(error);
            if (!isBackground) toast.error('Failed to load helpdesk queries');
        } finally {
            setTabLoading(false);
        }
    };

    const fetchBootstrap = async (force = false) => {
        const CACHE_KEY = `helpdesk_data_${user?._id}_admin_${isAdmin}`;
        const cached = readSessionCache(CACHE_KEY);

        if (!force && cached) {
            const data = cached.data || cached;
            setQueries(data.myQueries || []);
            setAssignedQueries(data.assignedQueries || []);
            setAllQueries(data.allQueries || []);
            setEscalatedQueries(data.escalatedQueries || []);
            setTabLoading(false);
            loadedTabs.current = new Set(['my-queries', ...(isResolverRole ? ['assigned'] : []), ...(isAdmin ? ['escalated'] : [])]);

            if (isCacheFresh(cached, HELPDESK_CACHE_TTL_MS)) {
                return;
            }
        }

        try {
            if (!cached) setTabLoading(true);
            const res = await api.get('/helpdesk/bootstrap');
            const payload = {
                myQueries: res.data.myQueries || [],
                assignedQueries: res.data.assignedQueries || [],
                allQueries: res.data.allQueries || [],
                escalatedQueries: res.data.escalatedQueries || []
            };

            setQueries(payload.myQueries);
            setAssignedQueries(payload.assignedQueries);
            setAllQueries(payload.allQueries);
            setEscalatedQueries(payload.escalatedQueries);

            const minimal = (items) => (items || []).map(q => ({
                _id: q._id,
                queryId: q.queryId,
                subject: q.subject,
                status: q.status,
                priority: q.priority,
                queryType: q.queryType ? { _id: q.queryType._id, name: q.queryType.name } : null,
                raisedBy: q.raisedBy ? { _id: q.raisedBy._id, firstName: q.raisedBy.firstName, lastName: q.raisedBy.lastName } : null,
                createdAt: q.createdAt,
                closedAt: q.closedAt,
                commentsCount: q.comments?.length || q.commentsCount || 0
            }));

            const nextData = {
                myQueries: minimal(payload.myQueries),
                assignedQueries: minimal(payload.assignedQueries),
                allQueries: minimal(payload.allQueries),
                escalatedQueries: minimal(payload.escalatedQueries)
            };
            const fp = [
                nextData.myQueries.map(q => `${q._id}-${q.status}-${q.priority}-${q.commentsCount}`).join('|'),
                nextData.assignedQueries.map(q => `${q._id}-${q.status}-${q.priority}-${q.commentsCount}`).join('|'),
                nextData.allQueries.map(q => `${q._id}-${q.status}-${q.priority}-${q.commentsCount}`).join('|'),
                nextData.escalatedQueries.map(q => `${q._id}-${q.status}-${q.priority}-${q.commentsCount}`).join('|')
            ].join('##');

            sessionStorage.setItem(CACHE_KEY, JSON.stringify(createCachePayload(nextData, fp)));
            loadedTabs.current = new Set(['my-queries', ...(isResolverRole ? ['assigned'] : []), ...(isAdmin ? ['escalated'] : [])]);
        } catch (error) {
            console.error(error);
            toast.error('Failed to load helpdesk queries');
        } finally {
            setTabLoading(false);
        }
    };

    // Refresh only the currently active tab (called after raising a new query)
    const refreshTab = () => {
        loadedTabs.current.delete(activeTab);
        if (activeTab === 'my-queries' || activeTab === 'assigned' || activeTab === 'escalated') {
            fetchBootstrap(true);
            return;
        }
        fetchTabData(activeTab, true);
    };

    // Initial fetch on mount
    useEffect(() => {
        if (initialBootstrapDoneRef.current) return;
        initialBootstrapDoneRef.current = true;
        fetchBootstrap();
    }, [isResolverRole]);

    // Fetch data whenever the active tab changes (for tabs not fetched on mount)
    useEffect(() => {
        const alreadyFetched =
            activeTab === 'my-queries' ||
            (activeTab === 'assigned' && isResolverRole) ||
            (activeTab === 'escalated' && isAdmin);
        if (!alreadyFetched) {
            fetchTabData(activeTab);
        }
    }, [activeTab, isResolverRole]);

    const getStatusBadge = (status) => {
        const lowerS = status?.toLowerCase() || '';
        let style = 'bg-slate-100 text-slate-600 border border-slate-200';

        if (lowerS === 'new') style = 'bg-amber-100 text-amber-700 border border-amber-200';
        else if (lowerS === 'in progress') style = 'bg-blue-100 text-blue-700 border border-blue-200';
        else if (lowerS === 'pending') style = 'bg-purple-100 text-purple-700 border border-purple-200';
        else if (lowerS === 'escalated') style = 'bg-red-100 text-red-700 border border-red-200 animate-pulse';
        else if (lowerS === 'closed') style = 'bg-emerald-100 text-emerald-700 border border-emerald-200';

        return <span className={`px-2.5 py-1 text-[11px] font-bold uppercase rounded-full tracking-wider ${style}`}>{status}</span>;
    };

    const getPriorityIcon = (priority) => {
        switch (priority) {
            case 'Urgent': return <AlertCircle size={14} className="text-red-500" />;
            case 'High': return <AlertCircle size={14} className="text-orange-500" />;
            case 'Low': return <Clock size={14} className="text-slate-400" />;
            default: return <CheckCircle size={14} className="text-blue-500" />;
        }
    };

    const renderTable = (data, isAssignedView = false) => {
        const loadingSpinner = (
            <div className="flex flex-col items-center justify-center gap-3 py-16">
                <div className="w-8 h-8 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin" />
                <p className="text-sm text-slate-400 font-medium">Loading queries...</p>
            </div>
        );
        const emptyState = (
            <div className="flex flex-col items-center justify-center py-12 text-slate-400">
                <LifeBuoy size={48} className="text-slate-200 mb-4" />
                <p className="text-base font-medium text-slate-600">No queries found</p>
                <p className="text-sm mt-1">You're all caught up!</p>
            </div>
        );
        return (
            <div className="mt-4">
                {/* ── Mobile card list (hidden on md+) ── */}
                <div className="md:hidden space-y-3">
                    {tabLoading ? loadingSpinner : data.length === 0 ? emptyState : data.map(query => (
                        <div key={query._id} className="bg-white rounded-xl border border-slate-200 shadow-sm p-4 space-y-3">
                            <div className="flex items-start justify-between gap-2">
                                <div className="flex-1 min-w-0">
                                    <div className="font-semibold text-slate-800 text-sm truncate flex items-center gap-1">
                                        {query.status === 'Escalated' && <AlertTriangle size={14} className="text-red-500 fill-red-50" />}
                                        {query.subject}
                                    </div>
                                    <div className="text-xs text-indigo-500 font-medium mt-0.5">{query.queryId}</div>
                                </div>
                                {getStatusBadge(query.status)}
                            </div>
                            <div className="flex flex-wrap gap-2 text-xs">
                                <span className="inline-flex items-center px-2 py-1 rounded bg-slate-100 text-slate-600 font-medium">{query.queryType?.name || 'Unknown'}</span>
                                <span className="inline-flex items-center gap-1 px-2 py-1 rounded bg-slate-100 text-slate-600 font-medium">{getPriorityIcon(query.priority)}{query.priority}</span>
                                {isAssignedView && query.raisedBy && (
                                    <span className="inline-flex items-center px-2 py-1 rounded bg-indigo-50 text-indigo-600 font-medium">{query.raisedBy.firstName} {query.raisedBy.lastName}</span>
                                )}
                            </div>
                            <div className="flex items-center justify-between pt-1">
                                <div className="text-xs text-slate-400">
                                    <span className="font-semibold text-slate-500">Opened: </span>{format(new Date(query.createdAt), 'MMM dd, yy')}
                                    {query.closedAt && <span className="ml-2 text-emerald-600"><span className="font-semibold">Closed: </span>{format(new Date(query.closedAt), 'MMM dd, yy')}</span>}
                                </div>
                                <button
                                    onClick={() => navigate(`/helpdesk/${query._id}`)}
                                    className="inline-flex items-center px-3 py-1.5 border border-slate-300 text-xs font-semibold rounded-lg text-slate-700 bg-white hover:bg-slate-50 hover:text-indigo-600 hover:border-indigo-300 transition-all"
                                >
                                    View
                                </button>
                            </div>
                        </div>
                    ))}
                </div>

                {/* ── Desktop table (hidden below md) ── */}
                <div className="hidden md:block bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                    <div className="overflow-x-auto">
                        <table className="w-full text-sm text-left">
                            <thead className="bg-slate-50 border-b border-slate-200 text-slate-500 font-semibold uppercase text-xs tracking-wider">
                                <tr>
                                    <th className="px-6 py-4">Query ID</th>
                                    <th className="px-6 py-4">Subject</th>
                                    <th className="px-6 py-4">Type</th>
                                    {isAssignedView && <th className="px-6 py-4">Raised By</th>}
                                    <th className="px-6 py-4">Priority</th>
                                    <th className="px-6 py-4 text-center">Status</th>
                                    <th className="px-6 py-4 text-center">Dates</th>
                                    <th className="px-6 py-4 text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100">
                                {tabLoading ? (
                                    <tr><td colSpan={isAssignedView ? '8' : '7'} className="py-16">
                                        <div className="flex flex-col items-center justify-center gap-3">
                                            <div className="w-8 h-8 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin" />
                                            <p className="text-sm text-slate-400 font-medium">Loading queries...</p>
                                        </div>
                                    </td></tr>
                                ) : data.length === 0 ? (
                                    <tr><td colSpan={isAssignedView ? '8' : '7'} className="px-6 py-12 text-center text-slate-400">
                                        <div className="flex flex-col items-center justify-center">
                                            <LifeBuoy size={48} className="text-slate-200 mb-4" />
                                            <p className="text-base font-medium text-slate-600">No queries found</p>
                                            <p className="text-sm mt-1">You're all caught up!</p>
                                        </div>
                                    </td></tr>
                                ) : data.map(query => (
                                    <tr key={query._id} className="hover:bg-slate-50 transition border-b border-slate-50">
                                        <td className="px-6 py-4 font-medium text-indigo-600">{query.queryId}</td>
                                        <td className="px-6 py-4">
                                            <div className="font-semibold text-slate-800 flex items-center gap-1.5 cursor-pointer hover:text-indigo-600 transition-colors" onClick={() => navigate(`/helpdesk/${query._id}`)}>
                                                {query.status === 'Escalated' && <AlertTriangle size={14} className="text-red-500 fill-red-50" />}
                                                {query.subject}
                                            </div>
                                            <div className="text-xs text-slate-500 mt-1 flex items-center">
                                                <MessageSquare size={12} className="mr-1" /> {query.commentsCount || query.comments?.length || 0} comments
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <span className="inline-flex items-center px-2 py-1 rounded bg-slate-100 text-slate-600 text-xs font-medium">{query.queryType?.name || 'Unknown'}</span>
                                        </td>
                                        {isAssignedView && (
                                            <td className="px-6 py-4 text-slate-600 font-medium text-xs">{query.raisedBy?.firstName} {query.raisedBy?.lastName}</td>
                                        )}
                                        <td className="px-6 py-4">
                                            <div className="flex items-center space-x-1.5 font-medium text-slate-700">
                                                {getPriorityIcon(query.priority)}<span>{query.priority}</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-center">{getStatusBadge(query.status)}</td>
                                        <td className="px-6 py-4 text-slate-600 text-xs text-center border-l bg-slate-50/30">
                                            <div className="flex flex-col gap-1 items-center justify-center">
                                                <div className="font-semibold text-slate-700 whitespace-nowrap">
                                                    <span className="text-[10px] uppercase text-slate-400 font-bold block mb-0.5">Opened</span>
                                                    {format(new Date(query.createdAt), 'MMM dd, yy')}
                                                </div>
                                                {query.closedAt && (
                                                    <div className="font-semibold text-emerald-600 whitespace-nowrap mt-1 pt-1 border-t border-slate-200">
                                                        <span className="text-[10px] uppercase text-emerald-600/70 font-bold block mb-0.5">Closed</span>
                                                        {format(new Date(query.closedAt), 'MMM dd, yy')}
                                                    </div>
                                                )}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            <button
                                                onClick={() => navigate(`/helpdesk/${query._id}`)}
                                                className="inline-flex items-center justify-center px-4 py-2 border border-slate-300 text-xs font-semibold rounded-lg text-slate-700 bg-white hover:bg-slate-50 hover:text-indigo-600 hover:border-indigo-300 transition-all shadow-sm"
                                            >
                                                View Details
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>
        );
    };

    if (false) return (
        <div className="min-h-screen bg-slate-50 p-6 md:p-10">
            <div className="max-w-6xl mx-auto space-y-6">
                <Skeleton className="h-8 w-48 mb-2" />
                <Skeleton className="h-64 w-full rounded-xl" />
            </div>
        </div>
    );

    return (
        <div className="min-h-screen bg-slate-50 font-sans p-4 sm:p-6 md:p-10">
            <div className="max-w-6xl mx-auto space-y-4 sm:space-y-6">

                {/* Header */}
                <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-3 mb-4 sm:mb-6">
                    <div>
                        <h1 className="text-2xl sm:text-3xl font-extrabold text-slate-900 tracking-tight flex items-center">
                            <LifeBuoy className="mr-2 sm:mr-3 text-indigo-600" size={28} /> Help Desk
                        </h1>
                        <p className="text-xs sm:text-sm text-slate-500 mt-1">Raise support tickets, track resolutions, and get help quickly.</p>
                    </div>
                    <button
                        onClick={() => setIsModalOpen(true)}
                        className="flex items-center justify-center space-x-2 bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2.5 sm:px-5 rounded-xl font-semibold shadow-md shadow-indigo-600/20 transition-all hover:-translate-y-0.5 w-full sm:w-auto"
                    >
                        <Plus size={18} />
                        <span>Raise Query</span>
                    </button>
                </div>

                {/* Tabs */}
                <div className="overflow-x-auto pb-1 mb-4 sm:mb-6">
                    <div className="flex space-x-1 bg-slate-200/50 p-1 rounded-xl w-max">
                        <button
                            onClick={() => setActiveTab('my-queries')}
                            className={`px-5 py-2 rounded-lg text-sm font-semibold transition-all ${activeTab === 'my-queries' ? 'bg-white text-indigo-700 shadow-sm' : 'text-slate-600 hover:text-slate-900'}`}
                        >
                            My Queries
                        </button>
                        {(isResolverRole || assignedQueries.length > 0) && (
                            <button
                                onClick={() => setActiveTab('assigned')}
                                className={`px-5 py-2 rounded-lg text-sm font-semibold transition-all ${activeTab === 'assigned' ? 'bg-white text-indigo-700 shadow-sm' : 'text-slate-600 hover:text-slate-900'}`}
                            >
                                <span className="flex items-center">
                                    {isAdmin ? 'Queries' : 'Assigned to Me'}
                                    {assignedQueries.filter(q => q.status === 'New' || q.status === 'In Progress').length > 0 && (
                                        <span className="ml-2 bg-indigo-500 text-white text-[10px] px-1.5 py-0.5 rounded-full">
                                            {assignedQueries.filter(q => q.status === 'New' || q.status === 'In Progress').length}
                                        </span>
                                    )}
                                </span>
                            </button>
                        )}
                        {isAdmin && (
                            <>
                                <button
                                    onClick={() => setActiveTab('escalated')}
                                    className={`px-5 py-2 rounded-lg text-sm font-semibold transition-all ${activeTab === 'escalated' ? 'bg-white text-indigo-700 shadow-sm' : 'text-slate-600 hover:text-slate-900'}`}
                                >
                                    <span className="flex items-center">
                                        <AlertTriangle size={14} className="mr-1.5 text-red-500" />
                                        Escalated
                                        {escalatedQueries.length > 0 && (
                                            <span className="ml-2 bg-red-500 text-white text-[10px] px-1.5 py-0.5 rounded-full animate-pulse">
                                                {escalatedQueries.length}
                                            </span>
                                        )}
                                    </span>
                                </button>
                                <button
                                    onClick={() => setActiveTab('workflows')}
                                    className={`px-5 py-2 rounded-lg text-sm font-semibold transition-all ${activeTab === 'workflows' ? 'bg-white text-indigo-700 shadow-sm' : 'text-slate-600 hover:text-slate-900'}`}
                                >
                                    Manage Workflows
                                </button>
                            </>
                        )}
                    </div>
                </div>

                {/* Content */}
                {activeTab === 'my-queries' && renderTable(queries, false)}
                {activeTab === 'assigned' && (
                    <div className="space-y-4">
                        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                            <div className="flex flex-wrap items-center gap-2">
                                <select 
                                    value={filters.status}
                                    onChange={(e) => setFilters({...filters, status: e.target.value})}
                                    className="px-3 py-1.5 border border-slate-300 rounded-lg text-xs font-semibold focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
                                >
                                    <option value="">All Statuses</option>
                                    <option value="New">New</option>
                                    <option value="In Progress">In Progress</option>
                                    <option value="Pending">Pending</option>
                                    <option value="Escalated">Escalated</option>
                                    <option value="Closed">Closed</option>
                                </select>
                                <select 
                                    value={filters.priority}
                                    onChange={(e) => setFilters({...filters, priority: e.target.value})}
                                    className="px-3 py-1.5 border border-slate-300 rounded-lg text-xs font-semibold focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
                                >
                                    <option value="">All Priorities</option>
                                    <option value="Urgent">Urgent</option>
                                    <option value="High">High</option>
                                    <option value="Medium">Medium</option>
                                    <option value="Low">Low</option>
                                </select>
                            </div>

                            {isAdmin && (
                                <div className="bg-slate-200/50 p-1 rounded-lg inline-flex items-center">
                                    <button
                                        onClick={() => setShowAllQueries(false)}
                                        className={`px-3 py-1.5 rounded-md text-xs font-semibold transition-all ${!showAllQueries ? 'bg-white text-indigo-700 shadow-sm' : 'text-slate-600 hover:text-slate-900'}`}
                                    >
                                        Assigned to Me
                                    </button>
                                    <button
                                        onClick={() => setShowAllQueries(true)}
                                        className={`px-3 py-1.5 rounded-md text-xs font-semibold transition-all ${showAllQueries ? 'bg-white text-indigo-700 shadow-sm' : 'text-slate-600 hover:text-slate-900'}`}
                                    >
                                        All Queries
                                    </button>
                                </div>
                            )}
                        </div>
                        {renderTable((showAllQueries ? allQueries : assignedQueries).filter(q => {
                            if (filters.status && q.status !== filters.status) return false;
                            if (filters.priority && q.priority !== filters.priority) return false;
                            return true;
                        }), true)}
                    </div>
                )}
                {activeTab === 'escalated' && renderTable(escalatedQueries, true)}
                {activeTab === 'workflows' && isAdmin && <HelpdeskWorkflows />}

            </div>

            <QueryFormModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSuccess={refreshTab} />
        </div>
    );
};

export default HelpDesk;

import React, { useState, useEffect } from 'react';
import api from '../api/axios';
import { Plus, Trash2, Save, X, AlertCircle } from 'lucide-react';
import toast from 'react-hot-toast';

const HelpdeskWorkflows = () => {
    const [queryTypes, setQueryTypes] = useState([]);
    const [users, setUsers] = useState([]);
    const [roles, setRoles] = useState([]);
    const [loading, setLoading] = useState(true);

    // Editor State
    const [editingId, setEditingId] = useState(null); // 'new' or ID
    const [formData, setFormData] = useState({
        name: '', assignedRole: '', assignedPerson: '',
        enableEscalation: false, escalationDays: 2, escalationRole: '', escalationPerson: ''
    });

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        try {
            setLoading(true);
            const [typesRes, usersRes, rolesRes] = await Promise.all([
                api.get('/helpdesk/types'),
                api.get('/admin/users'), // assuming this endpoint gets all users
                api.get('/admin/roles')
            ]);
            setQueryTypes(typesRes.data.data);
            setUsers(usersRes.data);
            setRoles(rolesRes.data);
        } catch (error) {
            console.error('Failed to fetch data', error);
            toast.error('Failed to load configuration data');
        } finally {
            setLoading(false);
        }
    };

    const handleConfigure = (type = null) => {
        if (type) {
            setEditingId(type._id);
            setFormData({
                name: type.name,
                assignedRole: type.assignedRole?._id || '',
                assignedPerson: type.assignedPerson?._id || '',
                enableEscalation: type.enableEscalation || false,
                escalationDays: type.escalationDays || 2,
                escalationRole: type.escalationRole?._id || '',
                escalationPerson: type.escalationPerson?._id || ''
            });
        } else {
            setEditingId('new');
            setFormData({
                name: '', assignedRole: '', assignedPerson: '',
                enableEscalation: false, escalationDays: 2, escalationRole: '', escalationPerson: ''
            });
        }
    };

    const handleCancel = () => {
        setEditingId(null);
        setFormData({
            name: '', assignedRole: '', assignedPerson: '',
            enableEscalation: false, escalationDays: 2, escalationRole: '', escalationPerson: ''
        });
    };

    const handleSave = async () => {
        if (!formData.name.trim()) return toast.error('Name is required');
        if (!formData.assignedPerson) return toast.error('Assigned Responsible Person is required');

        try {
            if (editingId === 'new') {
                await api.post('/helpdesk/types', formData);
                toast.success('Query Type created');
            } else {
                await api.put(`/helpdesk/types/${editingId}`, formData);
                toast.success('Query Type updated');
            }
            handleCancel();
            fetchData();
        } catch (error) {
            toast.error(error.response?.data?.message || 'Failed to save Query Type');
        }
    };

    const handleDelete = async (id) => {
        if (!window.confirm('Are you sure you want to delete this Query Type? Users will no longer be able to select it.')) return;
        try {
            await api.delete(`/helpdesk/types/${id}`);
            toast.success('Query Type deleted');
            fetchData();
        } catch (error) {
            toast.error('Failed to delete Query Type');
        }
    };

    if (loading) return <div className="p-6 text-slate-500 font-medium">Loading configuration...</div>;

    return (
        <div className="space-y-4">
            <div className="flex justify-between items-start">
                <div className="bg-indigo-50 border border-indigo-100 p-3 rounded-lg flex items-start text-indigo-800 text-xs flex-1 mr-4">
                    <AlertCircle size={16} className="mr-2 text-indigo-500 shrink-0 mt-0.5" />
                    <p>
                        Map Query Types to a single responsible person. When a ticket matching this type is raised, it is assigned directly to the chosen User.
                    </p>
                </div>
                {!editingId && (
                    <button
                        onClick={() => handleConfigure()}
                        className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg flex items-center gap-1.5 text-xs font-semibold shadow-sm transition-all shrink-0"
                    >
                        <Plus size={14} /> Add Query Type
                    </button>
                )}
            </div>

            {editingId ? (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-5 shadow-indigo-100/40">
                    <div className="flex justify-between items-center mb-5 pb-3 border-b border-slate-100">
                        <h3 className="text-lg font-bold text-slate-800 tracking-tight flex items-center">
                            {editingId === 'new' ? 'Create Query Type' : 'Edit Query Type'}
                        </h3>
                        <button onClick={handleCancel} className="text-slate-400 hover:text-slate-600 transition-colors">
                            <X size={18} />
                        </button>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Query Type Name</label>
                            <input
                                type="text"
                                value={formData.name}
                                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:border-indigo-500 outline-none font-medium text-slate-700"
                                placeholder="e.g., Payroll Setup"
                            />
                        </div>

                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Assigned Role</label>
                            <select
                                value={formData.assignedRole}
                                onChange={(e) => {
                                    setFormData({ ...formData, assignedRole: e.target.value, assignedPerson: '' });
                                }}
                                className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:border-indigo-500 outline-none font-medium text-slate-700 bg-white"
                            >
                                <option value="">Select Role (Optional)</option>
                                {roles.map(r => (
                                    <option key={r._id} value={r._id}>{r.name}</option>
                                ))}
                            </select>
                        </div>

                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Assigned Responsible Person</label>
                            <select
                                value={formData.assignedPerson}
                                onChange={(e) => setFormData({ ...formData, assignedPerson: e.target.value })}
                                className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:border-indigo-500 outline-none font-medium text-slate-700 bg-white disabled:opacity-50 disabled:bg-slate-50"
                                disabled={!formData.assignedRole && false /* could be optional */}
                            >
                                <option value="">Select User</option>
                                {users
                                    .filter(u => !formData.assignedRole || u.roles.some(r => (r._id || r) === formData.assignedRole))
                                    .map(u => (
                                        <option key={u._id} value={u._id}>{u.firstName} {u.lastName} ({u.email})</option>
                                    ))
                                }
                            </select>
                        </div>
                    </div>

                    {/* Escalation Workflow Settings */}
                    <div className="border border-slate-200 rounded-xl p-4 bg-slate-50/50">
                        <div className="flex items-center space-x-3 mb-4">
                            <label className="flex items-center space-x-2 cursor-pointer">
                                <input
                                    type="checkbox"
                                    checked={formData.enableEscalation}
                                    onChange={(e) => setFormData({ ...formData, enableEscalation: e.target.checked })}
                                    className="rounded border-slate-300 text-indigo-600 focus:ring-indigo-500 w-4 h-4"
                                />
                                <span className="text-sm font-bold text-slate-700">Enable Escalation Workflow</span>
                            </label>
                            {formData.enableEscalation && (
                                <span className="text-xs text-slate-500 bg-white border border-slate-200 px-2 py-1 rounded-md shadow-sm">
                                    If unresolved after <strong className="text-indigo-600">{formData.escalationDays} days</strong>, re-assign ticket automatically.
                                </span>
                            )}
                        </div>

                        {formData.enableEscalation && (
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 pt-2 border-t border-slate-200 animate-in fade-in slide-in-from-top-2">
                                <div>
                                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Escalation Time (Days)</label>
                                    <input
                                        type="number"
                                        min="1"
                                        max="30"
                                        value={formData.escalationDays}
                                        onChange={(e) => setFormData({ ...formData, escalationDays: Number(e.target.value) })}
                                        className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:border-indigo-500 outline-none font-medium text-slate-700"
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Escalate To Role</label>
                                    <select
                                        value={formData.escalationRole}
                                        onChange={(e) => {
                                            setFormData({ ...formData, escalationRole: e.target.value, escalationPerson: '' });
                                        }}
                                        className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:border-indigo-500 outline-none font-medium text-slate-700 bg-white"
                                    >
                                        <option value="">Select Role (Optional)</option>
                                        {roles.map(r => (
                                            <option key={r._id} value={r._id}>{r.name}</option>
                                        ))}
                                    </select>
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Escalate To Person</label>
                                    <select
                                        value={formData.escalationPerson}
                                        onChange={(e) => setFormData({ ...formData, escalationPerson: e.target.value })}
                                        className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:border-indigo-500 outline-none font-medium text-slate-700 bg-white disabled:opacity-50 disabled:bg-slate-50"
                                    >
                                        <option value="">Select User</option>
                                        {users
                                            .filter(u => !formData.escalationRole || u.roles.some(r => (r._id || r) === formData.escalationRole))
                                            .map(u => (
                                                <option key={u._id} value={u._id}>{u.firstName} {u.lastName} ({u.email})</option>
                                            ))
                                        }
                                    </select>
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="flex justify-end pt-5 mt-5 border-t border-slate-100 gap-2">
                        <button onClick={handleCancel} className="px-4 py-2 rounded-lg text-xs font-semibold text-slate-600 hover:bg-slate-100 transition-colors">
                            Cancel
                        </button>
                        <button onClick={handleSave} className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg flex items-center gap-1.5 text-xs font-semibold shadow-sm transition-all">
                            <Save size={14} /> Save
                        </button>
                    </div>
                </div>
            ) : (
                <div className="bg-white rounded-lg shadow-sm border border-slate-200 overflow-hidden">
                    <table className="w-full text-left text-sm whitespace-nowrap">
                        <thead className="bg-slate-50 border-b border-slate-200 text-slate-500 font-semibold uppercase text-[10px] tracking-wider">
                            <tr>
                                <th className="px-5 py-3">Query Type</th>
                                <th className="px-5 py-3">Assigned Responsible Person</th>
                                <th className="px-5 py-3 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {queryTypes.length === 0 && (
                                <tr>
                                    <td colSpan={3} className="px-5 py-8 text-center text-slate-500">
                                        No Query Types configured. Click "Add Query Type" to create one.
                                    </td>
                                </tr>
                            )}
                            {queryTypes.map(qt => (
                                <tr key={qt._id} className="hover:bg-slate-50 transition-colors">
                                    <td className="px-5 py-4 font-semibold text-slate-800 text-sm">
                                        {qt.name}
                                    </td>
                                    <td className="px-5 py-4 text-slate-600 font-medium text-sm">
                                        {qt.assignedPerson ? `${qt.assignedPerson.firstName} ${qt.assignedPerson.lastName}` : <span className="text-red-500 text-xs">Unassigned</span>}
                                    </td>
                                    <td className="px-5 py-4 text-right">
                                        <button onClick={() => handleConfigure(qt)} className="text-[11px] font-semibold text-indigo-600 bg-indigo-50 hover:bg-indigo-100 px-2.5 py-1.5 rounded transition-colors mr-2">
                                            Edit
                                        </button>
                                        <button onClick={() => handleDelete(qt._id)} className="text-slate-400 hover:text-red-600 hover:bg-red-50 p-1.5 rounded transition-colors">
                                            <Trash2 size={14} />
                                        </button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}
        </div>
    );
};

export default HelpdeskWorkflows;

import React, { useState, useEffect, useRef } from 'react';
import api from '../api/axios';
import { useAuth } from '../context/AuthContext';
import { Plus, Edit2, Trash2, Calendar, X, Save, CalendarCheck, CalendarOff, CalendarDays } from 'lucide-react';
import toast from 'react-hot-toast';
import { format } from 'date-fns';
import { createCachePayload, isCacheFresh, readSessionCache } from '../utils/cache';

const Holidays = () => {
    const { user } = useAuth();
    const [holidays, setHolidays] = useState([]);
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingHoliday, setEditingHoliday] = useState(null);
    const initialFetchDoneRef = useRef(false);
    const HOLIDAY_CACHE_TTL_MS = 60 * 1000;

    const [formData, setFormData] = useState({
        name: '',
        date: '',
        isOptional: false
    });

    // Determine stats
    const totalHolidays = holidays.length;
    const upcomingHolidays = holidays.filter(h => new Date(h.date) >= new Date() && !h.isOptional).length;
    const optionalHolidays = holidays.filter(h => h.isOptional).length;

    const isAdmin = user?.roles?.includes('Admin') || user?.roles?.some(r => r.name === 'Admin');
    const canCreateHoliday = isAdmin || user?.permissions?.includes('holiday.create') || user?.hasAllPermissions;
    const canEditHoliday = isAdmin || user?.permissions?.includes('holiday.edit') || user?.hasAllPermissions;
    const canDeleteHoliday = isAdmin || user?.permissions?.includes('holiday.delete') || user?.hasAllPermissions;

    useEffect(() => {
        if (initialFetchDoneRef.current) return;
        initialFetchDoneRef.current = true;
        fetchHolidays();
    }, []);

    const fetchHolidays = async (isBackground = false, force = false) => {
        const CACHE_KEY = `holiday_data_${user?._id}_${new Date().getFullYear()}`;

        // Helper: Generate fingerprint for change detection
        const buildFingerprint = (data) => {
            const items = data?.data || data;
            if (!Array.isArray(items)) return '';
            return items.map(h => `${h._id}-${h.name}-${h.date}-${h.isOptional}`).join('|');
        };

        // 1. Initial Load from Cache
        if (!isBackground && !force) {
            const cached = readSessionCache(CACHE_KEY);
            if (cached) {
                setHolidays(cached.data || cached);
                setLoading(false);
                if (isCacheFresh(cached, HOLIDAY_CACHE_TTL_MS)) return;
            }
        }

        try {
            if (!isBackground && !force && !readSessionCache(CACHE_KEY)) setLoading(true);
            const res = await api.get('/holidays');
            const freshData = res.data;

            // 2. Check for changes via fingerprint
            const cachedValue = readSessionCache(CACHE_KEY);
            const oldFingerprint = cachedValue ? buildFingerprint(cachedValue.data || cachedValue) : '';
            const newFingerprint = buildFingerprint(freshData);

            if (newFingerprint !== oldFingerprint || force) {
                setHolidays(freshData);
                
                // Minimal data for caching
                const minimalHolidays = freshData.map(h => ({
                    _id: h._id,
                    name: h.name,
                    date: h.date,
                    isOptional: h.isOptional
                }));

                const payload = createCachePayload(minimalHolidays, newFingerprint);
                sessionStorage.setItem(CACHE_KEY, JSON.stringify(payload));
            }
        } catch (error) {
            console.error(error);
            if (!isBackground) toast.error("Failed to load holidays");
        } finally {
            setLoading(false);
        }
    };

    const handleOpenModal = (holiday = null) => {
        if (holiday) {
            setEditingHoliday(holiday);
            setFormData({
                name: holiday.name,
                date: new Date(holiday.date).toISOString().split('T')[0],
                isOptional: holiday.isOptional
            });
        } else {
            setEditingHoliday(null);
            setFormData({ name: '', date: '', isOptional: false });
        }
        setIsModalOpen(true);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            if (editingHoliday) {
                await api.put(`/holidays/${editingHoliday._id}`, formData);
                toast.success("Holiday updated");
            } else {
                await api.post('/holidays', formData);
                toast.success("Holiday added");
            }
            setIsModalOpen(false);
            fetchHolidays(false, true); // Force refresh cache
        } catch (error) {
            toast.error(error.response?.data?.message || "Operation failed");
        }
    };

    const handleDelete = async (id) => {
        if (!window.confirm("Are you sure you want to delete this holiday?")) return;
        try {
            await api.delete(`/holidays/${id}`);
            toast.success("Holiday deleted");
            fetchHolidays(false, true); // Force refresh cache
        } catch (error) {
            toast.error("Failed to delete holiday");
        }
    };

    return (
        <div className="p-6 max-w-[1600px] mx-auto w-full">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
                <div>
                    <h1 className="text-3xl font-bold text-slate-800 tracking-tight">Holiday Calendar</h1>
                    <p className="text-slate-500 mt-1">Manage annual holidays and optional leaves for your organization.</p>
                </div>
                {canCreateHoliday && (
                    <button
                        onClick={() => handleOpenModal()}
                        className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-lg shadow-sm hover:shadow-md transition-all font-medium"
                    >
                        <Plus size={20} />
                        <span>Add New Holiday</span>
                    </button>
                )}
            </div>

            {/* Stats Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
                <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex items-center space-x-4">
                    <div className="p-3 bg-blue-50 text-blue-600 rounded-lg">
                        <CalendarDays size={24} />
                    </div>
                    <div>
                        <p className="text-sm font-medium text-slate-500">Total Holidays</p>
                        <p className="text-2xl font-bold text-slate-800">{totalHolidays}</p>
                    </div>
                </div>
                <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex items-center space-x-4">
                    <div className="p-3 bg-green-50 text-green-600 rounded-lg">
                        <CalendarCheck size={24} />
                    </div>
                    <div>
                        <p className="text-sm font-medium text-slate-500">Upcoming Holidays</p>
                        <p className="text-2xl font-bold text-slate-800">{upcomingHolidays}</p>
                    </div>
                </div>
                <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex items-center space-x-4">
                    <div className="p-3 bg-amber-50 text-amber-600 rounded-lg">
                        <CalendarOff size={24} />
                    </div>
                    <div>
                        <p className="text-sm font-medium text-slate-500">Optional Leaves</p>
                        <p className="text-2xl font-bold text-slate-800">{optionalHolidays}</p>
                    </div>
                </div>
            </div>

            {loading ? (
                <div className="flex justify-center p-12 bg-white rounded-xl shadow-sm border border-slate-200">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
                </div>
            ) : (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden ring-1 ring-black/5">
                    <div className="overflow-x-auto">
                        <table className="w-full text-left bg-white">
                            <thead>
                                <tr className="bg-slate-50 border-b border-slate-200">
                                    <th className="px-6 py-4 font-semibold text-slate-700 text-sm tracking-wide uppercase">Date</th>
                                    <th className="px-6 py-4 font-semibold text-slate-700 text-sm tracking-wide uppercase">Holiday Name</th>
                                    <th className="px-6 py-4 font-semibold text-slate-700 text-sm tracking-wide uppercase">Type</th>
                                    <th className="px-6 py-4 font-semibold text-slate-700 text-sm tracking-wide uppercase">Status</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100">
                                {holidays.length > 0 ? (
                                    holidays.map((holiday) => {
                                        const isPast = new Date(holiday.date) < new Date().setHours(0, 0, 0, 0);
                                        return (
                                            <tr
                                                key={holiday._id}
                                                // Make row clickable for admins to edit
                                                onClick={() => canEditHoliday && handleOpenModal(holiday)}
                                                className={`hover:bg-slate-50/80 transition-colors group ${canEditHoliday ? 'cursor-pointer' : ''}`}
                                            >
                                                <td className="px-6 py-4 whitespace-nowrap">
                                                    <div className="flex items-center space-x-4">
                                                        <div className={`p-2 rounded-lg ${isPast ? 'bg-slate-100 text-slate-400' : 'bg-blue-50 text-blue-600'}`}>
                                                            <Calendar size={20} />
                                                        </div>
                                                        <div>
                                                            <p className={`font-semibold ${isPast ? 'text-slate-500' : 'text-slate-900'}`}>
                                                                {format(new Date(holiday.date), 'MMMM d, yyyy')}
                                                            </p>
                                                            <p className="text-xs text-slate-400 font-medium">
                                                                {format(new Date(holiday.date), 'EEEE')}
                                                            </p>
                                                        </div>
                                                    </div>
                                                </td>
                                                <td className="px-6 py-4">
                                                    <span className={`text-base font-medium ${isPast ? 'text-slate-500' : 'text-slate-800'}`}>{holiday.name}</span>
                                                </td>
                                                <td className="px-6 py-4">
                                                    <span className={`inline-flex items-center px-3 py-1 rounded-full text-xs font-semibold uppercase tracking-wide border ${holiday.isOptional
                                                        ? 'bg-amber-50 text-amber-700 border-amber-200'
                                                        : 'bg-green-50 text-green-700 border-green-200'
                                                        }`}>
                                                        {holiday.isOptional ? 'Optional' : 'Fixed'}
                                                    </span>
                                                </td>
                                                <td className="px-6 py-4">
                                                    <span className={`text-sm ${isPast ? 'text-slate-400 italic' : 'text-blue-600 font-medium'}`}>
                                                        {isPast ? 'Completed' : 'Upcoming'}
                                                    </span>
                                                </td>
                                            </tr>
                                        )
                                    })
                                ) : (
                                    <tr>
                                        <td colSpan="4" className="px-6 py-24 text-center">
                                            <div className="flex flex-col items-center justify-center text-slate-400">
                                                <CalendarOff size={48} className="mb-4 text-slate-300" />
                                                <p className="text-lg font-medium text-slate-500">No holidays found for this year</p>
                                                <p className="text-sm mt-1">Get started by adding a new holiday to the calendar.</p>
                                            </div>
                                        </td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                    {holidays.length > 0 && (
                        <div className="px-6 py-4 bg-slate-50 border-t border-slate-200 text-xs text-slate-500 flex justify-between uppercase tracking-wider font-semibold">
                            <span>Total: {totalHolidays}</span>
                            {/* <span>Powered by HRCODE</span> */}
                        </div>
                    )}
                </div>
            )}

            {/* Modal */}
            {isModalOpen && (
                <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm flex items-center justify-center z-50 p-4 transition-opacity">
                    <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden transform transition-all scale-100">
                        <div className="bg-white px-8 py-6 border-b border-slate-100 flex justify-between items-center">
                            <div>
                                <h3 className="font-bold text-xl text-slate-800">
                                    {editingHoliday ? 'Edit Holiday' : 'Add New Holiday'}
                                </h3>
                                <p className="text-sm text-slate-500 mt-1">Enter holiday details below</p>
                            </div>
                            <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600 hover:bg-slate-100 p-2 rounded-full transition">
                                <X size={24} />
                            </button>
                        </div>

                        <form onSubmit={handleSubmit} className="p-8 space-y-6">
                            <div>
                                <label className="block text-sm font-semibold text-slate-700 mb-2 uppercase tracking-wide">Holiday Name</label>
                                <input
                                    type="text"
                                    required
                                    value={formData.name}
                                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all font-medium text-slate-800 placeholder:font-normal"
                                    placeholder="e.g. Independence Day"
                                />
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div>
                                    <label className="block text-sm font-semibold text-slate-700 mb-2 uppercase tracking-wide">Date</label>
                                    <input
                                        type="date"
                                        required
                                        value={formData.date}
                                        onChange={(e) => setFormData({ ...formData, date: e.target.value })}
                                        className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all font-medium text-slate-800"
                                    />
                                </div>
                                <div className="flex flex-col justify-end">
                                    <label className="flex items-center space-x-3 p-3 bg-slate-50 rounded-xl border border-slate-200 cursor-pointer hover:border-blue-300 transition-colors">
                                        <input
                                            type="checkbox"
                                            id="isOptional"
                                            checked={formData.isOptional}
                                            onChange={(e) => setFormData({ ...formData, isOptional: e.target.checked })}
                                            className="rounded border-slate-300 text-blue-600 focus:ring-blue-500 h-5 w-5"
                                        />
                                        <span className="text-sm font-medium text-slate-700 select-none">
                                            Optional / Floating
                                        </span>
                                    </label>
                                </div>
                            </div>

                            <div className="pt-6 flex justify-between items-center border-t border-slate-100 mt-4">
                                <div>
                                    {editingHoliday && canDeleteHoliday && (
                                        <button
                                            type="button"
                                            onClick={() => {
                                                if (window.confirm("Are you sure you want to delete this holiday?")) {
                                                    handleDelete(editingHoliday._id);
                                                    setIsModalOpen(false);
                                                }
                                            }}
                                            className="text-red-500 hover:text-red-700 text-sm font-medium flex items-center space-x-1"
                                        >
                                            <Trash2 size={16} />
                                            <span>Delete Holiday</span>
                                        </button>
                                    )}
                                </div>
                                <div className="flex space-x-4">
                                    <button
                                        type="button"
                                        onClick={() => setIsModalOpen(false)}
                                        className="px-6 py-2.5 text-slate-600 hover:bg-slate-50 rounded-lg transition text-sm font-semibold border border-transparent hover:border-slate-200"
                                    >
                                        Cancel
                                    </button>
                                    <button
                                        type="submit"
                                        className="px-6 py-2.5 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition text-sm font-semibold shadow-lg shadow-blue-500/30 flex items-center space-x-2"
                                    >
                                        <Save size={18} />
                                        <span>{editingHoliday ? 'Update Changes' : 'Save Holiday'}</span>
                                    </button>
                                </div>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Holidays;

import React, { useState, useEffect, useRef } from 'react';
import api from '../api/axios';
import { Settings, Edit2, Shield, Plus, Check, X, AlertCircle, Trash2 } from 'lucide-react';
import toast from 'react-hot-toast';
import { createCachePayload, isCacheFresh, readSessionCache } from '../utils/cache';

import { useAuth } from '../context/AuthContext';

const LeaveConfig = () => {
    const { user } = useAuth();
    const [policies, setPolicies] = useState([]);
    const [loading, setLoading] = useState(true);
    const [editingPolicy, setEditingPolicy] = useState(null);
    const [showModal, setShowModal] = useState(false);
    const initialFetchDoneRef = useRef(false);
    const LEAVE_CONFIG_CACHE_TTL_MS = 60 * 1000;
    const cacheKey = `leave_config_data_${user?._id}`;

    const [formData, setFormData] = useState({
        leaveType: '', name: '', description: '', isPaid: true,
        accrualType: 'Monthly', accrualAmount: 0,
        maxLimitPerYear: 0, carryForward: false, maxCarryForward: 0,
        sandwichRule: false, allowNegativeBalance: false,
        allowBackdated: true, proRata: true, proofRequiredAbove: 0
    });

    const fetchPolicies = async ({ force = false } = {}) => {
        try {
            const cachedData = readSessionCache(cacheKey);

            if (cachedData) {
                const data = cachedData.data || cachedData;
                setPolicies(data.policies || []);
                setLoading(false);
                if (!force && isCacheFresh(cachedData, LEAVE_CONFIG_CACHE_TTL_MS)) return;
            }

            const res = await api.get('/leaves/config');
            const policiesData = res.data;

            const newFingerprint = JSON.stringify({ l: policiesData.length, lp: policiesData[0]?._id });
            const oldFingerprint = cachedData?.fingerprint || null;

            setPolicies(policiesData);

            if (newFingerprint !== oldFingerprint || force) {
                const minimalPolicies = policiesData.map(p => ({
                    _id: p._id,
                    name: p.name,
                    leaveType: p.leaveType,
                    description: p.description,
                    isPaid: p.isPaid,
                    accrualType: p.accrualType,
                    accrualAmount: p.accrualAmount,
                    maxLimitPerYear: p.maxLimitPerYear,
                    carryForward: p.carryForward,
                    maxCarryForward: p.maxCarryForward,
                    sandwichRule: p.sandwichRule,
                    allowBackdated: p.allowBackdated,
                    employeeTypes: p.employeeTypes,
                    proRata: p.proRata,
                    proofRequiredAbove: p.proofRequiredAbove,
                    allowNegativeBalance: p.allowNegativeBalance
                }));

                const payload = createCachePayload({ policies: minimalPolicies }, newFingerprint);
                sessionStorage.setItem(cacheKey, JSON.stringify(payload));
            }
        } catch (error) {
            console.error(error);
            toast.error('Failed to load policies');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (initialFetchDoneRef.current) return;
        initialFetchDoneRef.current = true;
        fetchPolicies();
    }, []);

    const handleCreate = () => {
        setEditingPolicy(null);
        setFormData({
            leaveType: '', name: '', description: '', isPaid: true,
            employeeTypes: [],
            accrualType: 'Monthly', accrualAmount: 0,
            maxLimitPerYear: 0, carryForward: false, maxCarryForward: 0,
            sandwichRule: false, allowNegativeBalance: false,
            allowBackdated: true, proRata: true, proofRequiredAbove: 0
        });
        setShowModal(true);
    };

    const handleEdit = (policy) => {
        setEditingPolicy(policy);
        setFormData({
            leaveType: policy.leaveType,
            name: policy.name,
            description: policy.description || '',
            employeeTypes: policy.employeeTypes?.filter(t => t !== 'All') || [],
            isPaid: policy.isPaid,
            accrualType: policy.accrualType,
            accrualAmount: policy.accrualAmount,
            maxLimitPerYear: policy.maxLimitPerYear,
            carryForward: policy.carryForward,
            maxCarryForward: policy.maxCarryForward,
            sandwichRule: policy.sandwichRule,
            allowNegativeBalance: policy.allowNegativeBalance,
            allowBackdated: policy.allowBackdated,
            proRata: policy.proRata ?? true,
            proofRequiredAbove: policy.proofRequiredAbove || 0
        });
        setShowModal(true);
    };

    const handleDelete = async (id) => {
        if (!confirm('Are you sure you want to delete this policy? This action cannot be undone.')) return;
        try {
            await api.delete(`/leaves/config/${id}`);
            toast.success('Policy Deleted');
            sessionStorage.removeItem(`leave_config_data_${user?._id}`);
            fetchPolicies({ force: true });
        } catch (error) {
            toast.error('Failed to delete policy');
        }
    };

    const handleChange = (e) => {
        const value = e.target.type === 'checkbox' ? e.target.checked : e.target.value;
        setFormData({ ...formData, [e.target.name]: value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        // Validation Rules
        const parsedMaxLimit = Number(formData.maxLimitPerYear);
        const parsedAmount = Number(formData.accrualAmount);
        const parsedMaxCarry = Number(formData.maxCarryForward);

        if (parsedAmount < 0 || parsedMaxLimit < 0 || parsedMaxCarry < 0) {
            return toast.error('Amounts cannot be negative numbers.');
        }

        if (parsedMaxLimit > 365) {
            return toast.error('Max Limit Per Year cannot exceed 365 days.');
        }

        if (formData.accrualType === 'Yearly') {
            if (parsedAmount === 0 && parsedMaxLimit > 0) {
                return toast.error('If Amount is Unlimited (0), the Max Limit must also be Unlimited (0).');
            }
            if (parsedAmount > 0 && parsedMaxLimit > 0 && parsedAmount > parsedMaxLimit) {
                return toast.error('Yearly Initial Amount cannot exceed the Max Limit Per Year.');
            }
        }

        if (formData.carryForward && parsedMaxCarry > parsedMaxLimit && parsedMaxLimit !== 0) {
            return toast.error('Max Carry Forward cannot exceed the Max Limit Per Year.');
        }

        try {
            await api.post('/leaves/config', formData);
            toast.success('Policy Updated Successfully');
            sessionStorage.removeItem(`leave_config_data_${user?._id}`);
            setShowModal(false);
            fetchPolicies({ force: true });
        } catch (error) {
            toast.error(error.response?.data?.message || 'Failed to update policy');
        }
    };

    const seedDefaults = async () => {
        if (!confirm('This will create missing default policies. Continue?')) return;
        try {
            await api.post('/leaves/config/seed');
            toast.success('Defaults Seeded');
            sessionStorage.removeItem(`leave_config_data_${user?._id}`);
            fetchPolicies({ force: true });
        } catch (error) {
            toast.error('Seed Failed');
        }
    };

    if (loading) return <div className="p-10 flex justify-center"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div></div>;

    return (
        <div className="min-h-screen bg-slate-100 font-sans p-6 md:p-10">
            <div className="max-w-7xl mx-auto space-y-6">

                <div className="flex justify-between items-center">
                    <div>
                        <h1 className="text-2xl font-bold text-slate-800 flex items-center">
                            <Settings className="mr-2" /> Leave Policies
                        </h1>
                        <p className="text-sm text-slate-500">Configure rules for different leave types</p>
                    </div>
                    <div className="flex space-x-3">
                        <button onClick={handleCreate} className="flex items-center space-x-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg shadow transition-all text-sm font-semibold">
                            <Plus size={16} /> <span>Create Policy</span>
                        </button>
                        <button onClick={seedDefaults} className="flex items-center space-x-2 px-4 py-2 bg-slate-700 hover:bg-slate-800 text-white rounded-lg shadow transition-all text-sm font-semibold">
                            <Shield size={16} /> <span>Seed Defaults</span>
                        </button>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {policies.map(policy => (
                        <div key={policy._id} className="bg-white rounded-xl shadow border border-slate-200 overflow-hidden hover:shadow-md transition-shadow group">
                            <div className="px-6 py-4 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
                                <div className="flex items-center space-x-3">
                                    <div className="h-8 w-8 rounded bg-blue-100 text-blue-600 flex items-center justify-center font-bold text-sm">
                                        {policy.leaveType}
                                    </div>
                                    <h3 className="font-bold text-slate-700">{policy.name}</h3>
                                </div>
                                <div className="flex space-x-1 opacity-100 md:opacity-0 group-hover:opacity-100 transition-opacity">
                                    <button onClick={() => handleEdit(policy)} className="p-1.5 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded transition-colors" title="Edit">
                                        <Edit2 size={16} />
                                    </button>
                                    <button onClick={() => handleDelete(policy._id)} className="p-1.5 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded transition-colors" title="Delete">
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            </div>
                            <div className="p-6 space-y-4 text-sm">
                                <div className="grid grid-cols-2 gap-y-2 text-slate-600">
                                    <div className="flex flex-col">
                                        <span className="text-xs text-slate-400 uppercase font-bold">Accrual</span>
                                        <span className="font-medium">{policy.accrualType} ({policy.accrualAmount === 0 ? 'Unlimited' : policy.accrualAmount})</span>
                                    </div>
                                    <div className="flex flex-col">
                                        <span className="text-xs text-slate-400 uppercase font-bold">Max / Year</span>
                                        <span className="font-medium">{policy.maxLimitPerYear || 'Unlimited'}</span>
                                    </div>
                                    <div className="flex flex-col">
                                        <span className="text-xs text-slate-400 uppercase font-bold">Type</span>
                                        <span className={`font-medium ${policy.isPaid ? 'text-emerald-600' : 'text-red-500'}`}>{policy.isPaid ? 'Paid' : 'Unpaid'}</span>
                                    </div>
                                    <div className="flex flex-col">
                                        <span className="text-xs text-slate-400 uppercase font-bold">Carry Fwd</span>
                                        <span className="font-medium">{policy.carryForward ? `Yes (Max ${policy.maxCarryForward})` : 'No'}</span>
                                    </div>
                                    <div className="col-span-2 flex flex-col mt-2">
                                        <span className="text-xs text-slate-400 uppercase font-bold">Applicable To</span>
                                        <span className="font-medium text-xs bg-slate-100 p-1 rounded inline-block">
                                            {policy.employeeTypes?.filter(t => t !== 'All').join(', ') || 'None'}
                                        </span>
                                    </div>
                                </div>
                                <div className="border-t border-slate-100 pt-3 flex flex-wrap gap-2">
                                    {policy.sandwichRule && <span className="px-2 py-1 bg-orange-50 text-orange-600 text-xs rounded border border-orange-100 flex items-center"><AlertCircle size={10} className="mr-1" /> Sandwich Rule</span>}
                                    {policy.allowBackdated && <span className="px-2 py-1 bg-emerald-50 text-emerald-600 text-xs rounded border border-emerald-100 flex items-center"><Check size={10} className="mr-1" /> Backdated</span>}
                                </div>
                            </div>
                        </div>
                    ))}
                </div>

                {/* Edit Modal */}
                {showModal && (
                    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50 p-4">
                        <div className="bg-white rounded-lg shadow-2xl w-full max-w-2xl overflow-hidden animate-blob max-h-[90vh] overflow-y-auto">
                            <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                                <div className="flex items-center space-x-2">
                                    <div className={`h-8 w-8 rounded flex items-center justify-center font-bold ${editingPolicy ? 'bg-blue-600 text-white' : 'bg-green-600 text-white'}`}>
                                        {editingPolicy ? <Edit2 size={16} /> : <Plus size={16} />}
                                    </div>
                                    <h3 className="font-bold text-slate-800">{editingPolicy ? `Configure ${formData.name}` : 'Create New Policy'}</h3>
                                </div>
                                <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-red-500 text-2xl leading-none">&times;</button>
                            </div>
                            <form onSubmit={handleSubmit} className="p-6 space-y-6">

                                {/* Base Config */}
                                <div className="space-y-4">
                                    <h4 className="text-xs font-bold text-slate-400 uppercase border-b pb-2">Basic Settings</h4>
                                    <div className="grid grid-cols-2 gap-4">
                                        <div>
                                            <label className="zoho-label">Code (Unique)</label>
                                            <input
                                                name="leaveType"
                                                value={formData.leaveType}
                                                onChange={(e) => setFormData({ ...formData, leaveType: e.target.value.toUpperCase() })}
                                                className="zoho-input uppercase"
                                                required
                                                disabled={!!editingPolicy}
                                                placeholder="e.g. PL"
                                            />
                                        </div>
                                        <div>
                                            <label className="zoho-label">Name</label>
                                            <input name="name" value={formData.name} onChange={handleChange} className="zoho-input" required />
                                        </div>
                                        <div>
                                            <label className="zoho-label">Is Paid Leave?</label>
                                            <select name="isPaid" value={formData.isPaid} onChange={(e) => setFormData({ ...formData, isPaid: e.target.value === 'true' })} className="zoho-input">
                                                <option value="true">Yes (Paid)</option>
                                                <option value="false">No (Unpaid)</option>
                                            </select>
                                        </div>
                                        <div className="col-span-2">
                                            <label className="zoho-label">Description</label>
                                            <textarea name="description" value={formData.description} onChange={handleChange} className="zoho-input" rows="2" placeholder="Policy details..."></textarea>
                                        </div>
                                    </div>
                                </div>

                                {/* Accrual Settings */}
                                <div className="space-y-4">
                                    <h4 className="text-xs font-bold text-slate-400 uppercase border-b pb-2">Accrual & Limits</h4>
                                    <div className="grid grid-cols-3 gap-4">
                                        <div>
                                            <label className="zoho-label">Type</label>
                                            <select name="accrualType" value={formData.accrualType} onChange={handleChange} className="zoho-input">
                                                <option value="Monthly">Monthly</option>
                                                <option value="Yearly">Yearly</option>
                                                <option value="Policy">Policy Based</option>
                                                <option value="None">None</option>
                                            </select>
                                        </div>
                                        <div>
                                            <label className="zoho-label">Amount (0 = Unlimited)</label>
                                            <input type="number" step="0.5" min="0" name="accrualAmount" value={formData.accrualAmount} onChange={handleChange} className="zoho-input" required />
                                        </div>
                                        <div>
                                            <label className="zoho-label">Max / Year (0 = Unlimited)</label>
                                            <input type="number" name="maxLimitPerYear" min="0" max="365" value={formData.maxLimitPerYear} onChange={handleChange} className="zoho-input" />
                                        </div>
                                    </div>
                                </div>

                                {/* Employee Types */}
                                <div className="space-y-4">
                                    <h4 className="text-xs font-bold text-slate-400 uppercase border-b pb-2">Applicable Employment Types</h4>
                                    <div className="flex flex-wrap gap-4">
                                        {['Full Time', 'Part Time', 'Contract', 'Intern', 'Probation', 'Consultant'].map(type => (
                                            <label key={type} className="flex items-center space-x-2 cursor-pointer">
                                                <input
                                                    type="checkbox"
                                                    checked={formData.employeeTypes?.includes(type)}
                                                    onChange={(e) => {
                                                        const current = formData.employeeTypes || [];
                                                        if (e.target.checked) {
                                                            setFormData({ ...formData, employeeTypes: [...current, type] });
                                                        } else {
                                                            setFormData({ ...formData, employeeTypes: current.filter(t => t !== type) });
                                                        }
                                                    }}
                                                    className="rounded text-blue-600 focus:ring-blue-500"
                                                />
                                                <span className="text-sm text-slate-700">{type}</span>
                                            </label>
                                        ))}
                                    </div>
                                </div>

                                {/* Rules */}
                                <div className="space-y-4">
                                    <h4 className="text-xs font-bold text-slate-400 uppercase border-b pb-2">Business Rules</h4>
                                    <div className="grid grid-cols-2 gap-4">
                                        <label className="flex items-center space-x-2 p-3 border rounded-lg hover:bg-slate-50 cursor-pointer">
                                            <input type="checkbox" name="sandwichRule" checked={formData.sandwichRule} onChange={handleChange} className="rounded text-blue-600 focus:ring-blue-500" />
                                            <span className="text-sm font-medium text-slate-700">Sandwich Rule (Include Holidays)</span>
                                        </label>
                                        <label className="flex items-center space-x-2 p-3 border rounded-lg hover:bg-slate-50 cursor-pointer">
                                            <input type="checkbox" name="allowBackdated" checked={formData.allowBackdated} onChange={handleChange} className="rounded text-blue-600 focus:ring-blue-500" />
                                            <span className="text-sm font-medium text-slate-700">Allow Backdated Application</span>
                                        </label>
                                        <label className="flex items-center space-x-2 p-3 border rounded-lg hover:bg-slate-50 cursor-pointer">
                                            <input type="checkbox" name="carryForward" checked={formData.carryForward} onChange={handleChange} className="rounded text-blue-600 focus:ring-blue-500" />
                                            <span className="text-sm font-medium text-slate-700">Allow Carry Forward</span>
                                        </label>
                                        {formData.carryForward && (
                                            <div>
                                                <label className="zoho-label">Max Carry Fwd</label>
                                                <input type="number" name="maxCarryForward" min="0" value={formData.maxCarryForward} onChange={handleChange} className="zoho-input" />
                                            </div>
                                        )}
                                        <label className="flex items-center space-x-2 p-3 border rounded-lg hover:bg-slate-50 cursor-pointer">
                                            <input type="checkbox" name="allowNegativeBalance" checked={formData.allowNegativeBalance} onChange={handleChange} className="rounded text-blue-600 focus:ring-blue-500" />
                                            <span className="text-sm font-medium text-slate-700">Allow Negative Balance</span>
                                        </label>
                                        <label className="flex items-center space-x-2 p-3 border rounded-lg hover:bg-slate-50 cursor-pointer">
                                            <input type="checkbox" name="proRata" checked={formData.proRata} onChange={handleChange} className="rounded text-blue-600 focus:ring-blue-500" />
                                            <span className="text-sm font-medium text-slate-700">Calculate Pro-Rata (Mid-month joining)</span>
                                        </label>
                                        <div className="flex flex-col justify-center">
                                            <label className="zoho-label">Proof Required Above (Days)</label>
                                            <div className="flex items-center space-x-2">
                                                <input type="number" name="proofRequiredAbove" value={formData.proofRequiredAbove} onChange={handleChange} className="zoho-input flex-1" min="0" />
                                                <span className="text-xs text-slate-400 w-24">0 = Never</span>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                <div className="flex justify-end pt-4 border-t border-slate-100">
                                    <button type="button" onClick={() => setShowModal(false)} className="px-4 py-2 text-slate-600 font-medium hover:bg-slate-100 rounded mr-2">Cancel</button>
                                    <button type="submit" className="px-6 py-2 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded shadow">Save Changes</button>
                                </div>
                            </form>
                        </div>
                    </div >
                )}

            </div >
        </div >
    );
};

export default LeaveConfig;

import React, { useState, useEffect, useRef } from 'react';
import api from '../api/axios';
import { useAuth } from '../context/AuthContext';
import {
    Calendar, Plus, RefreshCw, User, CheckCircle, XCircle,
    Check, X, Infinity, ChevronDown, Clock, AlertCircle, Layers,
    Eye, FileText
} from 'lucide-react';
import toast from 'react-hot-toast';
import Button from '../components/Button';
import { format } from 'date-fns';
import { createCachePayload, isCacheFresh, readSessionCache } from '../utils/cache';

// ─── Donut Chart for Balance Card ────────────────────────────────────────────
const DonutChart = ({ utilized, total, isUnlimited }) => {
    const r = 28;
    const circ = 2 * Math.PI * r;
    const pct = isUnlimited ? 0 : Math.min((utilized / (total || 1)) * 100, 100);
    const offset = circ - (pct / 100) * circ;
    const available = isUnlimited ? '∞' : Math.max(total - utilized, 0);

    return (
        <div className="relative flex items-center justify-center w-20 h-20">
            <svg className="-rotate-90 w-20 h-20" viewBox="0 0 72 72">
                <circle cx="36" cy="36" r={r} stroke="#EFF0F3" strokeWidth="7" fill="none" />
                <circle
                    cx="36" cy="36" r={r}
                    stroke={isUnlimited ? '#22c55e' : pct > 80 ? '#ef4444' : '#1a73e8'}
                    strokeWidth="7" fill="none"
                    strokeDasharray={circ}
                    strokeDashoffset={isUnlimited ? circ : offset}
                    strokeLinecap="round"
                    style={{ transition: 'stroke-dashoffset 0.8s ease' }}
                />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
                <span className="text-base font-bold text-gray-800 leading-none">{available}</span>
                <span className="text-[9px] text-gray-400 font-semibold uppercase tracking-wide mt-0.5">Left</span>
            </div>
        </div>
    );
};

// ─── Status Badge ─────────────────────────────────────────────────────────────
const StatusBadge = ({ status }) => {
    const styles = {
        Approved: 'bg-green-50 text-green-700 border border-green-200',
        Rejected: 'bg-red-50 text-red-600 border border-red-200',
        Pending: 'bg-amber-50 text-amber-700 border border-amber-200',
        Cancelled: 'bg-gray-100 text-gray-500 border border-gray-200',
    };
    return (
        <span className={`inline-flex items-center gap-1 text-xs font-semibold px-2 py-0.5 rounded-full ${styles[status] || styles.Cancelled}`}>
            {status === 'Approved' && <span className="w-1.5 h-1.5 rounded-full bg-green-500 inline-block" />}
            {status === 'Pending' && <span className="w-1.5 h-1.5 rounded-full bg-amber-400 inline-block" />}
            {status === 'Rejected' && <span className="w-1.5 h-1.5 rounded-full bg-red-500 inline-block" />}
            {status === 'Cancelled' && <span className="w-1.5 h-1.5 rounded-full bg-gray-400 inline-block" />}
            {status}
        </span>
    );
};

// ─── Leaves Page ──────────────────────────────────────────────────────────────
const Leaves = () => {
    const { user } = useAuth();
    const initialFetchDoneRef = useRef(false);
    const [activeTab, setActiveTab] = useState('my-leaves');

    const [balances, setBalances] = useState([]);
    const [requests, setRequests] = useState([]);
    const [requestsPagination, setRequestsPagination] = useState({ page: 1, limit: 10, total: 0, totalPages: 0 });
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);

    const [approvalRequests, setApprovalRequests] = useState([]);
    const [loadingApprovals, setLoadingApprovals] = useState(false);
    const [approvalsLoaded, setApprovalsLoaded] = useState(false);
    const [approvalStatusFilter, setApprovalStatusFilter] = useState('Pending');
    const [processingId, setProcessingId] = useState(null);
    const [cancellingId, setCancellingId] = useState(null);
    const [formData, setFormData] = useState({
        leaveType: '', startDate: '', endDate: '',
        isHalfDay: false, halfDaySession: 'First Half', reason: ''
    });
    const [expandedRows, setExpandedRows] = useState([]);

    const toggleRowExpansion = (id) => {
        setExpandedRows(prev => 
            prev.includes(id) ? prev.filter(rowId => rowId !== id) : [...prev, id]
        );
    };

    const [proofFile, setProofFile] = useState(null);

    const isAdminUser = user?.roles?.some(r => (typeof r === 'string' ? r : r?.name) === 'Admin')
        || user?.permissions?.includes('*');
    const isManager = (user?.directReportsCount ?? user?.directReports?.length ?? 0) > 0;
    const hasApprovalAccess = isAdminUser || isManager;
    const LEAVES_CACHE_TTL_MS = 20 * 1000;


    const fetchData = async (page = 1, skipCache = false) => {
        // Cache Key: Scoped by User and Date
        const CACHE_KEY = `leaves_${user?._id}_${new Date().toISOString().slice(0, 10)}`;

        const readCache = () => {
            const parsed = readSessionCache(CACHE_KEY);
            const data = parsed?.data || parsed;
            if (!data || !data.balances) {
                sessionStorage.removeItem(CACHE_KEY);
                return null;
            }
            return parsed;
        };

        const writeCache = (data, fingerprint) => {
            try {
                // Minimal data for caching
                const minimalBalances = (data.balances || []).map(b => ({
                    leaveType: b.leaveType,
                    policyName: b.policyName,
                    openingBalance: b.openingBalance,
                    accrued: b.accrued,
                    utilized: b.utilized,
                    closingBalance: b.closingBalance,
                    policyAccrualAmount: b.policyAccrualAmount,
                    proofRequiredAbove: b.proofRequiredAbove
                }));

                const minimalRequests = (data.requests || []).map(r => ({
                    _id: r._id,
                    leaveType: r.leaveType,
                    startDate: r.startDate,
                    endDate: r.endDate,
                    daysCount: r.daysCount,
                    isHalfDay: r.isHalfDay,
                    halfDaySession: r.halfDaySession,
                    reason: r.reason,
                    createdAt: r.createdAt,
                    status: r.status
                }));

                const payload = createCachePayload({
                    balances: minimalBalances,
                    requests: minimalRequests,
                    pagination: data.pagination
                }, fingerprint);
                sessionStorage.setItem(CACHE_KEY, JSON.stringify(payload));
            } catch { /* Silently fail if storage full */ }
        };

        const buildFingerprint = (data) => {
            const items = data?.data || data;
            if (!items) return '';
            const balPart = items.balances?.map(b => `${b.leaveType}:${b.utilized}:${b.closingBalance}`).join('|') || '';
            const reqPart = items.requests?.map(r => `${r._id}:${r.status}`).join('|') || '';
            return `${balPart}#${reqPart}`;
        };

        const applyData = (data) => {
            if (data.balances) setBalances(data.balances);
            if (data.requests) setRequests(data.requests);
            if (data.pagination) setRequestsPagination(data.pagination);
        };

        const cached = skipCache ? null : readCache();

        // 1. Show cached data instantly if available
        if (!skipCache && cached && page === 1) {
            applyData(cached.data || cached);
            setLoading(false);
            if (isCacheFresh(cached, LEAVES_CACHE_TTL_MS)) return;
        } else {
            setLoading(true);
        }

        // 2. Fetch fresh data
        try {
            const res = await api.get('/leaves/bootstrap', {
                params: { page, limit: 10 }
            });

            const payload = res.data;

            const freshFingerprint = buildFingerprint(payload);
            const cachedFingerprint = cached?.fingerprint || (readCache()?.fingerprint || '');

            if (freshFingerprint !== cachedFingerprint || page !== 1) {
                applyData(payload);
                if (page === 1) writeCache(payload, freshFingerprint);
            } else {
                // Refresh cache entry even if fingerprint same to keep it alive
                writeCache(payload, freshFingerprint);
            }
        } catch (err) {
            console.error('Failed to load leave data', err);
            if (!cached?.data) toast.error('Failed to load leave data');
        } finally {
            setLoading(false);
        }
    };

    const fetchOnlyRequests = async (page = 1) => {
        setLoading(true);
        try {
            const reqRes = await api.get(`/leaves/requests?page=${page}&limit=10`);
            setRequests(reqRes.data.data);
            setRequestsPagination(reqRes.data.pagination);
        } catch { toast.error('Failed to load leave history'); }
        finally { setLoading(false); }
    };

    const fetchApprovals = async (force = false, status = approvalStatusFilter) => {
        if (!hasApprovalAccess || (approvalsLoaded && !force && status === approvalStatusFilter)) return;
        setLoadingApprovals(true);
        try {
            const url = status === 'All' ? '/leaves/approvals?status=All' : `/leaves/approvals?status=${status}`;
            const res = await api.get(url);
            setApprovalRequests(res.data);
            setApprovalsLoaded(true);
            setApprovalStatusFilter(status);
        } catch { toast.error('Failed to load approvals'); }
        finally { setLoadingApprovals(false); }
    };

    useEffect(() => {
        if (!user?._id) return;
        if (initialFetchDoneRef.current) return;
        initialFetchDoneRef.current = true;

        fetchData(1);

        // Add background polling for real-time leave status updates
        const pollInterval = setInterval(() => fetchData(1, true), 30000);
        return () => clearInterval(pollInterval);
    }, [user?._id]);

    const handleChange = (e) => {
        const val = e.target.type === 'checkbox' ? e.target.checked : e.target.value;
        setFormData(prev => ({ ...prev, [e.target.name]: val }));
    };

    const handleFileChange = (e) => {
        setProofFile(e.target.files[0] || null);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setProcessingId('apply');
        try {
            const submitData = new FormData();
            submitData.append('leaveType', formData.leaveType);
            submitData.append('startDate', formData.startDate);
            submitData.append('endDate', formData.endDate);
            submitData.append('isHalfDay', String(formData.isHalfDay));
            submitData.append('halfDaySession', formData.isHalfDay ? formData.halfDaySession : '');
            submitData.append('reason', formData.reason);

            if (proofFile) {
                submitData.append('document', proofFile);
            }

            await api.post('/leaves/apply', submitData, {
                headers: { 'Content-Type': 'multipart/form-data' }
            });
            toast.success('Leave applied successfully');
            setShowModal(false);
            setFormData({ leaveType: '', startDate: '', endDate: '', isHalfDay: false, halfDaySession: 'First Half', reason: '' });
            setProofFile(null);
            fetchData(1);
        } catch (err) {
            toast.error(err.response?.data?.message || 'Application failed');
        } finally {
            setProcessingId(null);
        }
    };

    const handleAction = async (id, status) => {
        if (!confirm(`Are you sure you want to ${status} this request?`)) return;
        let rejectionReason = '';
        if (status === 'Rejected') {
            rejectionReason = prompt('Enter rejection reason:');
            if (!rejectionReason) return;
        }
        setProcessingId(id);
        try {
            await api.put(`/leaves/approve/${id}`, { status, rejectionReason });
            toast.success(`Request ${status}`);
            fetchApprovals(true); // Force refresh after action
        } catch (err) { toast.error(err.response?.data?.message || 'Action failed'); }
        finally { setProcessingId(null); }
    };

    const handleCancel = async (id) => {
        if (!confirm('Cancel this leave request?')) return;
        setCancellingId(id);
        try {
            await api.put(`/leaves/cancel/${id}`);
            toast.success('Leave cancelled');
            fetchData(requestsPagination.page);
        } catch (err) { toast.error(err.response?.data?.message || 'Failed to cancel'); }
        finally { setCancellingId(null); }
    };

    const renderLeaveDocuments = (documents = []) => {
        if (!Array.isArray(documents) || documents.length === 0) {
            return <span className="text-xs text-gray-400">No attachment</span>;
        }

        return (
            <div className="flex flex-wrap gap-2">
                {documents.map((doc, index) => (
                    <a
                        key={`${doc}-${index}`}
                        href={doc}
                        target="_blank"
                        rel="noreferrer"
                        className="inline-flex items-center gap-1.5 text-xs font-medium text-blue-700 bg-blue-50 border border-blue-100 px-2.5 py-1 rounded-md hover:bg-blue-100 transition-colors"
                    >
                        <FileText size={12} />
                        <span>View proof{documents.length > 1 ? ` ${index + 1}` : ''}</span>
                    </a>
                ))}
            </div>
        );
    };

    if (loading && balances.length === 0) {
        return (
            <div className="flex items-center justify-center h-64">
                <div className="flex flex-col items-center gap-3">
                    <div className="w-8 h-8 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" />
                    <span className="text-sm text-gray-500">Loading leave data…</span>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-[#f4f5f8] font-sans">
            {/* ── Top Bar ── */}
            <div className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between">
                <div>
                    <h1 className="text-xl font-bold text-gray-800 tracking-tight">Leave Management</h1>
                    <p className="text-xs text-gray-400 mt-0.5">Apply and manage your leave requests</p>
                </div>
                <div className="flex items-center gap-3">
                    <button
                        onClick={() => {
                            fetchData(1);
                            if (activeTab === 'approvals') fetchApprovals(true);
                        }}
                        className="p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                        title="Refresh"
                    >
                        <RefreshCw size={15} />
                    </button>
                    {activeTab === 'my-leaves' && (
                        <button
                            onClick={() => setShowModal(true)}
                            className="flex items-center gap-2 bg-[#1a73e8] hover:bg-[#1557b0] text-white text-sm font-semibold px-4 py-2 rounded-lg transition-colors shadow-sm"
                        >
                            <Plus size={15} /> Apply Leave
                        </button>
                    )}
                </div>
            </div>

            {/* ── Tab Bar ── */}
            {hasApprovalAccess && (
                <div className="bg-white border-b border-gray-200 px-6 flex gap-1">
                    {[
                        { id: 'my-leaves', label: 'My Leaves', icon: <User size={14} /> },
                        { id: 'approvals', label: 'Team Approvals', icon: <CheckCircle size={14} />, badge: approvalRequests.length },
                    ].map(tab => (
                        <button
                            key={tab.id}
                            onClick={() => {
                                setActiveTab(tab.id);
                                if (tab.id === 'approvals') fetchApprovals();
                            }}
                            className={`flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === tab.id
                                ? 'border-[#1a73e8] text-[#1a73e8]'
                                : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                                }`}
                        >
                            {tab.icon} {tab.label}
                            {tab.badge > 0 && (
                                <span className="bg-red-500 text-white text-[10px] font-bold w-4 h-4 rounded-full flex items-center justify-center">
                                    {tab.badge}
                                </span>
                            )}
                        </button>
                    ))}
                </div>
            )}

            <div className="px-6 py-6 max-w-7xl mx-auto space-y-6">

                {/* ════════════ MY LEAVES TAB ════════════ */}
                {activeTab === 'my-leaves' && (
                    <>
                        {/* ── Balance Cards ── */}
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                            {balances.map(b => {
                                const total = b.openingBalance + b.accrued;
                                const available = b.policyAccrualAmount === 0 ? '∞' : Math.max(total - b.utilized, 0);
                                const isUnlim = b.policyAccrualAmount === 0;
                                const pct = isUnlim ? 0 : Math.min((b.utilized / (total || 1)) * 100, 100);
                                const accentColor = isUnlim
                                    ? 'border-l-green-500'
                                    : pct > 80
                                        ? 'border-l-red-400'
                                        : 'border-l-[#1a73e8]';

                                return (
                                    <div
                                        key={b.leaveType}
                                        className={`bg-white rounded-xl border border-gray-200 border-l-4 ${accentColor} p-5 flex items-center justify-between hover:shadow-md transition-shadow`}
                                    >
                                        <div className="flex flex-col gap-1 min-w-0">
                                            <span className="text-[11px] font-bold text-gray-400 uppercase tracking-wider truncate">{b.policyName}</span>
                                            <span className="text-xs text-gray-400 font-mono">{b.leaveType}</span>
                                            {!isUnlim && (
                                                <div className="mt-2 space-y-0.5">
                                                    <div className="flex items-center gap-2 text-xs text-gray-500">
                                                        <span className="w-16 text-gray-400">Allocated</span>
                                                        <span className="font-semibold text-gray-700">{total}</span>
                                                    </div>
                                                    <div className="flex items-center gap-2 text-xs text-gray-500">
                                                        <span className="w-16 text-gray-400">Used</span>
                                                        <span className="font-semibold text-gray-700">{b.utilized}</span>
                                                    </div>
                                                    <div className="flex items-center gap-2 text-xs">
                                                        <span className="w-16 text-gray-400">Available</span>
                                                        <span className={`font-bold ${pct > 80 ? 'text-red-500' : 'text-[#1a73e8]'}`}>{available}</span>
                                                    </div>
                                                </div>
                                            )}
                                            {isUnlim && (
                                                <span className="mt-2 text-xs text-green-600 font-semibold">Unlimited</span>
                                            )}
                                        </div>
                                        <DonutChart utilized={b.utilized} total={total} isUnlimited={isUnlim} />
                                    </div>
                                );
                            })}
                        </div>

                        {/* ── Leave History Table ── */}
                        <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
                            <div className="px-6 py-4 border-b border-gray-100 flex items-center justify-between">
                                <div className="flex items-center gap-2">
                                    <Layers size={16} className="text-gray-400" />
                                    <h2 className="text-sm font-bold text-gray-700">My Leave History</h2>
                                    <span className="text-xs bg-gray-100 text-gray-500 font-semibold px-2 py-0.5 rounded-full">{requestsPagination.total}</span>
                                </div>
                            </div>

                            {requests.length === 0 ? (
                                <div className="py-16 flex flex-col items-center gap-3 text-gray-400">
                                    <Calendar size={40} className="text-gray-300" />
                                    <p className="text-sm font-medium">No leave requests found</p>
                                    <p className="text-xs text-gray-300">Click "Apply Leave" to submit your first request</p>
                                </div>
                            ) : (
                                <>
                                <div className="overflow-x-auto">
                                    <table className="w-full text-sm">
                                        <thead>
                                            <tr className="bg-gray-50 border-b border-gray-100">
                                                <th className="text-left px-6 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wider">Type</th>
                                                <th className="text-left px-4 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wider">From</th>
                                                <th className="text-left px-4 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wider">To</th>
                                                <th className="text-left px-4 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wider">Days</th>
                                                <th className="text-left px-4 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wider">Reason</th>
                                                <th className="text-left px-4 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wider">Applied On</th>
                                                <th className="text-left px-4 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wider">Status</th>
                                                <th className="px-4 py-3" />
                                            </tr>
                                        </thead>
                                        <tbody className="divide-y divide-gray-50">
                                            {requests.map(req => (
                                                <tr key={req._id} className="hover:bg-gray-50 transition-colors group">
                                                    <td className="px-6 py-3.5">
                                                        <span className="inline-block bg-blue-50 text-[#1a73e8] text-xs font-bold px-2 py-1 rounded border border-blue-100">
                                                            {req.leaveType}
                                                        </span>
                                                    </td>
                                                    <td className="px-4 py-3.5 text-gray-700 font-medium whitespace-nowrap">
                                                        {format(new Date(req.startDate), 'dd MMM yyyy')}
                                                    </td>
                                                    <td className="px-4 py-3.5 text-gray-700 whitespace-nowrap">
                                                        {format(new Date(req.endDate), 'dd MMM yyyy')}
                                                    </td>
                                                    <td className="px-4 py-3.5 text-gray-700">
                                                        <span className="font-semibold">{req.daysCount}</span>
                                                        <span className="text-gray-400 text-xs ml-1">{req.isHalfDay ? '(½)' : 'd'}</span>
                                                    </td>
                                                    <td className="px-4 py-3.5 text-gray-500 w-[200px] min-w-[200px] max-w-[200px]">
                                                        {expandedRows.includes(req._id) ? (
                                                            <div className="bg-gray-50/80 p-2.5 rounded-lg border border-gray-100 text-[11px] leading-relaxed text-gray-700 whitespace-pre-wrap break-words animate-fade-in">
                                                                {req.reason}
                                                            </div>
                                                        ) : (
                                                            <div className="text-xs truncate" title={req.reason}>
                                                                {req.reason.length > 60 ? `${req.reason.substring(0, 60)}...` : req.reason}
                                                            </div>
                                                        )}
                                                    </td>
                                                    <td className="px-4 py-3.5 text-gray-400 text-xs whitespace-nowrap">
                                                        {format(new Date(req.createdAt), 'dd MMM yyyy')}
                                                    </td>
                                                    <td className="px-4 py-3.5">
                                                        <StatusBadge status={req.status} />
                                                    </td>
                                                    <td className="px-4 py-3.5 text-right">
                                                        <div className="flex items-center justify-end gap-2">
                                                            {req.status === 'Pending' && (
                                                                <button
                                                                    onClick={() => handleCancel(req._id)}
                                                                    disabled={cancellingId === req._id}
                                                                    className="opacity-0 group-hover:opacity-100 text-xs text-red-500 hover:text-red-700 font-semibold transition-all disabled:opacity-40"
                                                                >
                                                                    {cancellingId === req._id ? 'Cancelling…' : 'Cancel'}
                                                                </button>
                                                            )}
                                                            <button 
                                                                onClick={() => toggleRowExpansion(req._id)}
                                                                className={`p-1 rounded transition-colors ${expandedRows.includes(req._id) ? 'text-blue-600 bg-blue-50' : 'text-gray-400 hover:text-blue-500 hover:bg-gray-50'}`}
                                                                title="Toggle Reason"
                                                            >
                                                                <Eye size={14} />
                                                            </button>
                                                        </div>
                                                    </td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                                <div className="px-6 py-3 border-t border-gray-100 flex items-center justify-between bg-gray-50">
                                    <span className="text-xs text-gray-500 font-medium">
                                        Showing page <span className="text-gray-900 font-bold">{requestsPagination.page}</span> of <span className="text-gray-900 font-bold">{requestsPagination.totalPages}</span>
                                    </span>
                                    <div className="flex items-center gap-2">
                                        <button
                                            onClick={() => fetchOnlyRequests(requestsPagination.page - 1)}
                                            disabled={requestsPagination.page === 1}
                                            className="px-3 py-1 text-xs font-semibold text-gray-600 bg-white border border-gray-200 rounded-md hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                        >
                                            Previous
                                        </button>
                                        <button
                                            onClick={() => fetchOnlyRequests(requestsPagination.page + 1)}
                                            disabled={requestsPagination.page === requestsPagination.totalPages}
                                            className="px-3 py-1 text-xs font-semibold text-gray-600 bg-white border border-gray-200 rounded-md hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                        >
                                            Next
                                        </button>
                                    </div>
                                </div>
                                </>
                            )}
                        </div>

                    </>
                )}

                {/* ════════════ APPROVALS TAB ════════════ */}
                {activeTab === 'approvals' && hasApprovalAccess && (
                    <div className="space-y-4">
                        <div className="flex items-center justify-between">
                            <div>
                                <h2 className="text-sm font-bold text-gray-700">Team Requests & History</h2>
                                <p className="text-xs text-gray-400 mt-0.5">Review and track leave requests across your team</p>
                            </div>
                            <div className="flex items-center gap-3">
                                <div className="flex items-center p-1 bg-gray-100 rounded-lg">
                                    {['Pending', 'Approved', 'Rejected', 'All'].map(s => (
                                        <button
                                            key={s}
                                            onClick={() => fetchApprovals(true, s)}
                                            className={`px-3 py-1 text-[10px] font-bold uppercase tracking-wider rounded-md transition-all ${approvalStatusFilter === s
                                                ? 'bg-white text-blue-600 shadow-sm'
                                                : 'text-gray-400 hover:text-gray-600'
                                                }`}
                                        >
                                            {s}
                                        </button>
                                    ))}
                                </div>
                                <button 
                                    onClick={() => fetchApprovals(true)} 
                                    className="flex items-center gap-1.5 text-xs text-gray-500 hover:text-gray-700 font-medium border border-gray-200 rounded-lg px-3 py-1.5 hover:bg-gray-50 transition-colors"
                                >
                                    <RefreshCw size={12} className={loadingApprovals ? 'animate-spin' : ''} /> Refresh
                                </button>
                            </div>
                        </div>

                        {loadingApprovals ? (
                            <div className="bg-white rounded-xl border border-gray-200 py-16 flex justify-center">
                                <div className="w-7 h-7 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" />
                            </div>
                        ) : approvalRequests.length === 0 ? (
                            <div className="bg-white rounded-xl border border-dashed border-gray-200 py-16 flex flex-col items-center gap-3 text-gray-400">
                                <CheckCircle size={40} className="text-green-300" />
                                <p className="text-sm font-semibold text-gray-600">All caught up!</p>
                                <p className="text-xs">No pending leave requests from your team.</p>
                            </div>
                        ) : (
                            <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
                                <table className="w-full text-sm">
                                    <thead>
                                        <tr className="bg-gray-50 border-b border-gray-100">
                                            <th className="text-left px-6 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wider">Employee</th>
                                            <th className="text-left px-4 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wider">Type</th>
                                            <th className="text-left px-4 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wider">Duration</th>
                                            <th className="text-left px-4 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wider">Days</th>
                                            <th className="text-left px-4 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wider">Reason</th>
                                            <th className="text-left px-4 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wider">Status</th>
                                            <th className="text-right px-6 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wider">Action</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-50">
                                        {approvalRequests.map(req => (
                                            <React.Fragment key={req._id}>
                                            <tr className="hover:bg-gray-50 transition-colors">
                                                <td className="px-6 py-4">
                                                    <div className="flex items-center gap-3">
                                                        <div className="w-8 h-8 rounded-full bg-[#e8f0fe] text-[#1a73e8] flex items-center justify-center font-bold text-sm flex-shrink-0">
                                                            {req.user.firstName.charAt(0)}
                                                        </div>
                                                        <div>
                                                            <p className="font-semibold text-gray-800 text-sm">{req.user.firstName} {req.user.lastName}</p>
                                                            <p className="text-xs text-gray-400 font-mono">{req.user.employeeCode}</p>
                                                        </div>
                                                    </div>
                                                </td>
                                                <td className="px-4 py-4">
                                                    <span className="bg-blue-50 text-[#1a73e8] text-xs font-bold px-2 py-1 rounded border border-blue-100">
                                                        {req.leaveType}
                                                    </span>
                                                </td>
                                                <td className="px-4 py-4 text-gray-600 text-xs whitespace-nowrap">
                                                    <div>{format(new Date(req.startDate), 'dd MMM')}</div>
                                                    <div className="text-gray-400">→ {format(new Date(req.endDate), 'dd MMM yyyy')}</div>
                                                </td>
                                                <td className="px-4 py-4">
                                                    <span className={`inline-flex items-center gap-1 font-bold text-sm ${req.daysCount > 3 ? 'text-orange-600' : 'text-gray-700'}`}>
                                                        {req.daysCount}d
                                                        {req.daysCount > 3 && <AlertCircle size={12} className="text-orange-400" />}
                                                    </span>
                                                    {req.isHalfDay && <span className="text-xs text-gray-400 block">({req.halfDaySession || 'Half day'})</span>}
                                                </td>
                                                <td className="px-4 py-4 text-gray-500 w-[180px] min-w-[180px] max-w-[180px]">
                                                    <div className="text-[11px] truncate" title={req.reason}>
                                                        {req.reason.length > 60 ? `${req.reason.substring(0, 60)}...` : req.reason}
                                                    </div>
                                                </td>
                                                <td className="px-4 py-4">
                                                    <StatusBadge status={req.status} />
                                                </td>
                                                <td className="px-6 py-4">
                                                    <div className="flex items-center justify-end gap-2">
                                                        <button
                                                            onClick={() => toggleRowExpansion(req._id)}
                                                            className={`p-1 rounded transition-colors ${expandedRows.includes(req._id) ? 'text-blue-600 bg-blue-50' : 'text-gray-400 hover:text-blue-500 hover:bg-gray-50'}`}
                                                            title="View details"
                                                        >
                                                            <Eye size={16} />
                                                        </button>
                                                        {req.status === 'Pending' && (
                                                            <>
                                                                <button
                                                                    onClick={() => handleAction(req._id, 'Rejected')}
                                                                    disabled={processingId === req._id}
                                                                    className="flex items-center gap-1 text-xs font-semibold text-red-600 border border-red-200 hover:bg-red-50 px-3 py-1.5 rounded-lg transition-colors disabled:opacity-50"
                                                                >
                                                                    <X size={13} /> Reject
                                                                </button>
                                                                <button
                                                                    onClick={() => handleAction(req._id, 'Approved')}
                                                                    disabled={processingId === req._id}
                                                                    className="flex items-center gap-1 text-xs font-semibold text-white bg-[#1a73e8] hover:bg-[#1557b0] px-3 py-1.5 rounded-lg transition-colors disabled:opacity-50 shadow-sm"
                                                                >
                                                                    <Check size={13} /> Approve
                                                                </button>
                                                            </>
                                                        )}
                                                    </div>
                                                </td>
                                            </tr>
                                            {expandedRows.includes(req._id) && (
                                                <tr className="bg-blue-50/40">
                                                    <td colSpan={7} className="px-6 py-4 border-t border-blue-100">
                                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                                            <div className="bg-white/80 rounded-lg border border-blue-100 p-3">
                                                                <div className="text-[10px] font-bold uppercase tracking-wider text-gray-400 mb-2">Reason</div>
                                                                <div className="text-sm text-gray-700 whitespace-pre-wrap break-words">
                                                                    {req.reason || 'No reason provided'}
                                                                </div>
                                                            </div>
                                                            <div className="bg-white/80 rounded-lg border border-blue-100 p-3">
                                                                <div className="text-[10px] font-bold uppercase tracking-wider text-gray-400 mb-2">Attachment</div>
                                                                {renderLeaveDocuments(req.documents)}
                                                                {req.status === 'Rejected' && req.rejectionReason && (
                                                                    <div className="mt-3 pt-3 border-t border-red-100">
                                                                        <div className="text-[10px] font-bold uppercase tracking-wider text-red-400 mb-1">Rejection Reason</div>
                                                                        <div className="text-sm text-red-700 whitespace-pre-wrap break-words">
                                                                            {req.rejectionReason}
                                                                        </div>
                                                                    </div>
                                                                )}
                                                            </div>
                                                        </div>
                                                    </td>
                                                </tr>
                                            )}
                                            </React.Fragment>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        )}
                    </div>
                )}
            </div>

            {/* ════════════ APPLY MODAL ════════════ */}
            {showModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4" style={{ backdropFilter: 'blur(4px)', backgroundColor: 'rgba(0,0,0,0.4)' }}>
                    <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-fade-in">
                        {/* Modal Header */}
                        <div className="bg-[#1a73e8] px-6 py-5">
                            <div className="flex items-center justify-between">
                                <div>
                                    <h3 className="text-white font-bold text-base">Apply for Leave</h3>
                                    <p className="text-blue-200 text-xs mt-0.5">Fill in your leave request details</p>
                                </div>
                                <button
                                    onClick={() => setShowModal(false)}
                                    className="text-blue-200 hover:text-white transition-colors"
                                >
                                    <X size={20} />
                                </button>
                            </div>
                        </div>

                        {/* Modal Body */}
                        <form onSubmit={handleSubmit} className="p-6 space-y-4">
                            {/* Leave Type */}
                            <div>
                                <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1.5">Leave Type</label>
                                <select
                                    name="leaveType" value={formData.leaveType} onChange={handleChange}
                                    required
                                    className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm text-gray-700 focus:outline-none focus:ring-2 focus:ring-[#1a73e8]/30 focus:border-[#1a73e8] transition bg-white"
                                >
                                    <option value="">— Select leave type —</option>
                                    {balances.map(b => (
                                        <option key={b.leaveType} value={b.leaveType}>
                                            {b.policyName} — Balance: {b.policyAccrualAmount === 0 ? 'Unlimited' : `${b.closingBalance} days`}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            {/* Dates */}
                            <div className="grid grid-cols-2 gap-3">
                                <div>
                                    <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1.5">From Date</label>
                                    <input
                                        type="date" name="startDate" value={formData.startDate} onChange={handleChange} required
                                        className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm text-gray-700 focus:outline-none focus:ring-2 focus:ring-[#1a73e8]/30 focus:border-[#1a73e8] transition"
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1.5">To Date</label>
                                    <input
                                        type="date" name="endDate" value={formData.endDate} onChange={handleChange} required
                                        className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm text-gray-700 focus:outline-none focus:ring-2 focus:ring-[#1a73e8]/30 focus:border-[#1a73e8] transition"
                                    />
                                </div>
                            </div>

                            {/* Half Day Toggle */}
                            <div className="flex items-center gap-3 p-3 bg-gray-50 rounded-lg border border-gray-100">
                                <div
                                    onClick={() => setFormData(p => ({ ...p, isHalfDay: !p.isHalfDay }))}
                                    className={`relative w-9 h-5 rounded-full cursor-pointer transition-colors ${formData.isHalfDay ? 'bg-[#1a73e8]' : 'bg-gray-300'}`}
                                >
                                    <span className={`absolute top-0.5 w-4 h-4 rounded-full bg-white shadow transition-all ${formData.isHalfDay ? 'left-[18px]' : 'left-0.5'}`} />
                                </div>
                                <span className="text-sm font-medium text-gray-700">Half Day Leave</span>
                            </div>

                            {formData.isHalfDay && (
                                <div>
                                    <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1.5">Session</label>
                                    <div className="grid grid-cols-2 gap-2">
                                        {['First Half', 'Second Half'].map(s => (
                                            <button
                                                key={s} type="button"
                                                onClick={() => setFormData(p => ({ ...p, halfDaySession: s }))}
                                                className={`py-2 rounded-lg text-sm font-medium border transition-colors ${formData.halfDaySession === s ? 'bg-[#e8f0fe] border-[#1a73e8] text-[#1a73e8]' : 'border-gray-200 text-gray-600 hover:bg-gray-50'}`}
                                            >
                                                {s}
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* Optional / Required Document Upload */}
                            {(() => {
                                const policy = balances.find(b => b.leaveType === formData.leaveType);
                                if (!policy || !policy.proofRequiredAbove) return null;

                                let daysCount = 0;
                                if (formData.startDate && formData.endDate) {
                                    const s = new Date(formData.startDate);
                                    const e = new Date(formData.endDate);
                                    if (s <= e) {
                                        if (formData.isHalfDay) {
                                            daysCount = 0.5;
                                        } else {
                                            // Rough client-side check (backend validates properly)
                                            let d = new Date(s);
                                            while (d <= e) {
                                                if (d.getDay() !== 0 && d.getDay() !== 6) daysCount++;
                                                d.setDate(d.getDate() + 1);
                                            }
                                        }
                                    }
                                }

                                const isRequired = daysCount > policy.proofRequiredAbove;
                                if (daysCount > 0) {
                                    return (
                                        <div>
                                            <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1.5 flex justify-between">
                                                <span>Proof Document</span>
                                                {isRequired ? <span className="text-red-500 font-bold">* Required</span> : <span className="text-gray-400">Optional</span>}
                                            </label>
                                            <input
                                                type="file" accept=".pdf,.jpg,.jpeg,.png"
                                                onChange={handleFileChange}
                                                required={isRequired}
                                                className="w-full text-sm text-gray-500 border border-gray-200 rounded-lg p-2
                                                file:mr-4 file:py-2 file:px-4 file:rounded-md file:border-0
                                                file:text-sm file:font-semibold file:bg-blue-50 file:text-[#1a73e8] hover:file:bg-blue-100 transition"
                                            />
                                            {isRequired && (
                                                <p className="text-[10px] text-red-500 mt-1.5 font-medium">
                                                    You requested {daysCount} days. A medical certificate or proof is required for {policy.leaveType} exceeding {policy.proofRequiredAbove} days.
                                                </p>
                                            )}
                                        </div>
                                    );
                                }
                                return null;
                            })()}

                            {/* Reason */}
                            <div>
                                <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1.5">Reason</label>
                                <textarea
                                    name="reason" rows="3" value={formData.reason} onChange={handleChange}
                                    required placeholder="Briefly describe your reason for leave…"
                                    className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm text-gray-700 resize-none focus:outline-none focus:ring-2 focus:ring-[#1a73e8]/30 focus:border-[#1a73e8] transition"
                                />
                            </div>

                            {/* Actions */}
                            <div className="flex items-center justify-end gap-2 pt-2 border-t border-gray-100">
                                <button
                                    type="button" onClick={() => setShowModal(false)}
                                    className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                                >
                                    Cancel
                                </button>
                                <button
                                    type="submit"
                                    disabled={processingId === 'apply'}
                                    className="px-5 py-2 text-sm font-semibold text-white bg-[#1a73e8] hover:bg-[#1557b0] rounded-lg transition-colors shadow-sm disabled:opacity-50"
                                >
                                    {processingId === 'apply' ? 'Processing...' : 'Submit Request'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

        </div>
    );
};

export default Leaves;

import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate, Link } from 'react-router-dom';
import toast from 'react-hot-toast';
import { motion } from 'framer-motion';
import { Mail, Lock, ArrowRight, Loader2, CheckCircle2, Eye, EyeOff } from 'lucide-react';
import Button from '../components/Button';

const Login = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [focusedInput, setFocusedInput] = useState(null);
  const [showPassword, setShowPassword] = useState(false);

  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    try {
      const data = await login(email, password);
      
      if (data?.passwordResetRequired) {
        toast.success("Identity verification required");
        navigate('/reset-password', { state: { email: data.email, userId: data.userId } });
        return;
      }

      toast.success("Welcome back!");
      navigate('/');
    } catch (error) {
      toast.error(error.response?.data?.message || 'Login Failed');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex bg-slate-50 font-sans overflow-hidden">
      {/* Essential Branding / Hero Section */}
      <div className="hidden lg:flex w-1/2 bg-slate-900 relative items-center justify-center overflow-hidden">
        {/* Abstract Background Shapes */}
        <div className="absolute inset-0 bg-gradient-to-br from-blue-900/40 to-slate-900 z-0" />
        <motion.div
          animate={{
            scale: [1, 1.1, 1],
            rotate: [0, 5, 0],
          }}
          transition={{
            duration: 20,
            repeat: Infinity,
            ease: "easeInOut"
          }}
          className="absolute -top-24 -left-24 w-96 h-96 bg-blue-600/20 rounded-full blur-3xl z-0 pointer-events-none"
        />
        <motion.div
          animate={{
            scale: [1, 1.2, 1],
            rotate: [0, -5, 0],
          }}
          transition={{
            duration: 25,
            repeat: Infinity,
            ease: "easeInOut",
            delay: 2
          }}
          className="absolute top-1/2 right-0 w-[500px] h-[500px] bg-indigo-600/10 rounded-full blur-3xl z-0 pointer-events-none"
        />

        {/* Content */}
        <div className="relative z-10 p-12 text-white max-w-lg">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
          >
