                                                                </div>
                                                            ) : (
                                                                <span className="italic text-slate-400">Values matched exactly (No sub-field changes)</span>
                                                            )}
                                                        </td>
                                                    </tr>
                                                ))}
                                            </tbody>
                                        </table>
                                    </div>
                                </div>
                            )}

                            {importResults.failed.length > 0 && (
                                <div className="w-full mt-4">
