                                            Approval Timeline
                                        </h3>
                                    </div>
                                    <div className="p-5">
                                        <div className="relative pl-4 border-l-2 border-slate-100 space-y-5">
                                            {request.approvalChain.map((step, index) => (
                                                <div key={index} className="relative">
                                                    {/* Timeline Dot */}
                                                    <div className={`absolute -left-[21px] top-1 h-4 w-4 rounded-full border-2 border-white shadow-sm ${step.status === 'Approved' ? 'bg-emerald-500 ring-4 ring-emerald-50' :
                                                        step.status === 'Rejected' ? 'bg-red-500 ring-4 ring-red-50' :
                                                            'bg-slate-300 ring-4 ring-slate-50'
                                                        }`}></div>

                                                    <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start gap-2">
                                                        <div>
                                                            <p className="text-sm font-bold text-slate-800">
                                                                Level {step.level} <span className="font-normal text-slate-500 mx-1">/</span> {step.roleName || 'Approver'}
                                                            </p>
                                                            <p className="text-xs text-slate-500 mt-1">
                                                                {step.status === 'Pending' ? 'Waiting for:' : 'Assigned to:'} <span className="font-medium text-slate-700">{step.approvers?.map(a => `${a.firstName} ${a.lastName}`).join(', ')}</span>
                                                            </p>
                                                            {step.status !== 'Pending' && (
                                                                <p className="text-xs text-slate-500 mt-0.5">
                                                                    {step.status} by <span className="font-medium text-slate-700">{step.approvedBy?.firstName} {step.approvedBy?.lastName}</span>
                                                                </p>
                                                            )}
                                                        </div>
                                                        <span className={`px-2 py-0.5 rounded text-xs font-bold uppercase tracking-wider ${step.status === 'Approved' ? 'bg-emerald-50 text-emerald-600' :
                                                            step.status === 'Rejected' ? 'bg-red-50 text-red-600' :
                                                                'bg-slate-100 text-slate-500'
                                                            }`}>
                                                            {step.status}
                                                        </span>
                                                    </div>

                                                    {step.date && (
                                                        <p className="text-xs text-slate-400 mt-1 flex items-center gap-1">
                                                            <Clock size={12} /> {format(new Date(step.date), 'MMM dd, yyyy • hh:mm a')}
                                                        </p>
                                                    )}

                                                    {step.comments && (
                                                        <div className="mt-3 bg-slate-50 p-3 rounded-lg border border-slate-100 text-sm text-slate-600 italic relative">
                                                            <span className="absolute top-2 left-2 text-slate-300 text-xl font-serif">"</span>
                                                            <span className="pl-4">{step.comments}</span>
                                                        </div>
                                                    )}
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                </section>
                            )}
                        </div>

                        {/* Sidebar */}
                        <div className="space-y-4">
                            {/* Hiring Details Card */}
                            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4 hover:shadow-md transition-shadow duration-300">
                                <h3 className="text-sm font-bold text-slate-800 mb-4 flex items-center gap-2 pb-3 border-b border-slate-50">
                                    <div className="p-1.5 bg-amber-100 text-amber-600 rounded-md">
                                        <DollarSign size={14} />
                                    </div>
                                    Hiring Specifics
                                </h3>
                                <div className="space-y-3">
                                    <div className="flex justify-between items-center group">
                                        <span className="text-slate-500 text-xs font-medium">Open Positions</span>
                                        <span className="text-slate-900 font-bold text-xs bg-slate-100 px-2 py-0.5 rounded group-hover:bg-blue-50 group-hover:text-blue-600 transition-colors">{request.hiringDetails.openPositions}</span>
                                    </div>
                                    <div className="flex justify-between items-center">
                                        <span className="text-slate-500 text-xs font-medium">Expected Joining</span>
                                        <span className="text-slate-900 font-semibold text-xs text-right">{request.hiringDetails.expectedJoiningDate ? format(new Date(request.hiringDetails.expectedJoiningDate), 'MMM dd, yyyy') : '-'}</span>
                                    </div>
                                    <div className="pt-3 border-t border-slate-50">
                                        <p className="text-xs font-bold text-slate-400 uppercase mb-1.5">Budget Range</p>
                                        <div className="flex items-baseline gap-1">
                                            <span className="text-sm font-bold text-slate-800">{request.hiringDetails.budgetRange?.min?.toLocaleString()}</span>
                                            <span className="text-slate-400 text-xs">to</span>
                                            <span className="text-sm font-bold text-slate-800">{request.hiringDetails.budgetRange?.max?.toLocaleString()}</span>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            {/* Position Created By Card */}
                            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4 hover:shadow-md transition-shadow duration-300">
                                <h3 className="text-sm font-bold text-slate-800 mb-4 flex items-center gap-2 pb-3 border-b border-slate-50">
                                    <div className="p-1.5 bg-indigo-100 text-indigo-600 rounded-md">
                                        <User size={14} />
                                    </div>
                                    Created By
                                </h3>
                                <div className="flex items-center gap-3">
                                    <div className="h-9 w-9 rounded-full bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center text-white font-bold text-sm shadow-md ring-2 ring-blue-50">
                                        {request.createdBy?.firstName?.charAt(0)}
                                    </div>
                                    <div>
                                        <p className="text-xs font-bold text-slate-800">{request.createdBy?.firstName} {request.createdBy?.lastName}</p>
                                        <p className="text-xs text-slate-500">{request.createdBy?.email}</p>
                                        <p className="text-xs text-slate-400 mt-0.5">
                                            on {format(new Date(request.createdAt), 'MMM dd, yyyy')}
                                        </p>
                                    </div>
                                </div>
                            </div>

                            {/* Status Card */}
                            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4 hover:shadow-md transition-shadow duration-300">
                                <h3 className="text-sm font-bold text-slate-800 mb-3 flex items-center gap-2 pb-3 border-b border-slate-50">
                                    <div className="p-1.5 bg-slate-100 text-slate-600 rounded-md">
                                        <CheckCircle size={14} />
                                    </div>
                                    Status
                                </h3>
                                <div className={`inline-flex items-center px-3 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wider border ${request.status === 'Approved' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' :
                                    request.status === 'Rejected' ? 'bg-red-50 text-red-700 border-red-200' :
                                        request.status === 'Closed' ? 'bg-gray-100 text-gray-600 border-gray-200' :
                                            request.status === 'Pending_L1' || request.status === 'Pending_Approval' ? 'bg-amber-50 text-amber-700 border-amber-200' :
                                                request.status === 'Pending_Final' ? 'bg-purple-50 text-purple-700 border-purple-200' :
                                                    'bg-blue-50 text-blue-700 border-blue-200'
                                    }`}>
                                    {request.status.replace(/_/g, ' ')}
                                </div>
                            </div>

                            {/* Actions Card */}
                            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4 hover:shadow-md transition-shadow duration-300">
                                <h3 className="text-sm font-bold text-slate-800 mb-3">Actions</h3>
                                <div className="space-y-3">
                                    <button
                                        onClick={handleEdit}
                                        className="w-full flex items-center justify-center gap-2 px-4 py-2.5 bg-slate-900 hover:bg-slate-800 text-white rounded-xl font-medium text-sm transition-all shadow-sm hover:shadow"
                                    >
                                        <Edit size={16} /> Edit Request
                                    </button>

                                    {request.status !== 'Closed' && (
                                        <button
                                            onClick={handleClose}
                                            disabled={actionLoading}
                                            className="w-full flex items-center justify-center gap-2 px-4 py-2.5 bg-white border border-slate-200 text-slate-600 hover:text-red-600 hover:border-red-200 hover:bg-red-50 rounded-xl font-medium text-sm transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                                        >
                                            {actionLoading ? <Loader className="animate-spin" size={16} /> : <XCircle size={16} />} Close Request
                                        </button>
                                    )}

                                    {request.status === 'Closed' && !request.reopenedToId && (
                                        <button
                                            onClick={() => navigate(`/ta/create-request?reopenFrom=${id}`)}
                                            className="w-full flex items-center justify-center gap-2 px-4 py-2.5 bg-blue-50 border border-blue-200 text-blue-700 hover:bg-blue-100 rounded-xl font-medium text-sm transition-all shadow-sm"
                                        >
                                            <Briefcase size={16} /> Reopen Requisition
                                        </button>
                                    )}

                                    {request.reopenedToId && (
                                        <div className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-center shadow-inner">
                                            <p className="text-xs font-semibold text-slate-600 mb-2">Superseded By</p>
                                            <button
                                                onClick={() => navigate(`/ta/view/${request.reopenedToId}`)}
                                                className="text-blue-600 hover:text-blue-800 font-bold text-sm underline transition-colors"
                                            >
                                                View Active Requisition
                                            </button>
                                        </div>
                                    )}

                                </div>
                            </div>

                            {/* Approval Action */}
                            {canApprove && (
                                <div className="bg-gradient-to-br from-blue-600 to-indigo-700 rounded-2xl shadow-lg shadow-blue-200 p-6 text-white relative overflow-hidden">
                                    <div className="absolute top-0 right-0 p-4 opacity-10">
                                        <Send size={64} />
                                    </div>
                                    <h3 className="font-bold text-white mb-2 relative z-10 text-lg">Approval Required</h3>
                                    <p className="text-xs text-blue-100 mb-4 relative z-10">Please review the details and take action.</p>

                                    <textarea
                                        value={approvalComment}
                                        onChange={(e) => setApprovalComment(e.target.value)}
                                        placeholder="Add comments (required for rejection)..."
                                        className="w-full p-3 bg-white/10 border border-white/20 rounded-xl text-sm mb-4 outline-none focus:bg-white/20 placeholder-blue-200 text-white transition-all backdrop-blur-sm"
                                        rows={3}
                                    />

                                    <div className="grid grid-cols-2 gap-3 relative z-10">
                                        <button
                                            onClick={() => handleApproval('APPROVE')}
                                            disabled={actionLoading}
                                            className="flex items-center justify-center gap-2 py-2.5 bg-white text-blue-600 hover:bg-blue-50 rounded-xl font-bold text-sm transition-colors shadow-sm disabled:opacity-50 disabled:cursor-not-allowed"
                                        >
                                            {actionLoading ? <Loader className="animate-spin" size={16} /> : <ThumbsUp size={16} />} Approve
                                        </button>
                                        <button
                                            onClick={() => handleApproval('REJECT')}
                                            disabled={actionLoading}
                                            className="flex items-center justify-center gap-2 py-2.5 bg-white/10 border border-white/20 text-white hover:bg-white/20 rounded-xl font-bold text-sm transition-colors backdrop-blur-sm disabled:opacity-50 disabled:cursor-not-allowed"
                                        >
                                            {actionLoading ? <Loader className="animate-spin" size={16} /> : <ThumbsDown size={16} />} Reject
                                        </button>
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {activeTab === 'applications' && (
                    <CandidateList hiringRequestId={id} positionName={request?.positionName} />
                )}

                {activeTab === 'legacy applications' && request.previousRequestId && (
                    <LegacyApplicationsView hiringRequestId={id} />
                )}

            </div>
        </div>
    );
};

export default HiringRequestDetails;

import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';
import api from '../../api/axios';
import { useAuth } from '../../context/AuthContext';
import { Plus, Search, Filter, Briefcase, Clock, CheckCircle, XCircle, AlertCircle, Settings, TrendingUp, ChevronRight } from 'lucide-react';
import { format } from 'date-fns';
import Skeleton from '../../components/Skeleton';

const HiringRequestList = () => {
    const { user } = useAuth();
    const { clientName } = useParams();
    const [requests, setRequests] = useState([]);
    const [clients, setClients] = useState([]);
    const [loading, setLoading] = useState(true);
    const [filterStatus, setFilterStatus] = useState('Approved'); // Default to Approved
    const [page, setPage] = useState(1);
    const [totalPages, setTotalPages] = useState(1);
    const navigate = useNavigate();

    const fetchRequests = async () => {
        try {
            setLoading(true);
            const [reqRes, clientRes] = await Promise.all([
                api.get('/ta/hiring-request', {
                    params: {
                        status: filterStatus === 'All' ? '' : filterStatus,
                        page,
                        limit: 10,
                        client: clientName ? decodeURIComponent(clientName) : ''
                    }
                }),
                api.get('/projects/clients')
            ]);
            // Backend now returns an object with requests and totalPages
            setRequests(reqRes.data.requests ? reqRes.data.requests : reqRes.data);
            if (reqRes.data.totalPages) {
                setTotalPages(reqRes.data.totalPages);
            } else {
                setTotalPages(1); // Fallback if backend hasn't updated immediately
            }
            setClients(clientRes.data);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const handleFilterChange = (status) => {
        setFilterStatus(status === 'All' ? 'All' : status === 'Pending' ? 'Pending_Approval' : status);
        setPage(1);
    };

    useEffect(() => {
        fetchRequests();
    }, [filterStatus, page]);

    const getClientIdByName = (name) => {
        const client = clients.find(c => c.name === name);
        return client ? client._id : null;
    };

    const getStatusBadge = (status) => {
        const styles = {
            'Draft': 'bg-slate-100 text-slate-600',
            'Submitted': 'bg-blue-50 text-blue-600',
            'Pending_L1': 'bg-amber-50 text-amber-600',
            'Pending_Approval': 'bg-amber-50 text-amber-600',
            'Pending_Final': 'bg-purple-50 text-purple-600',
            'Approved': 'bg-emerald-50 text-emerald-600',
            'Rejected': 'bg-red-50 text-red-600',
            'Closed': 'bg-gray-100 text-gray-600',
            'On_Hold': 'bg-gray-200 text-gray-600'
        };
        return (
            <span className={`px-2.5 py-0.5 rounded-full text-xs font-medium ${styles[status] || styles['Draft']}`}>
                {status?.replace('_', ' ')}
            </span>
        );
    };

    return (
        <div className="min-h-screen bg-slate-50">
            {/* Sticky Top Navbar */}
            <div className="bg-white border-b border-slate-200 sticky top-0 z-10 shadow-sm">
                <div className="w-full mx-auto px-4 sm:px-6 lg:px-8 py-4 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                    <div className="flex flex-col">
                        <div className="flex items-center gap-2 text-sm text-slate-500 mb-1">
                            <Link to="/ta" className="hover:text-blue-600 transition-colors">Talent Acquisition</Link>
                            <ChevronRight size={14} />
                            <span className="font-medium text-slate-800">{clientName ? decodeURIComponent(clientName) : 'All Positions'}</span>
                        </div>
                        <h1 className="text-xl font-bold text-slate-800">
                            {clientName ? `${decodeURIComponent(clientName)} Positions` : 'Talent Acquisition'}
                        </h1>
                    </div>
                    <div className="flex flex-wrap gap-3 w-full sm:w-auto">
                        <Link
                            to="/ta/workflows"
                            className="bg-white border border-slate-300 hover:bg-slate-50 text-slate-700 px-4 py-2 rounded-lg flex items-center gap-2 transition-colors font-medium text-sm"
                        >
                            <Settings size={18} /> Workflows
                        </Link>
                        <Link
                            to="/ta/analysis"
                            className="bg-white border border-slate-300 hover:bg-blue-50 text-slate-700 hover:text-blue-700 hover:border-blue-200 px-4 py-2 rounded-lg flex items-center gap-2 transition-all font-medium text-sm shadow-sm"
                        >
                            <TrendingUp size={18} /> Global Analysis
                        </Link>
                        {(user?.roles?.includes('Admin') || user?.permissions?.includes('ta.create')) && (
                            <Link
                                to="/ta/create-request"
                                className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors font-medium text-sm shadow-sm"
                            >
                                <Plus size={18} /> Raising Requisition
                            </Link>
                        )}
                    </div>
                </div>
            </div>

            {/* Main Content */}
            <div className="w-full mx-auto px-4 sm:px-6 lg:px-8 py-6">
                {/* Filter Section */}
                <div className="bg-white p-4 rounded-lg border border-slate-200 shadow-sm mb-6">
                    <div className="flex flex-col sm:flex-row items-start sm:items-center gap-4">
                        <div className="flex items-center gap-2 text-slate-600 whitespace-nowrap">
                            <Filter size={16} />
                            <span className="text-sm font-medium">Filter by Status:</span>
                        </div>
                        <div className="flex flex-wrap gap-2">
                            {['All', 'Pending', 'Draft', 'Approved', 'Closed'].map((status) => (
                                <button
                                    key={status}
                                    onClick={() => handleFilterChange(status)}
                                    className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${(filterStatus === status ||
                                        (status === 'Pending' && filterStatus === 'Pending_Approval') ||
                                        (status === 'All' && filterStatus === 'All'))
                                        ? 'bg-blue-600 text-white'
                                        : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                                        }`}
                                >
                                    {status}
                                </button>
                            ))}
                        </div>
                    </div>
                </div>

                {/* Table */}
                <div className="bg-white rounded-lg border border-slate-200 shadow-sm overflow-x-auto">
                    <table className="w-full text-sm text-left min-w-[900px]">
                        <thead className="bg-slate-50 text-slate-500 font-medium border-b border-slate-200">
                            <tr>
                                <th className="px-6 py-4">Request ID</th>
                                <th className="px-6 py-4">Client</th>
                                <th className="px-6 py-4">Role & Dept</th>
                                <th className="px-6 py-4">Created On</th>
                                <th className="px-6 py-4">Status</th>
                                <th className="px-6 py-4 text-right">Action</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {loading ? (
                                [...Array(5)].map((_, i) => (
                                    <tr key={i}>
                                        <td colSpan="6" className="p-4"><Skeleton className="h-8 w-full" /></td>
                                    </tr>
                                ))
                            ) : requests.length === 0 ? (
                                <tr>
                                    <td colSpan="6" className="p-8 text-center text-slate-500">
                                        No hiring requests found for the selected filter.
                                    </td>
                                </tr>
                            ) : (
                                requests.map(req => (
                                    <tr key={req._id} className="hover:bg-slate-50/50 transition-colors group">
                                        <td className="px-6 py-4 font-medium text-slate-700">
                                            {req.requestId}
                                        </td>
                                        <td className="px-6 py-4 font-medium text-blue-600">
                                            {req.client ? (
                                                (() => {
                                                    const clientId = getClientIdByName(req.client);
                                                    return clientId ? (
                                                        <Link
                                                            to={`/clients/${clientId}/view?tab=ta`}
                                                            className="hover:text-blue-800 hover:underline transition-colors"
                                                            title="View Client TA Dashboard"
                                                        >
                                                            {req.client}
                                                        </Link>
                                                    ) : (
                                                        <span>{req.client}</span>
                                                    );
                                                })()
                                            ) : '-'}
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="font-semibold text-slate-800">{req.roleDetails.title}</div>
                                            <div className="text-xs text-slate-500">{req.roleDetails.department} • {req.roleDetails.employmentType}</div>
                                        </td>
                                        <td className="px-6 py-4 text-slate-600">
                                            {format(new Date(req.createdAt), 'dd MMM yyyy')}
                                        </td>
                                        <td className="px-6 py-4">
                                            {getStatusBadge(req.status)}
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            <button
                                                onClick={() => navigate(`/ta/view/${req._id}${(req.status === 'Approved' || req.status === 'Closed') ? '?tab=applications' : ''}`)}
                                                className="text-blue-600 hover:text-blue-800 font-medium text-xs px-3 py-1.5 bg-blue-50 hover:bg-blue-100 rounded-md transition-colors"
                                            >
                                                View Details
                                            </button>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>

                {/* Pagination Controls */}
                {!loading && (
                    <div className="flex justify-end items-center mt-6 gap-4 pr-4">
                        <button
                            onClick={() => setPage(p => Math.max(1, p - 1))}
                            disabled={page === 1}
                            className="px-4 py-2 bg-white border border-slate-300 rounded-lg text-sm font-medium text-slate-700 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed focus:outline-none focus:ring-2 focus:ring-blue-500 transition-colors"
                        >
                            Previous
                        </button>
                        <span className="text-sm font-medium text-slate-600 min-w-[100px] text-center">
                            Page {page} of {totalPages}
                        </span>
                        <button
                            onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                            disabled={page === totalPages}
                            className="px-4 py-2 bg-white border border-slate-300 rounded-lg text-sm font-medium text-slate-700 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed focus:outline-none focus:ring-2 focus:ring-blue-500 transition-colors"
                        >
                            Next
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
};

export default HiringRequestList;

import React, { useState, useEffect, useCallback } from 'react';
import { createPortal } from 'react-dom';
import { format } from 'date-fns';
import {
    Calendar, ChevronDown, ChevronUp, Users, Eye, FileText,
    Briefcase, MoreVertical, ArrowRight, Download, Plus,
    CheckCircle, UserCheck, ThumbsUp, Clock, ThumbsDown, XCircle, Upload, Search
} from 'lucide-react';
import api from '../../api/axios';
import toast from 'react-hot-toast';
import { useNavigate } from 'react-router-dom';
import * as ExcelJS from 'exceljs';
import { saveAs } from 'file-saver';
import { useAuth } from '../../context/AuthContext';
import Skeleton from '../../components/Skeleton';

const decisionColor = (d) => {
    switch (d) {
        case 'Shortlisted': return 'bg-sky-100 text-sky-700 border-sky-200';
        case 'Rejected': return 'bg-red-100 text-red-700 border-red-200';
        case 'On Hold': return 'bg-amber-100 text-amber-700 border-amber-200';
        case 'Selected': return 'bg-purple-100 text-purple-700 border-purple-200';
        case 'None': return 'bg-slate-100 text-slate-500 border-slate-200';
        default: return 'bg-slate-100 text-slate-500 border-slate-200';
    }
};

const OpeningSection = ({ opening, openingNum, hiringRequestId, onTransfer, users }) => {
    const [expanded, setExpanded] = useState(openingNum === 1); // most recent expanded by default
    const [activePhase, setActivePhase] = useState(1);
    const [activeMenu, setActiveMenu] = useState(null);
    const [menuPosition, setMenuPosition] = useState({});
    const navigate = useNavigate();
    const { user } = useAuth();

    // Filtering State
    const [filterPreference, setFilterPreference] = useState('All');
    const [filterStatus, setFilterStatus] = useState('Interested');
    const [filterDecision, setFilterDecision] = useState('All');
    const [filterExperience, setFilterExperience] = useState('');
    const [filterInterviewStatus, setFilterInterviewStatus] = useState('All');
    const [filterRating, setFilterRating] = useState('All');
    const [filterPulledBy, setFilterPulledBy] = useState('All');
    const [filterTransferred, setFilterTransferred] = useState('All');


    const toggleMenu = (e, candidateId) => {
        e.stopPropagation();
        if (activeMenu === candidateId) { setActiveMenu(null); return; }
        const rect = e.currentTarget.getBoundingClientRect();
        const spaceBelow = window.innerHeight - rect.bottom;
        const menuHeight = 220;
        let pos = { right: window.innerWidth - rect.right };
        if (spaceBelow < menuHeight && rect.top > menuHeight) {
            pos.bottom = window.innerHeight - rect.top + 5;
        } else {
            pos.top = rect.bottom + 5;
        }
        setMenuPosition(pos);
        setActiveMenu(candidateId);
    };

    const { requisition, candidates } = opening;
    const openedAt = requisition.createdAt ? format(new Date(requisition.createdAt), 'MMM dd, yyyy') : '—';
    const closedAt = requisition.closedAt ? format(new Date(requisition.closedAt), 'MMM dd, yyyy') : 'Ongoing';
    const positionName = requisition.title || 'Position';

    // Metric Calculations (similar to CandidateList logic)
    const metrics = {
        total: candidates.length,
        totalSourced: candidates.filter(c => c.status !== 'Not Relevant').length,
        interested: candidates.filter(c => c.status === 'Interested').length,
        inInterviews: candidates.filter(c => c.decision === 'None' && c.interviewRounds?.length > 0 && !c.interviewRounds.some(r => r.status === 'Failed')).length,
        shortlisted: candidates.filter(c => c.decision === 'Shortlisted').length,
        onHold: candidates.filter(c => c.decision === 'On Hold').length,
        transferred: candidates.filter(c => c.isTransferred).length,
        conversion: candidates.length > 0 ? ((candidates.filter(c => c.phase3Decision === 'Joined' && c.phase2Decision === 'Selected').length / (candidates.filter(c => c.status !== 'Not Relevant').length || 1)) * 100).toFixed(1) : 0
    };



    const phase2Metrics = {
        totalShortlisted: candidates.filter(c => c.decision === 'Shortlisted' || c.decision === 'Selected').length,
        totalScreened: candidates.filter(c => (c.decision === 'Shortlisted' || c.decision === 'Selected') && (c.phase2Decision === 'Shortlisted' || c.phase2Decision === 'Selected')).length,
        interviewScheduled: candidates.filter(c => (c.decision === 'Shortlisted' || c.decision === 'Selected') && c.phase2Decision === 'None' && c.interviewRounds?.some(r => r.phase === 2 && (r.status === 'Scheduled' || r.status === 'Pending'))).length,
        selected: candidates.filter(c => (c.decision === 'Shortlisted' || c.decision === 'Selected') && c.phase2Decision === 'Selected').length,
        rejected: candidates.filter(c => (c.decision === 'Shortlisted' || c.decision === 'Selected') && c.phase2Decision === 'Rejected').length
    };

    const phase3Metrics = {
        total: candidates.filter(c => c.phase2Decision === 'Selected').length,
        offerSent: candidates.filter(c => c.phase2Decision === 'Selected' && c.phase3Decision === 'Offer Sent').length,
        offerAccepted: candidates.filter(c => c.phase2Decision === 'Selected' && c.phase3Decision === 'Offer Accepted').length,
        joined: candidates.filter(c => c.phase2Decision === 'Selected' && c.phase3Decision === 'Joined').length,
        noShow: candidates.filter(c => c.phase2Decision === 'Selected' && (c.phase3Decision === 'No Show' || c.phase3Decision === 'Offer Declined')).length
    };


    // Filter Logic
    const filteredCandidates = candidates.filter(candidate => {
        if (filterPreference !== 'All' && candidate.profilePreference !== filterPreference) return false;
        if (filterStatus !== 'All' && candidate.status !== filterStatus) return false;

        // Phase-specific Filtering
        if (activePhase === 1) {
            if (filterDecision !== 'All' && candidate.decision !== filterDecision) return false;
        } else if (activePhase === 2) {
            if (candidate.decision !== 'Shortlisted' && candidate.decision !== 'Selected') return false;
            if (filterDecision !== 'All') {
                if (filterDecision === 'Shortlisted_Selected' && candidate.phase2Decision !== 'Shortlisted' && candidate.phase2Decision !== 'Selected') return false;
                if (filterDecision !== 'Shortlisted_Selected' && candidate.phase2Decision !== filterDecision) return false;
            }
        } else if (activePhase === 3) {
            if (candidate.phase2Decision !== 'Selected') return false;
            if (filterDecision !== 'All') {
                if (filterDecision === 'No Show_Offer Declined' && candidate.phase3Decision !== 'No Show' && candidate.phase3Decision !== 'Offer Declined') return false;
                if (filterDecision !== 'No Show_Offer Declined' && candidate.phase3Decision !== filterDecision) return false;
            }
        }

        if (filterExperience && parseFloat(candidate.totalExperience) < parseFloat(filterExperience)) return false;
        if (filterRating !== 'All' && (candidate.averageRating || 0) < parseInt(filterRating)) return false;
        if (filterPulledBy !== 'All' && candidate.profilePulledBy !== filterPulledBy) return false;
        if (filterTransferred !== 'All') {
            if (filterTransferred === 'Transferred' && !candidate.isTransferred) return false;
            if (filterTransferred === 'New' && candidate.isTransferred) return false;
        }

        // Interview Status Filter
        if (filterInterviewStatus !== 'All') {
            const rounds = candidate.interviewRounds ? candidate.interviewRounds.filter(r => (r.phase || 1) === activePhase) : [];
            const hasPassed = rounds.length > 0 && rounds.every(r => r.status === 'Passed');
            const hasFailed = rounds.some(r => r.status === 'Failed');
            const hasInProcess = rounds.some(r => r.status === 'Scheduled' || r.status === 'Pending' || r.status === 'In Progress');

            if (filterInterviewStatus === 'None' && rounds.length > 0) return false;
            if (filterInterviewStatus === 'In_Process' && (hasFailed || rounds.length === 0)) return false;
            if (filterInterviewStatus === 'Pending' && !hasInProcess) return false;
            if (filterInterviewStatus === 'Passed' && !hasPassed) return false;
            if (filterInterviewStatus === 'Failed' && !hasFailed) return false;
        }

        return true;
    });



    const renderTable = (candidateList, phaseIndex) => {
        if (candidateList.length === 0) {
            return (
                <div className="bg-white rounded-xl border border-slate-200 p-12 text-center my-4 mx-6">
                    <Search className="mx-auto text-slate-300 mb-4" size={48} />
                    <h3 className="text-lg font-semibold text-slate-700 mb-2">No Matches Found</h3>
                    <p className="text-slate-500">Try adjusting your filters to see more candidates.</p>
                </div>
            );
        }
        return (
            <div className="overflow-x-auto p-6 pt-2">
                <div className="bg-white rounded-xl border border-slate-200 overflow-hidden shadow-sm">
                    <table className="w-full min-w-[1000px]">
                        <thead className="bg-slate-50 border-b border-slate-200">
                            <tr>
                                <th className="px-4 py-3 text-left text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Candidate</th>
                                <th className="px-4 py-3 text-left text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Contact</th>
                                <th className="px-4 py-3 text-left text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Experience</th>
                                <th className="px-4 py-3 text-left text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Decision</th>
                                {phaseIndex === 1 && <th className="px-4 py-3 text-left text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Pulled By</th>}
                                <th className="px-4 py-3 text-center text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {candidateList.map(candidate => {
                                let decision = candidate.decision || 'None';
                                if (phaseIndex === 2) decision = candidate.phase2Decision || 'None';
                                if (phaseIndex === 3) decision = candidate.phase3Decision || 'None';

                                return (
                                    <tr key={candidate._id} className="hover:bg-slate-50 transition-colors">
                                        <td className="px-4 py-3">
                                            <div>
                                                <span className="text-[13px] font-bold text-slate-800">{candidate.candidateName}</span>
                                                {candidate.isTransferred && (
                                                    <span className="ml-2 text-[10px] font-bold bg-blue-100 text-blue-700 px-1.5 py-0.5 rounded border border-blue-200">TRANSFERRED</span>
                                                )}
                                            </div>
                                        </td>
                                        <td className="px-4 py-3">
                                            <div className="text-[12px] text-slate-500">
                                                <div>{candidate.email}</div>
                                                <div>{candidate.mobile}</div>
                                            </div>
                                        </td>
                                        <td className="px-4 py-3">
                                            <span className="text-[13px] font-semibold text-slate-700">{candidate.totalExperience || '—'} yrs</span>
                                        </td>
                                        <td className="px-4 py-3">
                                            <span className={`text-[11px] font-bold px-2 py-1 rounded-lg border ${decisionColor(decision)}`}>
                                                {decision}
                                            </span>
                                        </td>
                                        {phaseIndex === 1 && (
                                            <td className="px-4 py-3">
                                                <span className="text-[12px] text-slate-600 font-medium">{candidate.profilePulledBy || '—'}</span>
                                            </td>
                                        )}
                                        <td className="px-4 py-3 text-center">
                                            <button
                                                onClick={(e) => toggleMenu(e, candidate._id)}
                                                className="p-2 text-slate-500 hover:bg-slate-100 rounded-full transition-colors"
                                            >
                                                <MoreVertical size={16} />
                                            </button>
                                            {activeMenu === candidate._id && typeof document !== 'undefined' && createPortal(
                                                <div
                                                    className="fixed z-[9999] w-52 bg-white rounded-xl shadow-xl border border-slate-200 py-1"
                                                    style={menuPosition}
                                                    onClick={e => e.stopPropagation()}
                                                >
                                                    <button
                                                        onClick={() => {
                                                            navigate(`/ta/hiring-request/${candidate.hiringRequestId}/candidate/${candidate._id}/view`);
                                                            setActiveMenu(null);
                                                        }}
                                                        className="w-full flex items-center gap-2 px-4 py-2 text-sm text-slate-700 hover:bg-slate-50 transition-colors text-left"
                                                    >
                                                        <Eye size={15} className="text-slate-500" />
                                                        View Details
                                                    </button>
                                                    {candidate.resumeUrl && (
                                                        <a
                                                            href={candidate.resumeUrl}
                                                            target="_blank"
                                                            rel="noopener noreferrer"
                                                            className="w-full flex items-center gap-2 px-4 py-2 text-sm text-slate-700 hover:bg-slate-50 transition-colors text-left"
                                                            onClick={() => setActiveMenu(null)}
                                                        >
                                                            <FileText size={15} className="text-slate-500" />
                                                            View Resume
                                                        </a>
                                                    )}
                                                    {(user?.roles?.includes('Admin') || user?.permissions?.includes('ta.edit')) && (
                                                        <>
                                                            <div className="border-t border-slate-100 my-1"></div>
                                                            <button
                                                                onClick={() => {
                                                                    onTransfer(candidate._id);
                                                                    setActiveMenu(null);
                                                                }}
                                                                className="w-full flex items-center gap-2 px-4 py-2 text-sm text-blue-700 hover:bg-blue-50 transition-colors text-left font-semibold"
                                                            >
                                                                <ArrowRight size={15} className="text-blue-500" />
                                                                Transfer to Active Req.
                                                            </button>
                                                        </>
                                                    )}
                                                </div>,
                                                document.body
                                            )}
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>
        );
    };

    return (
        <div className="bg-white rounded-2xl border border-slate-200 shadow-lg overflow-hidden mb-8 transition-shadow hover:shadow-xl">
            {/* Opening header */}
            <div className="border-b border-slate-100 bg-slate-50/30">
                <div className="flex items-center justify-between px-6 py-4">
                    <div className="flex items-center gap-4">
                        <div className="flex items-center justify-center w-12 h-12 rounded-2xl bg-gradient-to-br from-slate-700 to-slate-900 text-white font-bold text-lg shrink-0 shadow-md">
                            #{openingNum}
                        </div>
                        <div>
                            <div className="flex items-center gap-2 flex-wrap mb-1">
                                <h4 className="font-bold text-slate-800 text-base">Opening #{openingNum}: {positionName}</h4>
                                <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full border shadow-sm ${requisition.status === 'Closed' ? 'bg-gray-100 text-gray-600 border-gray-200' : 'bg-emerald-100 text-emerald-700 border-emerald-200'}`}>
                                    {requisition.status.toUpperCase()}
                                </span>
                            </div>
                            <div className="flex items-center gap-3 text-[12px] text-slate-500 flex-wrap font-medium">
                                <span className="flex items-center gap-1.5"><Calendar size={13} className="text-slate-400" /> {openedAt} — {closedAt}</span>
                                <span className="text-slate-300">|</span>
                                <span className="flex items-center gap-1.5"><Users size={13} className="text-slate-400" /> {candidates.length} candidates tracked</span>
                            </div>
                        </div>
                    </div>
                    <div className="flex items-center gap-3">
                        <button
                            className="p-2 text-slate-400 hover:bg-white hover:text-slate-600 rounded-xl transition-all border border-transparent hover:border-slate-200 shadow-sm"
                            onClick={() => setExpanded(v => !v)}
                        >
                            {expanded ? <ChevronUp size={24} /> : <ChevronDown size={24} />}
                        </button>
                    </div>
                </div>
            </div>

            {/* Content: Cards, Tabs, Filters and Table */}
            {expanded && (
                <div className="bg-slate-50/30">
                    {/* Header Row similar to CandidateList */}
                    <div className="px-6 pt-6 pb-2 flex justify-between items-center">
                        <h3 className="text-[11px] font-bold text-slate-500 uppercase tracking-[2px]">Pipeline Snapshot</h3>
                        <div className="flex rounded-xl border border-slate-200 bg-white p-1 shadow-sm">
                            {[1, 2, 3].map(v => (
                                <button
                                    key={v}
                                    onClick={() => {
                                        setActivePhase(v);
                                        setFilterStatus(v === 1 ? 'Interested' : 'All');
                                        setFilterDecision('All');
                                        setFilterInterviewStatus('All');
                                    }}
                                    className={`px-6 py-1.5 text-xs font-bold rounded-lg transition-all ${activePhase === v ? 'bg-slate-800 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'}`}
                                >
                                    Phase {v}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* Metric Cards - Exactly like CandidateList */}
                    <div className="px-6 pb-6">
                        {activePhase === 1 ? (
                            <div className="grid grid-cols-2 lg:grid-cols-6 gap-4">
                                <MetricCard label="Total Sourced" val={metrics.totalSourced} icon={<Users />} color="purple" onClick={() => { setFilterStatus('All'); setFilterDecision('All'); }} />
                                <MetricCard label="Interested" val={metrics.interested} icon={<CheckCircle />} color="green" onClick={() => { setFilterStatus('Interested'); setFilterDecision('All'); }} />
                                <MetricCard label="In Interviews" val={metrics.inInterviews} icon={<UserCheck />} color="amber" onClick={() => { setFilterStatus('All'); setFilterDecision('None'); setFilterInterviewStatus('In_Process'); }} />
                                <MetricCard label="Shortlisted" val={metrics.shortlisted} icon={<ThumbsUp />} color="sky" onClick={() => { setFilterStatus('All'); setFilterDecision('Shortlisted'); }} />
                                <MetricCard label="On Hold" val={metrics.onHold} icon={<Clock />} color="slate" onClick={() => { setFilterStatus('All'); setFilterDecision('On Hold'); }} />
                                <MetricCard label="Transferred" val={metrics.transferred} icon={<Briefcase />} color="blue" onClick={() => { setFilterStatus('All'); setFilterTransferred('Transferred'); }} />
                            </div>

                        ) : activePhase === 2 ? (
                            <div className="grid grid-cols-2 lg:grid-cols-5 gap-4">
                                <MetricCard label="Total Sent" val={phase2Metrics.totalShortlisted} icon={<Users />} color="purple" onClick={() => setFilterDecision('All')} />
                                <MetricCard label="Shortlisted" val={phase2Metrics.totalScreened} icon={<UserCheck />} color="sky" onClick={() => setFilterDecision('Shortlisted_Selected')} />
                                <MetricCard label="Interviews" val={phase2Metrics.interviewScheduled} icon={<Clock />} color="amber" onClick={() => { setFilterDecision('None'); setFilterInterviewStatus('In_Process'); }} />
                                <MetricCard label="Selected" val={phase2Metrics.selected} icon={<CheckCircle />} color="emerald" onClick={() => setFilterDecision('Selected')} />
                                <MetricCard label="Rejected" val={phase2Metrics.rejected} icon={<ThumbsDown />} color="rose" onClick={() => setFilterDecision('Rejected')} />
                            </div>
                        ) : (
                            <div className="grid grid-cols-2 lg:grid-cols-5 gap-4">
                                <MetricCard label="Total" val={phase3Metrics.total} icon={<Users />} color="purple" onClick={() => setFilterDecision('All')} />
                                <MetricCard label="Offer Sent" val={phase3Metrics.offerSent} icon={<FileText />} color="sky" onClick={() => setFilterDecision('Offer Sent')} />
                                <MetricCard label="Accepted" val={phase3Metrics.offerAccepted} icon={<ThumbsUp />} color="amber" onClick={() => setFilterDecision('Offer Accepted')} />
                                <MetricCard label="Joined" val={phase3Metrics.joined} icon={<CheckCircle />} color="emerald" onClick={() => setFilterDecision('Joined')} />
                                <MetricCard label="Declined" val={phase3Metrics.noShow} icon={<XCircle />} color="rose" onClick={() => setFilterDecision('No Show_Offer Declined')} />

                            </div>
                        )}
                    </div>

                    {/* Filter Bar */}
                    <div className="px-6 pb-6">
                        <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm flex flex-wrap gap-4 items-end">
                            <FilterSelect label="Preference" val={filterPreference} onChange={setFilterPreference} options={[
                                ['All', 'All Preferences'], ['Highly Recommended', 'Highly Recommended'], ['Recommended', 'Recommended'], ['Neutral / Average', 'Neutral / Average'], ['Not Recommended', 'Not Recommended'], ['Very Poor', 'Very Poor']
                            ]} />
                            <FilterSelect label="Status" val={filterStatus} onChange={setFilterStatus} options={[
                                ['All', 'All Statuses'], ['Interested', 'Interested'], ['Not Interested', 'Not Interested'], ['Not Relevant', 'Not Relevant'], ['Not Picking', 'Not Picking']
                            ]} />
                            <FilterSelect label="Decision" val={filterDecision} onChange={setFilterDecision} options={
                                activePhase === 1 ? [['All', 'All Decisions'], ['Shortlisted', 'Shortlisted'], ['Rejected', 'Rejected'], ['On Hold', 'On Hold'], ['None', 'None']] :
                                    activePhase === 2 ? [['All', 'All Decisions'], ['Shortlisted_Selected', 'Shortlisted/Selected'], ['Selected', 'Selected'], ['Rejected', 'Rejected'], ['On Hold', 'On Hold'], ['None', 'None']] :
                                        [['All', 'All Decisions'], ['Offer Sent', 'Offer Sent'], ['Offer Accepted', 'Offer Accepted'], ['Joined', 'Joined'], ['No Show_Offer Declined', 'Declined'], ['Rejected', 'Rejected'], ['None', 'None']]
                            } />
                            <FilterSelect label="Interviews" val={filterInterviewStatus} onChange={setFilterInterviewStatus} options={[
                                ['All', 'All Interviews'], ['None', 'None Scheduled'], ['In_Process', 'Active'], ['Pending', 'In Progress'], ['Passed', 'All Passed'], ['Failed', 'Failed']
                            ]} />
                            <FilterSelect label="Min Rating" val={filterRating} onChange={setFilterRating} options={[['All', 'Ratings'], ['9', '9+'], ['7', '7+'], ['5', '5+'], ['3', '3+']]} />
                            <FilterSelect label="Pulled By" val={filterPulledBy} onChange={setFilterPulledBy} options={[['All', 'All Users'], ...users.map(u => [`${u.firstName} ${u.lastName}`.trim(), `${u.firstName} ${u.lastName}`])]} />

                            <div className="w-28">
                                <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1.5 px-1">Experience</label>
                                <input type="number" value={filterExperience} onChange={e => setFilterExperience(e.target.value)} placeholder="0 Yrs" className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm font-semibold outline-none focus:ring-2 focus:ring-blue-500/20 transition-all" />
                            </div>

                            {(filterPreference !== 'All' || filterStatus !== (activePhase === 1 ? 'Interested' : 'All') || filterDecision !== 'All' || filterExperience !== '' || filterInterviewStatus !== 'All' || filterRating !== 'All' || filterPulledBy !== 'All' || filterTransferred !== 'All') && (
                                <button onClick={() => {
                                    setFilterPreference('All'); setFilterStatus(activePhase === 1 ? 'Interested' : 'All'); setFilterDecision('All'); setFilterExperience(''); setFilterInterviewStatus('All'); setFilterRating('All'); setFilterPulledBy('All'); setFilterTransferred('All');
                                }} className="px-4 py-2 text-xs font-bold text-rose-600 hover:bg-rose-50 rounded-xl transition-all mb-0.5">
                                    Clear
                                </button>
                            )}
                        </div>
                    </div>

                    {/* Table Container */}
                    <div className="bg-white border-t border-slate-100">
                        {renderTable(filteredCandidates, activePhase)}
                    </div>
                </div>
            )}
        </div>
    );
};

const MetricCard = ({ label, val, icon, color, onClick }) => (
    <div
        onClick={onClick}
        className={`bg-white border border-slate-200 border-b-4 border-b-${color}-500 shadow-sm p-4 relative overflow-hidden group hover:bg-slate-50 transition-all cursor-pointer active:scale-95 rounded-xl`}
    >
        <div className="relative z-10">
            <span className="block text-[28px] font-light text-slate-800 leading-none mb-1.5 tracking-tight">{val}</span>
            <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-[1px]">{label}</span>
        </div>
        <div className={`absolute -right-2 top-1/2 -translate-y-1/2 text-${color}-600 opacity-[0.06] transition-all group-hover:scale-110 group-hover:opacity-10 group-hover:-rotate-12`}>
            {React.cloneElement(icon, { size: 64 })}
        </div>
    </div>
);

const FilterSelect = ({ label, val, onChange, options }) => (
    <div className="flex-1 min-w-[130px]">
        <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1.5 px-1">{label}</label>
        <select
            value={val}
            onChange={e => onChange(e.target.value)}
            className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm font-semibold text-slate-700 outline-none focus:ring-2 focus:ring-blue-500/20 transition-all appearance-none"
        >
            {options.map(([v, l]) => <option key={v} value={v}>{l}</option>)}
        </select>
    </div>
);

const LegacyApplicationsView = ({ hiringRequestId }) => {
    const [openings, setOpenings] = useState([]);
    const [users, setUsers] = useState([]);
    const [loading, setLoading] = useState(true);

    const fetchUsers = useCallback(async () => {
        try {
            const res = await api.get('/admin/users');
            let fetchedUsers = [];
            if (res.data?.success) {
                fetchedUsers = res.data.data || [];
            } else if (Array.isArray(res.data)) {
                fetchedUsers = res.data;
            }

            const filteredUsers = fetchedUsers.filter(u => {
                const roleNames = u.roles?.map(r => r.name) || [];
                if (roleNames.includes('Admin')) return true;

                let hasTaCreate = false;
                if (u.roles && Array.isArray(u.roles)) {
                    u.roles.forEach(role => {
                        if (role.permissions && Array.isArray(role.permissions)) {
                            const keys = role.permissions.map(p => typeof p === 'string' ? p : p.key);
                            if (keys.includes('ta.create') || keys.includes('*')) {
                                hasTaCreate = true;
                            }
                        }
                    });
                }
                return hasTaCreate;
            });

            setUsers(filteredUsers);
        } catch (error) {
            console.error('Failed to fetch users', error);
        }
    }, []);

    const fetchLegacy = useCallback(async () => {
        try {
            setLoading(true);
            const res = await api.get(`/ta/hiring-request/${hiringRequestId}/previous-candidates`);
            setOpenings(res.data || []);
        } catch (e) {
            console.error(e);
            toast.error('Failed to load legacy applications');
        } finally {
            setLoading(false);
        }
    }, [hiringRequestId]);

    useEffect(() => { 
        fetchLegacy(); 
        fetchUsers();
    }, [fetchLegacy, fetchUsers]);

    const [selectedOpenings, setSelectedOpenings] = useState([]);
    const [exportMenuOpen, setExportMenuOpen] = useState(false);

    const handleExportSelected = async () => {
        if (selectedOpenings.length === 0) {
            toast.error('Please select at least one opening to export');
            return;
        }

        try {
            const workbook = new ExcelJS.Workbook();

            selectedOpenings.forEach(idx => {
                const opening = openings[idx];
                const openingNum = openings.length - idx;
                const sheet = workbook.addWorksheet(`Opening #${openingNum}`);

                sheet.columns = [
                    { header: 'Candidate Name', key: 'name', width: 25 },
                    { header: 'Email', key: 'email', width: 25 },
                    { header: 'Mobile', key: 'mobile', width: 15 },
                    { header: 'Experience', key: 'experience', width: 15 },
                    { header: 'Status', key: 'status', width: 15 },
                    { header: 'P1 Decision', key: 'p1', width: 15 },
                    { header: 'P2 Decision', key: 'p2', width: 15 },
                    { header: 'P3 Decision', key: 'p3', width: 15 },
                    { header: 'Pulled By', key: 'pulledBy', width: 20 }
                ];

                opening.candidates.forEach(c => {
                    sheet.addRow({
                        name: c.candidateName,
                        email: c.email,
                        mobile: c.mobile,
                        experience: c.totalExperience,
                        status: c.status,
                        p1: c.decision || 'None',
                        p2: c.phase2Decision || 'None',
                        p3: c.phase3Decision || 'None',
                        pulledBy: c.profilePulledBy
                    });
                });
            });

            const buffer = await workbook.xlsx.writeBuffer();
            const blob = new Blob([buffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
            saveAs(blob, `Legacy_Application_History_${format(new Date(), 'yyyy-MM-dd')}.xlsx`);
            toast.success('Excel exported successfully');
            setExportMenuOpen(false);
        } catch (e) {
            console.error(e);
            toast.error('Export failed');
        }
    };

    const toggleOpeningSelection = (idx) => {
        setSelectedOpenings(prev =>
            prev.includes(idx) ? prev.filter(i => i !== idx) : [...prev, idx]
        );
    };

    const handleTransfer = async (candidateId) => {
        if (!window.confirm('Transfer this candidate to the newest active requisition? This creates a fresh copy.')) return;
        try {
            const res = await api.post(`/ta/hiring-request/transfer-candidate/${candidateId}`);
            toast.success(res.data.message || 'Candidate transferred successfully');
            fetchLegacy();
        } catch (e) {
            toast.error(e.response?.data?.message || 'Failed to transfer candidate');
        }
    };

    if (loading) {
        return (
            <div className="space-y-4">
                {[1, 2].map(i => <Skeleton key={i} className="h-28 w-full rounded-2xl" />)}
            </div>
        );
    }

    if (openings.length === 0) {
        return (
            <div className="bg-white rounded-2xl border border-slate-200 p-12 text-center">
                <Briefcase className="mx-auto text-slate-300 mb-4" size={48} />
                <h3 className="text-lg font-semibold text-slate-700 mb-1">No Legacy Applications</h3>
                <p className="text-slate-400 text-sm">No previous openings found for this requisition.</p>
            </div>
        );
    }

    // Openings are returned newest-first from the backend
    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between mb-2">
                <div className="flex items-center gap-2">
                    <Briefcase size={16} className="text-slate-500" />
                    <h3 className="text-[13px] font-bold text-slate-500 uppercase tracking-widest">
                        Legacy Application History — {openings.length} Opening{openings.length > 1 ? 's' : ''}
                    </h3>
                </div>
                <div className="relative">
                    <button
                        onClick={() => setExportMenuOpen(!exportMenuOpen)}
                        className="flex items-center gap-2 px-4 py-2 bg-emerald-600 hover:bg-emerald-700 text-white rounded-lg text-sm font-semibold transition-all shadow-sm hover:shadow-md active:scale-95"
                    >
                        <Download size={16} />
                        Export Excel
                    </button>

                    {exportMenuOpen && (
                        <div className="absolute right-0 top-full mt-2 w-64 bg-white rounded-2xl shadow-xl border border-slate-200 z-[100] p-4 transition-all animate-in fade-in slide-in-from-top-2">
                            <h4 className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mb-3 px-1">Select Openings</h4>
                            <div className="space-y-2 max-h-60 overflow-y-auto pr-2 custom-scrollbar">
                                <label className="flex items-center gap-3 p-2 hover:bg-slate-50 rounded-xl cursor-pointer transition-colors group">
                                    <input
                                        type="checkbox"
                                        checked={selectedOpenings.length === openings.length}
                                        onChange={() => {
                                            if (selectedOpenings.length === openings.length) setSelectedOpenings([]);
                                            else setSelectedOpenings(openings.map((_, i) => i));
                                        }}
                                        className="w-4 h-4 rounded border-slate-300 text-emerald-600 focus:ring-emerald-500"
                                    />
                                    <span className="text-sm font-bold text-slate-700">Select All</span>
                                </label>
                                <div className="border-t border-slate-100 my-1"></div>
                                {openings.map((opening, idx) => (
                                    <label key={opening.requisition._id} className="flex items-center gap-3 p-2 hover:bg-slate-50 rounded-xl cursor-pointer transition-colors">
                                        <input
                                            type="checkbox"
                                            checked={selectedOpenings.includes(idx)}
                                            onChange={() => toggleOpeningSelection(idx)}
                                            className="w-4 h-4 rounded border-slate-300 text-emerald-600 focus:ring-emerald-500"
                                        />
                                        <div className="flex flex-col">
                                            <span className="text-xs font-bold text-slate-700">Opening #{openings.length - idx}</span>
                                            <span className="text-[10px] text-slate-400 font-medium">
                                                {format(new Date(opening.requisition.createdAt), 'MMM dd')} - {opening.requisition.closedAt ? format(new Date(opening.requisition.closedAt), 'MMM dd') : 'Current'}
                                            </span>
                                        </div>
                                    </label>
                                ))}
                            </div>
                            <button
                                onClick={handleExportSelected}
                                disabled={selectedOpenings.length === 0}
                                className="w-full mt-4 flex items-center justify-center gap-2 py-2.5 bg-slate-800 hover:bg-slate-900 disabled:bg-slate-300 text-white rounded-xl text-xs font-bold transition-all shadow-md active:scale-95"
                            >
                                <Download size={14} />
                                Download {selectedOpenings.length > 0 ? `(${selectedOpenings.length})` : ''}
                            </button>
                        </div>
                    )}
                </div>
            </div>
            {openings.map((opening, idx) => (
                <OpeningSection
                    key={opening.requisition._id}
                    opening={opening}
                    openingNum={openings.length - idx} // newest = highest number
                    hiringRequestId={hiringRequestId}
                    onTransfer={handleTransfer}
                    users={users}
                />
            ))}
        </div>
    );
};

export default LegacyApplicationsView;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { createPortal } from 'react-dom';
import { Edit, Trash2, FileText, Loader, Upload, Plus, Eye, MoreVertical, Users, ThumbsUp, ThumbsDown, CheckCircle, XCircle, Clock, UserCheck } from 'lucide-react';
import { useNavigate, useParams } from 'react-router-dom';
import api from '../../api/axios';
import toast from 'react-hot-toast';
import { format } from 'date-fns';
import { useAuth } from '../../context/AuthContext';
import Skeleton from '../../components/Skeleton';

const Phase1Candidates = () => {
    const { hiringRequestId } = useParams();
    const { user } = useAuth();
    const navigate = useNavigate();
    const [candidates, setCandidates] = useState([]);
    const [loading, setLoading] = useState(true);
    const [page, setPage] = useState(1);
    const [totalPages, setTotalPages] = useState(1);
    const [totalCandidates, setTotalCandidates] = useState(0);

    // Filter States
    const [filterPreference, setFilterPreference] = useState('All');
    const [filterStatus, setFilterStatus] = useState('Interested');
    const [filterDecision, setFilterDecision] = useState('All');
    const [filterExperience, setFilterExperience] = useState('');
    const [filterInterviewStatus, setFilterInterviewStatus] = useState('All');
    const [filterRating, setFilterRating] = useState('All');
    const [filterPulledBy, setFilterPulledBy] = useState('All');

    // Menu State
    const [activeMenu, setActiveMenu] = useState(null);

    // Close menu when clicking outside
    useEffect(() => {
        const handleClose = () => setActiveMenu(null);
        document.addEventListener('click', handleClose);
        window.addEventListener('scroll', handleClose, true);
        return () => {
            document.removeEventListener('click', handleClose);
            window.removeEventListener('scroll', handleClose, true);
        };
    }, []);


    // Reset page to 1 when any filter changes
    useEffect(() => {
        setPage(1);
    }, [filterPreference, filterStatus, filterDecision, filterExperience, filterInterviewStatus, filterRating]);

    // Computed filtered candidates based on active frontend filters logic (if any are retained with backend pages)
    // Note: Since we fetch exact Phase 1 users via the backend page by page, most complex frontend filter limits may cause 
    // mismatched views unless we send filters to the backend. We'll retain basic array filtering for the current page chunk.
    const filteredCandidates = useMemo(() => {
        return candidates.filter(candidate => {
            const matchPreference = filterPreference === 'All' || candidate.preference === filterPreference;
            const matchStatus = filterStatus === 'All' || candidate.status === filterStatus;
            const matchExperience = !filterExperience || (candidate.totalExperience && Number(candidate.totalExperience) >= Number(filterExperience));

            // Interview filtering logic
            let matchInterviewStatus = true;
            if (filterInterviewStatus !== 'All') {
                if (filterInterviewStatus === 'None') {
                    matchInterviewStatus = !candidate.interviewRounds || candidate.interviewRounds.length === 0;
                } else if (['Pending', 'Scheduled', 'Failed', 'Passed'].includes(filterInterviewStatus)) {
                    matchInterviewStatus = candidate.interviewRounds?.some(round => round.status === filterInterviewStatus);
                } else if (filterInterviewStatus === 'In_Process') {
                    matchInterviewStatus = candidate.interviewRounds?.length > 0 && !candidate.interviewRounds.some(round => round.status === 'Failed');
                }
            }

            const matchRating = filterRating === 'All' || (candidate.interviewRounds?.some(round => round.rating && round.rating >= Number(filterRating)));

            return matchPreference && matchStatus && matchExperience && matchInterviewStatus && matchRating;
        });
    }, [candidates, filterPreference, filterStatus, filterExperience, filterInterviewStatus, filterRating]);

    const itemsPerPage = 10;
    // totalPages and paginatedCandidates are now backend controlled, so paginatedCandidates is just filteredCandidates
    const paginatedCandidates = filteredCandidates;

    const fetchCandidates = useCallback(async () => {
        try {
            setLoading(true);
            const response = await api.get(`/ta/candidates/shortlisted/${hiringRequestId}?page=${page}&limit=${itemsPerPage}&preference=${filterPreference}&status=${filterStatus}&experience=${filterExperience}&interviewStatus=${filterInterviewStatus}&rating=${filterRating}`);

            // Expected backend format: { candidates: [], totalPages: N, count: N }
            setCandidates(response.data.candidates || []);
            setTotalPages(response.data.totalPages || 1);
            setTotalCandidates(response.data.count || 0);

        } catch (error) {
            console.error('Error fetching Phase 1 candidates:', error);
            toast.error('Failed to load Phase 1 candidates');
        } finally {
            setLoading(false);
        }
    }, [hiringRequestId, page, itemsPerPage, filterPreference, filterStatus, filterExperience, filterInterviewStatus, filterRating]);

    useEffect(() => {
        if (hiringRequestId) {
            fetchCandidates();
        }
    }, [hiringRequestId, fetchCandidates]);

    // Compute Metrics for Summary Boxes
    const metrics = useMemo(() => {
        // These metrics are now computed based on the *current page* of candidates,
        // or directly from backend data where available (like totalCandidates).
        // Dynamically compute 'interested' (pre-screened) based on the current filterStatus
        const targetStatus = filterStatus === 'All' ? 'Interested' : filterStatus;

        // Apply PulledBy filter to the base dataset for metrics if a user is selected
        const baseCandidates = filterPulledBy === 'All'
            ? candidates
            : candidates.filter(c => c.profilePulledBy === filterPulledBy);

        return {
            totalShortlisted: filterPulledBy === 'All' ? totalCandidates : baseCandidates.length, // If filtered, use local array length instead of total backend count
            totalScreened: baseCandidates.filter(c => c.status === 'Interested').length,
            interviewScheduled: baseCandidates.filter(c => {
                const rounds = c.interviewRounds || [];
                if (rounds.length === 0) return false;
                const hasFailed = rounds.some(r => r.status === 'Failed');
                if (hasFailed) return false;
                return true;
            }).length,
        };
    }, [candidates, totalCandidates, filterStatus, filterPulledBy]);



    const [menuPosition, setMenuPosition] = useState({ top: 0, right: 0 });

    const toggleMenu = useCallback((e, candidateId) => {
        e.stopPropagation();
        if (activeMenu === candidateId) {
            setActiveMenu(null);
        } else {
            const rect = e.currentTarget.getBoundingClientRect();
            const spaceBelow = window.innerHeight - rect.bottom;
            const menuHeight = 220; // safe estimation of dropdown height

            let positionStyles = {
                right: window.innerWidth - rect.right
            };

            // If not enough space below, open upwards
            if (spaceBelow < menuHeight && rect.top > menuHeight) {
                positionStyles.bottom = window.innerHeight - rect.top + 5;
            } else {
                positionStyles.top = rect.bottom + 5;
            }

            setMenuPosition(positionStyles);
            setActiveMenu(candidateId);
        }
    }, [activeMenu]);

    const handleEdit = useCallback((candidate) => {
        navigate(`/ta/hiring-request/${hiringRequestId}/candidate/${candidate._id}/edit`);
    }, [navigate, hiringRequestId]);

    const handleView = useCallback((candidate) => {
        navigate(`/ta/hiring-request/${hiringRequestId}/candidate/${candidate._id}/view?phase=1`);
    }, [navigate, hiringRequestId]);

    const handleDelete = useCallback(async (candidateId) => {
        if (!window.confirm('Are you sure you want to delete this candidate?')) return;

        try {
            await api.delete(`/ta/candidates/${candidateId}`);
            toast.success('Candidate deleted successfully');
            fetchCandidates();
        } catch (error) {
            console.error('Error deleting candidate:', error);
            toast.error(error.response?.data?.message || 'Failed to delete candidate');
        }
    }, [fetchCandidates]);

    const handleAddNew = useCallback(() => {
        navigate(`/ta/hiring-request/${hiringRequestId}/add-candidate`);
    }, [navigate, hiringRequestId]);



    const handleDecisionChange = async (candidateId, newDecision) => {
        try {
            await api.patch(`/ta/candidates/${candidateId}/decision`, { decision: newDecision });
            toast.success('Decision updated');
            // Re-fetch candidates to ensure the list is up-to-date and reflects any backend changes
            fetchCandidates();
        } catch (error) {
            console.error('Error updating decision:', error);
            toast.error('Failed to update decision');
        }
    };

    const getDecisionColor = (decision) => {
        switch (decision) {
            case 'Shortlisted': return 'text-emerald-600 font-bold';
            case 'Rejected': return 'text-red-600 font-bold';
            case 'On Hold': return 'text-amber-600 font-bold';
            default: return 'text-slate-600';
        }
    };

    const getInterviewStatusSummary = (rounds = []) => {
        if (!rounds || rounds.length === 0) return { label: 'None', color: 'text-slate-400 bg-slate-50 border-slate-200' };

        const pending = rounds.filter(r => r.status === 'Pending' || r.status === 'Scheduled').length;
        const passed = rounds.filter(r => r.status === 'Passed').length;
        const failedRounds = rounds.filter(r => r.status === 'Failed');
        const failedCount = failedRounds.length;
        const total = rounds.length;

        if (failedCount > 0) {
            const failedNames = failedRounds.map(r => r.levelName).join(', ');
            return { label: `Failed: ${failedNames}`, color: 'text-red-700 bg-red-50 border-red-200' };
        }
        if (pending > 0) return { label: `${passed}/${total} Completed`, color: 'text-amber-700 bg-amber-50 border-amber-200' };
        if (passed === total) return { label: 'All Passed', color: 'text-emerald-700 bg-emerald-50 border-emerald-200' };

        return { label: 'In Progress', color: 'text-blue-700 bg-blue-50 border-blue-200' };
    };

    if (loading) {
        return (
            <div className="space-y-4">
                <div className="flex justify-between items-center mb-6">
                    <div>
                        <Skeleton className="h-6 w-32 mb-2" />
                        <Skeleton className="h-4 w-48" />
                    </div>
                    <Skeleton className="h-10 w-36" />
                </div>
                {/* Skeleton for Summary Boxes */}
                <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
                    {[...Array(4)].map((_, i) => (
                        <Skeleton key={i} className="h-24 w-full rounded-none" />
                    ))}
                </div>
                <div className="bg-white p-4 rounded-xl border border-slate-200 flex gap-4">
                    <Skeleton className="h-10 w-32" />
                    <Skeleton className="h-10 w-32" />
                    <Skeleton className="h-10 w-32" />
                    <Skeleton className="h-10 w-32" />
                </div>
                <div className="bg-white rounded-xl border border-slate-200 overflow-hidden">
                    <div className="p-4 border-b border-slate-200 bg-slate-50 flex gap-4">
                        <Skeleton className="h-4 w-1/6" />
                        <Skeleton className="h-4 w-1/6" />
                        <Skeleton className="h-4 w-1/6" />
                        <Skeleton className="h-4 w-1/6" />
                        <Skeleton className="h-4 w-1/6" />
                        <Skeleton className="h-4 w-1/6" />
                    </div>
                    {[...Array(5)].map((_, i) => (
                        <div key={i} className="p-4 border-b border-slate-100 flex gap-4 items-center">
                            <Skeleton className="h-10 w-full" />
                        </div>
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-slate-50">
            {/* Header / Sticky Top Navbar */}
            <div className="bg-white border-b border-slate-200 sticky top-0 z-10 shadow-sm">
                <div className="w-full mx-auto px-4 sm:px-6 lg:px-8 py-4 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                    <div className="flex items-center gap-3">
                        <button
                            onClick={() => navigate(-1)}
                            className="p-1 hover:bg-slate-200 rounded-full transition-colors text-slate-500 flex items-center justify-center h-8 w-8"
                            aria-label="Go back"
                        >
                            &larr;
                        </button>
                        <h1 className="text-xl font-bold text-slate-800 uppercase tracking-widest">Phase 2 (Shortlisted)</h1>
                    </div>
                    <div className="flex gap-2">
                        {/* Phase Toggle */}
                        <div className="flex rounded-lg border border-slate-300 overflow-hidden">
                            <button
                                onClick={() => navigate(`/ta/view/${hiringRequestId}?tab=applications`)}
                                className="px-4 py-2 text-sm font-semibold bg-white text-slate-600 hover:bg-slate-100 transition-colors"
                            >
                                Phase 1
                            </button>
                            <button
                                className="px-4 py-2 text-sm font-semibold bg-slate-800 text-white cursor-default border-l border-slate-600"
                            >
                                Phase 2
                            </button>
                        </div>
                        {(user?.roles?.includes('Admin') || user?.permissions?.includes('ta.create')) && (
                            <button
                                onClick={handleAddNew}
                                className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-medium transition-colors"
                            >
                                <Plus size={18} />
                                Add Candidate
                            </button>
                        )}
                    </div>
                </div>
            </div>

            {/* Main Content */}
            <div className="w-full mx-auto px-4 sm:px-6 lg:px-8 py-6 space-y-6">

                {/* Pipeline Summary Boxes - Redesigned */}
                <div className="grid grid-cols-2 lg:grid-cols-3 gap-4">
                    <div 
                        onClick={() => { setFilterDecision('All'); setFilterStatus('All'); setFilterInterviewStatus('All'); }}
                        className="bg-white border border-slate-200 border-b-4 border-b-purple-500 shadow-sm p-4 relative overflow-hidden group hover:bg-slate-50 transition-colors cursor-pointer active:scale-[0.98]"
                    >
                        <span className="block text-[32px] font-light text-slate-800 leading-none mb-2 relative z-10">{metrics.totalShortlisted}</span>
                        <span className="block text-[11px] font-bold text-slate-500 uppercase tracking-wide relative z-10">Total Shortlisted</span>
                        <Users className="absolute -right-2 top-1/2 -translate-y-1/2 text-purple-600 opacity-[0.08] size-16 transition-transform group-hover:scale-110 group-hover:opacity-10" />
                    </div>

                    <div 
                        onClick={() => { setFilterStatus('Interested'); setFilterDecision('All'); setFilterInterviewStatus('All'); }}
                        className="bg-white border border-slate-200 border-b-4 border-b-sky-500 shadow-sm p-4 relative overflow-hidden group hover:bg-slate-50 transition-colors cursor-pointer active:scale-[0.98]"
                    >
                        <span className="block text-[32px] font-light text-slate-800 leading-none mb-2 relative z-10">{metrics.totalScreened}</span>
                        <span className="block text-[11px] font-bold text-slate-500 uppercase tracking-wide relative z-10">Total Screened</span>
                        <UserCheck className="absolute -right-2 top-1/2 -translate-y-1/2 text-sky-600 opacity-[0.08] size-16 transition-transform group-hover:scale-110 group-hover:opacity-10" />
                    </div>

                    <div 
                        onClick={() => { setFilterInterviewStatus('In_Process'); setFilterDecision('All'); setFilterStatus('All'); }}
                        className="bg-white border border-slate-200 border-b-4 border-b-amber-500 shadow-sm p-4 relative overflow-hidden group hover:bg-slate-50 transition-colors cursor-pointer active:scale-[0.98]"
                    >
                        <span className="block text-[32px] font-light text-slate-800 leading-none mb-2 relative z-10">{metrics.interviewScheduled}</span>
                        <span className="block text-[11px] font-bold text-slate-500 uppercase tracking-wide relative z-10">Interview Scheduled</span>
                        <Clock className="absolute -right-2 top-1/2 -translate-y-1/2 text-amber-600 opacity-[0.08] size-16 transition-transform group-hover:scale-110 group-hover:opacity-10" />
                    </div>

                </div>

                {/* Filters */}
                <div className="bg-white p-4 rounded-xl border border-slate-200 flex flex-wrap gap-4 items-end">
                    <div>
                        <label className="block text-xs font-semibold text-slate-500 mb-1">Preference</label>
                        <select
                            value={filterPreference}
                            onChange={(e) => setFilterPreference(e.target.value)}
                            className="px-3 py-2 border border-slate-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
                        >
                            <option value="All">All Preferences</option>
                            <option value="Highly Recommended">Highly Recommended</option>
                            <option value="Recommended">Recommended</option>
                            <option value="Neutral / Average">Neutral / Average</option>
                            <option value="Not Recommended">Not Recommended</option>
                            <option value="Very Poor">Very Poor</option>
                        </select>
                    </div>
                    <div>
                        <label className="block text-xs font-semibold text-slate-500 mb-1">Status</label>
                        <select
                            value={filterStatus}
                            onChange={(e) => setFilterStatus(e.target.value)}
                            className="px-3 py-2 border border-slate-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
                        >
                            <option value="All">All Statuses</option>
                            <option value="Interested">Interested</option>
                            <option value="Not Interested">Not Interested</option>
                            <option value="Not Relevant">Not Relevant</option>
                            <option value="Not Picking">Not Picking</option>
                        </select>
                    </div>
                    <div>
                        <label className="block text-xs font-semibold text-slate-500 mb-1">Interview Status</label>
                        <select
                            value={filterInterviewStatus}
                            onChange={(e) => setFilterInterviewStatus(e.target.value)}
                            className="px-3 py-2 border border-slate-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500 w-36"
                        >
                            <option value="All">All Interviews</option>
                            <option value="None">None Scheduled</option>
                            <option value="In_Process">In Interviews (Active)</option>
                            <option value="Pending">In Progress / Pending</option>
                            <option value="Passed">All Passed</option>
                            <option value="Failed">Failed</option>
                        </select>
                    </div>
                    <div>
                        <label className="block text-xs font-semibold text-slate-500 mb-1">Min Avg Rating</label>
                        <select
                            value={filterRating}
                            onChange={(e) => setFilterRating(e.target.value)}
                            className="px-3 py-2 border border-slate-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500 w-32"
                        >
                            <option value="All">All Ratings</option>
                            <option value="9">9+ (Excellent)</option>
                            <option value="7">7+ (Good)</option>
                            <option value="5">5+ (Average)</option>
                            <option value="3">3+ (Below Avg)</option>
                        </select>
                    </div>
                    <div>
                        <label className="block text-xs font-semibold text-slate-500 mb-1">Min Experience (Yrs)</label>
                        <input
                            type="number"
                            min="0"
                            placeholder="e.g. 2"
                            value={filterExperience}
                            onChange={(e) => setFilterExperience(e.target.value)}
                            className="px-3 py-2 border border-slate-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500 w-32"
                        />
                    </div>
                    {(filterPreference !== 'All' || filterStatus !== 'Interested' || filterExperience !== '' || filterInterviewStatus !== 'All' || filterRating !== 'All') && (
                        <button
                            onClick={() => {
                                setFilterPreference('All');
                                setFilterStatus('Interested');
                                setFilterExperience('');
                                setFilterInterviewStatus('All');
                                setFilterRating('All');
                            }}
                            className="px-3 py-2 text-sm text-red-600 hover:bg-red-50 rounded-lg transition-colors mb-0.5"
                        >
                            Clear Filters
                        </button>
                    )}
                </div>

                {/* Candidates Table */}
                {candidates.length === 0 ? (
                    <div className="bg-white rounded-xl border border-slate-200 p-12 text-center">
                        <Upload className="mx-auto text-slate-300 mb-4" size={48} />
                        <h3 className="text-lg font-semibold text-slate-700 mb-2">No Candidates Yet</h3>
                        <p className="text-slate-500 mb-4">Start by uploading candidate resumes and filling their details</p>
                        {(user?.roles?.includes('Admin') || user?.permissions?.includes('ta.create')) && (
                            <button
                                onClick={handleAddNew}
                                className="px-6 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-medium transition-colors"
                            >
                                Upload First Resume
                            </button>
                        )}
                    </div>
                ) : (
                    <div className="bg-white rounded-xl border border-slate-200 mb-24">
                        <div className="w-full overflow-x-auto">
                            <div className="min-w-[1100px]">
                                <table className="w-full">
                                    <thead className="bg-slate-50 border-b border-slate-200">
                                        <tr key="header-row">
                                            <th className="px-4 py-3.5 text-left text-[11px] font-semibold text-slate-500 uppercase tracking-wider whitespace-nowrap">Candidate</th>
                                            <th className="px-4 py-3.5 text-left text-[11px] font-semibold text-slate-500 uppercase tracking-wider whitespace-nowrap">Contact</th>
                                            <th className="px-4 py-3.5 text-left text-[11px] font-semibold text-slate-500 uppercase tracking-wider whitespace-nowrap">Experience</th>
                                            <th className="px-4 py-3.5 text-left text-[11px] font-semibold text-slate-500 uppercase tracking-wider whitespace-nowrap">Preference</th>
                                            <th className="px-4 py-3.5 text-left text-[11px] font-semibold text-slate-500 uppercase tracking-wider whitespace-nowrap">Interviews</th>
                                            <th className="px-4 py-3.5 text-left text-[11px] font-semibold text-slate-500 uppercase tracking-wider whitespace-nowrap">Decision</th>
                                            <th className="px-4 py-3.5 text-left text-[11px] font-semibold text-slate-500 uppercase tracking-wider whitespace-nowrap">Pulled By</th>
                                            <th className="px-4 py-3.5 text-center text-[11px] font-semibold text-slate-500 uppercase tracking-wider whitespace-nowrap">Actions</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-slate-200">
                                        {paginatedCandidates.length === 0 ? (
                                            <tr>
                                                <td colSpan="8" className="px-4 py-8 text-center text-slate-500">
                                                    No candidates match the selected filters.
                                                </td>
                                            </tr>
                                        ) : (
                                            paginatedCandidates.map((candidate) => (
                                                <tr key={candidate._id} className="hover:bg-slate-50 bg-white transition-colors border-b border-slate-100 last:border-0">
                                                    <td className="px-4 py-4 align-top">
                                                        <div className="flex flex-col gap-1">
                                                            <span className="text-[13px] font-bold text-slate-700 leading-tight">
                                                                {candidate.candidateName.split(' ')[0]}<br />
                                                                {candidate.candidateName.split(' ').slice(1).join(' ')}
                                                            </span>
                                                        </div>
                                                    </td>
                                                    <td className="px-4 py-4 align-top">
                                                        <div className="flex flex-col gap-1 text-[12px]">
                                                            <span className="text-slate-500 font-medium">{candidate.email}</span>
                                                            <span className="text-slate-500 font-medium">{candidate.mobile}</span>
                                                        </div>
                                                    </td>
                                                    <td className="px-4 py-4 align-top">
                                                        <span className="text-[13px] font-semibold text-slate-700">{candidate.totalExperience} yrs</span>
                                                    </td>
                                                    <td className="px-4 py-4 align-top">
                                                        <div className="flex flex-col gap-0.5 text-[13px]">
                                                            {candidate.preference ? (
                                                                <>
                                                                    <span className="text-slate-700 font-medium">
                                                                        {candidate.preference.split(' ')[0]}
                                                                    </span>
                                                                    <span className="text-slate-700 font-medium">
                                                                        {candidate.preference.split(' ').slice(1).join(' ')}
                                                                    </span>
                                                                </>
                                                            ) : (
                                                                <span className="text-slate-400 italic">-</span>
                                                            )}
                                                        </div>
                                                    </td>
                                                    <td className="px-4 py-4 align-top">
                                                        {(() => {
                                                            const summary = getInterviewStatusSummary(candidate.interviewRounds);

                                                            const rounds = candidate.interviewRounds || [];
                                                            const hasFailed = rounds.some(r => r.status === 'Failed');
                                                            const ratedRounds = rounds.filter(r => r.rating && r.rating > 0);
                                                            let avgRating = null;

                                                            if (!hasFailed && ratedRounds.length > 0) {
                                                                const total = ratedRounds.reduce((acc, curr) => acc + curr.rating, 0);
                                                                // Format to 1 decimal place, or no decimals if whole number
                                                                let calculatedAvg = total / ratedRounds.length;
                                                                avgRating = Number.isInteger(calculatedAvg) ? calculatedAvg.toString() : calculatedAvg.toFixed(1);
                                                            }

                                                            return (
                                                                <div className="flex flex-col gap-1.5 items-start">
                                                                    <span className={`px-2 py-0.5 border rounded-md text-[10px] font-bold tracking-wide ${summary.color}`}>
                                                                        {summary.label}
                                                                    </span>
                                                                    <div className="flex flex-col gap-1">
                                                                        <span className="text-[11px] text-slate-500 font-medium whitespace-nowrap leading-tight">
                                                                            {candidate.interviewRounds?.length || 0} rounds total
                                                                        </span>
                                                                        <div className="flex flex-wrap gap-1 mt-0.5">
                                                                            {ratedRounds.length > 0 && ratedRounds.slice(0, 2).map((r, idx) => (
                                                                                <span key={r._id || idx} title={r.roundName} className="text-[10px] font-bold text-amber-600 flex items-center gap-0.5 bg-amber-50 px-1.5 py-0.5 rounded border border-amber-200">
                                                                                    R{idx + 1}: {r.rating}/10
                                                                                </span>
                                                                            ))}
                                                                            {ratedRounds.length > 2 && (
                                                                                <span
                                                                                    className="text-[10px] font-bold text-amber-600 flex items-center justify-center bg-amber-50 px-1.5 py-0.5 rounded border border-amber-200 cursor-pointer hover:bg-amber-100 transition-colors"
                                                                                    onClick={(e) => { e.stopPropagation(); handleView(candidate); }}
                                                                                    title="View all rounds"
                                                                                >
                                                                                    ...
                                                                                </span>
                                                                            )}
                                                                        </div>
                                                                    </div>
                                                                </div>
                                                            )
                                                        })()}
                                                    </td>
                                                    <td className="px-4 py-4 align-top">
                                                        <div className="relative inline-block w-full max-w-[110px]">
                                                            <select
                                                                value={candidate.decision || 'None'}
                                                                onChange={(e) => handleDecisionChange(candidate._id, e.target.value)}
                                                                className={`w-full appearance-none px-2.5 py-1 pr-7 text-[12px] font-bold rounded-lg border border-slate-200 bg-white outline-none cursor-pointer transition-colors hover:border-slate-300 focus:ring-2 focus:ring-blue-100 ${getDecisionColor(candidate.decision || 'None')}`}
                                                                onClick={(e) => e.stopPropagation()}
                                                                disabled={!(user?.roles?.includes('Admin') || user?.permissions?.includes('ta.edit'))}
                                                            >
                                                                <option value="None" className="text-slate-600">None</option>
                                                                <option value="Shortlisted" className="text-emerald-600 font-bold">Shortlisted</option>
                                                                <option value="Rejected" className="text-red-600 font-bold">Rejected</option>
                                                                <option value="On Hold" className="text-amber-600 font-bold">On Hold</option>
                                                            </select>
                                                            <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-slate-400">
                                                                <svg className="h-4 w-4 fill-current" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20">
                                                                    <path d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" />
                                                                </svg>
                                                            </div>
                                                        </div>
                                                    </td>
                                                    <td className="px-4 py-4 align-top">
                                                        <div className="flex flex-col gap-0.5 text-[12px] text-slate-500 font-medium whitespace-nowrap">
                                                            <span
                                                                className="font-bold text-blue-600 mb-0.5 max-w-[120px] truncate cursor-pointer hover:underline"
                                                                title={candidate.profilePulledBy || '-'}
                                                                onClick={() => candidate.profilePulledBy && navigate(`/ta/user-dashboard/${encodeURIComponent(candidate.profilePulledBy)}`)}
                                                            >
                                                                {candidate.profilePulledBy || '-'}
                                                            </span>
                                                            <span>{format(new Date(candidate.uploadedAt), 'MMM dd, yyyy')}</span>
                                                            <span className="text-[10px] mt-0.5">{format(new Date(candidate.uploadedAt), 'hh:mm a')}</span>
                                                        </div>
                                                    </td>
                                                    <td className="px-4 py-4 align-top text-center">
                                                        <button
                                                            onClick={(e) => toggleMenu(e, candidate._id)}
                                                            className="p-2 text-slate-500 hover:bg-slate-100 rounded-full transition-colors relative"
                                                        >
                                                            <MoreVertical size={18} />
                                                        </button>

                                                        {/* Dropdown Menu */}
                                                        {activeMenu === candidate._id && typeof document !== 'undefined' && createPortal(
                                                            <div
                                                                className="fixed z-[9999] w-48 bg-white rounded-lg shadow-xl border border-slate-200 py-1"
                                                                style={menuPosition}
                                                                onClick={(e) => e.stopPropagation()}
                                                            >
                                                                <button
                                                                    onClick={() => {
                                                                        handleView(candidate);
                                                                        setActiveMenu(null);
                                                                    }}
                                                                    className="w-full flex items-center gap-2 px-4 py-2 text-sm text-slate-700 hover:bg-slate-50 transition-colors text-left"
                                                                >
                                                                    <Eye size={16} className="text-slate-500" />
                                                                    View Details
                                                                </button>

                                                                <a
                                                                    href={candidate.resumeUrl}
                                                                    target="_blank"
                                                                    rel="noopener noreferrer"
                                                                    className="w-full flex items-center gap-2 px-4 py-2 text-sm text-slate-700 hover:bg-slate-50 transition-colors text-left"
                                                                    onClick={() => setActiveMenu(null)}
                                                                >
                                                                    <FileText size={16} className="text-slate-500" />
                                                                    View Resume
                                                                </a>

                                                                {(user?.roles?.includes('Admin') || user?.permissions?.includes('ta.edit')) && (
                                                                    <button
                                                                        onClick={() => {
                                                                            handleEdit(candidate);
                                                                            setActiveMenu(null);
                                                                        }}
                                                                        className="w-full flex items-center gap-2 px-4 py-2 text-sm text-slate-700 hover:bg-slate-50 transition-colors text-left"
                                                                    >
                                                                        <Edit size={16} className="text-slate-500" />
                                                                        Edit Candidate
                                                                    </button>
                                                                )}

                                                                <div className="border-t border-slate-100 my-1"></div>

                                                                {(user?.roles?.includes('Admin') || user?.permissions?.includes('ta.delete')) && (
                                                                    <button
                                                                        onClick={() => {
                                                                            handleDelete(candidate._id);
                                                                            setActiveMenu(null);
                                                                        }}
                                                                        className="w-full flex items-center gap-2 px-4 py-2 text-sm text-red-600 hover:bg-red-50 transition-colors text-left"
                                                                    >
                                                                        <Trash2 size={16} />
                                                                        Delete Candidate
                                                                    </button>
                                                                )}
                                                            </div>,
                                                            document.body
                                                        )}
                                                    </td>
                                                </tr>
                                            ))
                                        )}
                                    </tbody>
                                </table>
                            </div>
                        </div>

                        {/* Pagination Controls */}
                        {!loading && filteredCandidates.length > 0 && (
                            <div className="flex justify-end items-center mt-6 gap-4 pr-4 pb-4">
                                <button
                                    onClick={() => setPage(p => Math.max(1, p - 1))}
                                    disabled={page === 1}
                                    className="px-4 py-2 bg-white border border-slate-300 rounded-lg text-sm font-medium text-slate-700 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed focus:outline-none focus:ring-2 focus:ring-blue-500 transition-colors"
                                >
                                    Previous
                                </button>
                                <span className="text-sm font-medium text-slate-600 min-w-[100px] text-center">
                                    Page {page} of {totalPages}
                                </span>
                                <button
                                    onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                                    disabled={page === totalPages}
                                    className="px-4 py-2 bg-white border border-slate-300 rounded-lg text-sm font-medium text-slate-700 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed focus:outline-none focus:ring-2 focus:ring-blue-500 transition-colors"
                                >
                                    Next
                                </button>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>
    );
};

export default Phase1Candidates;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, Users, ThumbsUp, ThumbsDown, CheckCircle, Clock, UserCheck, Eye, FileText, Upload } from 'lucide-react';
import api from '../../api/axios';
import toast from 'react-hot-toast';
import { format } from 'date-fns';
import { useAuth } from '../../context/AuthContext';
import Skeleton from '../../components/Skeleton';
import { Filter, Search, X } from 'lucide-react';

const UserTADashboard = ({ providedUserName }) => {
    const { userName: routeUserName } = useParams();
    const navigate = useNavigate();
    const { user } = useAuth();

    // Use the provided name (if used as embedded component) or the route param
    const userName = providedUserName || routeUserName;

    const [candidates, setCandidates] = useState([]);
    const [loading, setLoading] = useState(true);

    // Filter States
    const [searchTerm, setSearchTerm] = useState('');
    const [filterDateFrom, setFilterDateFrom] = useState('');
    const [filterDateTo, setFilterDateTo] = useState('');
    const [filterProfile, setFilterProfile] = useState('');
    const [filterStatus, setFilterStatus] = useState('');
    const [showFilters, setShowFilters] = useState(false);

    useEffect(() => {
        if (userName) {
            fetchUserCandidates();
        }
    }, [userName]);

    const fetchUserCandidates = useCallback(async () => {
        try {
            setLoading(true);
            const response = await api.get(`/ta/candidates/user/${encodeURIComponent(userName)}`);
            setCandidates(response.data.candidates || []);
        } catch (error) {
            console.error('Error fetching user candidates:', error);
            toast.error('Failed to load candidate metrics for this user');
        } finally {
            setLoading(false);
        }
    }, [userName]);

    const uniqueProfiles = useMemo(() => {
        const profiles = candidates.map(c => c.hiringRequestId?.roleDetails?.title).filter(Boolean);
        return [...new Set(profiles)];
    }, [candidates]);

    // Apply Filters
    const filteredCandidates = useMemo(() => {
        return candidates.filter(candidate => {
            // Search
            const searchLower = searchTerm.toLowerCase();
            const matchesSearch = !searchTerm ||
                candidate.candidateName?.toLowerCase().includes(searchLower) ||
                candidate.email?.toLowerCase().includes(searchLower) ||
                candidate.mobile?.includes(searchTerm);

            // Profile
            const matchesProfile = !filterProfile || candidate.hiringRequestId?.roleDetails?.title === filterProfile;

            // Status (which maps to candidate.status OR candidate.decision depending on context, but user specifically asked for 'Interested' filters)
            const matchesStatus = !filterStatus || candidate.status === filterStatus;

            // Date Range
            let matchesDate = true;
            if (filterDateFrom || filterDateTo) {
                const dateAdded = new Date(candidate.uploadedAt).getTime();
                if (filterDateFrom) {
                    const fromTime = new Date(filterDateFrom).getTime();
                    if (dateAdded < fromTime) matchesDate = false;
                }
                if (filterDateTo) {
                    const toTime = new Date(filterDateTo).getTime();
                    // Add 24 hours to "to" date to include the whole day
                    if (dateAdded > toTime + 86400000) matchesDate = false;
                }
            }

            return matchesSearch && matchesProfile && matchesStatus && matchesDate;
        });
    }, [candidates, searchTerm, filterProfile, filterStatus, filterDateFrom, filterDateTo]);

    // Calculate metrics based on FILTERED candidates
    const metrics = useMemo(() => {
        return {
            total: filteredCandidates.length,
            interested: filteredCandidates.filter(c => {
                if (c.status !== 'Interested') return false;
                if (c.decision && ['Rejected', 'On Hold'].includes(c.decision)) return false;
                if (c.interviewRounds && c.interviewRounds.length > 0) return false;
                return true;
            }).length,
            inInterviews: filteredCandidates.filter(c => {
                const rounds = c.interviewRounds || [];
                if (rounds.length === 0) return false;
                if (c.decision && ['Rejected', 'On Hold'].includes(c.decision)) return false;
                const hasFailed = rounds.some(r => r.status === 'Failed');
                if (hasFailed) return false;
                return true;
            }).length,
            rejected: filteredCandidates.filter(c => c.decision === 'Rejected').length,
            onHold: filteredCandidates.filter(c => c.decision === 'On Hold').length,
        };
    }, [filteredCandidates]);

    const getStatusColor = useCallback((status) => {
        switch (status) {
            case 'Interested': return 'bg-green-100 text-green-700';
            case 'Not Interested': return 'bg-red-100 text-red-700';
            case 'Not Relevant': return 'bg-gray-100 text-gray-700';
            case 'Not Picking': return 'bg-yellow-100 text-yellow-700';
            default: return 'bg-blue-100 text-blue-700';
        }
    }, []);

    const getDecisionColor = useCallback((decision) => {
        switch (decision) {
            case 'Rejected': return 'text-red-600 font-bold';
            case 'On Hold': return 'text-amber-600 font-bold';
            default: return 'text-slate-600';
        }
    }, []);

    const getInterviewStatusSummary = useCallback((rounds = []) => {
        if (!rounds || rounds.length === 0) return { label: 'None', color: 'text-slate-400 bg-slate-50 border-slate-200' };

        const pending = rounds.filter(r => r.status === 'Pending' || r.status === 'Scheduled').length;
        const passed = rounds.filter(r => r.status === 'Passed').length;
        const failedRounds = rounds.filter(r => r.status === 'Failed');
        const failedCount = failedRounds.length;
        const total = rounds.length;

        if (failedCount > 0) {
            const failedNames = failedRounds.map(r => r.levelName).join(', ');
            return { label: `Failed: ${failedNames}`, color: 'text-red-700 bg-red-50 border-red-200' };
        }
        if (pending > 0) return { label: `${passed}/${total} Completed`, color: 'text-amber-700 bg-amber-50 border-amber-200' };
        if (passed === total) return { label: 'All Passed', color: 'text-emerald-700 bg-emerald-50 border-emerald-200' };

        return { label: 'In Progress', color: 'text-blue-700 bg-blue-50 border-blue-200' };
    }, []);

    if (loading) {
        return (
            <div className="p-6 max-w-7xl mx-auto space-y-6 animate-pulse">
                <div className="h-8 bg-slate-200 rounded w-1/4 mb-6"></div>
                <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4">
                    {[...Array(6)].map((_, i) => (
                        <div key={i} className="h-24 bg-slate-200 rounded"></div>
                    ))}
                </div>
                <div className="h-64 bg-slate-200 rounded mt-6"></div>
            </div>
        );
    }

    return (
        <div className="max-w-7xl mx-auto p-4 md:p-6 space-y-6">
            <div className="flex items-center gap-4 mb-2">
                <button
                    onClick={() => navigate(-1)}
                    className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-full transition-colors"
                >
                    <ArrowLeft size={20} />
                </button>
                <div>
                    <h1 className="text-2xl font-bold text-slate-800">{userName}'s Dashboard</h1>
                    <p className="text-sm text-slate-500">Performance metrics and candidates sourced by {userName}</p>
                </div>
            </div>

            {/* Metrics */}
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
                <div className="bg-white border-t border-x border-slate-200 border-b-4 border-b-purple-500 shadow-sm p-5 relative overflow-hidden group">
                    <span className="block text-[28px] font-light text-slate-800 leading-none mb-1 relative z-10">{metrics.total}</span>
                    <span className="block text-[11px] font-bold text-slate-500 uppercase tracking-wide relative z-10">Total Sourced</span>
                    <Users className="absolute -right-2 top-1/2 -translate-y-1/2 text-purple-600 opacity-5 size-16 group-hover:opacity-10 transition-opacity" />
                </div>
                <div className="bg-white border-t border-x border-slate-200 border-b-4 border-b-amber-500 shadow-sm p-5 relative overflow-hidden group">
                    <span className="block text-[28px] font-light text-slate-800 leading-none mb-1 relative z-10">{metrics.inInterviews}</span>
                    <span className="block text-[11px] font-bold text-slate-500 uppercase tracking-wide relative z-10">In Interviews</span>
                    <UserCheck className="absolute -right-2 top-1/2 -translate-y-1/2 text-amber-600 opacity-5 size-16 group-hover:opacity-10 transition-opacity" />
                </div>
                <div className="bg-white border-t border-x border-slate-200 border-b-4 border-b-slate-400 shadow-sm p-5 relative overflow-hidden group">
                    <span className="block text-[28px] font-light text-slate-800 leading-none mb-1 relative z-10">{metrics.onHold}</span>
                    <span className="block text-[11px] font-bold text-slate-500 uppercase tracking-wide relative z-10">On Hold</span>
                    <Clock className="absolute -right-2 top-1/2 -translate-y-1/2 text-slate-600 opacity-5 size-16 group-hover:opacity-10 transition-opacity" />
                </div>
            </div>

            {/* Candidate List */}
            <div className="bg-white rounded-xl border border-slate-200 mt-8">
                <div className="px-5 py-4 border-b border-slate-200 bg-slate-50 rounded-t-xl flex justify-between items-center sm:flex-row flex-col gap-4">
                    <h2 className="text-lg font-semibold text-slate-800">Sourced Candidates</h2>

                    <div className="flex items-center gap-2 w-full sm:w-auto">
                        <div className="relative flex-grow sm:w-64">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 size-4" />
                            <input
                                type="text"
                                placeholder="Search candidates..."
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                className="w-full pl-9 pr-4 py-2 text-sm border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all"
                            />
                        </div>
                        <button
                            onClick={() => setShowFilters(!showFilters)}
                            className={`p-2 rounded-lg border transition-all ${showFilters || filterProfile || filterStatus || filterDateFrom || filterDateTo
                                ? 'bg-blue-50 border-blue-200 text-blue-700'
                                : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                                }`}
                            title="Toggle Filters"
                        >
                            <Filter size={18} />
                        </button>
                    </div>
                </div>

                {/* Filters Section */}
                {showFilters && (
                    <div className="p-4 border-b border-slate-100 bg-slate-50/50 animate-fade-in-down">
                        <div className="flex items-center justify-between mb-3">
                            <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider">Filter Candidates</h3>
                            {(filterProfile || filterStatus || filterDateFrom || filterDateTo) && (
                                <button
                                    onClick={() => {
                                        setFilterProfile('');
                                        setFilterStatus('');
                                        setFilterDateFrom('');
                                        setFilterDateTo('');
                                    }}
                                    className="text-[11px] font-semibold text-red-600 hover:text-red-700 flex items-center gap-1"
                                >
                                    <X size={12} /> Clear All
                                </button>
                            )}
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                            <div>
                                <label className="block text-[11px] font-medium text-slate-600 mb-1">Job Profile</label>
                                <select
                                    value={filterProfile}
                                    onChange={(e) => setFilterProfile(e.target.value)}
                                    className="w-full p-2 text-sm border border-slate-200 rounded-md focus:outline-none focus:border-blue-500 bg-white"
                                >
                                    <option value="">All Profiles</option>
                                    {uniqueProfiles.map(p => (
                                        <option key={p} value={p}>{p}</option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label className="block text-[11px] font-medium text-slate-600 mb-1">Status</label>
                                <select
                                    value={filterStatus}
                                    onChange={(e) => setFilterStatus(e.target.value)}
                                    className="w-full p-2 text-sm border border-slate-200 rounded-md focus:outline-none focus:border-blue-500 bg-white"
                                >
                                    <option value="">All Statuses</option>
                                    <option value="Interested">Interested</option>
                                    <option value="Not Interested">Not Interested</option>
                                    <option value="Not Relevant">Not Relevant</option>
                                    <option value="Not Picking">Not Picking</option>
                                </select>
                            </div>
                            <div>
                                <label className="block text-[11px] font-medium text-slate-600 mb-1">Date From</label>
                                <input
                                    type="date"
                                    value={filterDateFrom}
                                    onChange={(e) => setFilterDateFrom(e.target.value)}
                                    className="w-full p-2 text-sm border border-slate-200 rounded-md focus:outline-none focus:border-blue-500 bg-white"
                                />
                            </div>
                            <div>
                                <label className="block text-[11px] font-medium text-slate-600 mb-1">Date To</label>
                                <input
                                    type="date"
                                    value={filterDateTo}
                                    onChange={(e) => setFilterDateTo(e.target.value)}
                                    className="w-full p-2 text-sm border border-slate-200 rounded-md focus:outline-none focus:border-blue-500 bg-white"
                                />
                            </div>
                        </div>
                    </div>
                )}

                {filteredCandidates.length === 0 ? (
                    <div className="p-12 text-center flex flex-col items-center">
                        <Upload className="text-slate-300 mb-4" size={48} />
                        <h3 className="text-lg font-semibold text-slate-700 mb-2">No Candidates Found</h3>
                        <p className="text-slate-500">No candidates match the current filters or none have been sourced yet.</p>
                    </div>
                ) : (
                    <div className="w-full overflow-x-auto">
                        <div className="min-w-[1000px]">
                            <table className="w-full text-left border-collapse">
                                <thead>
                                    <tr className="bg-white border-b border-slate-200">
                                        <th className="px-5 py-4 text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Candidate</th>
                                        <th className="px-5 py-4 text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Experience</th>
                                        <th className="px-5 py-4 text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Interviews</th>
                                        <th className="px-5 py-4 text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Decision</th>
                                        <th className="px-5 py-4 text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Hiring Request</th>
                                        <th className="px-5 py-4 text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Date</th>
                                        <th className="px-5 py-4 text-[11px] font-semibold text-slate-500 uppercase tracking-wider text-center">Actions</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {filteredCandidates.map(candidate => (
                                        <tr key={candidate._id} className="hover:bg-slate-50 transition-colors">
                                            <td className="px-5 py-4 align-top">
                                                <div className="flex flex-col">
                                                    <span className="font-bold text-slate-800 text-[14px]">
                                                        {candidate.candidateName}
                                                    </span>
                                                    <span className="text-slate-500 text-[12px]">{candidate.email}</span>
                                                    <span className="text-slate-500 text-[12px] mt-0.5">{candidate.mobile}</span>
                                                </div>
                                            </td>
                                            <td className="px-5 py-4 align-top">
                                                <span className="text-[13px] font-semibold text-slate-700">{candidate.totalExperience} yrs</span>
                                            </td>
                                            <td className="px-5 py-4 align-top">
                                                {(() => {
                                                    const summary = getInterviewStatusSummary(candidate.interviewRounds);
                                                    const rounds = candidate.interviewRounds || [];
                                                    const hasFailed = rounds.some(r => r.status === 'Failed');
                                                    const ratedRounds = rounds.filter(r => r.rating && r.rating > 0);
                                                    let avgRating = null;

                                                    if (!hasFailed && ratedRounds.length > 0) {
                                                        const total = ratedRounds.reduce((acc, curr) => acc + curr.rating, 0);
                                                        let calculatedAvg = total / ratedRounds.length;
                                                        avgRating = Number.isInteger(calculatedAvg) ? calculatedAvg.toString() : calculatedAvg.toFixed(1);
                                                    }

                                                    return (
                                                        <div className="flex flex-col gap-1.5 items-start">
                                                            <span className={`px-2 py-0.5 border rounded-md text-[10px] font-bold tracking-wide ${summary.color}`}>
                                                                {summary.label}
                                                            </span>
                                                            <div className="flex flex-col gap-1">
                                                                <span className="text-[11px] text-slate-500 font-medium whitespace-nowrap leading-tight">
                                                                    {candidate.interviewRounds?.length || 0} rounds total
                                                                </span>
                                                                {avgRating && (
                                                                    <span className="text-[11px] font-bold text-amber-600 flex items-center gap-1 bg-amber-50 px-1.5 py-0.5 rounded border border-amber-200 self-start">
                                                                        ⭐ {avgRating}/10
                                                                    </span>
                                                                )}
                                                            </div>
                                                        </div>
                                                    )
                                                })()}
                                            </td>
                                            <td className="px-5 py-4 align-top">
                                                <span className={`text-[12px] ${getDecisionColor(candidate.decision || 'None')}`}>
                                                    {candidate.decision || 'None'}
                                                </span>
                                            </td>
                                            <td className="px-5 py-4 align-top">
                                                <div className="flex flex-col max-w-[150px]">
                                                    <span className="text-[12px] font-bold text-slate-700 truncate" title={candidate.hiringRequestId?.roleDetails?.title}>
                                                        {candidate.hiringRequestId?.roleDetails?.title || 'Unknown Role'}
                                                    </span>
                                                    <span className="text-[11px] text-slate-500 font-medium tracking-wide">
                                                        {candidate.hiringRequestId?.requestId || '-'}
                                                    </span>
                                                </div>
                                            </td>
                                            <td className="px-5 py-4 align-top">
                                                <div className="flex flex-col text-[12px] text-slate-500 font-medium">
                                                    <span>{format(new Date(candidate.uploadedAt), 'MMM dd, yyyy')}</span>
                                                    <span className="text-[11px]">{format(new Date(candidate.uploadedAt), 'hh:mm a')}</span>
                                                </div>
                                            </td>
                                            <td className="px-5 py-4 align-top text-center">
                                                <div className="flex items-center justify-center gap-2">
                                                    <button
                                                        onClick={() => navigate(`/ta/hiring-request/${candidate.hiringRequestId?._id || candidate.hiringRequestId}/candidate/${candidate._id}/view`)}
                                                        className="p-1.5 text-blue-600 hover:bg-blue-50 focus:ring-2 focus:ring-blue-100 rounded-lg transition-colors"
                                                        title="View Candidate"
                                                    >
                                                        <Eye size={18} />
                                                    </button>
                                                    {candidate.resumeUrl && (
                                                        <a
                                                            href={candidate.resumeUrl}
                                                            target="_blank"
                                                            rel="noopener noreferrer"
                                                            className="p-1.5 text-slate-500 hover:bg-slate-100 focus:ring-2 focus:ring-slate-200 rounded-lg transition-colors"
                                                            title="View Resume"
                                                        >
                                                            <FileText size={18} />
                                                        </a>
                                                    )}
                                                </div>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default UserTADashboard;

import React, { useState, useEffect } from 'react';
import api from '../../api/axios';
import { Plus, Trash2, Save, X, Check, ArrowRight, Loader } from 'lucide-react';
import { toast } from 'react-hot-toast';
import Skeleton from '../../components/Skeleton';

const WorkflowSettings = () => {
    // Tabs Support
    const [activeTab, setActiveTab] = useState('APPROVAL');

    // Shared State
    const [users, setUsers] = useState([]);
    const [roles, setRoles] = useState([]);

    // ==========================================
    // 1. APPROVAL WORKFLOWS STATE (HIRING APPROVALS)
    // ==========================================
    const [workflows, setWorkflows] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showCreate, setShowCreate] = useState(false);
    const [actionLoading, setActionLoading] = useState(false);

    // Create/Edit Approval State
    const [newName, setNewName] = useState('');
    const [levels, setLevels] = useState([{ levelCheck: 1, role: '', approvers: [], isFinal: false }]);
    const [editingId, setEditingId] = useState(null);

    // ==========================================
    // 2. INTERVIEW WORKFLOWS STATE
    // ==========================================
    const [interviewWorkflows, setInterviewWorkflows] = useState([]);
    const [loadingInterview, setLoadingInterview] = useState(true);
    const [showCreateInterview, setShowCreateInterview] = useState(false);
    const [actionLoadingInterview, setActionLoadingInterview] = useState(false);

    // Create/Edit Interview State
    const [newInterviewName, setNewInterviewName] = useState('');
    const [newInterviewDesc, setNewInterviewDesc] = useState('');
    const [interviewRounds, setInterviewRounds] = useState([{ levelCheck: 1, levelName: '', role: '' }]);
    const [editingInterviewId, setEditingInterviewId] = useState(null);


    // Init
    useEffect(() => {
        fetchWorkflows();
        fetchInterviewWorkflows();
        fetchUsers();
        fetchRoles();
    }, []);

    const fetchUsers = async () => {
        try {
            const res = await api.get('/admin/users');
            setUsers(res.data);
        } catch (error) {
            console.error('Failed to fetch users', error);
        }
    };

    const fetchRoles = async () => {
        try {
            const res = await api.get('/admin/roles');
            setRoles(res.data);
        } catch (error) {
            console.error('Failed to fetch roles', error);
        }
    };

    // ==========================================
    // APPROVAL WORKFLOWS LOGIC
    // ==========================================
    const fetchWorkflows = async () => {
        try {
            const res = await api.get('/workflows?module=TA');
            setWorkflows(res.data);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const handleAddLevel = () => setLevels([...levels, { levelCheck: levels.length + 1, role: '', approvers: [], isFinal: false }]);
    const handleRemoveLevel = (index) => {
        const newLevels = levels.filter((_, i) => i !== index);
        setLevels(newLevels.map((l, i) => ({ ...l, levelCheck: i + 1 })));
    };
    const handleLevelChange = (index, field, value) => {
        const newLevels = [...levels];
        newLevels[index][field] = value;
        setLevels(newLevels);
    };
    const handleApproverChange = (index, userId) => {
        const newLevels = [...levels];
        const currentApprovers = newLevels[index].approvers || [];
        if (currentApprovers.includes(userId)) newLevels[index].approvers = currentApprovers.filter(id => id !== userId);
        else newLevels[index].approvers = [...currentApprovers, userId];
        setLevels(newLevels);
    };

    const handleCreateWorkflow = async () => {
        if (!newName) return toast.error('Workflow name is required');
        for (let l of levels) {
            if (!l.role) return toast.error(`Role is required for Level ${l.levelCheck}`);
            if (!l.approvers || l.approvers.length === 0) return toast.error(`Select at least one approver for Level ${l.levelCheck}`);
        }

        try {
            setActionLoading(true);
            if (editingId) {
                await api.put(`/workflows/${editingId}`, { name: newName, levels, module: 'TA' });
                toast.success('Hiring workflow updated');
            } else {
                await api.post('/workflows', { name: newName, levels, module: 'TA' });
                toast.success('Hiring workflow created');
            }
            setShowCreate(false);
            setEditingId(null);
            setNewName('');
            setLevels([{ levelCheck: 1, role: '', approvers: [], isFinal: false }]);
            fetchWorkflows();
        } catch (error) {
            toast.error(error.response?.data?.message || 'Failed to save');
        } finally {
            setActionLoading(false);
        }
    };

    const handleEdit = (wf) => {
        setEditingId(wf._id);
        setNewName(wf.name);
        setLevels(wf.levels.map(l => ({
            levelCheck: l.levelCheck,
            role: l.role ? (l.role._id || l.role) : '',
            approvers: l.approvers ? l.approvers.map(a => a._id || a) : [],
            isFinal: l.isFinal
        })));
        setShowCreate(true);
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    const handleDelete = async (id) => {
        if (!window.confirm('Are you sure you want to delete this workflow?')) return;
        try {
            await api.delete(`/workflows/${id}`);
            toast.success('Workflow deleted');
            fetchWorkflows();
        } catch (error) {
            toast.error('Failed to delete');
        }
    };

    // ==========================================
    // INTERVIEW WORKFLOWS LOGIC
    // ==========================================
    const fetchInterviewWorkflows = async () => {
        try {
            const res = await api.get('/ta/interview-workflows');
            setInterviewWorkflows(res.data);
        } catch (error) {
            console.error(error);
        } finally {
            setLoadingInterview(false);
        }
    };

    const handleAddInterviewRound = () => setInterviewRounds([...interviewRounds, { levelCheck: interviewRounds.length + 1, levelName: '', role: '', user: '' }]);
    const handleRemoveInterviewRound = (index) => {
        const newRounds = interviewRounds.filter((_, i) => i !== index);
        setInterviewRounds(newRounds.map((r, i) => ({ ...r, levelCheck: i + 1 })));
    };
    const handleInterviewRoundChange = (index, field, value) => {
        const newRounds = [...interviewRounds];
        newRounds[index][field] = value;
        setInterviewRounds(newRounds);
    };

    const handleCreateInterviewWorkflow = async () => {
        if (!newInterviewName) return toast.error('Interview template name is required');
        for (let r of interviewRounds) {
            if (!r.levelName) return toast.error(`Round Title is required for Round ${r.levelCheck}`);
        }

        try {
            setActionLoadingInterview(true);
            if (editingInterviewId) {
                await api.put(`/ta/interview-workflows/${editingInterviewId}`, { name: newInterviewName, description: newInterviewDesc, rounds: interviewRounds });
                toast.success('Interview Workflow updated');
            } else {
                await api.post('/ta/interview-workflows', { name: newInterviewName, description: newInterviewDesc, rounds: interviewRounds });
                toast.success('Interview Workflow created');
            }
            setShowCreateInterview(false);
            setEditingInterviewId(null);
            setNewInterviewName('');
            setNewInterviewDesc('');
            setInterviewRounds([{ levelCheck: 1, levelName: '', role: '', user: '' }]);
            fetchInterviewWorkflows();
        } catch (error) {
            toast.error(error.response?.data?.message || 'Failed to save');
        } finally {
            setActionLoadingInterview(false);
        }
    };

    const handleEditInterview = (wf) => {
        setEditingInterviewId(wf._id);
        setNewInterviewName(wf.name);
        setNewInterviewDesc(wf.description || '');
        setInterviewRounds(wf.rounds.map(r => ({
            levelCheck: r.levelCheck,
            levelName: r.levelName,
            role: r.role ? (r.role._id || r.role) : '',
            user: r.user ? (r.user._id || r.user) : ''
        })));
        setShowCreateInterview(true);
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    const handleDeleteInterview = async (id) => {
        if (!window.confirm('Are you sure you want to delete this Interview Workflow?')) return;
        try {
            await api.delete(`/ta/interview-workflows/${id}`);
            toast.success('Interview workflow deleted');
            fetchInterviewWorkflows();
        } catch (error) {
            toast.error('Failed to delete');
        }
    };

    return (
        <div className="w-full mx-auto px-4 sm:px-6 lg:px-8 py-6">
            {/* Header Area */}
            <div className="flex justify-between items-center mb-6">
                <div>
                    <h1 className="text-2xl font-bold text-slate-800">TA Workflows</h1>
                    <p className="text-slate-500">Configure hiring rules and candidate interview templates</p>
                </div>
                {activeTab === 'APPROVAL' ? (
                    <button onClick={() => setShowCreate(!showCreate)} className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2">
                        {showCreate ? <X size={18} /> : <Plus size={18} />}
                        {showCreate ? 'Cancel' : 'Create Approval Workflow'}
                    </button>
                ) : (
                    <button onClick={() => setShowCreateInterview(!showCreateInterview)} className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2">
                        {showCreateInterview ? <X size={18} /> : <Plus size={18} />}
                        {showCreateInterview ? 'Cancel' : 'Create Interview Workflow'}
                    </button>
                )}
            </div>

            {/* Tabs Navigation */}
            <div className="flex gap-4 border-b border-slate-200 mb-6 font-medium">
                <button
                    onClick={() => setActiveTab('APPROVAL')}
                    className={`pb-3 px-4 transition-colors ${activeTab === 'APPROVAL' ? 'border-b-2 border-blue-600 text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    Hiring Approvals
                </button>
                <button
                    onClick={() => setActiveTab('INTERVIEW')}
                    className={`pb-3 px-4 transition-colors ${activeTab === 'INTERVIEW' ? 'border-b-2 border-blue-600 text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    Candidate Interviews
                </button>
            </div>

            {/* =========================================================================
                                APPROVAL TAB CONTENT
            ========================================================================== */}
            {activeTab === 'APPROVAL' && (
                <>
                    {/* Create / Edit Form */}
                    {showCreate && (
                        <div className="bg-white p-6 rounded-lg border border-slate-200 shadow-sm mb-6 animate-in fade-in slide-in-from-top-4 duration-300">
                            <div className="flex justify-between items-center mb-4">
                                <h3 className="font-semibold text-lg">{editingId ? 'Edit Hiring Workflow' : 'New Hiring Workflow'}</h3>
                                {editingId && (
                                    <button onClick={() => { setEditingId(null); setNewName(''); setLevels([{ levelCheck: 1, role: '', approvers: [], isFinal: false }]); setShowCreate(false); }} className="text-slate-400 hover:text-slate-600">
                                        <X size={20} />
                                    </button>
                                )}
                            </div>

                            <div className="mb-4">
                                <label className="block text-sm font-medium text-slate-700 mb-1">Workflow Name</label>
                                <input type="text" value={newName} onChange={(e) => setNewName(e.target.value)} className="w-full border border-slate-300 rounded-md px-3 py-2 outline-none focus:border-blue-500" placeholder="e.g., Standard Hiring Approval" />
                            </div>

                            <div className="mb-4">
                                <label className="block text-sm font-medium text-slate-700 mb-2">Approval Levels</label>
                                <div className="space-y-3">
                                    {levels.map((level, index) => {
                                        const roleUsers = users.filter(u => u.roles && u.roles.some(r => r._id === level.role || r === level.role));
                                        return (
                                            <div key={index} className="flex flex-col gap-3 bg-slate-50 p-4 rounded-md border border-slate-200">
                                                <div className="flex items-center justify-between">
                                                    <div className="flex items-center gap-2">
                                                        <div className="w-6 h-6 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center font-bold text-xs">{level.levelCheck}</div>
                                                        <span className="font-semibold text-sm text-slate-700">Level {level.levelCheck}</span>
                                                    </div>
                                                    {index > 0 && <button onClick={() => handleRemoveLevel(index)} className="text-red-500 hover:text-red-700"><Trash2 size={16} /></button>}
                                                </div>

                                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                                    <div>
                                                        <label className="block text-xs font-medium text-slate-500 mb-1">Role</label>
                                                        <select value={level.role || ''} onChange={(e) => { handleLevelChange(index, 'role', e.target.value); handleLevelChange(index, 'approvers', []); }} className="w-full border border-slate-300 rounded-md px-3 py-1.5 text-sm">
                                                            <option value="">Select Role</option>
                                                            {roles.map(r => <option key={r._id} value={r._id}>{r.name}</option>)}
                                                        </select>
                                                    </div>
                                                    <div>
                                                        <label className="block text-xs font-medium text-slate-500 mb-1">Approvers (Select Multiple)</label>
                                                        <div className="border border-slate-300 rounded-md max-h-32 overflow-y-auto bg-white p-2">
                                                            {level.role ? (
                                                                roleUsers.length > 0 ? (
                                                                    roleUsers.map(u => (
                                                                        <div key={u._id} className="flex items-center gap-2 mb-1 last:mb-0">
                                                                            <input type="checkbox" id={`lvl-${index}-u-${u._id}`} checked={level.approvers?.includes(u._id)} onChange={() => handleApproverChange(index, u._id)} className="rounded border-slate-300 text-blue-600 focus:ring-blue-500" />
                                                                            <label htmlFor={`lvl-${index}-u-${u._id}`} className="text-sm text-slate-700 cursor-pointer select-none">{u.firstName} {u.lastName}</label>
                                                                        </div>
                                                                    ))
                                                                ) : <p className="text-xs text-slate-400 italic p-1">No users found with this role.</p>
                                                            ) : <p className="text-xs text-slate-400 italic p-1">So select a role first.</p>}
                                                        </div>
                                                        <p className="text-xs text-slate-400 mt-1">{level.approvers?.length || 0} selected</p>
                                                    </div>
                                                </div>
                                            </div>
                                        )
                                    })}
                                </div>
                                <button onClick={handleAddLevel} className="mt-3 text-sm text-blue-600 font-medium hover:text-blue-800 flex items-center gap-1"><Plus size={16} /> Add Level</button>
                            </div>

                            <div className="flex justify-end">
                                <button onClick={handleCreateWorkflow} disabled={actionLoading} className="bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 disabled:opacity-50">
                                    {actionLoading ? <Loader size={18} className="animate-spin" /> : <Save size={18} />} Save Hiring Workflow
                                </button>
                            </div>
                        </div>
                    )}

                    {/* Data Table */}
                    <div className="bg-white rounded-lg border border-slate-200 shadow-sm overflow-hidden animate-in fade-in duration-300">
                        {loading ? (
